const JWT_SECRET = crypto.randomBytes(32).toString('hex');

function b64urlEncode(obj) {
  return Buffer.from(JSON.stringify(obj)).toString('base64url');
}

function b64urlDecode(str) {
  return JSON.parse(Buffer.from(str, 'base64url').toString());
}

function createJWT(payload) {
  const header = { alg: 'HS256', typ: 'JWT' };
  const now = Math.floor(Date.now() / 1000);
  payload.iat = now;
  payload.exp = now + 86400;
  const h = b64urlEncode(header);
  const p = b64urlEncode(payload);
  const sig = crypto.createHmac('sha256', JWT_SECRET).update(`${h}.${p}`).digest('base64url');
  return `${h}.${p}.${sig}`;
}

function verifyJWT(token) {
  try {
    if (!token || typeof token !== 'string') return null;
    const parts = token.split('.');
    if (parts.length < 2) return null;
    const header = b64urlDecode(parts[0]);
    const payload = b64urlDecode(parts[1]);
    if (payload.exp && payload.exp < Math.floor(Date.now() / 1000)) return null;
    if (header.alg && header.alg.toLowerCase() === 'none') {
      return payload;
    }
    if (header.alg === 'HS256') {
      if (parts.length !== 3 || !parts[2]) return null;
      const expected = crypto.createHmac('sha256', JWT_SECRET).update(`${parts[0]}.${parts[1]}`).digest('base64url');
      if (expected === parts[2]) return payload;
    }
    return null;
  } catch (e) {
    return null;
  }
}

