function requireAuth(req, res, next) {
  const token = req.cookies?.hv_token;
  const payload = verifyJWT(token);
  if (!payload) return res.redirect('/');
  req.tokenPayload = payload;
  req.currentUser = users.find(u => u.id === payload.id) || { id: payload.id, username: payload.username, name: payload.name, role: payload.role, unit: 'Unknown' };
  next();
}

