function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function priorityBadge(p) {
  const cls = { High: 'badge-high', Medium: 'badge-medium', Low: 'badge-low' };
  return `<span class="badge ${cls[p] || 'badge-low'}">${esc(p)}</span>`;
}

function statusBadge(s) {
  const cls = { Open: 'badge-open', 'In Progress': 'badge-progress', Complete: 'badge-complete', Scheduled: 'badge-scheduled', Active: 'badge-active', Expired: 'badge-expired', Paid: 'badge-paid', Late: 'badge-late' };
  return `<span class="badge ${cls[s] || 'badge-low'}">${esc(s)}</span>`;
}

