app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.redirect('/?error=Invalid+username+or+password');
  const token = createJWT({ id: user.id, username: user.username, name: user.name, role: user.role });
  res.cookie('hv_token', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  res.clearCookie('hv_token');
  res.redirect('/');
});

