function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function statusBadge(s) {
  const cls = { Complete:'badge-complete','In Progress':'badge-progress',Pending:'badge-pending',Late:'badge-late',Active:'badge-active',Archived:'badge-archived',Completed:'badge-complete' };
  return `<span class="badge ${cls[s]||'badge-pending'}">${esc(s)}</span>`;
}

function priorityBadge(s) {
  const cls = { High:'badge-high',Medium:'badge-medium',Low:'badge-low' };
  return `<span class="badge ${cls[s]||'badge-medium'}">${esc(s)}</span>`;
}

function roleBadge(s) {
  const cls = { tenant:'badge-tenant',manager:'badge-manager',admin:'badge-admin' };
  return `<span class="badge ${cls[s]||'badge-tenant'}">${esc(s)}</span>`;
}

function getInitials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function renderSidebar(activePage, user) {
  const init = getInitials(user.name || 'U');
  const isElevated = user.role === 'manager' || user.role === 'admin';
  return `
