function pageShell(title, activePage, user, content) {
  return `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>${esc(title)} — HarborView</title><style>${baseStyles}</style></head><body class="fade-in"><div class="app-layout">${renderSidebar(activePage, user)}<main class="main-content">${content}</main></div></body></html>`;
}

function requireAuth(req, res, next) {
  const token = req.cookies?.hv_token;
  if (!token) return res.redirect('/');
  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = decoded;
    next();
  } catch (e) {
    res.clearCookie('hv_token');
    return res.redirect('/');
  }
}

function requireRole(...roles) {
  return (req, res, next) => {
    if (!roles.includes(req.user.role)) {
      return res.send(pageShell('Access Denied', '', req.user, `
        <div class="access-denied">
          <div class="lock-icon">🔒</div>
          <h2>Access Denied</h2>
          <p>This area is restricted. Your current role does not have permission to view this page.</p>
          <div class="role-badge">Required role: ${esc(roles.join(' or '))}</div>
          <p style="margin-top:16px;font-size:0.8rem;color:var(--text-muted);">Your role: <strong>${esc(req.user.role)}</strong></p>
        </div>
      `));
    }
    next();
  };
}

