app.get('/', (req, res) => {
  const token = req.cookies?.hv_token;
  if (token) {
    try { jwt.verify(token, JWT_SECRET); return res.redirect('/dashboard'); } catch(e) {}
  }
  res.send(loginPageContent.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const tenant = tenants.find(t => t.username === username && t.password === password);
  if (!tenant) {
    return res.send(loginPageContent
      .replace('%%LOGIN_MSG%%', '<div class="error-msg">Invalid credentials.</div>')
      .replace('%%REG_MSG%%', ''));
  }
  const token = jwt.sign({ id: tenant.id, username: tenant.username, name: tenant.name, role: tenant.role, unit: tenant.unit }, JWT_SECRET, { algorithm: 'HS256', expiresIn: '4h' });
  res.cookie('hv_token', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(loginPageContent.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', '<div class="error-msg">All fields required.</div>'));
  }
  if (tenants.find(t => t.username === username)) {
    return res.send(loginPageContent.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', '<div class="error-msg">Username taken.</div>'));
  }
  const newId = nextTenantId++;
  const newTenant = {
    id: newId, username, password, name, role: 'tenant', unit: 'TBD',
    email: username + '@email.com', phone: 'N/A',
    leaseStart: new Date().toISOString().split('T')[0], leaseEnd: 'Pending',
    rent: 0, balance: 0, status: 'Active',
    privateNotes: 'Newly registered tenant. Pending unit assignment.',
    visible: true
  };
  tenants.push(newTenant);
  const token = jwt.sign({ id: newTenant.id, username: newTenant.username, name: newTenant.name, role: newTenant.role, unit: newTenant.unit }, JWT_SECRET, { algorithm: 'HS256', expiresIn: '4h' });
  res.cookie('hv_token', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  res.clearCookie('hv_token');
  res.redirect('/');
});

