app.get('/api/tenants/:id', requireAuth, (req, res) => {
  if (req.user.role !== 'manager' && req.user.role !== 'admin') {
    return res.status(403).json({ error: 'ACCESS DENIED', message: 'Manager or admin role required.' });
  }
  const tenantId = parseInt(req.params.id);
  const tenant = tenants.find(t => t.id === tenantId);
  if (!tenant) {
    return res.status(404).json({ error: 'Tenant not found', message: 'No tenant record with ID ' + tenantId });
  }
  res.json({
    id: tenant.id,
    username: tenant.username,
    name: tenant.name,
    role: tenant.role,
    unit: tenant.unit,
    email: tenant.email,
    phone: tenant.phone,
    leaseStart: tenant.leaseStart,
    leaseEnd: tenant.leaseEnd,
    rent: tenant.rent,
    balance: tenant.balance,
    status: tenant.status,
    privateNotes: tenant.privateNotes
  });
});

