        <a href="/maintenance" class="${activePage==='maintenance'?'active':''}"><span class="ic">🔧</span> Maintenance</a>
        <a href="/lease" class="${activePage==='lease'?'active':''}"><span class="ic">📄</span> Lease Info</a>
