app.get('/maintenance', requireAuth, (req, res) => {
  const user = req.user;

  const requestCards = maintenanceRequests.map(r => `
    <div class="request-card">
      <div class="req-header">
        <span class="req-title">${esc(r.title)}</span>
        <span>${priorityBadge(r.priority)} ${statusBadge(r.status)}</span>
      </div>
      <div class="req-meta">Unit ${esc(r.unit)} &bull; ${esc(r.author)} &bull; ${esc(r.date)}</div>
      <div class="req-body">${r.description}</div>
    </div>`).join('');

  res.send(pageShell('Maintenance', 'maintenance', user, `
    <div class="page-header">
      <h1>Maintenance Requests</h1>
      <p class="subtitle">Submit and track building maintenance issues</p>
    </div>

    <div class="card" style="margin-bottom:24px;">
      <h3 style="font-family:var(--font-mono);font-size:.95rem;margin-bottom:16px;color:var(--accent);">Submit New Request</h3>
      <div id="submit-msg"></div>
      <form id="maint-form">
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;">
          <div class="form-group"><label>Title</label><input type="text" name="title" placeholder="Brief description of the issue" required></div>
          <div class="form-group"><label>Priority</label>
            <select name="priority"><option value="Low">Low</option><option value="Medium" selected>Medium</option><option value="High">High</option></select>
          </div>
        </div>
        <div class="form-group"><label>Description</label><textarea name="description" rows="3" placeholder="Detailed description of the maintenance issue..." required></textarea></div>
        <button type="submit" class="btn btn-primary">Submit Request</button>
      </form>
      <script>
        document.getElementById('maint-form').addEventListener('submit', async function(e) {
          e.preventDefault();
          const form = e.target;
          const body = {
            title: form.title.value,
            description: form.description.value,
            priority: form.priority.value
          };
          const resp = await fetch('/api/maintenance', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body)
          });
          const result = await resp.json();
          if (result.success) {
            document.getElementById('submit-msg').innerHTML = '<div class="success-msg">Request submitted successfully!</div>';
            form.reset();
            setTimeout(() => location.reload(), 800);
          } else {
            document.getElementById('submit-msg').innerHTML = '<div class="error-msg">' + result.error + '</div>';
          }
        });
      </script>
    </div>

    <h3 style="font-family:var(--font-mono);font-size:.95rem;margin-bottom:16px;">All Requests</h3>
    ${requestCards.length ? requestCards : '<p style="color:var(--text-muted);">No maintenance requests yet.</p>'}
  `));
});

app.post('/api/maintenance', requireAuth, (req, res) => {
  const user = req.user;
  const { title, description, priority } = req.body;
  if (!title || !description) {
    return res.json({ success: false, error: 'Title and description are required.' });
  }
  const request = {
    id: nextRequestId++,
    unit: user.unit,
    author: user.username,
    title: String(title).substring(0, 200),
    description: String(description),
    priority: ['Low','Medium','High'].includes(priority) ? priority : 'Medium',
    status: 'Open',
    date: new Date().toISOString().split('T')[0],
  };
  maintenanceRequests.push(request);
  res.json({ success: true, id: request.id });
});

