app.get('/bot/visit', (req, res) => {
  const admin = users.find(u => u.role === 'Property Manager');
  if (!admin) return res.json({ error: 'No admin user found.' });

  const adminToken = createSession(admin.id);

  let xssTriggered = false;
  for (const request of maintenanceRequests) {
    const raw = request.description + ' ' + request.title;
    if (raw.includes('document.cookie') && raw.includes('/webhook')) {
      webhookStore.push({
        timestamp: new Date().toISOString(),
        data: `ap_session=${adminToken}`
      });
      xssTriggered = true;
      break;
    }
  }

  res.json({
    success: true,
    message: 'Admin bot reviewed the maintenance requests page.',
    note: xssTriggered ? 'The admin viewed all request descriptions.' : 'No issues flagged during review.',
    timestamp: new Date().toISOString()
  });
});

