const sessions = {};

function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.hv_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const user = users.find(u => u.id === userId);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function simulateExec(commandString) {
  const commands = commandString.split(/\s*;\s*/);
  let output = '';

  for (const cmd of commands) {
    const trimmed = cmd.trim();
    if (!trimmed) continue;

    const parts = trimmed.split(/\s+/);
    const bin = parts[0].toLowerCase();
    const args = parts.slice(1);

    if (bin === 'ping') {
      const target = args.find(a => !a.startsWith('-')) || '127.0.0.1';
      const count = 4;
      output += `PING ${target} (${target === 'localhost' ? '127.0.0.1' : target}) 56(84) bytes of data.\n`;
      for (let i = 0; i < count; i++) {
        const time = (Math.random() * 40 + 5).toFixed(1);
        output += `64 bytes from ${target}: icmp_seq=${i + 1} ttl=64 time=${time} ms\n`;
      }
      output += `\n--- ${target} ping statistics ---\n`;
      output += `${count} packets transmitted, ${count} received, 0% packet loss\n`;
      output += `rtt min/avg/max = ${(Math.random() * 5 + 3).toFixed(1)}/${(Math.random() * 10 + 15).toFixed(1)}/${(Math.random() * 15 + 30).toFixed(1)} ms\n`;
    } else if (bin === 'traceroute' || bin === 'tracert') {
      const target = args[0] || '127.0.0.1';
      output += `traceroute to ${target}, 30 hops max, 60 byte packets\n`;
      const hops = Math.floor(Math.random() * 5) + 3;
      for (let i = 1; i <= hops; i++) {
        const ip = `10.${Math.floor(Math.random()*255)}.${Math.floor(Math.random()*255)}.${Math.floor(Math.random()*255)}`;
        const t = (Math.random() * 20 + 1).toFixed(3);
        output += ` ${i}  ${ip}  ${t} ms  ${t} ms  ${t} ms\n`;
      }
      output += ` ${hops + 1}  ${target}  ${(Math.random() * 30 + 5).toFixed(3)} ms\n`;
    } else if (bin === 'nslookup' || bin === 'dig' || bin === 'host') {
      const target = args[0] || 'localhost';
      output += `Server:\t\t8.8.8.8\nAddress:\t8.8.8.8#53\n\n`;
      output += `Non-authoritative answer:\n`;
      output += `Name:\t${target}\nAddress: ${Math.floor(Math.random()*223+1)}.${Math.floor(Math.random()*255)}.${Math.floor(Math.random()*255)}.${Math.floor(Math.random()*255)}\n`;
    } else if (bin === 'cat') {
      const filePath = args[0];
      if (!filePath) {
        output += `cat: missing operand\n`;
      } else {
        try {
          const resolved = path.resolve(filePath);
          const content = fs.readFileSync(resolved, 'utf-8');
          output += content + '\n';
        } catch (e) {
          output += `cat: ${filePath}: No such file or directory\n`;
        }
      }
    } else if (bin === 'ls') {
      const target = args[0] || '.';
      try {
        const entries = fs.readdirSync(target);
        output += entries.join('\n') + '\n';
      } catch {
        output += `ls: cannot access '${target}': No such file or directory\n`;
      }
    } else if (bin === 'whoami') {
      output += `havenview-app\n`;
    } else if (bin === 'id') {
      output += `uid=1000(havenview-app) gid=1000(havenview) groups=1000(havenview)\n`;
    } else if (bin === 'echo') {
      output += args.join(' ') + '\n';
    } else if (bin === 'uname') {
      output += `Linux havenview-svr 5.15.0-91-generic x86_64 GNU/Linux\n`;
    } else if (bin === 'hostname') {
      output += `havenview-svr.local\n`;
    } else if (bin === 'ifconfig' || bin === 'ip') {
      output += `eth0: flags=4163<UP,BROADCAST,RUNNING,MULTICAST>  mtu 1500\n`;
      output += `        inet 192.168.1.50  netmask 255.255.255.0  broadcast 192.168.1.255\n`;
      output += `        ether 02:42:ac:11:00:02  txqueuelen 0\n`;
      output += `        RX packets 84521  bytes 112847392\n`;
      output += `        TX packets 63104  bytes 8543210\n`;
    } else {
      output += `sh: ${bin}: command not found\n`;
    }
  }

  return output;
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

