function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function priorityBadge(p) {
  const cls = { High: 'badge-high', Medium: 'badge-medium', Low: 'badge-low' };
  return `<span class="badge ${cls[p] || 'badge-low'}">${esc(p)}</span>`;
}

function statusBadge(s) {
  const map = { 'In Progress': 'badge-progress', Scheduled: 'badge-scheduled', Complete: 'badge-complete', Active: 'badge-active', 'Renewal Pending': 'badge-renewal', Paid: 'badge-paid', Late: 'badge-late' };
  return `<span class="badge ${map[s] || 'badge-progress'}">${esc(s)}</span>`;
}

function renderSidebar(activePage, user) {
  const init = initials(user.name);
  return `
    <aside class="sidebar">
      <div class="sidebar-brand">
        <div class="icon-box">🏢</div>
        <h1>Haven<span>View</span></h1>
      </div>
      <nav class="sidebar-nav">
        <div class="section-label">Management</div>
        <a href="/dashboard" class="${activePage === 'dashboard' ? 'active' : ''}">
          <span class="icon">📊</span> Dashboard
        </a>
        <a href="/maintenance" class="${activePage === 'maintenance' ? 'active' : ''}">
          <span class="icon">🔧</span> Maintenance
        </a>
        <a href="/leases" class="${activePage === 'leases' ? 'active' : ''}">
          <span class="icon">📄</span> Leases
        </a>
        <a href="/payments" class="${activePage === 'payments' ? 'active' : ''}">
          <span class="icon">💳</span> Payments
        </a>
        <div class="section-label">Utilities</div>
        <a href="/tools/network" class="${activePage === 'network' ? 'active' : ''}">
          <span class="icon">🌐</span> Network Tools
        </a>
        <div class="section-label">&nbsp;</div>
        <a href="/logout">
          <span class="icon">🚪</span> Sign Out
        </a>
      </nav>
      <div class="sidebar-user">
        <div class="avatar">${initials(user.name)}</div>
        <div class="user-info">
          <div class="user-name">${esc(user.name)}</div>
          <div class="user-role">${esc(user.role)} · ${esc(user.unit)}</div>
        </div>
      </div>
    </aside>`;
}

function pageShell(title, activePage, user, content) {
  return `<!DOCTYPE html>
<html lang="en"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${esc(title)} — HavenView</title>
<style>${baseStyles}</style>
</head><body class="fade-in">
<div class="app-layout">
  ${renderSidebar(activePage, user)}
  <main class="main-content">${content}</main>
</div>
</body></html>`;
}

