function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function statusBadge(s) {
  const cls = { Open: 'badge-open', 'In Progress': 'badge-progress', Complete: 'badge-complete', Scheduled: 'badge-scheduled', Completed: 'badge-complete', Pending: 'badge-pending', Outstanding: 'badge-outstanding' };
  return `<span class="badge ${cls[s] || 'badge-open'}">${esc(s)}</span>`;
}

function priorityBadge(p) {
  const cls = { High: 'badge-high', Medium: 'badge-medium', Low: 'badge-low' };
  return `<span class="badge ${cls[p] || 'badge-medium'}">${esc(p)}</span>`;
}

function typeBadge(t) {
  if (t === 'Confidential') return '<span class="badge badge-confidential">' + esc(t) + '</span>';
  return '<span class="badge badge-lease">' + esc(t) + '</span>';
}

