function initials(name) {
  return String(name).split(' ').map(n => n[0]).join('');
}

function statusBadge(s) {
  const cls = { Open: 'badge-open', 'In Progress': 'badge-progress', Resolved: 'badge-resolved' };
  return `<span class="badge ${cls[s] || 'badge-open'}">${esc(s)}</span>`;
}

function priorityBadge(p) {
  const cls = { High: 'badge-high', Medium: 'badge-medium', Low: 'badge-low' };
  return `<span class="badge ${cls[p] || 'badge-medium'}">${esc(p)}</span>`;
}

