        </div>
      </div>`;
  }

  const myTickets = isAdmin
    ? db.exec("SELECT * FROM maintenance ORDER BY submitted DESC LIMIT 5")
    : db.exec(`SELECT * FROM maintenance WHERE unit = '${user.unit}' ORDER BY submitted DESC LIMIT 5`);

  let ticketRows = '';
