app.get('/tenants', requireAuth, (req, res) => {
  const user = req.user;
  if (user.role !== 'Property Manager') return res.redirect('/dashboard');

  const tenants = db.exec("SELECT * FROM users WHERE role = 'Tenant' ORDER BY unit ASC");

  let tenantCards = '';
  if (tenants.length && tenants[0].values.length) {
    const cols = tenants[0].columns;
    tenantCards = tenants[0].values.map(row => {
      const t = {};
      cols.forEach((c, i) => t[c] = row[i]);
      const balanceTag = t.balance > 0
        ? `<span class="badge badge-overdue">$${Number(t.balance).toFixed(2)} Due</span>`
        : `<span class="badge badge-paid">Current</span>`;
      return `
        <div class="tenant-mini">
          <div class="tm-name">${esc(t.name)}</div>
          <div class="tm-unit">Unit ${esc(t.unit)} · $${Number(t.rent_amount).toLocaleString()}/mo</div>
          <div style="font-size:0.78rem;color:var(--text-muted);margin-top:4px;">${esc(t.email)}</div>
          <div style="font-size:0.75rem;color:var(--text-muted);">Lease: ${esc(t.lease_start)} → ${esc(t.lease_end)}</div>
          <div class="tm-status">${balanceTag}</div>
        </div>`;
    }).join('');
  }

  res.send(pageShell('Tenants', 'tenants', user, `
    <div class="page-header">
      <h1>👥 Tenant Directory</h1>
      <p class="subtitle">All current residents at HavenView Apartments</p>
    </div>
    <div class="tenant-grid">${tenantCards || '<p style="color:var(--text-muted);">No tenants found.</p>'}</div>
  `));
});

