function priorityBadge(p) {
  const cls = { Critical: 'badge-critical', High: 'badge-high', Medium: 'badge-medium', Low: 'badge-low' };
  return `<span class="badge ${cls[p] || 'badge-medium'}">${esc(p)}</span>`;
}

function statusBadge(s) {
  const cls = { Complete: 'badge-complete', 'In Progress': 'badge-progress', Pending: 'badge-pending', Late: 'badge-late', Paid: 'badge-paid' };
  return `<span class="badge ${cls[s] || 'badge-pending'}">${esc(s)}</span>`;
}

function initials(name) {
  return name.split(' ').map(w => w[0]).join('').toUpperCase();
}

