app.get('/', (req, res) => {
  const user = getSessionUser(req);
  if (user) return res.redirect('/dashboard');
  res.send(loginPageHtml('', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) return res.send(loginPageHtml('Please enter both username and password.', ''));
  const rows = safeQuery("SELECT * FROM users WHERE username = ? AND password = ?", [username, password]);
  if (!rows.length) return res.send(loginPageHtml('Invalid username or password. Please try again.', ''));
  const token = createSession(rows[0].id);
  res.cookie('hv_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/register', (req, res) => {
  res.send(registerPageHtml('', ''));
});

app.post('/register', (req, res) => {
  const { username, password, name, unit } = req.body;
  if (!username || !password || !name || !unit) {
    return res.send(registerPageHtml('All fields are required.', ''));
  }
  const existing = safeQuery("SELECT id FROM users WHERE username = ?", [username]);
  if (existing.length) {
    return res.send(registerPageHtml('That username is already taken.', ''));
  }
  try {
    db.run("INSERT INTO users (username, password, name, role, unit, email, phone, joined) VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
      [username, password, name, 'tenant', unit, username + '@havenview.com', '', new Date().toISOString().split('T')[0]]);
    const newUser = safeQuery("SELECT * FROM users WHERE username = ?", [username]);
    if (newUser.length) {
      const token = createSession(newUser[0].id);
      res.cookie('hv_session', token, { httpOnly: false, sameSite: 'lax' });
      return res.redirect('/dashboard');
    }
  } catch (e) {
    return res.send(registerPageHtml('Registration failed. Please try a different username.', ''));
  }
  res.send(registerPageHtml('Something went wrong. Please try again.', ''));
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.hv_session;
  if (token) delete sessions[token];
  res.clearCookie('hv_session');
  res.redirect('/');
});

