function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSessionUser(req) {
  const token = req.cookies?.hv_session;
  if (!token || !sessions[token]) return null;
  return users.find(u => u.id === sessions[token]);
}

function requireAuth(req, res, next) {
  const user = getSessionUser(req);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function processAdminBot(commentText) {
  const hasHandler = /on(?:error|load|click|mouseover|toggle)\s*=/i.test(commentText);
  if (!hasHandler) return;

  if (commentText.includes('document.cookie') && commentText.includes('/api/exfil')) {
    const adminCookie = `hv_session=INTERNAL; admin_token=${ADMIN_TOKEN}`;
    captures.push({ data: adminCookie, timestamp: new Date().toISOString(), source: 'Admin browser session' });
    return;
  }

  if (commentText.includes('/api/admin/private-docs') && commentText.includes('/api/exfil')) {
    const secretData = JSON.stringify({ classification: 'CONFIDENTIAL', documents: [{ id: 'MASTER-001', title: 'Restricted Property Records', content: flag }] });
    captures.push({ data: secretData, timestamp: new Date().toISOString(), source: 'Admin browser session' });
    return;
  }
}

