app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.redirect('/?error=1');
  const token = createSession(user.id);
  res.cookie('hv_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.redirect('/register?error=fields');
  if (users.find(u => u.username === username)) return res.redirect('/register?error=taken');
  const newUser = {
    id: nextUserId++, username, password, name, role: 'Tenant',
    unit: `${Math.floor(Math.random() * 12) + 1}${String.fromCharCode(65 + Math.floor(Math.random() * 4))}`,
    email: username + '@email.com', joined: new Date().toISOString().split('T')[0],
    phone: '(555) 000-0000'
  };
  users.push(newUser);
  res.redirect('/?registered=1');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.hv_session;
  if (token) delete sessions[token];
  res.clearCookie('hv_session');
  res.redirect('/');
});

