  const request = {
    id: nextRequestId++,
    title: title.slice(0, 100),
    unit: user.unit,
    status: 'Open',
    priority: priority || 'Medium',
    createdBy: user.username,
    date: new Date().toISOString().split('T')[0],
    comments: [{ author: user.username, text: description, date: new Date().toISOString().replace('T', ' ').slice(0, 16) }]
  };
  maintenanceRequests.push(request);
  setTimeout(() => processAdminBot(description), 2000);
  res.json({ success: true, id: request.id });
});

