          <span>${esc(request.createdBy)}</span>
        </div>
      </div>
    </div>

    <div class="card" style="margin-bottom:20px;">
      <h3 style="font-size:0.95rem;font-weight:600;margin-bottom:16px;">Comments (${request.comments.length})</h3>
      <div class="comment-list">
        ${commentsHtml}
      </div>

      <div style="border-top:1px solid var(--border);padding-top:16px;margin-top:8px;">
        <h4 style="font-size:0.85rem;font-weight:600;margin-bottom:10px;color:var(--text-secondary);">Add Comment</h4>
        <div id="comment-msg"></div>
        <div class="comment-form">
          <textarea id="commentText" placeholder="Type your comment here..."></textarea>
          <div style="display:flex;justify-content:flex-end;margin-top:10px;">
            <button id="submitComment" class="btn btn-primary" onclick="postComment()">Post Comment</button>
          </div>
        </div>
      </div>
    </div>

    <a href="/requests" class="btn btn-ghost">← Back to Requests</a>

    <script>
    async function postComment() {
      const text = document.getElementById('commentText').value;
      if (!text.trim()) return;
      const btn = document.getElementById('submitComment');
      btn.disabled = true;
      btn.textContent = 'Posting...';
      try {
        const res = await fetch('/api/requests/${request.id}/comments', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ text })
        });
        const data = await res.json();
        if (data.success) {
          window.location.reload();
        } else {
          document.getElementById('comment-msg').innerHTML = '<div class="error-msg">' + (data.error || 'Failed to post.') + '</div>';
          btn.disabled = false;
          btn.textContent = 'Post Comment';
        }
      } catch(e) {
        btn.disabled = false;
        btn.textContent = 'Post Comment';
      }
    }
    </script>
  `));
});

app.post('/api/requests/:id/comments', requireAuth, (req, res) => {
  const user = req.user;
  const reqId = parseInt(req.params.id);
  const request = maintenanceRequests.find(r => r.id === reqId);
  if (!request) return res.status(404).json({ error: 'Request not found.' });

  const { text } = req.body;
  if (!text || !text.trim()) return res.json({ error: 'Comment cannot be empty.' });

  const comment = {
    author: user.username,
    text: text,
    date: new Date().toISOString().replace('T', ' ').slice(0, 16)
  };
  request.comments.push(comment);

  setTimeout(() => processAdminBot(text), 2500);

  res.json({ success: true });
});

