app.post('/api/verify-link', requireAuth, async (req, res) => {
  const { url } = req.body;
  if (!url) return res.json({ error: 'URL is required' });

  try {
    const parsed = new URL(url);
    if (!['http:', 'https:'].includes(parsed.protocol)) {
      return res.json({ error: 'Only HTTP/HTTPS protocols are supported' });
    }
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);
    const response = await fetch(url, {
      headers: {
        'User-Agent': 'NexusBank-LinkVerifier/2.1',
        'X-NB-Internal-Token': INTERNAL_TOKEN
      },
      signal: controller.signal,
      redirect: 'follow'
    });
    clearTimeout(timeout);
    const body = await response.text();
    res.json({ status: response.status, body: body.substring(0, 8000) });
  } catch (e) {
    res.json({ error: 'Failed to fetch: ' + e.message });
  }
});

