  const q = req.query.q || '';
  if (!q) {
    return res.json({ status: 'error', message: 'Query parameter "q" is required. Search by account number.' });
  }
  const query = `SELECT account_number, holder_name, account_type, status FROM accounts WHERE account_number = '${q}'`;
  try {
    const result = db.exec(query);
    if (result.length > 0 && result[0].values.length > 0) {
      res.json({ status: 'found', message: 'Account matched.', count: result[0].values.length });
    } else {
      res.json({ status: 'not_found', message: 'No matching account found.' });
    }
  } catch (e) {
    res.json({ status: 'error', message: 'Search query failed.' });
  }
});

