function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.nxb_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const user = users.find(u => u.id === userId);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function runBasicCommand(cmd) {
  const tokens = cmd.match(/(?:[^\s"']+|"[^"]*"|'[^']*')+/g) || [];
  const bin = (tokens[0] || '').toLowerCase();
  const args = tokens.slice(1).map(a => a.replace(/^["']|["']$/g, ''));

  switch (bin) {
    case 'cat':
      if (args.some(a => a === '.flag' || a.endsWith('/.flag') || a === '/app/.flag')) return flag;
      if (args.some(a => a.includes('statement') || a.includes('stm'))) return 'Account Statement — NexusBank Digital Banking\nPeriod: Monthly\nGenerated by automated system.';
      return `cat: ${args[0] || ''}: No such file or directory`;
    case 'ls':
      if (args.length === 0 || args[0] === '.' || args[0] === '/app') return '.flag\nserver.js\npackage.json\nnode_modules';
      if (args[0] === '-la' || args[0] === '-al') return 'total 48\ndrwxr-xr-x  1 nexus nexus  4096 Jan 15 08:00 .\n-rw-r--r--  1 nexus nexus    42 Jan 15 08:00 .flag\n-rw-r--r--  1 nexus nexus 28491 Jan 15 08:00 server.js\n-rw-r--r--  1 nexus nexus   187 Jan 15 08:00 package.json';
      return `ls: cannot access '${args[0]}': No such file or directory`;
    case 'echo':
      return args.join(' ');
    case 'whoami':
      return 'nexusbank-svc';
    case 'id':
      return 'uid=1000(nexusbank) gid=1000(nexusbank) groups=1000(nexusbank)';
    case 'pwd':
      return '/app';
    case 'env':
      return 'NODE_ENV=production\nHOSTNAME=nxb-prod-01\nSERVICE=nexusbank-portal';
    case 'uname':
      return 'Linux nxb-prod-01 5.15.0-91-generic';
    case 'grep':
      return `(no matches found)`;
    case 'find':
      return `find: ${args.join(' ')}: No results`;
    default:
      if (bin === '') return '';
      return `sh: ${bin}: command not found`;
  }
}

function simulateShell(rawInput) {
  let processed = rawInput;

  for (let i = 0; i < 5; i++) {
    const before = processed;
    processed = processed.replace(/\$\(([^()]+)\)/g, (_, innerCmd) => {
      return runBasicCommand(innerCmd.trim());
    });
    if (processed === before) break;
  }

  for (let i = 0; i < 5; i++) {
    const before = processed;
    processed = processed.replace(/`([^`]+)`/g, (_, innerCmd) => {
      return runBasicCommand(innerCmd.trim());
    });
    if (processed === before) break;
  }

  const lines = processed.split('\n').map(l => l.trim()).filter(Boolean);
  const outputs = [];
  for (const line of lines) {
    outputs.push(runBasicCommand(line));
  }
  return outputs.join('\n');
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

