app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.redirect('/?error=Invalid+credentials.+Please+try+again.');
  const token = createSession(user.id);
  res.cookie('nxb_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nxb_session;
  if (token) delete sessions[token];
  res.clearCookie('nxb_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const userAccounts = accounts.filter(a => a.owner === user.id);
  const totalBalance = userAccounts.reduce((s, a) => s + a.balance, 0);
  const userTxns = transactions.filter(t => userAccounts.some(a => a.id === t.account));
  const recentTxns = userTxns.slice(0, 5);

  const txnRows = recentTxns.map(t => `
    <tr>
      <td style="font-family:var(--font-mono);font-size:0.8rem;color:var(--accent);">${esc(t.ref)}</td>
      <td>${esc(t.date)}</td>
      <td>${esc(t.description)}</td>
      <td class="${t.type === 'credit' ? 'amount-credit' : 'amount-debit'}">${fmtCurrency(t.amount)}</td>
    </tr>`).join('');

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header">
      <h1>Welcome back, ${esc(user.name.split(' ')[0])}</h1>
      <p class="subtitle">Your banking dashboard overview</p>
    </div>

    <div class="stats-row">
      <div class="stat-card">
        <div class="stat-value">${fmtCurrency(totalBalance)}</div>
        <div class="stat-label">Total Balance</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">${userAccounts.length}</div>
        <div class="stat-label">Accounts</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">${userTxns.length}</div>
        <div class="stat-label">Transactions</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">${beneficiaries.filter(b => b.owner === user.id).length}</div>
        <div class="stat-label">Beneficiaries</div>
      </div>
    </div>

    <div class="card">
      <h3>Recent Transactions</h3>
      <table class="data-table">
        <thead><tr><th>Reference</th><th>Date</th><th>Description</th><th>Amount</th></tr></thead>
        <tbody>${txnRows}</tbody>
      </table>
    </div>
  `));
});

