app.get('/transfers', requireAuth, (req, res) => {
  const user = req.user;
  const userAccounts = accounts.filter(a => a.owner === user.id);
  const userBeneficiaries = beneficiaries.filter(b => b.owner === user.id);

  const fromOpts = userAccounts.map(a =>
    `<option value="${esc(a.id)}">${esc(a.id)} — ${esc(a.type)} (${fmtCurrency(a.balance)})</option>`).join('');
  const toOpts = userBeneficiaries.map(b =>
    `<option value="${b.id}">${esc(b.name)} — ${esc(b.bank)} (${esc(b.accountEnding)})</option>`).join('');

  res.send(pageShell('Transfers', 'transfers', user, `
    <div class="page-header">
      <h1>Transfer Funds</h1>
      <p class="subtitle">Send money to your beneficiaries</p>
    </div>

    <div class="grid-2">
      <div class="card">
        <h3>New Transfer</h3>
        <div id="transfer-msg"></div>
        <div class="form-group">
          <label>From Account</label>
          <select id="tf-from" class="form-input">${fromOpts}</select>
        </div>
        <div class="form-group">
          <label>To Beneficiary</label>
          <select id="tf-to" class="form-input">${toOpts}</select>
        </div>
        <div class="form-group">
          <label>Amount (USD)</label>
          <input type="number" id="tf-amount" class="form-input" placeholder="0.00" step="0.01" min="0.01">
        </div>
        <div class="form-group">
          <label>Reference Note</label>
          <input type="text" id="tf-ref" class="form-input" placeholder="Optional reference">
        </div>
        <button class="btn btn-primary" onclick="submitTransfer()">Send Transfer</button>
      </div>
      <div class="card">
        <h3>Transfer Limits</h3>
        <div style="margin-bottom:12px;">
          <div style="font-size:0.75rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px;">Daily Limit</div>
          <div style="font-family:var(--font-mono);font-size:1.1rem;color:var(--text-primary);">$25,000.00</div>
        </div>
        <div style="margin-bottom:12px;">
          <div style="font-size:0.75rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px;">Used Today</div>
          <div style="font-family:var(--font-mono);font-size:1.1rem;color:var(--accent-green);">$0.00</div>
        </div>
        <div>
          <div style="font-size:0.75rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px;">Wire Cut-off</div>
          <div style="font-family:var(--font-mono);font-size:1.1rem;color:var(--text-primary);">4:30 PM EST</div>
        </div>
      </div>
    </div>

    <script>
    function submitTransfer() {
      const amount = document.getElementById('tf-amount').value;
      const from = document.getElementById('tf-from').value;
      const to = document.getElementById('tf-to').value;
      const ref = document.getElementById('tf-ref').value;
      if (!amount || parseFloat(amount) <= 0) {
        document.getElementById('transfer-msg').innerHTML = '<div class="error-msg">Please enter a valid amount.</div>';
        return;
      }
      fetch('/api/transfer', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ from, to, amount: parseFloat(amount), ref })
      }).then(r => r.json()).then(data => {
        if (data.error) {
          document.getElementById('transfer-msg').innerHTML = '<div class="error-msg">' + data.error + '</div>';
        } else {
          document.getElementById('transfer-msg').innerHTML = '<div class="success-msg">' + data.message + '</div>';
          document.getElementById('tf-amount').value = '';
          document.getElementById('tf-ref').value = '';
        }
      });
    }
    </script>
  `));
});

app.post('/api/transfer', requireAuth, (req, res) => {
  const { from, to, amount, ref } = req.body;
  if (!from || !to || !amount || amount <= 0) {
    return res.json({ error: 'Invalid transfer parameters.' });
  }
  const acc = accounts.find(a => a.id === from && a.owner === req.user.id);
  if (!acc) return res.json({ error: 'Account not found.' });
  if (acc.balance < amount) return res.json({ error: 'Insufficient funds.' });
  if (amount > 25000) return res.json({ error: 'Amount exceeds daily transfer limit.' });
  acc.balance -= amount;
  const txnId = 'TXN-' + Date.now().toString().slice(-10) + '-' + Math.floor(Math.random() * 999);
  const ben = beneficiaries.find(b => b.id === parseInt(to));
  transactions.unshift({
    id: txnId, account: from, date: new Date().toISOString().split('T')[0],
    description: `Transfer to ${ben ? ben.name : 'Beneficiary'}`, amount: -amount,
    type: 'debit', ref: ref || txnId
  });
  res.json({ message: `Transfer of ${fmtCurrency(amount)} initiated successfully. Reference: ${txnId}` });
});

