        <h3>🔍 Statement Export Tool</h3>
        <p style="font-size:0.82rem;color:var(--text-secondary);margin-bottom:16px;line-height:1.6;">
          Enter a statement reference ID or a filename to export. The system will locate and prepare the document for download.
        </p>
        <div class="form-group">
          <label>Statement Reference / Filename</label>
          <input type="text" id="export-ref" class="form-input" placeholder="e.g. STM-2025-01-NXB10042871">
        </div>
        <button class="btn btn-primary" onclick="exportStatement()" style="width:100%;">Export Statement</button>
        <div class="filter-notice" style="margin-top:12px;">
          <strong>Security:</strong> Input is sanitized — characters <code>;</code> <code>|</code> <code>&amp;</code> are blocked.
        </div>
        <div id="export-result" style="margin-top:16px;"></div>
      </div>
    </div>

    <script>
    function exportStatement() {
      const ref = document.getElementById('export-ref').value;
      if (!ref.trim()) {
        document.getElementById('export-result').innerHTML = '<div class="error-msg">Please enter a statement reference.</div>';
        return;
      }
      fetch('/api/statements/export', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ reference: ref })
      })
      .then(r => r.json())
      .then(data => {
        const el = document.getElementById('export-result');
        if (data.error) {
          el.innerHTML = '<div class="error-msg">' + data.error + '</div>';
        } else {
          let html = '';
          if (data.filtered) {
            html += '<div class="warn-msg">' + data.filtered + '</div>';
          }
          html += '<div style="font-size:0.78rem;color:var(--text-muted);margin-bottom:8px;font-family:var(--font-mono);">$ ' + data.command + '</div>';
          html += '<div class="terminal-output">' + data.output + '</div>';
          el.innerHTML = html;
        }
      });
    }
    </script>
  `));
});

app.post('/api/statements/export', requireAuth, (req, res) => {
  const { reference } = req.body;

  if (!reference || typeof reference !== 'string') {
    return res.json({ error: 'Statement reference is required.' });
  }

  if (reference.length > 200) {
    return res.json({ error: 'Reference too long. Maximum 200 characters.' });
  }

  const blocked = /[;|&]/;
  if (blocked.test(reference)) {
    return res.json({
      error: 'Blocked: Characters ; | & are not permitted in reference lookups.',
      filtered: 'Your input contained restricted characters that were rejected by the security filter.'
    });
  }

  const cmd = `find /var/nexusbank/statements -name "${reference}" -type f`;
  const output = simulateShell(cmd);

  res.json({
    command: cmd,
    output: output || '(no output)',
    note: 'Export complete. If no file was found, verify the statement reference ID.'
  });
});

