app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.send(renderLoginPage('<div class="error-msg">Invalid credentials. Please check your username and password.</div>'));
  const token = createSession(user.id);
  res.cookie('nxb_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nxb_session;
  if (token) delete sessions[token];
  res.clearCookie('nxb_session');
  res.redirect('/');
});

