      <div class="loading">Loading documents...</div>
    </div>
    <script>
      (function() {
        const userId = ${user.id};
        fetch('/api/users/' + userId + '/documents')
          .then(r => r.json())
          .then(data => {
            const container = document.getElementById('docContainer');
            if (!data.documents || data.documents.length === 0) {
              container.innerHTML = '<h3>Your Documents</h3><p style="color:var(--text-muted);padding:20px;text-align:center;">No documents found.</p>';
              return;
            }
            let html = '<h3>Your Documents</h3>';
            data.documents.forEach(doc => {
              const clsBadge = doc.classification === 'Confidential' || doc.classification === 'Restricted'
                ? 'badge-confidential' : doc.classification === 'Private' ? 'badge-gold' : 'badge-muted';
              html += '<div class="doc-row">' +
                '<div class="doc-info">' +
                  '<div class="doc-title">' + doc.title + '</div>' +
                  '<div class="doc-meta">' + doc.type + ' · ' + doc.date + ' · ' + doc.size +
                  ' &nbsp;<span class="badge ' + clsBadge + '">' + doc.classification + '</span></div>' +
                '</div>' +
                '<span class="btn btn-ghost" style="font-size:0.75rem;cursor:default;">Download</span>' +
              '</div>';
            });
            container.innerHTML = html;
          })
          .catch(() => {
            document.getElementById('docContainer').innerHTML = '<h3>Your Documents</h3><p style="color:var(--red);padding:20px;">Failed to load documents.</p>';
          });
      })();
    </script>
  `));
});

