app.get('/api/users/:id/documents', requireAuth, (req, res) => {
  const targetId = parseInt(req.params.id);
  const docs = userDocuments[targetId];

  if (!docs) {
    return res.status(404).json({ error: 'User not found', documents: [] });
  }

  res.json({
    userId: targetId,
    documents: docs.map(d => ({
      id: d.id,
      title: d.title,
      type: d.type,
      date: d.date,
      size: d.size,
      classification: d.classification,
      content: d.content || null,
    })),
  });
});

