function typeBadge(t) {
  if (t === 'credit') return '<span class="badge badge-credit">Credit</span>';
  if (t === 'debit') return '<span class="badge badge-debit">Debit</span>';
  if (t === 'system') return '<span class="badge badge-system">System</span>';
  return '<span class="badge badge-transfer">' + esc(t) + '</span>';
}

