app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const rows = db.exec(`SELECT * FROM users WHERE username = '${username}' AND role = 'customer'`);
  let user = null;
  if (rows.length && rows[0].values.length) {
    const cols = rows[0].columns;
    const vals = rows[0].values[0];
    const u = {};
    cols.forEach((c, i) => u[c] = vals[i]);
    if (u.password === password) user = u;
  }
  if (!user) {
    return res.send(`<!DOCTYPE html>
<html lang="en"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>NexusBank — Sign In</title>
<style>${baseStyles}</style>
</head><body class="fade-in">
<div class="login-page">
  <div class="login-wrapper">
    <div class="login-brand">
      <div class="logo-lg">🏦</div>
      <h1>Nexus<span>Bank</span></h1>
      <p>Secure Online Banking Portal</p>
    </div>
    <div class="auth-card">
      <h2>// Sign In</h2>
      <div class="error-msg">Invalid username or password. Please try again.</div>
      <form method="POST" action="/login">
        <div class="form-group">
          <label>Username</label>
          <input type="text" name="username" placeholder="Enter your username" autocomplete="off" required>
        </div>
        <div class="form-group">
          <label>Password</label>
          <input type="password" name="password" placeholder="Enter your password" required>
        </div>
        <button type="submit" class="submit-btn">Sign In</button>
      </form>
      <div class="demo-creds">
        <p>Demo Accounts</p>
        <code>maria.santos / bankpass1</code>
        <code>james.chen / bankpass2</code>
        <code>lisa.brooks / bankpass3</code>
      </div>
    </div>
  </div>
</div>
</body></html>`);
  }
  const token = createSession(user.id);
  res.cookie('nb_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nb_session;
  if (token) delete sessions[token];
  res.clearCookie('nb_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const txRows = db.exec(`SELECT * FROM transactions WHERE user_id = ${user.id} ORDER BY date DESC LIMIT 5`);
  const benRows = db.exec(`SELECT COUNT(*) as cnt FROM beneficiaries WHERE user_id = ${user.id}`);
  const txAll = db.exec(`SELECT * FROM transactions WHERE user_id = ${user.id}`);

  let totalIn = 0, totalOut = 0, txCount = 0;
  if (txAll.length && txAll[0].values.length) {
    const cols = txAll[0].columns;
    txAll[0].values.forEach(row => {
      const tx = {};
      cols.forEach((c, i) => tx[c] = row[i]);
      txCount++;
      if (tx.type === 'credit') totalIn += tx.amount;
      else if (tx.type === 'debit') totalOut += tx.amount;
    });
  }

  const benCount = benRows.length ? benRows[0].values[0][0] : 0;

  let recentRows = '';
  if (txRows.length && txRows[0].values.length) {
