app.get('/statements', requireAuth, (req, res) => {
  const user = req.user;
  const search = req.query.q || '';

  let rows = [];
  let queryError = false;

  if (search) {
    try {
      const sql = "SELECT * FROM transactions WHERE user_id = " + user.id + " AND description LIKE '%" + search + "%' ORDER BY date DESC";
      const result = db.exec(sql);
      if (result.length && result[0].values.length) {
        const cols = result[0].columns;
        rows = result[0].values.map(row => {
          const tx = {};
          cols.forEach((c, i) => tx[c] = row[i]);
          return tx;
        });
      }
    } catch(e) {
      queryError = true;
    }
  } else {
    const result = db.exec(`SELECT * FROM transactions WHERE user_id = ${user.id} ORDER BY date DESC`);
    if (result.length && result[0].values.length) {
      const cols = result[0].columns;
      rows = result[0].values.map(row => {
        const tx = {};
        cols.forEach((c, i) => tx[c] = row[i]);
        return tx;
      });
    }
  }

  const tableRows = rows.map(tx => {
    const amtClass = tx.type === 'credit' ? 'color:var(--green)' : tx.type === 'debit' ? 'color:var(--red)' : 'color:var(--purple)';
    const amtPrefix = tx.type === 'credit' ? '+' : tx.type === 'debit' ? '-' : '';
    return `<tr>
      <td style="font-family:var(--font-mono);font-size:0.8rem;color:var(--text-muted);">${esc(tx.date)}</td>
      <td>${esc(tx.description)}</td>
      <td style="font-family:var(--font-mono);font-size:0.78rem;color:var(--text-muted);">${esc(tx.category)}</td>
      <td>${typeBadge(tx.type)}</td>
      <td style="font-family:var(--font-mono);font-weight:600;${amtClass};">${amtPrefix}${fmtCurrency(tx.amount)}</td>
      <td style="font-family:var(--font-mono);font-size:0.75rem;color:var(--text-muted);">${esc(tx.reference)}</td>
    </tr>`;
  }).join('');

  const resultInfo = search
    ? `<div class="result-count">Found <em>${rows.length}</em> transaction${rows.length !== 1 ? 's' : ''} matching "<em>${esc(search)}</em>"</div>`
    : `<div class="result-count">Showing <em>${rows.length}</em> transaction${rows.length !== 1 ? 's' : ''}</div>`;

  res.send(pageShell('Statements', 'statements', user, `
    <div class="page-header">
      <h1>Account Statements</h1>
      <p class="subtitle">Search and view your transaction history</p>
    </div>

    <div class="card" style="margin-bottom:20px;">
      <form method="GET" action="/statements">
        <div class="search-bar">
          <input type="text" name="q" placeholder="Search transactions by description..." value="${esc(search)}">
          <button type="submit" class="btn btn-primary">🔍 Search</button>
          ${search ? '<a href="/statements" class="btn btn-ghost">Clear</a>' : ''}
        </div>
      </form>
      ${queryError ? '<div class="error-msg">An error occurred while processing your search query.</div>' : ''}
    </div>

    <div class="card">
      ${resultInfo}
      ${rows.length > 0 ? `
        <table class="data-table">
          <thead><tr><th>Date</th><th>Description</th><th>Category</th><th>Type</th><th>Amount</th><th>Reference</th></tr></thead>
          <tbody>${tableRows}</tbody>
