app.post('/transfer', requireAuth, (req, res) => {
  const user = req.user;
  const { to_account, amount, description } = req.body;
  const amtNum = parseFloat(amount);

  if (!amtNum || amtNum <= 0 || isNaN(amtNum)) {
    return res.redirect('/transfer?error=amount');
  }
  if (amtNum > user.balance) {
    return res.redirect('/transfer?error=funds');
  }

  const desc = description || `Transfer to ${to_account}`;
  db.run(`UPDATE users SET balance = balance - ${amtNum} WHERE id = ${user.id}`);
  db.run(`INSERT INTO transactions (user_id, date, description, amount, type, category, reference) VALUES (${user.id}, '${new Date().toISOString().split('T')[0]}', '${desc.replace(/'/g, "''")}', ${amtNum}, 'debit', 'Transfer', 'TRF-${Date.now()}')`);

  res.redirect('/transfer?success=1');
});

