app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(renderLogin('<div class="error-msg">Invalid username or password. Please try again.</div>'));
  }
  const token = createSession(user.id);
  res.cookie('scb_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.scb_session;
  if (token) delete sessions[token];
  res.clearCookie('scb_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const userAccounts = accounts.filter(a => a.owner === user.id);
  const totalBal = userAccounts.reduce((s, a) => s + a.balance, 0);
  const userTxns = transactions.filter(t => userAccounts.some(a => a.id === t.account));
  const recentTxns = userTxns.slice(0, 5);

  const txnRows = recentTxns.map(t => `
    <tr>
      <td style="font-family:var(--font-mono);font-size:0.78rem;color:var(--text-muted);">${esc(t.date)}</td>
      <td>${esc(t.description)}</td>
      <td>${esc(t.category)}</td>
      <td class="${t.type === 'credit' ? 'amount-credit' : 'amount-debit'}">${t.type === 'credit' ? '+' : ''}${formatCurrency(t.amount)}</td>
    </tr>`).join('');

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header">
      <h1>Welcome back, ${esc(user.name.split(' ')[0])}</h1>
      <p class="subtitle">Here's your financial overview</p>
    </div>

    <div class="stats-row">
      <div class="stat-card">
        <div class="stat-label">Total Balance</div>
        <div class="stat-value">${formatCurrency(totalBal)}</div>
        <div class="stat-sub">Across ${userAccounts.length} accounts</div>
      </div>
      <div class="stat-card">
        <div class="stat-label">Accounts</div>
        <div class="stat-value">${userAccounts.length}</div>
        <div class="stat-sub">Active accounts</div>
      </div>
      <div class="stat-card">
        <div class="stat-label">Recent Transactions</div>
        <div class="stat-value">${userTxns.length}</div>
        <div class="stat-sub">This period</div>
      </div>
      <div class="stat-card">
        <div class="stat-label">Beneficiaries</div>
        <div class="stat-value">${beneficiaries.filter(b => b.addedBy === user.id).length}</div>
        <div class="stat-sub">Saved payees</div>
      </div>
    </div>

    <div class="card">
      <div class="card-title">📋 Recent Transactions</div>
      <table class="data-table">
        <thead>
          <tr><th>Date</th><th>Description</th><th>Category</th><th>Amount</th></tr>
        </thead>
        <tbody>${txnRows || '<tr><td colspan="4" style="text-align:center;color:var(--text-muted);padding:20px;">No recent transactions</td></tr>'}</tbody>
      </table>
    </div>
  `));
});

