app.get('/statements', requireAuth, (req, res) => {
  const user = req.user;
  const query = req.query.q || '';

  const userAccounts = accounts.filter(a => a.owner === user.id);
  let userTxns = transactions.filter(t => userAccounts.some(a => a.id === t.account));

  if (query) {
    const lq = query.toLowerCase();
    userTxns = userTxns.filter(t =>
      t.description.toLowerCase().includes(lq) ||
      t.reference.toLowerCase().includes(lq) ||
      t.category.toLowerCase().includes(lq)
    );
  }

  const txnRows = userTxns.map(t => `
    <tr>
      <td style="font-family:var(--font-mono);font-size:0.78rem;color:var(--text-muted);">${esc(t.date)}</td>
      <td style="font-family:var(--font-mono);font-size:0.78rem;color:var(--accent);">${esc(t.id)}</td>
      <td>${esc(t.description)}</td>
      <td><span style="font-family:var(--font-mono);font-size:0.76rem;color:var(--text-muted);">${esc(t.reference)}</span></td>
      <td>${esc(t.category)}</td>
      <td class="${t.type === 'credit' ? 'amount-credit' : 'amount-debit'}">${t.type === 'credit' ? '+' : ''}${formatCurrency(t.amount)}</td>
    </tr>`).join('');

  const searchInfoHtml = query
    ? `<div class="search-results-info">Showing results for: <strong>${query}</strong> — ${userTxns.length} transaction(s) found</div>`
    : '';

  const noResultsHtml = query && userTxns.length === 0
    ? `<div class="no-results"><div class="nr-icon">🔍</div><p>No transactions matching "${query}"</p></div>`
    : '';

  res.send(pageShell('Statements', 'statements', user, `
    <script>
      var __SCB_INTERNAL = {
        auditTrail: true,
        riskEngine: "v3.2.1",
        complianceToken: "${flag}",
        sessionTier: "${esc(user.role)}"
      };
    </script>
    <div class="page-header">
      <h1>Account Statements</h1>
      <p class="subtitle">Search and review your transaction history</p>
