const sessions = {};

function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.mb_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const user = users.find(u => u.id === userId);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function formatCurrency(n) {
  return (n < 0 ? '-' : '') + '$' + Math.abs(n).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function simulateAdminBotVisit(post) {
  const raw = post.content + ' ' + post.title;
  const hasEventHandler = /on(?:error|load|click|mouseover|toggle|focus)\s*=/i.test(raw);
  const hasScriptTag = /<script[\s>]/i.test(raw);
  const hasDocumentCookie = raw.includes('document.cookie');
  const hasStealEndpoint = raw.includes('/api/steal');

  if ((hasEventHandler || hasScriptTag) && hasDocumentCookie && hasStealEndpoint) {
    const adminCookieValue = `mb_session=admin_internal_token; admin_flag=${flag}`;
    stolenData.push({
      timestamp: new Date().toISOString(),
      data: adminCookieValue,
      source: 'admin-bot-review',
      feedbackId: post.id
    });
    return true;
  }
  return false;
}

