function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.nexus_session;
  if (token === undefined || token === null) return null;
  const uid = sessions[token];
  return uid !== undefined ? uid : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (userId === null) return res.redirect('/');
  const emp = employees.find(e => e.id === userId);
  if (!emp) return res.redirect('/');
  req.user = emp;
  next();
}

function requireAdminApi(req, res, next) {
  const userId = getSession(req);
  if (userId === null) return res.status(401).json({ error: 'Authentication required' });
  const emp = employees.find(e => e.id === userId);
  if (!emp) return res.status(401).json({ error: 'Authentication required' });
  if (!emp.isAdmin) return res.status(403).json({ error: 'ACCESS DENIED — HR Director clearance required.' });
  req.user = emp;
  next();
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

