function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

const avatarGradients = {
  'HR Director': 'linear-gradient(135deg, #f59e0b, #ef4444)',
  'Software Engineer': 'linear-gradient(135deg, #4f8cff, #6366f1)',
  'Marketing Lead': 'linear-gradient(135deg, #34d399, #059669)',
  'DevOps Engineer': 'linear-gradient(135deg, #22d3ee, #3b82f6)',
  'Analyst': 'linear-gradient(135deg, #a78bfa, #6366f1)',
};

function deptBadge(dept) {
  const map = { 'Human Resources': 'badge-hr', Engineering: 'badge-eng', Marketing: 'badge-mkt', 'IT Operations': 'badge-sys' };
  return '<span class="badge ' + (map[dept] || 'badge-eng') + '">' + esc(dept) + '</span>';
}

function renderSidebar(activePage, user) {
  const init = initials(user.name);
  const adminLinks = user.isAdmin ? `
    <div class="section-label">Administration</div>
    <a href="/hr/records" class="${activePage === 'hr' ? 'active' : ''}"><span class="icon">🔐</span> HR Records</a>
  ` : '';
  return `<aside class="sidebar">
    <div class="sidebar-brand"><div class="shield">🏢</div><h1>Nexus<span>Corp</span></h1></div>
    <nav class="sidebar-nav">
      <div class="section-label">Workspace</div>
      <a href="/dashboard" class="${activePage === 'dashboard' ? 'active' : ''}"><span class="icon">📊</span> Dashboard</a>
      <a href="/directory" class="${activePage === 'directory' ? 'active' : ''}"><span class="icon">👥</span> Directory</a>
      <a href="/shoutouts" class="${activePage === 'shoutouts' ? 'active' : ''}"><span class="icon">⭐</span> Shoutouts</a>
      ${adminLinks}
      <div class="section-label">Tools</div>
      <a href="/webhook" class="${activePage === 'webhook' ? 'active' : ''}"><span class="icon">📡</span> Webhook Log</a>
      <a href="/logout"><span class="icon">🚪</span> Sign Out</a>
    </nav>
    <div class="sidebar-user">
      <div class="avatar">${initials(user.name)}</div>
      <div class="user-info">
        <div class="user-name">${esc(user.name)}${user.isAdmin ? '<span class="admin-badge">Admin</span>' : ''}</div>
        <div class="user-role">${esc(user.role)}</div>
      </div>
    </div>
  </aside>`;
}

function pageShell(title, activePage, user, content) {
  return `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>${esc(title)} — NexusCorp</title><style>${baseStyles}</style></head><body class="fade-in"><div class="app-layout">${renderSidebar(activePage, user)}<main class="main-content">${content}</main></div></body></html>`;
}

const loginPageTpl = `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>NexusCorp — Employee Portal</title><style>${baseStyles}</style></head><body>
<div class="login-page"><div class="login-wrapper">
  <div class="login-brand"><div class="shield-lg">🏢</div><h1>Nexus<span>Corp</span></h1><p>Internal Employee Portal</p></div>
  <div class="login-grid">
    <div class="auth-card"><h2>// Sign In</h2>%%LOGIN_MSG%%
      <form method="POST" action="/login">
        <div class="form-group"><label>Username</label><input type="text" name="username" placeholder="username" autocomplete="off" required></div>
        <div class="form-group"><label>Password</label><input type="password" name="password" placeholder="password" required></div>
        <button type="submit" class="submit-btn btn-primary">Authenticate</button>
      </form>
      <div class="demo-creds"><p>Demo Credentials</p><code>kevin.zhao / kevin2024</code><code>maria.santos / santos99!</code></div>
    </div>
