      <form method="POST" action="/register">
        <div class="form-group"><label>Full Name</label><input type="text" name="name" placeholder="Your name" autocomplete="off" required></div>
        <div class="form-group"><label>Username</label><input type="text" name="username" placeholder="Choose a username" autocomplete="off" required></div>
        <div class="form-group"><label>Password</label><input type="password" name="password" placeholder="Choose a password" required></div>
        <button type="submit" class="submit-btn btn-green">Create Account</button>
      </form>
    </div>
  </div>
</div></div></body></html>`;

app.get('/', (req, res) => {
  res.send(loginPageTpl.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const emp = employees.find(e => e.username === username && e.password === password && e.password !== null);
  if (!emp) {
    return res.send(loginPageTpl.replace('%%LOGIN_MSG%%', '<div class="error-msg">Invalid credentials.</div>').replace('%%REG_MSG%%', ''));
  }
  const token = createSession(emp.id);
  res.cookie('nexus_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(loginPageTpl.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', '<div class="error-msg">All fields are required.</div>'));
  }
  if (employees.find(e => e.username === username)) {
    return res.send(loginPageTpl.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', '<div class="error-msg">Username already taken.</div>'));
  }
  const newEmp = {
    id: nextEmployeeId++, username, password, name, role: 'Analyst', department: 'Engineering',
    email: username + '@nexuscorp.io', joined: new Date().toISOString().split('T')[0],
    isAdmin: false, hidden: false, salary: 'Pending', performanceRating: 'New Hire',
    privateNotes: 'Onboarding in progress.', managerNotes: 'New hire — assign mentor.'
  };
  employees.push(newEmp);
  const token = createSession(newEmp.id);
  res.cookie('nexus_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nexus_session;
  if (token) delete sessions[token];
  res.clearCookie('nexus_session');
  res.redirect('/');
});

