  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header"><h1>Welcome back, ${esc(user.name.split(' ')[0])}</h1><p class="subtitle">NexusCorp Employee Portal — ${new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p></div>
    <div class="stats-row">
      <div class="stat-card"><div class="stat-value">${visibleEmps.length}</div><div class="stat-label">Employees</div></div>
      <div class="stat-card"><div class="stat-value">${shoutouts.length}</div><div class="stat-label">Shoutouts</div></div>
