      <div class="emp-avatar" style="background:${grad};">${initials(e.name)}</div>
      <div class="emp-name">${esc(e.name)}</div>
      <div class="emp-role">${esc(e.role)}</div>
      <div class="emp-dept">${deptBadge(e.department)}</div>
      <div style="font-size:0.78rem;color:var(--text-muted);font-family:var(--font-mono);">${esc(e.email)}</div>
    </div>`;
  }).join('');
  res.send(pageShell('Directory', 'directory', user, `
    <div class="page-header"><h1>Employee Directory</h1><p class="subtitle">NexusCorp team members</p></div>
    <div class="emp-grid">${cards}</div>
