app.get('/shoutouts', requireAuth, (req, res) => {
  const user = req.user;
  const shoutoutHtml = shoutouts.slice().reverse().map(s => `
    <div class="shoutout-card">
      <div class="shoutout-meta">
        <div><span class="shoutout-author">${esc(s.author)}</span> <span class="shoutout-recipient">→ ${esc(s.recipient)}</span></div>
        <div class="shoutout-date">${esc(s.date)}</div>
      </div>
      <div class="shoutout-body">${s.message}</div>
    </div>`).join('');

  res.send(pageShell('Shoutouts', 'shoutouts', user, `
    <div class="page-header"><h1>⭐ Employee Shoutouts</h1><p class="subtitle">Recognize your colleagues for great work</p></div>
    <div class="card" style="margin-bottom:24px;">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:16px;">Post a Shoutout</h3>
      <div id="post-result"></div>
      <div class="form-group">
        <label>Recipient</label>
        <input type="text" id="shout-recipient" placeholder="Who deserves recognition?" />
      </div>
      <div class="form-group">
        <label>Message</label>
        <textarea id="shout-message" placeholder="Write your shoutout..." rows="3"></textarea>
      </div>
      <button class="btn btn-green" onclick="postShoutout()">Send Shoutout ⭐</button>
    </div>
    <div style="margin-bottom:14px;display:flex;justify-content:space-between;align-items:center;">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;">${shoutouts.length} Shoutout${shoutouts.length !== 1 ? 's' : ''}</h3>
      <span style="font-size:0.75rem;color:var(--text-muted);">The HR Director reviews all shoutouts daily</span>
    </div>
    ${shoutoutHtml}
    <script>
      function postShoutout() {
        const recipient = document.getElementById('shout-recipient').value;
        const message = document.getElementById('shout-message').value;
        if (!recipient || !message) { document.getElementById('post-result').innerHTML = '<div class="error-msg">Both fields are required.</div>'; return; }
        fetch('/api/shoutouts', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ recipient, message })
        }).then(r => r.json()).then(d => {
          if (d.success) { location.reload(); } else { document.getElementById('post-result').innerHTML = '<div class="error-msg">' + d.error + '</div>'; }
        });
      }
    </script>
  `));
});

app.post('/api/shoutouts', requireAuth, (req, res) => {
  const user = req.user;
  const { recipient, message } = req.body;
  if (!recipient || !message) return res.json({ error: 'Both fields are required.' });
  if (message.length > 2000) return res.json({ error: 'Message too long.' });
  shoutouts.push({
    id: nextShoutoutId++,
    authorId: user.id,
    author: user.name,
    recipient: recipient,
    message: message,
    date: new Date().toISOString().split('T')[0]
  });
  res.json({ success: true });
});

