app.get('/api/admin/employees/:id', requireAdminApi, (req, res) => {
  const empId = parseInt(req.params.id);
  const emp = employees.find(e => e.id === empId);
  if (!emp) return res.status(404).json({ error: 'Employee not found' });
  res.json({
    id: emp.id,
    username: emp.username,
    name: emp.name,
    role: emp.role,
    department: emp.department,
    email: emp.email,
    joined: emp.joined,
    salary: emp.salary,
    performanceRating: emp.performanceRating,
    privateNotes: emp.privateNotes,
    managerNotes: emp.managerNotes,
  });
});

app.get('/bot/visit', (req, res) => {
  const admin = employees.find(e => e.isAdmin);
  if (!admin) return res.status(500).json({ error: 'No admin configured' });

  const adminToken = createSession(admin.id);

  const allContent = shoutouts.map(s => s.message).join(' ');
  if (allContent.includes('document.cookie') && allContent.includes('/webhook')) {
    webhookData.push(`nexus_session=${adminToken}`);
  }

  res.json({
    status: 'ok',
    message: 'HR Director Diana Price has reviewed the shoutouts board.',
    timestamp: new Date().toISOString()
  });
});

app.get('/webhook/collect', (req, res) => {
  const data = req.query.data;
  if (data) {
    webhookData.push(data);
    res.json({ status: 'collected', length: webhookData.length });
  } else {
    res.json({ status: 'no data provided' });
  }
});

app.get('/webhook', requireAuth, (req, res) => {
  const user = req.user;
  const entries = webhookData.length > 0
