const sessions = {};

function createSession(user) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = { id: user.id, username: user.username, name: user.name, role: user.role, department: user.department, email: user.email, title: user.title, joined: user.joined };
  return token;
}

function getSession(req) {
  const token = req.cookies?.hc_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const session = getSession(req);
  if (!session) return res.redirect('/');
  req.user = session;
  next();
}

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

