app.post('/login', async (req, res) => {
  if (!db) await dbReady;
  const { username, password } = req.body;

  if (!username || !password) {
    return res.send(renderLogin('<div class="error-msg">Please enter both username and password.</div>'));
  }

  const query = `SELECT * FROM users WHERE username='${username}' AND password='${password}'`;

  try {
    const result = db.exec(query);

    if (result.length === 0 || result[0].values.length === 0) {
      return res.send(renderLogin('<div class="error-msg">Invalid credentials. Please check your username and password.</div>'));
    }

    const row = result[0].values[0];
    const columns = result[0].columns;
    const user = {};
    columns.forEach((col, i) => { user[col] = row[i]; });

    const token = createSession(user);
    res.cookie('hc_session', token, { httpOnly: false, sameSite: 'lax' });
    res.redirect('/dashboard');
  } catch (e) {
    return res.send(renderLogin('<div class="error-msg">Authentication error. Please try again.</div>'));
  }
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.hc_session;
  if (token) delete sessions[token];
  res.clearCookie('hc_session');
  res.redirect('/');
});

