import express from 'express';
import cookieParser from 'cookie-parser';
import crypto from 'crypto';
import fs from 'fs';
import initSqlJs from 'sql.js';

const app = express();
app.use(express.urlencoded({ extended: true }));
app.use(express.json());
app.use(cookieParser());

const flag = fs.readFileSync('.flag', 'utf-8').trim();

const sessions = {};
const accounts = [
  { id: 1, username: 'j.martinez', password: 'jmart2024', name: 'Julia Martinez', role: 'Engineer', deptId: 1 },
  { id: 2, username: 't.nguyen', password: 'tnguyen!', name: 'Tom Nguyen', role: 'Marketing Lead', deptId: 2 },
  { id: 3, username: 'k.patel', password: 'kpatel99', name: 'Kira Patel', role: 'HR Specialist', deptId: 3 },
];
let nextAccountId = 4;

function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.ep_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const acct = accounts.find(a => a.id === userId);
  if (!acct) return res.redirect('/');
  req.user = acct;
  next();
}

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function initials(name) {
  return name.split(' ').map(w => w[0]).join('');
}

