function ratingBadge(r) {
  const cls = {
    'Excellent': 'badge-excellent',
    'Good': 'badge-good',
    'Satisfactory': 'badge-satisfactory',
    'Needs Improvement': 'badge-needs-improvement',
    'CLASSIFIED': 'badge-classified'
  };
  return `<span class="badge ${cls[r] || 'badge-classified'}">${esc(r)}</span>`;
}

