app.get('/', (req, res) => {
  const userId = getSession(req);
  if (userId && accounts.find(a => a.id === userId)) return res.redirect('/dashboard');
  res.send(loginPageHtml.replace('%%ERROR%%', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const acct = accounts.find(a => a.username === username && a.password === password);
  if (!acct) {
    return res.send(loginPageHtml.replace('%%ERROR%%', '<div class="error-msg">Invalid credentials. Please try again.</div>'));
  }
  const token = createSession(acct.id);
  res.cookie('ep_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.ep_session;
  if (token) delete sessions[token];
  res.clearCookie('ep_session');
  res.redirect('/');
});

