app.get('/reviews', requireAuth, (req, res) => {
  const user = req.user;
  const deptParam = req.query.dept;

  if (!deptParam) return res.redirect('/reviews?dept=1');

  const departments = db.exec(`SELECT id, name FROM departments ORDER BY id`);
  const deptButtons = departments[0] ? departments[0].values.map(d =>
    `<a href="/reviews?dept=${d[0]}" class="dept-btn ${String(d[0]) === String(deptParam) ? 'active' : ''}">${esc(d[1])}</a>`
  ).join('') : '';

  let rows = '';
  let resultCount = 0;
  let queryError = false;

  try {
    const results = db.exec(`SELECT id, employee_name, department_id, quarter, rating, summary FROM reviews WHERE department_id = ${deptParam}`);
    if (results[0]) {
      resultCount = results[0].values.length;
      rows = results[0].values.map(r => `
        <tr>
          <td><span style="font-family:var(--font-mono);color:var(--accent);font-size:0.8rem;">#${esc(r[0])}</span></td>
          <td><strong>${esc(r[1])}</strong></td>
