          <td>${esc(r[3])}</td>
          <td>${ratingBadge(r[4])}</td>
          <td style="max-width:340px;font-size:0.82rem;color:var(--text-secondary);line-height:1.5;">${esc(r[5])}</td>
        </tr>`).join('');
    }
  } catch (e) {
    queryError = true;
  }

  const tableContent = queryError
    ? `<div class="empty-state"><div class="icon-lg">⚠️</div><p>Query error. Invalid department filter.</p></div>`
    : resultCount === 0
    ? `<div class="empty-state"><div class="icon-lg">📭</div><p>No reviews found for this department filter.</p></div>`
    : `<table class="data-table">
        <thead><tr><th>ID</th><th>Employee</th><th>Dept ID</th><th>Quarter</th><th>Rating</th><th>Summary</th></tr></thead>
        <tbody>${rows}</tbody>
      </table>`;

  res.send(pageShell('Performance Reviews', 'reviews', user, `
    <div class="page-header">
      <h1>Performance Reviews</h1>
      <p class="subtitle">Q4 2024 review cycle — Filter by department</p>
    </div>
    <div class="dept-filters">
      ${deptButtons}
    </div>
    <div class="info-bar">
      <span class="tag">QUERY</span>
      <span>department_id = <strong style="color:var(--text-primary)">${esc(String(deptParam))}</strong></span>
      <span style="margin-left:auto">${resultCount} result${resultCount !== 1 ? 's' : ''}</span>
    </div>
    <div class="card">${tableContent}</div>
  `));
});

