function ratingBadge(rating) {
  if (rating === 'Outstanding') return '<span class="badge badge-outstanding">Outstanding</span>';
  if (rating === 'Exceeds Expectations') return '<span class="badge badge-exceeds">Exceeds</span>';
  if (rating === 'Meets Expectations') return '<span class="badge badge-meets">Meets</span>';
  if (rating === 'N/A') return '<span class="badge badge-na">N/A</span>';
  return '<span class="badge badge-na">' + esc(rating) + '</span>';
}

function statusBadge(status) {
  if (status === 'active') return '<span class="badge badge-active">Active</span>';
  if (status === 'restricted') return '<span class="badge badge-restricted">🔒 Restricted</span>';
  return '<span class="badge badge-na">' + esc(status) + '</span>';
}

