app.get('/directory', requireAuth, (req, res) => {
  const user = req.user;
  const search = req.query.q || '';
  let rows = [];
  let queryError = false;

  try {
    let results;
    if (search.trim() === '') {
      results = db.exec("SELECT id, full_name, department, position, email, hire_date, status, rating, notes FROM employees WHERE status = 'active' ORDER BY full_name");
    } else {
      const query = "SELECT id, full_name, department, position, email, hire_date, status, rating, notes FROM employees WHERE (full_name LIKE '%" + search + "%' OR department LIKE '%" + search + "%' OR position LIKE '%" + search + "%') AND status = 'active' ORDER BY full_name";
      results = db.exec(query);
    }
    if (results.length > 0) {
      rows = results[0].values;
    }
  } catch (e) {
    queryError = true;
  }

  let tableContent = '';
  if (queryError) {
    tableContent = `<div class="no-results">
      <div class="nr-icon">⚠️</div>
      <p>An error occurred while processing your search. Please try different keywords.</p>
    </div>`;
  } else if (rows.length === 0) {
    tableContent = `<div class="no-results">
      <div class="nr-icon">🔍</div>
      <p>No employees found matching your search criteria.</p>
    </div>`;
  } else {
    const tableRows = rows.map(r => {
      const isRestricted = r[6] === 'restricted';
      const notesCls = isRestricted ? 'notes-cell flag-cell' : 'notes-cell';
      return `<tr${isRestricted ? ' style="background:rgba(239,68,68,0.04);"' : ''}>
        <td style="font-weight:500;${isRestricted ? 'color:var(--accent-red);' : ''}">${esc(String(r[1]))}</td>
