function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function createToken(user) {
  return jwt.sign({ id: user.id, username: user.username, role: user.role }, JWT_SECRET, { expiresIn: '2h' });
}

function authenticateToken(req, res, next) {
  const token = req.cookies?.nk_token;
  if (!token) return res.redirect('/');
  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = decoded;
    const fullUser = users.find(u => u.id === decoded.id);
    req.fullUser = fullUser || { id: decoded.id, username: decoded.username, name: decoded.username, role: decoded.role, email: '', loyaltyTier: 'Standard' };
    next();
  } catch (e) {
    res.clearCookie('nk_token');
    return res.redirect('/');
  }
}

function requireRole(...roles) {
  return (req, res, next) => {
    if (!roles.includes(req.user.role)) {
      return res.status(403).send(pageShell('Access Denied', req.user.role === 'customer' ? 'shop' : 'manager', req.fullUser, `
        <div class="page-header"><h1>⛔ Access Denied</h1><p class="subtitle">Your role <code style="font-family:var(--font-mono);color:var(--accent-red);">${esc(req.user.role)}</code> does not have permission to access this resource.</p></div>
        <a href="/shop" class="btn btn-primary">← Back to Shop</a>
      `));
    }
    next();
  };
}

