function statusBadge(s) {
  const m = { Delivered: 'badge-delivered', Shipped: 'badge-shipped', Processing: 'badge-processing', Archived: 'badge-archived', Cancelled: 'badge-cancelled' };
  return `<span class="badge ${m[s] || 'badge-archived'}">${esc(s)}</span>`;
}

function roleBadge(r) {
  const m = { customer: 'badge-customer', manager: 'badge-manager', admin: 'badge-admin' };
  return `<span class="badge ${m[r] || 'badge-standard'}">${esc(r)}</span>`;
}

function tierBadge(t) {
  const m = { Gold: 'badge-gold', Silver: 'badge-silver', Obsidian: 'badge-obsidian', Standard: 'badge-standard' };
  return `<span class="badge ${m[t] || 'badge-standard'}">${esc(t)}</span>`;
}

function initials(name) {
  return String(name).split(' ').map(w => w[0] || '').join('').toUpperCase();
}

function renderSidebar(activePage, user) {
  const init = initials(user.name || user.username);
  const isElevated = user.role === 'manager' || user.role === 'admin';
  return `
    <aside class="sidebar">
      <div class="sidebar-brand">
        <div class="logo">🛒</div>
        <h1>Neon<span>Kart</span></h1>
      </div>
      <nav class="sidebar-nav">
        <div class="section-label">Shop</div>
        <a href="/shop" class="${activePage === 'shop' ? 'active' : ''}"><span class="icon">🏪</span> Products</a>
        <a href="/orders" class="${activePage === 'orders' ? 'active' : ''}"><span class="icon">📦</span> My Orders</a>
        <div class="section-label">Account</div>
        <a href="/session" class="${activePage === 'session' ? 'active' : ''}"><span class="icon">🔑</span> Session</a>
        ${isElevated ? `
        <div class="section-label">Management</div>
        <a href="/manager" class="${activePage === 'manager' ? 'active' : ''}"><span class="icon">📊</span> Order Manager</a>
        ` : ''}
        ${user.role === 'admin' ? `<a href="/admin" class="${activePage === 'admin' ? 'active' : ''}"><span class="icon">⚙️</span> Admin Console</a>` : ''}
        <div style="flex:1"></div>
        <a href="/logout"><span class="icon">🚪</span> Sign Out</a>
      </nav>
      <div class="sidebar-user">
        <div class="avatar">${init}</div>
        <div class="user-info">
          <div class="user-name">${esc(user.name || user.username)}</div>
          <div class="user-role">${esc(user.role)}</div>
        </div>
      </div>
    </aside>`;
}

function pageShell(title, activePage, user, content) {
  return `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>${esc(title)} — NeonKart</title><style>${baseStyles}</style></head><body class="fade-in"><div class="app-layout">${renderSidebar(activePage, user)}<main class="main-content">${content}</main></div></body></html>`;
}

function buildLoginPage(errorMsg, registerMsg) {
  return `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>NeonKart — Sign In</title><style>${baseStyles}</style></head><body class="fade-in">
  <div class="login-page"><div class="login-wrapper">
    <div class="login-brand">
      <div class="logo-lg">🛒</div>
      <h1>Neon<span>Kart</span></h1>
      <p>Premium E-Commerce Platform</p>
    </div>
    <div class="auth-card" style="margin-bottom:16px;">
      <h2>// Sign In</h2>
      ${errorMsg ? `<div class="error-msg">${errorMsg}</div>` : ''}
      <form method="POST" action="/login">
        <div class="form-group"><label>Username</label><input type="text" name="username" placeholder="username" autocomplete="off" required></div>
        <div class="form-group"><label>Password</label><input type="password" name="password" placeholder="password" required></div>
        <button type="submit" class="submit-btn btn-primary">Authenticate</button>
      </form>
      <div class="demo-creds">
        <p>Demo Accounts</p>
        <code>jane.doe / shopper123</code>
        <code>bob.smith / buyitall99</code>
      </div>
    </div>
    <div class="auth-card">
      <h2>// Create Account</h2>
      ${registerMsg ? `<div class="${registerMsg.startsWith('Account') ? 'success-msg' : 'error-msg'}">${registerMsg}</div>` : ''}
      <form method="POST" action="/register">
        <div class="form-group"><label>Full Name</label><input type="text" name="name" placeholder="Your name" autocomplete="off" required></div>
        <div class="form-group"><label>Username</label><input type="text" name="username" placeholder="Choose a username" autocomplete="off" required></div>
        <div class="form-group"><label>Password</label><input type="password" name="password" placeholder="Choose a password" required></div>
        <button type="submit" class="submit-btn btn-purple">Create Account</button>
      </form>
    </div>
  </div></div></body></html>`;
}

app.get('/', (req, res) => {
  const token = req.cookies?.nk_token;
  if (token) {
    try { jwt.verify(token, JWT_SECRET); return res.redirect('/shop'); } catch (e) { /* ignore */ }
  }
  res.send(buildLoginPage('', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.send(buildLoginPage('Invalid credentials. Please try again.', ''));
  const token = createToken(user);
  res.cookie('nk_token', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/shop');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.send(buildLoginPage('', 'All fields are required.'));
  if (users.find(u => u.username === username)) return res.send(buildLoginPage('', 'Username already taken.'));
  const newUser = { id: nextUserId++, username, password, name, role: 'customer', email: username + '@neonkart.io', joined: new Date().toISOString().split('T')[0], bio: 'New customer.', loyaltyTier: 'Standard' };
  users.push(newUser);
  const token = createToken(newUser);
  res.cookie('nk_token', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/shop');
});

app.get('/logout', (req, res) => {
  res.clearCookie('nk_token');
  res.redirect('/');
});

app.get('/shop', authenticateToken, (req, res) => {
  const user = req.fullUser;
  const cards = products.map(p => `
    <div class="product-card">
      <div class="pc-icon">${p.image}</div>
      <div class="pc-name">${esc(p.name)}</div>
      <div class="pc-cat">${esc(p.category)}</div>
      <div class="pc-price">$${p.price.toFixed(2)}</div>
      <div class="pc-stock">${p.stock} in stock</div>
      <div class="pc-rating">${'★'.repeat(Math.floor(p.rating))}${'☆'.repeat(5 - Math.floor(p.rating))} ${p.rating}</div>
    </div>`).join('');

  res.send(pageShell('Shop', 'shop', user, `
    <div class="page-header">
      <h1>Product Catalog</h1>
      <p class="subtitle">Browse our curated collection of premium tech products</p>
    </div>
    <div class="stats-row">
      <div class="stat-card"><div class="stat-value">${products.length}</div><div class="stat-label">Products</div></div>
      <div class="stat-card"><div class="stat-value">${products.reduce((s, p) => s + p.stock, 0)}</div><div class="stat-label">Total Stock</div></div>
      <div class="stat-card"><div class="stat-value">${orders.filter(o => o.userId === user.id).length}</div><div class="stat-label">Your Orders</div></div>
      <div class="stat-card"><div class="stat-value">${user.loyaltyTier || 'Standard'}</div><div class="stat-label">Loyalty Tier</div></div>
    </div>
    <div class="product-grid">${cards}</div>
  `));
});

app.get('/orders', authenticateToken, (req, res) => {
  const user = req.fullUser;
  const myOrders = orders.filter(o => o.userId === req.user.id);
  const rows = myOrders.map(o => `
    <tr>
      <td><span style="font-family:var(--font-mono);color:var(--accent);font-size:0.8rem">${esc(o.id)}</span></td>
      <td>${o.items.map(i => esc(i.name)).join(', ')}</td>
      <td style="font-family:var(--font-mono)">$${o.total.toFixed(2)}</td>
      <td>${statusBadge(o.status)}</td>
      <td>${esc(o.date)}</td>
    </tr>`).join('');

  const emptyState = myOrders.length === 0 ? '<p style="padding:20px;color:var(--text-muted);text-align:center;">No orders yet. Start shopping!</p>' : '';

  res.send(pageShell('My Orders', 'orders', user, `
    <div class="page-header">
      <h1>My Orders</h1>
      <p class="subtitle">Track your order history and delivery status</p>
    </div>
    <div class="card">
      ${myOrders.length > 0 ? `<table class="data-table">
        <thead><tr><th>Order ID</th><th>Items</th><th>Total</th><th>Status</th><th>Date</th></tr></thead>
        <tbody>${rows}</tbody>
      </table>` : emptyState}
    </div>
  `));
});

app.get('/session', authenticateToken, (req, res) => {
  const user = req.fullUser;
  const rawToken = req.cookies.nk_token;
  const parts = rawToken.split('.');
  let headerDecoded = '', payloadDecoded = '';
  try { headerDecoded = JSON.stringify(JSON.parse(Buffer.from(parts[0], 'base64url').toString()), null, 2); } catch (e) { headerDecoded = 'Error decoding header'; }
  try { payloadDecoded = JSON.parse(Buffer.from(parts[1], 'base64url').toString()); } catch (e) { payloadDecoded = {}; }

  const payloadHtml = Object.entries(payloadDecoded).map(([k, v]) => {
    let displayVal = typeof v === 'number' && (k === 'iat' || k === 'exp') ? `${v} <span style="color:var(--text-muted);font-size:0.75rem">(${new Date(v * 1000).toISOString()})</span>` : `"${esc(String(v))}"`;
    return `<div><span class="payload-key">"${esc(k)}"</span>: <span class="payload-val">${displayVal}</span></div>`;
  }).join('');

  res.send(pageShell('Session', 'session', user, `
    <div class="page-header">
      <h1>Session Details</h1>
      <p class="subtitle">Your current authentication token and session information</p>
    </div>

    <div class="card" style="margin-bottom:16px;">
      <h3 style="font-family:var(--font-mono);font-size:0.9rem;margin-bottom:12px;color:var(--accent)">🔑 JWT Token</h3>
      <p style="font-size:0.78rem;color:var(--text-muted);margin-bottom:10px;">This token is sent with every request as the <code>nk_token</code> cookie. It uses HS256 signing.</p>
      <div class="token-display">${esc(rawToken)}</div>
    </div>

