          if (data.error) {
            title.textContent = 'Error';
            content.innerHTML = '<p style="color:var(--accent-red)">' + data.error + '</p>';
            return;
          }
          title.textContent = 'Orders for Customer #' + customerId;
          let html = '<table class="data-table"><thead><tr><th>Order ID</th><th>Items</th><th>Total</th><th>Status</th><th>Date</th><th>Shipping</th><th>Notes</th></tr></thead><tbody>';
          data.orders.forEach(o => {
            const items = o.items.map(i => i.name + ' x' + i.qty).join(', ');
            html += '<tr><td style="font-family:var(--font-mono);color:var(--accent);font-size:0.8rem">' + o.id + '</td>';
            html += '<td>' + items + '</td>';
            html += '<td style="font-family:var(--font-mono)">$' + o.total.toFixed(2) + '</td>';
            html += '<td>' + o.status + '</td>';
            html += '<td>' + o.date + '</td>';
            html += '<td style="font-size:0.78rem;color:var(--text-secondary)">' + o.shippingAddress + '</td>';
            html += '<td style="font-size:0.78rem;color:var(--accent-amber)">' + (o.privateNotes || '—') + '</td></tr>';
          });
          html += '</tbody></table>';
          content.innerHTML = html;
          box.scrollIntoView({ behavior: 'smooth' });
        })
        .catch(e => console.error(e));
    }
    </script>
  `));
});

app.get('/api/manager/customers/:id/orders', authenticateToken, requireRole('manager', 'admin'), (req, res) => {
  const customerId = parseInt(req.params.id);
  if (isNaN(customerId)) return res.status(400).json({ error: 'Invalid customer ID' });

  const customer = users.find(u => u.id === customerId);
  if (!customer) return res.status(404).json({ error: 'Customer not found' });

  const customerOrders = orders.filter(o => o.userId === customerId);
  res.json({
    customerId: customer.id,
    name: customer.name,
    email: customer.email,
    loyaltyTier: customer.loyaltyTier,
    orders: customerOrders.map(o => ({
      id: o.id,
      items: o.items,
      total: o.total,
      status: o.status,
      date: o.date,
      shippingAddress: o.shippingAddress,
      privateNotes: o.privateNotes,
    })),
  });
});

