app.post('/api/cart/add', requireAuth, (req, res) => {
  const user = req.user;
  const { productId, quantity } = req.body;
  if (!carts[user.id]) carts[user.id] = [];
  const existing = carts[user.id].find(i => i.productId === productId);
  if (existing) {
    existing.quantity += (quantity || 1);
  } else {
    carts[user.id].push({ productId, quantity: quantity || 1 });
  }
  res.json({ success: true, cartSize: carts[user.id].length });
});

app.get('/cart', requireAuth, (req, res) => {
  const user = req.user;
  const cartItems = carts[user.id] || [];
  const results = db.exec('SELECT * FROM products');
  const allProducts = results.length > 0 ? results[0].values : [];

  let rows = '';
  let total = 0;
  cartItems.forEach(ci => {
    const p = allProducts.find(pr => pr[0] === ci.productId);
    if (p) {
      const lineTotal = p[3] * ci.quantity;
      total += lineTotal;
      rows += `<tr>
        <td>${p[6]} ${esc(String(p[1]))}</td>
        <td style="font-family:var(--font-mono);font-size:0.8rem;color:var(--text-muted)">${esc(String(p[2]))}</td>
        <td style="text-align:center">${ci.quantity}</td>
        <td style="font-family:var(--font-mono)">$${Number(p[3]).toFixed(2)}</td>
        <td style="font-family:var(--font-mono);color:var(--accent)">$${lineTotal.toFixed(2)}</td>
      </tr>`;
    }
  });

  const emptyMsg = cartItems.length === 0 ? '<p style="color:var(--text-muted);text-align:center;padding:40px 0;">Your cart is empty. <a href="/shop">Browse products</a></p>' : '';

  res.send(pageShell('Cart', 'cart', user, `
