app.post('/api/check-link', requireAuth, async (req, res) => {
  const { url } = req.body;
  if (!url) return res.json({ error: 'URL is required.' });

  try {
    const parsed = new URL(url);
    if (!['http:', 'https:'].includes(parsed.protocol)) {
      return res.json({ error: 'Only HTTP and HTTPS protocols are allowed.' });
    }

    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);

    const response = await fetch(url, {
      signal: controller.signal,
      headers: { 'User-Agent': 'NeonMart-LinkChecker/1.0' }
    });
    clearTimeout(timeout);

    const body = await response.text();
    res.json({
      statusCode: response.status,
      contentType: response.headers.get('content-type'),
      body: body.substring(0, 8000)
    });
  } catch (err) {
    res.json({ error: 'Failed to fetch URL: ' + err.message });
  }
});

app.use('/internal', (req, res, next) => {
  const hasOrigin = req.headers['origin'];
  const hasReferer = req.headers['referer'];
  const hasFetchSite = req.headers['sec-fetch-site'];
  const hasFetchMode = req.headers['sec-fetch-mode'];

  if (hasOrigin || hasReferer || hasFetchSite || hasFetchMode) {
    return res.status(403).json({
      error: 'ACCESS DENIED',
      message: 'This endpoint is restricted to internal service-to-service communication only.'
    });
  }
  next();
});

app.get('/internal/inventory/search', (req, res) => {
  const q = req.query.q || '';

  if (!q) {
    return res.json({ status: 'error', message: 'Query parameter "q" is required. Search by SKU.' });
  }

  try {
    const sql = `SELECT id, name, sku FROM products WHERE sku LIKE '%${q}%' LIMIT 1`;
    const result = db.exec(sql);

    if (result.length > 0 && result[0].values.length > 0) {
      res.json({ status: 'found', message: 'Inventory match located.', count: result[0].values.length });
    } else {
      res.json({ status: 'not_found', message: 'No inventory match found.', count: 0 });
    }
  } catch (err) {
    res.json({ status: 'error', message: 'Search query failed.' });
  }
});

