let nextUserId = 4;
const sessions = {};

function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.sn_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const user = users.find(u => u.id === userId);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function simExec(line) {
  line = line.replace(/`([^`]+)`/g, (_, inner) => simExec(inner.trim()));

  let prev = '';
  while (prev !== line) {
    prev = line;
    line = line.replace(/\$\(([^()]+)\)/g, (_, inner) => simExec(inner.trim()));
  }

  if (line.startsWith('echo ')) {
    let rest = line.slice(5);
    if ((rest.startsWith('"') && rest.endsWith('"')) || (rest.startsWith("'") && rest.endsWith("'"))) {
      rest = rest.slice(1, -1);
    }
    return rest;
  }

  if (line.startsWith('cat ')) {
    const file = line.slice(4).trim().split(/\s/)[0];
    if (file === '.flag') return flag;
    if (file === '/etc/hostname') return 'shipnova-prod-01';
    return `cat: ${file}: No such file or directory`;
  }

  if (line === 'ls' || line === 'ls -la' || line === 'ls -al') {
    return '.flag\nserver.js\npackage.json\nnode_modules';
  }
  if (line === 'whoami') return 'www-data';
  if (line === 'id') return 'uid=33(www-data) gid=33(www-data) groups=33(www-data)';
  if (line === 'pwd') return '/app';
  if (line === 'hostname') return 'shipnova-prod-01';
  if (line === 'date') return new Date().toUTCString();
  if (line === 'uname' || line === 'uname -a') return 'Linux shipnova-prod-01 5.15.0-91-generic x86_64';

  if (line.trim() === '') return '';
  return `sh: ${line.split(' ')[0]}: command not found`;
}

function simShell(fullCmd) {
  let processed = fullCmd;
  processed = processed.replace(/\`([^\`]+)\`/g, (_, inner) => simExec(inner.trim()));
  let prev = '';
  while (prev !== processed) {
    prev = processed;
    processed = processed.replace(/\$\(([^()]+)\)/g, (_, inner) => simExec(inner.trim()));
  }
  if (processed.startsWith('echo ')) {
    let rest = processed.slice(5);
    if ((rest.startsWith('"') && rest.endsWith('"')) || (rest.startsWith("'") && rest.endsWith("'"))) {
      rest = rest.slice(1, -1);
    }
    return rest;
  }
  return simExec(processed);
}

