            outputEl.innerHTML = '<span class="prompt">shipnova-cli&gt; label-format --recipient "' + recipient.replace(/</g, '&lt;').replace(/"/g, '&amp;quot;') + '"</span>\\n\\n' + escaped;
          }
        } catch (err) {
          outputEl.innerHTML = '<span class="prompt">shipnova-cli&gt; </span><span style="color:#ef4444;">Connection error</span>';
        }
      }
    </script>
  `));
});

app.post('/api/generate-label', requireAuth, (req, res) => {
  const { recipient, service } = req.body;

  if (!recipient || typeof recipient !== 'string') {
    return res.json({ error: 'Recipient name is required.' });
  }

  if (recipient.length > 500) {
    return res.json({ error: 'Input too long.' });
  }

  const blockedPattern = /[;|&]/;
  if (blockedPattern.test(recipient)) {
    return res.json({ error: 'Blocked characters detected. The characters ; | & are not permitted in recipient names for security reasons.' });
  }

  const svc = (service === 'Express' || service === 'Overnight') ? service : 'Standard';
  const dateStr = new Date().toISOString().split('T')[0];
  const trackingNum = 'SN' + crypto.randomBytes(6).toString('hex').toUpperCase();

  const cmd = `echo "========================================\n  SHIPNOVA EXPRESS SHIPPING LABEL\n========================================\n  TO:       ${recipient}\n  SERVICE:  ${svc}\n  DATE:     ${dateStr}\n  TRACKING: ${trackingNum}\n========================================\n  FROM: ShipNova Warehouse #7\n        1200 Commerce Blvd\n        Austin, TX 78701\n========================================"`;

  try {
    const output = simShell(cmd);
    res.json({ output });
  } catch (e) {
    res.json({ error: 'Label generation failed.' });
  }
});

