function statusBadge(s) {
  const cls = { Delivered: 'badge-delivered', Shipped: 'badge-shipped', Processing: 'badge-processing' };
  return '<span class="badge ' + (cls[s] || 'badge-processing') + '">' + esc(s) + '</span>';
}

function renderSidebar(activePage, user) {
  const init = initials(user.name);
  const roleBadge = user.role === 'VIP Customer' ? 'VIP' : 'Customer';
  return `
    <aside class="sidebar">
      <div class="sidebar-brand">
        <div class="logo-icon">🛒</div>
        <h1>Neon<span>Cart</span></h1>
      </div>
      <nav class="sidebar-nav">
        <div class="section-label">Store</div>
        <a href="/shop" class="${activePage === 'shop' ? 'active' : ''}">
          <span class="icon">🏪</span> Shop
        </a>
        <a href="/orders" class="${activePage === 'orders' ? 'active' : ''}">
          <span class="icon">📦</span> My Orders
        </a>
        <div class="section-label">Account</div>
        <a href="/account" class="${activePage === 'account' ? 'active' : ''}">
          <span class="icon">👤</span> Profile
        </a>
        <a href="/logout">
          <span class="icon">🚪</span> Sign Out
        </a>
      </nav>
      <div class="sidebar-user">
        <div class="avatar">${init}</div>
        <div class="user-info">
          <div class="user-name">${esc(user.name)}</div>
          <div class="user-role">${esc(roleBadge)}</div>
