      <div class="p-rating">${'★'.repeat(Math.floor(p.rating))}${'☆'.repeat(5 - Math.floor(p.rating))} ${p.rating}</div>
    </div>
  `).join('');

  res.send(pageShell('Shop', 'shop', user, `
    <div class="page-header">
