app.get('/orders', requireAuth, (req, res) => {
  const user = req.user;
  const userOrders = orders.filter(o => o.userId === user.id);
  const firstOrderId = userOrders.length > 0 ? userOrders[0].id : '';

  const rows = userOrders.map(o => `
    <tr>
      <td><span style="font-family:var(--font-mono);font-size:0.8rem;color:var(--accent);">#${o.id}</span></td>
      <td>${esc(o.date)}</td>
      <td>${o.items.map(i => esc(i.name)).join(', ')}</td>
      <td style="font-family:var(--font-mono);">$${o.total.toFixed(2)}</td>
      <td>${statusBadge(o.status)}</td>
      <td>${o.tracking ? '<span style="font-family:var(--font-mono);font-size:0.78rem;">' + esc(o.tracking) + '</span>' : '<span style="color:var(--text-muted);">—</span>'}</td>
    </tr>
  `).join('');

  res.send(pageShell('My Orders', 'orders', user, `
    <div class="page-header">
      <h1>My Orders</h1>
      <p class="subtitle">View your order history and track shipments</p>
    </div>

    <div class="lookup-form">
      <h3>🔍 Order Lookup</h3>
      <p style="font-size:0.82rem;color:var(--text-secondary);margin-bottom:14px;">
        Enter an order ID to view full details including items, shipping address, and digital codes.
      </p>
      <form method="GET" action="/orders/detail">
        <div class="form-row">
          <div class="form-group">
            <label>Order ID</label>
            <input type="number" name="order_id" value="${firstOrderId}" min="1" required>
          </div>
