            <button type="submit" class="btn btn-primary" style="padding:10px 24px;color:#fff;">View Details</button>
          </div>
        </div>
      </form>
    </div>

    <div class="card">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">Order History</h3>
      ${userOrders.length > 0 ? `
      <table class="data-table">
        <thead>
          <tr><th>Order ID</th><th>Date</th><th>Items</th><th>Total</th><th>Status</th><th>Tracking</th></tr>
