app.get('/orders/detail', requireAuth, (req, res) => {
  const user = req.user;
  const orderId = parseInt(req.query.order_id);

  if (!orderId || isNaN(orderId)) {
    return res.send(pageShell('Order Not Found', 'orders', user, `
      <div class="page-header">
        <h1>Order Not Found</h1>
        <p class="subtitle">Please enter a valid order ID</p>
      </div>
      <a href="/orders" class="btn btn-ghost" style="cursor:pointer;color:var(--text-secondary);">← Back to Orders</a>
    `));
  }

  const order = orders.find(o => o.id === orderId);

  if (!order) {
    return res.send(pageShell('Order Not Found', 'orders', user, `
      <div class="page-header">
        <h1>Order Not Found</h1>
        <p class="subtitle">No order found with ID #${esc(String(orderId))}</p>
