function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function renderSidebar(activePage, user) {
  const init = initials(user.name);
  const cartCount = db.exec(`SELECT SUM(quantity) as c FROM cart WHERE user_id = ${user.id}`);
  const count = (cartCount.length && cartCount[0].values[0][0]) || 0;
  return `
    <aside class="sidebar">
      <div class="sidebar-brand">
        <div class="logo">🛒</div>
        <h1>Neon<span>Mart</span></h1>
      </div>
      <nav class="sidebar-nav">
        <div class="section-label">Store</div>
        <a href="/shop" class="${activePage === 'shop' ? 'active' : ''}">
          <span class="icon">🏪</span> Browse Products
        </a>
        <a href="/cart" class="${activePage === 'cart' ? 'active' : ''}">
          <span class="icon">🛒</span> Cart${count > 0 ? ' (' + count + ')' : ''}
        </a>
        <a href="/orders" class="${activePage === 'orders' ? 'active' : ''}">
          <span class="icon">📦</span> My Orders
        </a>
        <div class="section-label">Account</div>
        <a href="/account" class="${activePage === 'account' ? 'active' : ''}">
          <span class="icon">👤</span> Profile
        </a>
        <a href="/logout">
          <span class="icon">🚪</span> Sign Out
        </a>
      </nav>
      <div class="sidebar-user">
        <div class="avatar">${init}</div>
        <div class="user-info">
          <div class="user-name">${esc(user.name)}</div>
          <div class="user-role">Customer</div>
        </div>
      </div>
    </aside>`;
}

function pageShell(title, activePage, user, content) {
  return `<!DOCTYPE html>
<html lang="en"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${esc(title)} — NeonMart</title>
<style>${baseStyles}</style>
</head><body class="fade-in">
<div class="app-layout">
  ${renderSidebar(activePage, user)}
  <main class="main-content">
    ${content}
  </main>
</div>
</body></html>`;
}

function statusBadge(s) {
  const cls = { Delivered: 'badge-delivered', Shipped: 'badge-shipped', Processing: 'badge-processing' };
  return `<span class="badge ${cls[s] || 'badge-processing'}">${esc(s)}</span>`;
}

