app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) {
    return res.send(renderLoginPage('Please enter both username and password.', ''));
  }
  const rows = db.exec(`SELECT * FROM users WHERE username = '${username.replace(/'/g, "''")}' AND password = '${password.replace(/'/g, "''")}'`);
  if (!rows.length || !rows[0].values.length) {
    return res.send(renderLoginPage('Invalid username or password.', ''));
  }
  const cols = rows[0].columns;
  const vals = rows[0].values[0];
  const userId = vals[cols.indexOf('id')];
  const token = createSession(userId);
  res.cookie('nm_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/shop');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(renderLoginPage('', 'All fields are required.'));
  }
  const existing = db.exec(`SELECT id FROM users WHERE username = '${username.replace(/'/g, "''")}'`);
  if (existing.length && existing[0].values.length) {
    return res.send(renderLoginPage('', 'Username already taken.'));
  }
  db.run(`INSERT INTO users (username, password, name, email, role, joined) VALUES (?, ?, ?, ?, 'customer', ?)`,
    [username, password, name, username + '@neonmart.io', new Date().toISOString().split('T')[0]]);
  const newUser = db.exec(`SELECT id FROM users WHERE username = '${username.replace(/'/g, "''")}'`);
  const newId = newUser[0].values[0][0];
  const token = createSession(newId);
  res.cookie('nm_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/shop');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nm_session;
  if (token) delete sessions[token];
  res.clearCookie('nm_session');
  res.redirect('/');
});

app.get('/shop', requireAuth, (req, res) => {
  const user = req.user;
  const q = req.query.q || '';

  let products = [];
  let error = '';

  try {
    let rows;
    if (q) {
      rows = db.exec(`SELECT * FROM products WHERE listed = 1 AND name LIKE '%${q}%'`);
    } else {
      rows = db.exec(`SELECT * FROM products WHERE listed = 1`);
    }
    if (rows.length && rows[0].values.length) {
      const cols = rows[0].columns;
      products = rows[0].values.map(vals => {
        const obj = {};
        cols.forEach((c, i) => obj[c] = vals[i]);
        return obj;
      });
    }
  } catch (e) {
    error = 'Search query error. Please try a different search term.';
  }

  const productCards = products.map(p => `
    <div class="product-card">
      <span class="p-emoji">${esc(p.emoji || '📦')}</span>
      <div class="p-category">${esc(p.category)}</div>
      <div class="p-name">${esc(p.name)}</div>
      <div class="p-desc">${esc(p.description)}</div>
      <div class="p-bottom">
        <span class="p-price">$${Number(p.price).toFixed(2)}</span>
        ${p.stock > 0
          ? `<span class="p-stock">In Stock (${p.stock})</span>`
          : `<span class="p-stock out">Out of Stock</span>`}
      </div>
      ${p.stock > 0 ? `<form method="POST" action="/cart/add" style="margin-top:12px;">
        <input type="hidden" name="product_id" value="${p.id}">
        <button type="submit" class="btn btn-primary btn-sm" style="width:100%;">Add to Cart</button>
      </form>` : `<button class="btn btn-ghost btn-sm" style="width:100%;margin-top:12px;cursor:not-allowed;" disabled>Unavailable</button>`}
    </div>`).join('');

  const resultInfo = q
    ? `<div class="result-count">Showing <strong>${products.length}</strong> result${products.length !== 1 ? 's' : ''} for "<strong>${esc(q)}</strong>"</div>`
    : `<div class="result-count"><strong>${products.length}</strong> products available</div>`;

  res.send(pageShell('Shop', 'shop', user, `
    <div class="page-header">
      <h1>Browse Products</h1>
      <p class="subtitle">Premium electronics and accessories</p>
    </div>

    <form method="GET" action="/shop" class="search-bar">
      <input type="text" name="q" placeholder="Search products by name..." value="${esc(q)}">
      <button type="submit">Search</button>
    </form>

    ${error ? `<div class="error-msg" style="margin-bottom:16px;">${esc(error)}</div>` : ''}
    ${resultInfo}

    ${products.length > 0
      ? `<div class="product-grid">${productCards}</div>`
      : `<div class="empty-state"><span class="empty-icon">🔍</span><p>No products found. Try a different search.</p></div>`}
  `));
});

app.get('/product/:id', requireAuth, (req, res) => {
  const user = req.user;
  const pid = parseInt(req.params.id);
  const rows = db.exec(`SELECT * FROM products WHERE id = ${pid} AND listed = 1`);

  if (!rows.length || !rows[0].values.length) {
    return res.send(pageShell('Not Found', 'shop', user,
      '<div class="page-header"><h1>Product Not Found</h1></div><div class="empty-state"><span class="empty-icon">🚫</span><p>This product does not exist or is no longer available.</p></div>'));
  }

  const cols = rows[0].columns;
  const vals = rows[0].values[0];
  const p = {};
  cols.forEach((c, i) => p[c] = vals[i]);

  res.send(pageShell(p.name, 'shop', user, `
    <div class="page-header">
      <h1>${esc(p.name)}</h1>
      <p class="subtitle">${esc(p.category)}</p>
    </div>
    <div class="card" style="max-width:600px;">
