app.post('/cart/add', requireAuth, (req, res) => {
  const user = req.user;
  const productId = parseInt(req.body.product_id);
  const existing = db.exec(`SELECT id, quantity FROM cart WHERE user_id = ${user.id} AND product_id = ${productId}`);
  if (existing.length && existing[0].values.length) {
    const cartId = existing[0].values[0][0];
    const qty = existing[0].values[0][1];
    db.run(`UPDATE cart SET quantity = ${qty + 1} WHERE id = ${cartId}`);
  } else {
    db.run(`INSERT INTO cart (user_id, product_id, quantity) VALUES (${user.id}, ${productId}, 1)`);
  }
  res.redirect('/cart');
});

app.post('/cart/remove', requireAuth, (req, res) => {
  const user = req.user;
  const cartId = parseInt(req.body.cart_id);
  db.run(`DELETE FROM cart WHERE id = ${cartId} AND user_id = ${user.id}`);
  res.redirect('/cart');
});

app.get('/cart', requireAuth, (req, res) => {
  const user = req.user;
  const rows = db.exec(`SELECT cart.id as cart_id, cart.quantity, products.name, products.price, products.emoji FROM cart JOIN products ON cart.product_id = products.id WHERE cart.user_id = ${user.id}`);

  let items = [];
  if (rows.length && rows[0].values.length) {
    const cols = rows[0].columns;
    items = rows[0].values.map(vals => {
      const obj = {};
      cols.forEach((c, i) => obj[c] = vals[i]);
      return obj;
    });
  }

  const total = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const cartItems = items.map(item => `
    <div class="cart-item">
      <span class="ci-emoji">${esc(item.emoji || '📦')}</span>
      <div class="ci-info">
