        <input type="hidden" name="cart_id" value="${item.cart_id}">
        <button type="submit" class="btn btn-danger btn-sm">Remove</button>
      </form>
    </div>`).join('');

  res.send(pageShell('Cart', 'cart', user, `
    <div class="page-header">
      <h1>Shopping Cart</h1>
      <p class="subtitle">${items.length} item${items.length !== 1 ? 's' : ''} in your cart</p>
    </div>

    ${items.length > 0 ? `
      <div class="card" style="margin-bottom:20px;">
        ${cartItems}
      </div>
      <div class="card" style="display:flex;align-items:center;justify-content:space-between;max-width:500px;">
        <div>
          <div style="font-size:0.78rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.8px;margin-bottom:4px;">Total</div>
          <div style="font-family:var(--font-mono);font-size:1.5rem;font-weight:700;color:var(--accent);">$${total.toFixed(2)}</div>
        </div>
        <form method="POST" action="/checkout">
          <button type="submit" class="btn btn-green" style="padding:12px 28px;font-size:0.9rem;">Checkout</button>
        </form>
      </div>
    ` : `
      <div class="card">
        <div class="empty-state">
