app.post('/checkout', requireAuth, (req, res) => {
  const user = req.user;
  const rows = db.exec(`SELECT cart.quantity, products.name, products.price FROM cart JOIN products ON cart.product_id = products.id WHERE cart.user_id = ${user.id}`);

  if (!rows.length || !rows[0].values.length) {
    return res.redirect('/cart');
  }

  const cols = rows[0].columns;
  const items = rows[0].values.map(vals => {
    const obj = {};
    cols.forEach((c, i) => obj[c] = vals[i]);
    return obj;
  });

  const orderRef = 'NM-' + Date.now().toString(36).toUpperCase();
  const today = new Date().toISOString().split('T')[0];

  for (const item of items) {
    const total = item.price * item.quantity;
    db.run(`INSERT INTO orders (user_id, order_ref, product_name, quantity, total, status, date) VALUES (?, ?, ?, ?, ?, 'Processing', ?)`,
      [user.id, orderRef, item.name, item.quantity, total, today]);
  }

  db.run(`DELETE FROM cart WHERE user_id = ${user.id}`);
  res.redirect('/orders');
});

app.get('/orders', requireAuth, (req, res) => {
  const user = req.user;
  const rows = db.exec(`SELECT * FROM orders WHERE user_id = ${user.id} ORDER BY date DESC`);

