app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.redirect('/?error=1');
  const token = createSession(user.id);
  res.cookie('nk_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/shop');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.redirect('/?error=2');
  if (users.find(u => u.username === username)) return res.redirect('/?error=3');
  const newUser = {
    id: nextUserId++,
    username,
    password,
    name,
    role: 'Customer',
    email: username + '@email.com',
    joined: new Date().toISOString().split('T')[0],
    orders: 0,
  };
  users.push(newUser);
  res.redirect('/?registered=1');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nk_session;
  if (token) delete sessions[token];
  res.clearCookie('nk_session');
  res.redirect('/');
});

app.get('/shop', requireAuth, (req, res) => {
  const user = req.user;
  const query = req.query.q || '';
  const category = req.query.cat || '';

  let filtered = products;
  if (query) {
    const q = query.toLowerCase();
    filtered = products.filter(p =>
      p.name.toLowerCase().includes(q) ||
      p.category.toLowerCase().includes(q) ||
      p.description.toLowerCase().includes(q)
    );
  }
  if (category) {
    filtered = filtered.filter(p => p.category === category);
  }

  const categories = [...new Set(products.map(p => p.category))];
  const catLinks = categories.map(c =>
    `<a href="/shop?cat=${encodeURIComponent(c)}" class="${category === c ? 'active' : ''}">${esc(c)}</a>`
  ).join('');

  let searchInfoHtml = '';
  if (query) {
    searchInfoHtml = `<div class="search-info">Showing results for: <strong>${query}</strong> — ${filtered.length} product${filtered.length !== 1 ? 's' : ''} found</div>`;
  }

  let productHtml = '';
  if (filtered.length === 0) {
    productHtml = `<div class="no-results">
      <span class="nr-icon">🔍</span>
      <h3>No products found</h3>
      <p>Try a different search term or browse categories above.</p>
