        <form method="POST" action="/cart/add" style="margin:0;">
          <input type="hidden" name="productId" value="${p.id}">
          <button type="submit" class="btn btn-primary">Add to Cart</button>
        </form>
      </div>`).join('')}</div>`;
  }

  res.send(pageShell('Shop', 'shop', user, `
