});

app.post('/cart/add', requireAuth, (req, res) => {
  const user = req.user;
  const productId = parseInt(req.body.productId);
  const product = products.find(p => p.id === productId);
  if (!product) return res.redirect('/shop');

  if (!carts[user.id]) carts[user.id] = [];
  const existing = carts[user.id].find(item => item.productId === productId);
  if (existing) {
    existing.qty += 1;
  } else {
    carts[user.id].push({ productId, qty: 1 });
  }
  res.redirect('/cart');
});

app.post('/cart/remove', requireAuth, (req, res) => {
  const user = req.user;
  const productId = parseInt(req.body.productId);
  if (carts[user.id]) {
    carts[user.id] = carts[user.id].filter(item => item.productId !== productId);
  }
  res.redirect('/cart');
});

