app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(renderLogin('<div class="error-msg">Invalid username or password. Please try again.</div>'));
  }
  const token = createSession(user.id);
  res.cookie('fp_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.fp_session;
  if (token) delete sessions[token];
  res.clearCookie('fp_session');
  res.redirect('/');
});

