app.get('/coach-notes', requireAuth, (req, res) => {
  const user = req.user;
  let relevantNotes;
  if (user.role === 'Head Coach') {
    relevantNotes = coachNotes;
  } else {
    relevantNotes = coachNotes.filter(n => n.athlete === user.username);
  }

  const noteCards = relevantNotes.map(n => {
    const athlete = users.find(u => u.username === n.athlete);
    return `
    <div class="note-card">
      <div class="nc-header">
        <span class="nc-athlete">${athlete ? esc(athlete.name) : esc(n.athlete)} ${athlete ? athlete.avatar : ''}</span>
        <span class="nc-date">${esc(n.date)}</span>
      </div>
      <div class="nc-body">${esc(n.note)}</div>
    </div>`;
  }).join('');

  res.send(pageShell('Coach Notes', 'notes', user, `
    <div class="page-header">
      <h1>Coach Notes</h1>
      <p class="subtitle">${user.role === 'Head Coach' ? 'Your coaching feedback and athlete progress notes' : 'Feedback from your coach'}</p>
    </div>
    ${noteCards || '<div class="card"><p style="color:var(--text-muted);text-align:center;padding:40px 0;">No coach notes yet.</p></div>'}
  `));
});

