app.get('/', (req, res) => res.send(loginHtml()));

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.send(loginHtml('Invalid username or password.'));
  const tok = createSession(user.id);
  res.cookie('fc_session', tok, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { name, username, password } = req.body;
  if (!name || !username || !password) return res.send(loginHtml('', 'All fields are required.'));
  if (users.find(u => u.username === username)) return res.send(loginHtml('', 'Username already taken.'));
  const nu = {
    id: users.length + 1,
    username, password, name,
    role: 'Basic Member', level: 'Beginner',
    joinDate: new Date().toISOString().split('T')[0],
    goal: 'General Fitness',
    avatar: name.split(' ').map(p => p[0]).join('').slice(0,2).toUpperCase(),
    avatarColor: 'linear-gradient(135deg, #64748b, #475569)',
    streak: 0, totalWorkouts: 0,
    prs: {},
  };
  users.push(nu);
  const tok = createSession(nu.id);
  res.cookie('fc_session', tok, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const tok = req.cookies?.fc_session;
  if (tok) delete sessions[tok];
  res.clearCookie('fc_session');
  res.redirect('/');
});

