          </div>
          <div class="form-group">
            <label>Card Number</label>
            <input type="text" id="bill-card" placeholder="•••• •••• •••• ••••" maxlength="19">
          </div>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
            <div class="form-group">
              <label>Expiry</label>
              <input type="text" placeholder="MM / YY" maxlength="7">
            </div>
            <div class="form-group">
              <label>CVC</label>
              <input type="text" placeholder="•••" maxlength="4">
            </div>
          </div>
        </div>

        <div class="card">
          <div class="card-title">🏷️ Discount Code</div>
          <p style="font-size:0.82rem;color:var(--text-2);margin-bottom:14px;">Have a promotional code? Enter it below to save on your purchase.</p>

          <div id="applied-coupons"></div>

          <div class="coupon-row">
            <input type="text" id="coupon-input" placeholder="e.g. WELCOME25" style="background:var(--bg-root);border:1px solid var(--border);border-radius:var(--r);padding:10px 14px;color:var(--text-1);font-size:0.88rem;">
            <button class="btn btn-outline" onclick="applyCoupon()">Apply</button>
          </div>
          <p id="coupon-msg" style="font-size:0.78rem;margin-top:8px;color:var(--text-3);"></p>

          <div style="margin-top:16px;padding:12px;background:var(--bg-root);border-radius:var(--r);border:1px solid var(--border);">
            <p style="font-size:0.72rem;text-transform:uppercase;letter-spacing:0.6px;color:var(--text-3);margin-bottom:6px;">Active Promotions</p>
            <code style="display:block;font-size:0.78rem;color:var(--text-2);">WELCOME25 — 25% new member offer</code>
            <code style="display:block;font-size:0.78rem;color:var(--text-2);">SUMMER10 — 10% seasonal discount</code>
          </div>
        </div>
      </div>

      <div class="checkout-summary">
        <div class="card-title" style="margin-bottom:16px;">🧾 Order Summary</div>

        <div class="checkout-item">
          <div>
            <div class="checkout-item-name">${esc(plan.name)}</div>
            <div class="checkout-item-sub">Monthly subscription</div>
          </div>
          <div class="checkout-item-price" id="base-price-display">${esc(plan.priceDisplay)}</div>
        </div>

        <div id="discount-rows"></div>

        <div class="checkout-total">
          <span class="label">Total Due</span>
          <span class="amount" id="total-display">${esc(plan.priceDisplay)}</span>
        </div>

        <button class="btn btn-primary" style="width:100%;justify-content:center;margin-top:20px;padding:13px;" onclick="submitCheckout()">
          Complete Purchase
        </button>

        <div id="checkout-result" style="margin-top:16px;"></div>

        <p style="font-size:0.72rem;color:var(--text-3);text-align:center;margin-top:12px;">🔒 Secured with 256-bit encryption</p>
      </div>
    </div>

    <script>
      const BASE_PRICE = ${plan.price};
      const PLAN_ID = '${plan.id}';
      let appliedCoupons = [];
      let couponLocked = false;

      const validCodes = {
        'FIT10': 10, 'HEALTH20': 20, 'GAINS15': 15,
        'WELCOME25': 25, 'SUMMER10': 10, 'NEWUSER15': 15, 'PROMO20': 20
      };

      function applyCoupon() {
        if (couponLocked) {
          showCouponMsg('Only one coupon allowed per order.', 'var(--accent-red)');
          return;
        }
        const code = document.getElementById('coupon-input').value.trim().toUpperCase();
        if (!code) return;
        if (!validCodes[code]) {
          showCouponMsg('Invalid coupon code.', 'var(--accent-red)');
          return;
        }
        appliedCoupons.push(code);
        couponLocked = true;
        document.getElementById('coupon-input').value = '';
        document.getElementById('coupon-input').disabled = true;
        renderDiscounts();
        showCouponMsg('Coupon applied!', 'var(--accent)');
      }

      function renderDiscounts() {
        let price = BASE_PRICE;
        const rows = document.getElementById('discount-rows');
        rows.innerHTML = '';
        appliedCoupons.forEach(code => {
          const pct = validCodes[code];
          const saving = Math.round(price * pct / 100);
          price -= saving;
          rows.innerHTML += \`
            <div class="discount-row">
              <span><span class="d-code">\${code}</span> — \${pct}% off</span>
              <span class="d-amount">-$\${(saving/100).toFixed(2)}</span>
            </div>\`;
        });
        const display = price <= 0 ? '$0.00' : '$' + (price/100).toFixed(2);
        document.getElementById('total-display').textContent = display;
      }

      function showCouponMsg(msg, color) {
        const el = document.getElementById('coupon-msg');
        el.textContent = msg;
        el.style.color = color;
      }

      async function submitCheckout() {
        const result = document.getElementById('checkout-result');
        result.innerHTML = '<p style="color:var(--text-2);font-size:0.83rem;">Processing...</p>';
        try {
          const resp = await fetch('/api/checkout', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ planId: PLAN_ID, coupons: appliedCoupons })
          });
          const data = await resp.json();
