                <div class="flag-label">🚩 Capture The Flag</div>
                <div class="flag-value">\${data.flag}</div>
              </div>\`;
          } else if (data.orderId) {
            result.innerHTML = \`<div class="msg-ok">✅ Order #\${data.orderId} confirmed! Welcome to \${data.planName}.</div>\`;
          } else {
            result.innerHTML = \`<div class="msg-err">\${data.error || 'Checkout failed.'}</div>\`;
          }
        } catch(e) {
          result.innerHTML = '<div class="msg-err">Network error. Please try again.</div>';
        }
      }
    </script>
  `));
});

