app.post('/api/checkout', requireAuth, (req, res) => {
  const { planId, coupons: rawCoupons } = req.body;

  const plan = plans.find(p => p.id === planId);
  if (!plan) return res.status(400).json({ error: 'Invalid plan.' });

  const couponList = Array.isArray(rawCoupons)
    ? rawCoupons
    : (typeof rawCoupons === 'string' ? [rawCoupons] : []);

  let price = plan.price;
  const applied = [];

  for (const code of couponList) {
    const upper = String(code).toUpperCase();
    const coupon = coupons[upper];
    if (!coupon) continue;
    const saving = Math.ceil(price * coupon.discount / 100);
    price -= saving;
    applied.push({ code: upper, discount: coupon.discount });
  }

  if (price <= 0) {
    return res.json({ free: true, flag, appliedCoupons: applied, planName: plan.name });
  }

  const orderId = 'FC-' + (++orderCounter);
  return res.json({ orderId, planName: plan.name, total: price, appliedCoupons: applied });
});

