function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function createToken(user) {
  return jwt.sign(
    { id: user.id, username: user.username, name: user.name, role: user.role },
    JWT_SECRET,
    { algorithm: 'HS256', expiresIn: '24h' }
  );
}

function authMiddleware(req, res, next) {
  const token = req.cookies?.fp_session;
  if (!token) return res.redirect('/');
  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = decoded;
    next();
  } catch (e) {
    res.clearCookie('fp_session');
    res.redirect('/');
  }
}

function coachGuard(req, res, next) {
  if (req.user.role === 'coach' || req.user.role === 'admin') return next();
  return res.status(403).send(errorPage('Access Denied', 'Coach-level clearance required to access this resource.', req.user));
}

