app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const result = db.exec(`SELECT * FROM users WHERE username = ? AND password = ?`, [username, password]);
  if (!result.length || !result[0].values.length) {
    return res.send(loginPageHtml('<div class="error-msg">Invalid credentials.</div>', ''));
  }
  const row = result[0].values[0];
  const user = { id: row[0], username: row[1], name: row[3], role: row[4] };
  const token = createToken(user);
  res.cookie('fp_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(loginPageHtml('', '<div class="error-msg">All fields are required.</div>'));
  }
  const exists = db.exec(`SELECT id FROM users WHERE username = ?`, [username]);
  if (exists.length && exists[0].values.length) {
    return res.send(loginPageHtml('', '<div class="error-msg">Username already taken.</div>'));
  }
  const id = nextUserId++;
  db.run(`INSERT INTO users VALUES (?, ?, ?, ?, 'athlete')`, [id, username, password, name]);
  const user = { id, username, name, role: 'athlete' };
  const token = createToken(user);
  res.cookie('fp_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  res.clearCookie('fp_session');
