let nextUserId = 4;
let nextWorkoutId = 8;
const sessions = {};

function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.ft_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const result = db.exec(`SELECT * FROM users WHERE id = ${userId}`);
  if (!result.length || !result[0].values.length) return res.redirect('/');
  const row = result[0].values[0];
  req.user = { id: row[0], username: row[1], password: row[2], name: row[3], role: row[4], joined: row[5] };
  next();
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

