function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function categoryBadge(cat) {
  const cls = { Strength: 'badge-strength', Cardio: 'badge-cardio', HIIT: 'badge-hiit', Flexibility: 'badge-flex' };
  return '<span class="badge ' + (cls[cat] || 'badge-strength') + '">' + esc(cat) + '</span>';
}

function difficultyBadge(d) {
  const cls = { Beginner: 'badge-beginner', Intermediate: 'badge-intermediate', Advanced: 'badge-advanced' };
  return '<span class="badge ' + (cls[d] || 'badge-intermediate') + '">' + esc(d) + '</span>';
}

