app.get('/', (req, res) => {
  res.send(loginPageTpl.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const result = db.exec(`SELECT * FROM users WHERE username = '${esc(username)}'`);
  if (!result.length || !result[0].values.length) {
    return res.send(loginPageTpl.replace('%%LOGIN_MSG%%', '<div class="error-msg">Invalid credentials.</div>').replace('%%REG_MSG%%', ''));
  }
  const row = result[0].values[0];
  if (row[2] !== password) {
    return res.send(loginPageTpl.replace('%%LOGIN_MSG%%', '<div class="error-msg">Invalid credentials.</div>').replace('%%REG_MSG%%', ''));
  }
  const token = createSession(row[0]);
  res.cookie('ft_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(loginPageTpl.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', '<div class="error-msg">All fields are required.</div>'));
  }
  const existing = db.exec(`SELECT id FROM users WHERE username = '${esc(username)}'`);
  if (existing.length && existing[0].values.length) {
    return res.send(loginPageTpl.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', '<div class="error-msg">Username already taken.</div>'));
  }
  const uid = nextUserId++;
  const joined = new Date().toISOString().split('T')[0];
  db.run(`INSERT INTO users VALUES (?, ?, ?, ?, 'Athlete', ?)`, [uid, username, password, name, joined]);
  const token = createSession(uid);
  res.cookie('ft_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.ft_session;
  if (token) delete sessions[token];
  res.clearCookie('ft_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const myWorkouts = db.exec(`SELECT * FROM workouts WHERE user_id = ${user.id} ORDER BY date DESC`);
  const workoutRows = myWorkouts.length ? myWorkouts[0].values : [];
  const totalDuration = workoutRows.reduce((s, r) => s + r[4], 0);
  const totalCalories = workoutRows.reduce((s, r) => s + r[5], 0);
  const allExercises = db.exec(`SELECT COUNT(*) FROM exercises`);
  const exerciseCount = allExercises.length ? allExercises[0].values[0][0] : 0;

  const recentEntries = workoutRows.slice(0, 4).map(w => {
    const colors = ['rgba(255,107,53,0.15)', 'rgba(0,212,170,0.15)', 'rgba(59,130,246,0.15)', 'rgba(168,85,247,0.15)'];
    const icons = ['🏋️', '🏃', '⚡', '🧘'];
    const idx = Math.abs(w[0]) % 4;
    return `<div class="workout-entry">
      <div class="we-icon" style="background:${colors[idx]}">${icons[idx]}</div>
      <div class="we-info">
        <div class="we-title">${esc(w[2])}</div>
        <div class="we-meta">${esc(w[3])}</div>
      </div>
      <div class="we-stats">
        <div class="we-duration">${w[4]} min</div>
        <div class="we-cal">${w[5]} kcal</div>
      </div>
    </div>`;
  }).join('');

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header">
      <h1>Welcome back, ${esc(user.name.split(' ')[0])} 🔥</h1>
      <p class="subtitle">Your training overview</p>
    </div>
    <div class="stats-row">
      <div class="stat-card"><div class="stat-value">${workoutRows.length}</div><div class="stat-label">Workouts</div></div>
      <div class="stat-card teal"><div class="stat-value">${totalDuration}</div><div class="stat-label">Total Minutes</div></div>
      <div class="stat-card"><div class="stat-value">${totalCalories.toLocaleString()}</div><div class="stat-label">Calories Burned</div></div>
      <div class="stat-card teal"><div class="stat-value">${exerciseCount}</div><div class="stat-label">Exercises</div></div>
    </div>
    <div class="card">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">Recent Workouts</h3>
      ${recentEntries || '<p style="color:var(--text-muted);font-size:0.85rem;">No workouts yet. Start training!</p>'}
    </div>
  `));
});

app.get('/workouts', requireAuth, (req, res) => {
  const user = req.user;
  const myWorkouts = db.exec(`SELECT * FROM workouts WHERE user_id = ${user.id} ORDER BY date DESC`);
  const rows = myWorkouts.length ? myWorkouts[0].values : [];

  const tableRows = rows.map(w => `
    <tr>
      <td style="font-family:var(--font-mono);color:var(--accent);font-size:0.8rem;">#${w[0]}</td>
      <td><strong>${esc(w[2])}</strong></td>
      <td>${esc(w[3])}</td>
      <td style="font-family:var(--font-mono);">${w[4]} min</td>
      <td style="font-family:var(--font-mono);color:var(--accent-teal);">${w[5]} kcal</td>
      <td style="font-size:0.8rem;color:var(--text-muted);max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(w[6] || '')}</td>
    </tr>`).join('');

  res.send(pageShell('Workouts', 'workouts', user, `
    <div class="page-header">
      <h1>My Workouts</h1>
      <p class="subtitle">Your training history and session logs</p>
    </div>
    <div class="card" style="margin-bottom:20px;">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">Log New Workout</h3>
      <form id="logForm" style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
        <div><label style="display:block;font-size:0.7rem;text-transform:uppercase;letter-spacing:0.8px;color:var(--text-muted);margin-bottom:4px;">Title</label><input class="import-input" type="text" name="title" placeholder="Workout title" required></div>
        <div><label style="display:block;font-size:0.7rem;text-transform:uppercase;letter-spacing:0.8px;color:var(--text-muted);margin-bottom:4px;">Date</label><input class="import-input" type="text" name="date" placeholder="YYYY-MM-DD" required></div>
        <div><label style="display:block;font-size:0.7rem;text-transform:uppercase;letter-spacing:0.8px;color:var(--text-muted);margin-bottom:4px;">Duration (min)</label><input class="import-input" type="number" name="duration" placeholder="45" required></div>
        <div><label style="display:block;font-size:0.7rem;text-transform:uppercase;letter-spacing:0.8px;color:var(--text-muted);margin-bottom:4px;">Calories</label><input class="import-input" type="number" name="calories" placeholder="350" required></div>
        <div style="grid-column:1/-1;"><label style="display:block;font-size:0.7rem;text-transform:uppercase;letter-spacing:0.8px;color:var(--text-muted);margin-bottom:4px;">Notes</label><input class="import-input" type="text" name="notes" placeholder="Session notes..."></div>
        <div style="grid-column:1/-1;"><button type="submit" class="btn btn-primary">Log Workout</button></div>
      </form>
      <script>
        document.getElementById('logForm').addEventListener('submit', async (e) => {
          e.preventDefault();
          const fd = new FormData(e.target);
          const body = Object.fromEntries(fd.entries());
          await fetch('/api/workouts', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify(body) });
          window.location.reload();
        });
      </script>
    </div>
    <div class="card">
      <table class="data-table">
        <thead><tr><th>ID</th><th>Title</th><th>Date</th><th>Duration</th><th>Calories</th><th>Notes</th></tr></thead>
        <tbody>${tableRows || '<tr><td colspan="6" style="color:var(--text-muted);text-align:center;">No workouts logged yet.</td></tr>'}</tbody>
      </table>
    </div>
