app.post('/api/fetch-url', requireAuth, async (req, res) => {
  const { url } = req.body;
  if (!url) return res.status(400).json({ error: 'URL is required' });

  try {
    const parsed = new URL(url);
    if (!['http:', 'https:'].includes(parsed.protocol)) {
      return res.status(400).json({ error: 'Only HTTP/HTTPS protocols are supported' });
    }

    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);

    const response = await fetch(url, {
      headers: {
        'User-Agent': 'PeakForm-Importer/1.0',
        'X-PeakForm-Internal': 'true'
      },
      signal: controller.signal,
      redirect: 'follow'
    });

    clearTimeout(timeout);
    const body = await response.text();
    res.json({ status: response.status, body });
  } catch (err) {
    res.status(500).json({ error: 'Failed to fetch: ' + err.message });
  }
});

app.get('/internal/api/search', (req, res) => {
  const internalHeader = req.headers['x-peakform-internal'];
  if (internalHeader !== 'true') {
    return res.status(403).json({
      error: 'ACCESS DENIED',
      message: 'This endpoint is restricted to internal service requests only.'
    });
  }

  const q = req.query.q || '';

  if (!q) {
    return res.json({
      service: 'PeakForm Internal Exercise Search',
      usage: 'Provide ?q= parameter to search exercises by category',
      categories: ['Strength', 'Cardio', 'HIIT', 'Flexibility']
    });
  }

  const query = `SELECT id, name, category, muscle_group, difficulty FROM exercises WHERE category LIKE '%${q}%' OR name LIKE '%${q}%'`;

  try {
    const result = db.exec(query);
    const rows = result.length ? result[0].values.map(r => ({
      id: r[0], name: r[1], category: r[2], muscle_group: r[3], difficulty: r[4]
    })) : [];
    res.json({ query_term: q, count: rows.length, results: rows });
  } catch (err) {
    res.status(500).json({ error: 'Query error', detail: err.message });
  }
});

