  .post-author-name{font-weight:600;font-size:0.88rem;}
  .post-date{font-size:0.72rem;color:var(--text-muted);}
  .post-body{font-size:0.88rem;color:var(--text-secondary);line-height:1.7;margin-bottom:8px;}
  .post-type{margin-top:8px;}
  .search-box{display:flex;gap:10px;margin-bottom:20px;}
  .search-box input{flex:1;padding:10px 14px;background:var(--bg-input);border:1px solid var(--border);border-radius:var(--radius);color:var(--text-primary);font-size:0.88rem;}
  .search-box input:focus{outline:none;border-color:var(--accent);box-shadow:0 0 0 3px rgba(249,115,22,0.1);}
  .search-box button{padding:10px 20px;background:linear-gradient(135deg,var(--accent),#ea580c);color:#fff;border:none;border-radius:var(--radius);font-weight:600;cursor:pointer;}
  textarea{width:100%;padding:10px 14px;background:var(--bg-input);border:1px solid var(--border);border-radius:var(--radius);color:var(--text-primary);font-size:0.88rem;font-family:var(--font-sans);resize:vertical;min-height:80px;}
  textarea:focus{outline:none;border-color:var(--accent);box-shadow:0 0 0 3px rgba(249,115,22,0.1);}
  select{padding:10px 14px;background:var(--bg-input);border:1px solid var(--border);border-radius:var(--radius);color:var(--text-primary);font-size:0.88rem;}
  .fade-in{animation:fadeIn 0.3s ease-out;}
  @keyframes fadeIn{from{opacity:0;transform:translateY(6px);}to{opacity:1;transform:translateY(0);}}
`;

