app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.redirect('/?error=1');
  const token = createSession(user.id);
  res.cookie('ft_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.redirect('/?error=1');
  if (users.find(u => u.username === username)) return res.redirect('/?error=1');
  const newUser = {
    id: nextUserId++,
    username, password, name,
    role: 'athlete',
    email: username + '@ironpulse.fit',
    joined: new Date().toISOString().split('T')[0],
    specialty: 'General Fitness',
  };
  users.push(newUser);
  res.redirect('/?registered=1');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.ft_session;
  if (token) delete sessions[token];
  res.clearCookie('ft_session');
  res.redirect('/');
});

