          <option value="General">General</option>
        </select>
      </div>
      <div style="margin-bottom:10px;">
        <label style="display:block;font-size:0.75rem;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;color:var(--text-muted);margin-bottom:6px;">Content</label>
        <textarea id="post-content" placeholder="Share your workout, PR, or training update..."></textarea>
      </div>
      <button class="btn btn-green" onclick="submitPost()">Post Update</button>
    </div>
    <div id="posts-feed">${postsHtml}</div>
    <script>
      function submitPost() {
        const content = document.getElementById('post-content').value;
        const type = document.getElementById('post-type').value;
        if (!content.trim()) return;
        fetch('/api/community/post', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ content, type })
        }).then(r => r.json()).then(data => {
          if (data.success) {
            document.getElementById('post-status').innerHTML = '<div class="success-msg">Post published! Refreshing...</div>';
            setTimeout(() => location.reload(), 800);
          } else {
            document.getElementById('post-status').innerHTML = '<div class="error-msg">' + data.error + '</div>';
          }
        });
      }
    </script>
  `));
});

app.post('/api/community/post', requireAuth, (req, res) => {
  const user = req.user;
  const { content, type } = req.body;
  if (!content || !content.trim()) return res.json({ success: false, error: 'Content is required.' });
  if (content.length > 2000) return res.json({ success: false, error: 'Post too long (max 2000 chars).' });
  const validTypes = ['Workout', 'PR', 'General', 'Announcement'];
  const postType = validTypes.includes(type) ? type : 'General';
  const post = {
    id: nextPostId++,
    author: user.username,
    authorName: user.name,
    type: postType,
    content: content,
    date: new Date().toISOString().split('T')[0],
  };
  communityPosts.push(post);
  res.json({ success: true, post: { id: post.id, date: post.date } });
});

