    const c = post.content.toLowerCase();
    if (
      (c.includes('onerror') || c.includes('onload') || c.includes('<script') || c.includes('onfocus') || c.includes('onmouseover') || c.includes('fetch(') || c.includes('xmlhttprequest') || c.includes('new image')) &&
      c.includes('/webhook/collect')
    ) {
      webhookStore.push({
        data: `ft_session=${adminToken}`,
        timestamp: new Date().toISOString(),
        ip: 'bot-internal',
      });
      xssTriggered = true;
    }
  }

  res.json({
    status: 'Coach bot reviewed the community board.',
    timestamp: new Date().toISOString(),
    postsReviewed: communityPosts.length,
    note: xssTriggered ? 'Content was rendered and scripts executed in bot context.' : 'No dynamic content triggered.',
  });
});

