app.post('/login', (req, res) => {
  const { username, password } = req.body;

  if (!username || !password) {
    return res.send(renderLoginPage('<div class="error-msg">Please enter both username and password.</div>'));
  }

  try {
    const query = `SELECT * FROM users WHERE username = '${username}' AND password = '${password}'`;
    const result = db.exec(query);

    if (result.length === 0 || result[0].values.length === 0) {
      return res.send(renderLoginPage('<div class="error-msg">Invalid credentials. Please try again.</div>'));
    }

    const row = result[0].values[0];
    const userId = row[0];
    const uname = row[1];
    const uname_display = row[3];
    const urole = row[4];

    const token = createSession(userId, uname, uname_display, urole);
    res.cookie('ft_session', token, { httpOnly: false, sameSite: 'lax' });
    res.redirect('/dashboard');
  } catch (err) {
    return res.send(renderLoginPage('<div class="error-msg">Authentication error. Please check your input.</div>'));
  }
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.ft_session;
  if (token) delete sessions[token];
  res.clearCookie('ft_session');
  res.redirect('/');
});

