function rarityBadge(r) {
  const cls = { Common: 'badge-common', Uncommon: 'badge-uncommon', Rare: 'badge-rare', Epic: 'badge-epic', Legendary: 'badge-legendary', Mythic: 'badge-mythic' };
  return `<span class="badge ${cls[r] || 'badge-common'}">${esc(r)}</span>`;
}

function rankBadge(r) {
  let cls = 'rank-gold';
  if (r.includes('Nexus')) cls = 'rank-nexus';
  else if (r.includes('Grandmaster')) cls = 'rank-grandmaster';
  else if (r.includes('Diamond')) cls = 'rank-diamond';
  else if (r.includes('Platinum')) cls = 'rank-platinum';
  return `<span class="rank-badge ${cls}">${esc(r)}</span>`;
}

