app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.redirect('/?error=Invalid+credentials');
  const token = createSession(user.id);
  res.cookie('nc_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.redirect('/?reg_error=All+fields+required');
  if (users.find(u => u.username === username)) return res.redirect('/?reg_error=Username+taken');
  const newUser = {
    id: nextUserId++,
    username,
    password,
    name,
    level: 1,
    playerClass: 'Recruit',
    guild: 'Unaffiliated',
    balance: 150,
    joined: new Date().toISOString().split('T')[0],
    gamesWon: 0,
    gamesPlayed: 0,
    kdr: 0,
    rank: 'Bronze I',
    bio: 'New player on NexusCore.',
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('nc_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nc_session;
  if (token) delete sessions[token];
  res.clearCookie('nc_session');
  res.redirect('/');
});

