let txCounter = 1000;

app.post('/store/buy', requireAuth, (req, res) => {
  const user = req.user;
  let { itemId, quantity } = req.body;

  itemId = Number(itemId);
  quantity = Number(quantity);

  const item = storeItems.find(i => i.id === itemId);
  if (!item) {
    return res.status(400).json({ error: 'Item not found in store catalog.' });
  }

  if (isNaN(quantity) || !Number.isFinite(quantity) || quantity === 0) {
    return res.status(400).json({ error: 'Quantity must be a valid non-zero number.' });
  }

  const totalCost = item.price * quantity;

  if (user.balance < totalCost) {
    return res.status(400).json({ error: 'Insufficient credits. You need ◈ ' + formatCredits(totalCost) + ' but only have ◈ ' + formatCredits(user.balance) + '.' });
  }

  user.balance -= totalCost;

  const userInv = inventory.get(user.id) || [];
  const existing = userInv.find(i => i.itemId === item.id);
  if (existing) {
    existing.quantity += quantity;
  } else {
    userInv.push({ itemId: item.id, name: item.name, icon: item.icon, rarity: item.rarity, quantity: quantity });
  }
  inventory.set(user.id, userInv);

  const userTx = transactions.get(user.id) || [];
  userTx.push({
    txId: txCounter++,
    itemId: item.id,
    itemName: item.name,
    quantity: quantity,
    unitPrice: item.price,
    totalCost: totalCost,
    date: new Date().toISOString().split('T')[0],
    balanceAfter: user.balance,
  });
  transactions.set(user.id, userTx);

  return res.json({
    success: true,
    message: `Purchased ${quantity}x ${item.name} for ◈ ${formatCredits(totalCost)}`,
    balance: user.balance,
    txId: txCounter - 1,
  });
});

