let nextUserId = 4;
const sessions = {};

function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.nx_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const user = users.find(u => u.id === userId);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function initials(name) {
  return name.slice(0, 2).toUpperCase();
}

function tierBadge(tier) {
  const colors = {
    Mythic: 'badge-mythic', Diamond: 'badge-diamond', Platinum: 'badge-platinum',
    Gold: 'badge-gold', Silver: 'badge-silver', Bronze: 'badge-bronze'
  };
  return `<span class="badge ${colors[tier] || 'badge-silver'}">${esc(tier)}</span>`;
}

function resultBadge(r) {
  return r === 'Victory'
    ? '<span class="badge badge-victory">Victory</span>'
    : '<span class="badge badge-defeat">Defeat</span>';
}

