function renderLogin(loginMsg, regMsg) {
  return loginPageTemplate
    .replace('%%LOGIN_MSG%%', loginMsg || '')
    .replace('%%REG_MSG%%', regMsg || '');
}

app.get('/', (req, res) => {
  const userId = getSession(req);
  if (userId && users.find(u => u.id === userId)) return res.redirect('/dashboard');
  res.send(renderLogin('', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(renderLogin('<div class="error-msg">Invalid credentials. Check your username and password.</div>', ''));
  }
  const token = createSession(user.id);
  res.cookie('nx_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(renderLogin('', '<div class="error-msg">All fields are required.</div>'));
  }
  if (users.find(u => u.username === username)) {
    return res.send(renderLogin('', '<div class="error-msg">Username already taken.</div>'));
  }
  const newUser = {
    id: nextUserId++, username, password, name,
    role: 'Player', tier: 'Bronze', elo: 1000,
    email: username + '@nexusarena.gg',
    joined: new Date().toISOString().split('T')[0],
    main_class: 'Unassigned',
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('nx_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nx_session;
  if (token) delete sessions[token];
  res.clearCookie('nx_session');
  res.redirect('/');
});

