app.post('/api/clips/preview', requireAuth, (req, res) => {
  const { url } = req.body;
  if (!url) return res.status(400).json({ error: 'URL is required' });

  let parsed;
  try {
    parsed = new URL(url);
  } catch (e) {
    return res.status(400).json({ error: 'Invalid URL format' });
  }

  if (parsed.protocol !== 'http:') {
    return res.status(400).json({ error: 'Only HTTP protocol is supported for previews' });
  }

  const options = {
    hostname: parsed.hostname,
    port: parsed.port || 80,
    path: parsed.pathname + parsed.search,
    method: 'GET',
    headers: {
      'User-Agent': 'NexusArena-ClipBot/2.1',
      'X-Internal-Request': 'true'
    },
    timeout: 5000
  };

  const proxyReq = http.request(options, (proxyRes) => {
    let body = '';
    proxyRes.setEncoding('utf-8');
    proxyRes.on('data', chunk => { body += chunk; });
    proxyRes.on('end', () => {
      res.json({
        statusCode: proxyRes.statusCode,
        contentType: proxyRes.headers['content-type'] || 'unknown',
        body: body.substring(0, 50000)
      });
    });
  });

  proxyReq.on('error', (err) => {
    res.status(502).json({ error: 'Failed to fetch URL', details: err.message });
  });

  proxyReq.on('timeout', () => {
    proxyReq.destroy();
    res.status(504).json({ error: 'Request timed out' });
  });

  proxyReq.end();
});

app.get('/internal/api/players', (req, res) => {
  const internalHeader = req.headers['x-internal-request'];
  if (internalHeader !== 'true') {
    return res.status(403).json({
      error: 'ACCESS DENIED',
      message: 'This endpoint is restricted to internal services only. Direct browser access is forbidden.',
      required: 'X-Internal-Request header must be present.'
    });
  }

  const search = req.query.search || '';

  if (!search) {
    return res.json({
      service: 'NexusArena Internal Player Search',
      usage: 'Provide a ?search= parameter to query player records by username.',
      example: '/internal/api/players?search=phantom'
    });
  }

  const query = `SELECT id, username, display_name, tier, elo FROM players WHERE username LIKE '%${search}%'`;

  try {
    const results = db.exec(query);
    if (results.length === 0) {
      return res.json({ query_term: search, results: [] });
    }
    const cols = results[0].columns;
    const rows = results[0].values.map(row => {
      const obj = {};
      cols.forEach((c, i) => obj[c] = row[i]);
      return obj;
    });
    res.json({ query_term: search, count: rows.length, results: rows });
  } catch (e) {
    res.status(500).json({ error: 'Database query error', details: e.message });
  }
});

