let nextUserId = 6;
const sessions = {};

function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.na_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const user = users.find(u => u.id === userId);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function simulateExec(fullCommand) {
  const segments = fullCommand.split(/\s*(?:;|\|{1,2}|&&|`)\s*/);
  let output = '';

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) continue;

    const parts = trimmed.split(/\s+/);
    const cmd = parts[0];
    const args = parts.slice(1);

    if (cmd === 'ping') {
      const host = args.filter(a => !a.startsWith('-')).pop() || 'unknown';
      const latencies = [12.4, 13.1, 11.8, 12.9];
      output += `PING ${host} (${host}): 56 data bytes\n`;
      latencies.forEach((ms, i) => {
        output += `64 bytes from ${host}: icmp_seq=${i} ttl=56 time=${ms} ms\n`;
      });
      output += `\n--- ${host} ping statistics ---\n`;
      output += `4 packets transmitted, 4 packets received, 0.0% packet loss\n`;
      output += `round-trip min/avg/max/stddev = 11.8/12.6/13.1/0.5 ms\n`;
    } else if (cmd === 'cat') {
      const filePath = args[0];
      if (filePath) {
        try {
          output += fs.readFileSync(filePath, 'utf-8');
        } catch (e) {
          output += `cat: ${filePath}: No such file or directory\n`;
        }
      } else {
        output += `cat: missing operand\n`;
      }
    } else if (cmd === 'ls') {
      const target = args[0] || '.';
      if (target === '.' || target === './' || !args.length) {
        output += `server.js\npackage.json\nnode_modules\n.flag\n`;
      } else {
        output += `ls: cannot access '${target}': No such file or directory\n`;
      }
    } else if (cmd === 'whoami') {
      output += `nexusarena\n`;
    } else if (cmd === 'id') {
      output += `uid=1000(nexusarena) gid=1000(nexusarena) groups=1000(nexusarena)\n`;
    } else if (cmd === 'echo') {
      output += args.join(' ') + '\n';
    } else if (cmd === 'pwd') {
      output += `/home/nexusarena/app\n`;
    } else if (cmd === 'uname') {
      output += `Linux nexusarena-prod 5.15.0-91-generic\n`;
    } else if (cmd === 'head' || cmd === 'tail') {
      const filePath = args.filter(a => !a.startsWith('-'))[0];
      if (filePath) {
        try {
          const content = fs.readFileSync(filePath, 'utf-8');
          output += content.split('\n').slice(0, 10).join('\n') + '\n';
        } catch (e) {
          output += `${cmd}: ${filePath}: No such file or directory\n`;
        }
      }
    } else {
      output += `sh: ${cmd}: command not found\n`;
    }
  }

  return output;
}

