    --accent-mid: rgba(0,212,255,0.15);
    --accent-purple: #7c3aed;
    --accent-purple-dim: rgba(124,58,237,0.12);
    --accent-pink: #ec4899;
    --accent-gold: #fbbf24;
    --accent-green: #22c55e;
    --accent-red: #ef4444;
    --text-primary: #e2e8f0;
    --text-secondary: #94a3b8;
    --text-muted: #64748b;
    --font-display: 'Orbitron', sans-serif;
    --font-sans: 'Inter', -apple-system, sans-serif;
    --font-mono: 'JetBrains Mono', monospace;
    --radius: 8px;
    --radius-lg: 12px;
  }

  html { font-size: 15px; }
  body {
    font-family: var(--font-sans);
    background: var(--bg-main);
    color: var(--text-primary);
    line-height: 1.6;
    min-height: 100vh;
    background-image:
      radial-gradient(circle at 15% 50%, rgba(0,212,255,0.04) 0%, transparent 50%),
      radial-gradient(circle at 85% 20%, rgba(124,58,237,0.04) 0%, transparent 50%),
      radial-gradient(circle at 50% 80%, rgba(236,72,153,0.03) 0%, transparent 50%);
  }

  a { color: var(--accent); text-decoration: none; }
  a:hover { text-decoration: underline; }

  .app-layout { display: flex; min-height: 100vh; }

  .sidebar {
    width: 240px;
    background: var(--bg-sidebar);
    border-right: 1px solid var(--border);
    display: flex;
    flex-direction: column;
    position: fixed;
    top: 0;
    bottom: 0;
    z-index: 10;
  }
  .sidebar-brand {
    padding: 20px 16px;
    border-bottom: 1px solid var(--border);
    display: flex;
    align-items: center;
    gap: 10px;
  }
  .sidebar-brand .logo {
    width: 38px;
    height: 38px;
    background: linear-gradient(135deg, var(--accent), var(--accent-purple));
    border-radius: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 20px;
    flex-shrink: 0;
  }
  .sidebar-brand h1 {
    font-family: var(--font-display);
    font-size: 15px;
    font-weight: 700;
    letter-spacing: 1px;
  }
  .sidebar-brand h1 span { color: var(--accent); }

  .sidebar-nav {
    flex: 1;
    padding: 12px 8px;
    display: flex;
    flex-direction: column;
    gap: 2px;
  }
  .sidebar-nav .section-label {
    font-size: 10px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 1.2px;
    color: var(--text-muted);
    padding: 16px 12px 6px;
    font-family: var(--font-display);
  }
  .sidebar-nav a {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 9px 12px;
    border-radius: var(--radius);
    color: var(--text-secondary);
    font-size: 13px;
    font-weight: 500;
    transition: all 0.2s;
    text-decoration: none;
  }
  .sidebar-nav a:hover {
    background: var(--accent-dim);
    color: var(--text-primary);
  }
  .sidebar-nav a.active {
    background: var(--accent-mid);
    color: var(--accent);
    box-shadow: inset 3px 0 0 var(--accent);
  }
  .sidebar-nav a .icon { font-size: 16px; width: 22px; text-align: center; }

  .sidebar-user {
    padding: 14px 12px;
    border-top: 1px solid var(--border);
    display: flex;
    align-items: center;
    gap: 10px;
  }
  .sidebar-user .avatar {
    width: 34px;
    height: 34px;
    background: linear-gradient(135deg, var(--accent-purple), var(--accent-pink));
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 14px;
    flex-shrink: 0;
  }
  .sidebar-user .user-info { flex: 1; min-width: 0; }
  .sidebar-user .user-name { font-size: 12px; font-weight: 600; font-family: var(--font-mono); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  .sidebar-user .user-rank { font-size: 10px; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.5px; }

  .main-content {
    margin-left: 240px;
    flex: 1;
    padding: 32px;
    min-height: 100vh;
  }

  .page-header { margin-bottom: 28px; }
  .page-header h1 {
    font-family: var(--font-display);
    font-size: 1.4rem;
    font-weight: 700;
    letter-spacing: 0.5px;
    margin-bottom: 4px;
  }
  .page-header .subtitle { font-size: 0.85rem; color: var(--text-muted); }

  .card {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 20px;
    transition: all 0.25s;
  }
  .card:hover {
    border-color: var(--border-glow);
    background: var(--bg-card-hover);
  }

  .stats-row {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 16px;
    margin-bottom: 28px;
  }
  .stat-card {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 18px;
    text-align: center;
    position: relative;
    overflow: hidden;
  }
  .stat-card::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 2px;
    background: linear-gradient(90deg, var(--accent), var(--accent-purple));
  }
  .stat-card .stat-value {
    font-family: var(--font-display);
    font-size: 1.8rem;
    font-weight: 700;
    color: var(--accent);
    margin-bottom: 4px;
  }
  .stat-card .stat-label {
    font-size: 0.72rem;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.8px;
  }

  .badge {
    display: inline-block;
    padding: 3px 10px;
    border-radius: 4px;
    font-size: 0.7rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    font-family: var(--font-mono);
  }
  .badge-diamond { background: rgba(0,212,255,0.15); color: #00d4ff; border: 1px solid rgba(0,212,255,0.3); }
  .badge-platinum { background: rgba(168,85,247,0.15); color: #a855f7; border: 1px solid rgba(168,85,247,0.3); }
  .badge-gold { background: rgba(251,191,36,0.15); color: #fbbf24; border: 1px solid rgba(251,191,36,0.3); }
  .badge-silver { background: rgba(148,163,184,0.15); color: #94a3b8; border: 1px solid rgba(148,163,184,0.3); }
  .badge-bronze { background: rgba(180,130,80,0.15); color: #cd7f32; border: 1px solid rgba(180,130,80,0.3); }
  .badge-online { background: rgba(34,197,94,0.15); color: #22c55e; border: 1px solid rgba(34,197,94,0.3); }
  .badge-offline { background: rgba(239,68,68,0.15); color: #ef4444; border: 1px solid rgba(239,68,68,0.3); }
  .badge-legendary { background: rgba(251,191,36,0.15); color: #fbbf24; border: 1px solid rgba(251,191,36,0.3); }
  .badge-epic { background: rgba(168,85,247,0.15); color: #a855f7; border: 1px solid rgba(168,85,247,0.3); }
  .badge-rare { background: rgba(59,130,246,0.15); color: #3b82f6; border: 1px solid rgba(59,130,246,0.3); }
  .badge-common { background: rgba(148,163,184,0.1); color: #94a3b8; border: 1px solid rgba(148,163,184,0.2); }
  .badge-mythic { background: linear-gradient(135deg, rgba(236,72,153,0.2), rgba(251,191,36,0.2)); color: #ec4899; border: 1px solid rgba(236,72,153,0.4); }
  .badge-admin { background: rgba(239,68,68,0.15); color: #ef4444; border: 1px solid rgba(239,68,68,0.3); }

  .data-table {
    width: 100%;
    border-collapse: separate;
    border-spacing: 0;
  }
  .data-table th {
    font-size: 0.7rem;
    text-transform: uppercase;
    letter-spacing: 0.8px;
    color: var(--text-muted);
    padding: 10px 14px;
    text-align: left;
    border-bottom: 1px solid var(--border);
    font-weight: 600;
    font-family: var(--font-display);
  }
  .data-table td {
    padding: 12px 14px;
    font-size: 0.85rem;
    border-bottom: 1px solid rgba(26,26,62,0.5);
  }
  .data-table tr:hover td { background: var(--accent-dim); }

  .btn {
    display: inline-block;
    padding: 10px 20px;
    border-radius: var(--radius);
    font-size: 0.82rem;
    font-weight: 600;
    cursor: pointer;
    border: none;
    transition: all 0.2s;
    text-decoration: none;
    font-family: var(--font-sans);
  }
  .btn-primary {
    background: linear-gradient(135deg, var(--accent), #0099cc);
    color: #000;
    font-weight: 700;
  }
  .btn-primary:hover { filter: brightness(1.15); box-shadow: 0 0 24px rgba(0,212,255,0.3); text-decoration: none; }
  .btn-purple {
    background: linear-gradient(135deg, var(--accent-purple), #9333ea);
    color: #fff;
  }
  .btn-purple:hover { filter: brightness(1.15); box-shadow: 0 0 24px rgba(124,58,237,0.3); text-decoration: none; }
  .btn-ghost {
    background: transparent;
    border: 1px solid var(--border);
    color: var(--text-secondary);
  }
  .btn-ghost:hover { border-color: var(--accent); color: var(--accent); text-decoration: none; }

  .login-page {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    padding: 32px;
  }
  .login-wrapper { width: 100%; max-width: 440px; }
  .login-brand {
    text-align: center;
    margin-bottom: 32px;
  }
  .login-brand .logo-lg {
    width: 60px; height: 60px;
    background: linear-gradient(135deg, var(--accent), var(--accent-purple));
    border-radius: 14px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    font-size: 30px;
    margin-bottom: 14px;
    box-shadow: 0 0 40px rgba(0,212,255,0.2);
  }
  .login-brand h1 {
    font-family: var(--font-display);
    font-size: 1.8rem;
    font-weight: 900;
    letter-spacing: 2px;
  }
  .login-brand h1 span { color: var(--accent); }
  .login-brand p { color: var(--text-muted); font-size: 0.85rem; margin-top: 4px; }

  .auth-card {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 28px;
    margin-bottom: 16px;
  }
  .auth-card h2 {
    font-family: var(--font-display);
    font-size: 0.85rem;
    margin-bottom: 20px;
    color: var(--accent);
    letter-spacing: 1px;
  }
  .auth-card .form-group { margin-bottom: 14px; }
  .auth-card label {
    display: block;
    font-size: 0.72rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: var(--text-muted);
    margin-bottom: 6px;
  }
  .auth-card input[type="text"],
  .auth-card input[type="password"] {
    width: 100%;
    padding: 10px 14px;
    background: var(--bg-input);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    color: var(--text-primary);
    font-size: 0.88rem;
    font-family: var(--font-mono);
    transition: border-color 0.2s;
  }
  .auth-card input:focus {
    outline: none;
    border-color: var(--accent);
    box-shadow: 0 0 0 3px rgba(0,212,255,0.1);
  }
  .auth-card .submit-btn {
    width: 100%;
    padding: 11px;
    border: none;
    border-radius: var(--radius);
    font-weight: 700;
    font-size: 0.88rem;
    cursor: pointer;
    transition: all 0.2s;
    margin-top: 6px;
    font-family: var(--font-display);
    letter-spacing: 1px;
  }

  .demo-creds {
    margin-top: 16px;
    padding: 12px;
    background: var(--bg-deep);
    border-radius: var(--radius);
    border: 1px solid var(--border);
  }
  .demo-creds p {
    font-size: 0.72rem;
    color: var(--text-muted);
    margin-bottom: 6px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    font-family: var(--font-display);
  }
  .demo-creds code {
    display: block;
    font-family: var(--font-mono);
    font-size: 0.78rem;
    color: var(--text-secondary);
    padding: 2px 0;
  }

  .error-msg {
    padding: 10px;
    background: rgba(239,68,68,0.1);
    border: 1px solid rgba(239,68,68,0.3);
    border-radius: var(--radius);
    color: #ef4444;
    font-size: 0.82rem;
    margin-bottom: 14px;
  }

  .terminal-output {
    background: #050510;
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 16px;
    font-family: var(--font-mono);
    font-size: 0.82rem;
    color: var(--accent-green);
    white-space: pre-wrap;
    word-break: break-all;
    max-height: 400px;
    overflow-y: auto;
    line-height: 1.5;
  }
  .terminal-output .cmd-line {
    color: var(--accent);
    margin-bottom: 8px;
    display: block;
  }

  .tool-input-group {
    display: flex;
    gap: 12px;
    margin-bottom: 20px;
  }
  .tool-input-group input {
    flex: 1;
    padding: 10px 14px;
    background: var(--bg-input);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    color: var(--text-primary);
    font-family: var(--font-mono);
    font-size: 0.88rem;
  }
  .tool-input-group input:focus {
    outline: none;
    border-color: var(--accent);
    box-shadow: 0 0 0 3px rgba(0,212,255,0.1);
  }

  .server-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 12px;
    margin-bottom: 24px;
  }
  .server-chip {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 14px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    cursor: pointer;
    transition: all 0.2s;
  }
  .server-chip:hover { border-color: var(--border-glow); background: var(--bg-card-hover); }
  .server-chip .srv-info .srv-name { font-family: var(--font-mono); font-size: 0.82rem; font-weight: 600; }
  .server-chip .srv-info .srv-region { font-size: 0.72rem; color: var(--text-muted); }
  .server-chip .srv-meta { text-align: right; }
  .server-chip .srv-meta .srv-ip { font-family: var(--font-mono); font-size: 0.78rem; color: var(--text-secondary); }
  .server-chip .srv-meta .srv-players { font-size: 0.7rem; color: var(--text-muted); }

  .inventory-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 14px;
  }
  .item-card {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 18px;
    text-align: center;
    transition: all 0.3s;
    position: relative;
    overflow: hidden;
  }
  .item-card:hover { border-color: var(--border-glow); transform: translateY(-2px); }
  .item-card .item-icon { font-size: 36px; margin-bottom: 10px; display: block; }
  .item-card .item-name { font-weight: 600; font-size: 0.9rem; margin-bottom: 4px; }
  .item-card .item-type { font-size: 0.75rem; color: var(--text-muted); margin-bottom: 8px; }

  .xp-bar {
    width: 100%;
    height: 8px;
    background: var(--bg-deep);
    border-radius: 4px;
    overflow: hidden;
    margin-top: 8px;
  }
  .xp-bar .xp-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--accent), var(--accent-purple));
    border-radius: 4px;
    transition: width 0.5s ease;
  }

  .rank-medal { font-size: 1.2rem; margin-right: 6px; }

  .profile-header-card {
    display: flex;
    gap: 24px;
    align-items: center;
    margin-bottom: 24px;
  }
  .profile-avatar-lg {
    width: 90px; height: 90px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 40px;
    flex-shrink: 0;
    border: 3px solid var(--border);
    background: var(--bg-deep);
  }
  .profile-stats-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 14px;
    margin-bottom: 20px;
  }
  .profile-stat {
    text-align: center;
    padding: 14px;
    background: var(--bg-deep);
    border-radius: var(--radius);
    border: 1px solid var(--border);
  }
  .profile-stat .ps-val {
    font-family: var(--font-display);
    font-size: 1.3rem;
    font-weight: 700;
    color: var(--accent);
  }
  .profile-stat .ps-label {
    font-size: 0.7rem;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    margin-top: 2px;
  }

  .fade-in { animation: fadeIn 0.3s ease-out; }
  @keyframes fadeIn { from { opacity: 0; transform: translateY(6px); } to { opacity: 1; transform: translateY(0); } }

  .tab-row { display: flex; gap: 4px; margin-bottom: 20px; }
  .tab-btn {
    padding: 8px 16px;
    border: 1px solid var(--border);
    background: transparent;
    color: var(--text-muted);
    border-radius: var(--radius);
    font-size: 0.78rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s;
    font-family: var(--font-sans);
  }
  .tab-btn:hover { border-color: var(--accent); color: var(--text-primary); }
  .tab-btn.active { background: var(--accent-mid); color: var(--accent); border-color: var(--accent); }
`;

function rankBadge(rank) {
  const cls = { Diamond: 'badge-diamond', Platinum: 'badge-platinum', Gold: 'badge-gold', Silver: 'badge-silver', Bronze: 'badge-bronze' };
  return `<span class="badge ${cls[rank] || 'badge-silver'}">${esc(rank)}</span>`;
}

function rarityBadge(rarity) {
  const cls = { Mythic: 'badge-mythic', Legendary: 'badge-legendary', Epic: 'badge-epic', Rare: 'badge-rare', Common: 'badge-common' };
  return `<span class="badge ${cls[rarity] || 'badge-common'}">${esc(rarity)}</span>`;
}

function rankMedal(pos) {
  if (pos === 1) return '<span class="rank-medal">🥇</span>';
  if (pos === 2) return '<span class="rank-medal">🥈</span>';
  if (pos === 3) return '<span class="rank-medal">🥉</span>';
  return `<span style="display:inline-block;width:28px;text-align:center;font-family:var(--font-mono);color:var(--text-muted);font-size:0.85rem;">#${pos}</span>`;
}

