        <h1>NEXUS<span>ARENA</span></h1>
      </div>
      <nav class="sidebar-nav">
        <div class="section-label">Play</div>
        <a href="/dashboard" class="${activePage === 'dashboard' ? 'active' : ''}">
          <span class="icon">🏠</span> Dashboard
        </a>
        <a href="/leaderboard" class="${activePage === 'leaderboard' ? 'active' : ''}">
          <span class="icon">🏆</span> Leaderboard
        </a>
        <a href="/profile" class="${activePage === 'profile' ? 'active' : ''}">
