          <label>Password</label>
          <input type="password" name="password" placeholder="••••••••" required>
        </div>
        <button type="submit" class="submit-btn btn-primary" style="font-family:var(--font-display);letter-spacing:1px;">ENTER ARENA</button>
      </form>
