  res.send(renderLoginPage('', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.send(renderLoginPage('Invalid credentials. Check your username and password.', ''));
  const token = createSession(user.id);
  res.cookie('na_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.send(renderLoginPage('', 'All fields are required.'));
  if (users.find(u => u.username === username)) return res.send(renderLoginPage('', 'Username already taken.'));
  const newUser = {
    id: nextUserId++,
    username,
    password,
    name,
    role: 'Player',
    level: 1,
    rank: 'Bronze',
    xp: 0,
    wins: 0,
    losses: 0,
    kd: 0,
