        } catch(e) {
          document.getElementById('output-area').innerHTML =
            '<div class="terminal-output" style="color:var(--accent-red);">Error: Request failed</div>';
        }
        btn.textContent = '⚡ Run Ping';
        btn.disabled = false;
      }
      document.getElementById('host-input').addEventListener('keydown', function(e) {
        if (e.key === 'Enter') runPing();
      });
    </script>
  `));
});

app.post('/tools/ping', requireAuth, (req, res) => {
  const { host } = req.body;

  if (!host || typeof host !== 'string') {
    return res.json({ output: 'Error: Please provide a valid hostname or IP address.\n' });
  }

  if (host.length > 300) {
    return res.json({ output: 'Error: Input too long.\n' });
  }

  const command = `ping -c 4 ${host}`;
  const output = simulateExec(command);

  res.json({ output });
});

