function rarityBadge(r) {
  const cls = { Mythic: 'badge-mythic', Legendary: 'badge-legendary', Epic: 'badge-epic', Rare: 'badge-rare', Uncommon: 'badge-uncommon', Common: 'badge-common' };
  return `<span class="badge ${cls[r] || 'badge-common'}">${esc(r)}</span>`;
}

function rankBadge(r) {
  const cls = { Grandmaster: 'badge-grandmaster', Gold: 'badge-gold', Silver: 'badge-silver' };
  return `<span class="badge ${cls[r] || 'badge-common'}">${esc(r)}</span>`;
}

function renderSidebar(activePage, user) {
  return `
    <aside class="sidebar">
      <div class="sidebar-brand">
        <div class="logo">🎮</div>
        <h1>Nexus<span>Arena</span></h1>
      </div>
      <nav class="sidebar-nav">
        <div class="section-label">Game Hub</div>
