app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(renderLogin('<div class="error-msg">Invalid credentials. Check your username and password.</div>'));
  }
  const token = createSession(user.id);
  res.cookie('na_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.na_session;
  if (token) delete sessions[token];
  res.clearCookie('na_session');
  res.redirect('/');
});

