app.get('/leaderboard', requireAuth, (req, res) => {
  const user = req.user;
  const sorted = [...users].sort((a, b) => b.xp - a.xp);

  const rows = sorted.map((u, i) => {
    const medal = i === 0 ? '👑' : i === 1 ? '🥈' : i === 2 ? '🥉' : `#${i + 1}`;
    const winRate = ((u.wins / (u.wins + u.losses)) * 100).toFixed(1);
    const isMe = u.id === user.id;
    return `
      <tr style="${isMe ? 'background:var(--accent-dim);' : ''}">
        <td><span class="leaderboard-rank">${medal}</span></td>
        <td class="player-id-col">#${u.id}</td>
        <td>
          <span style="font-size:1.1rem;margin-right:6px;">${u.avatar}</span>
          <strong>${esc(u.displayName)}</strong>
          ${isMe ? '<span style="font-size:0.7rem;color:var(--accent);margin-left:6px;">(you)</span>' : ''}
        </td>
        <td>${rankBadge(u.rank)}</td>
        <td style="font-family:var(--font-mono);">${u.level}</td>
        <td style="font-family:var(--font-mono);">${u.xp.toLocaleString()}</td>
        <td style="font-family:var(--font-mono);">${u.wins}</td>
        <td style="font-family:var(--font-mono);">${winRate}%</td>
        <td style="font-family:var(--font-mono);">${u.kd}</td>
      </tr>`;
  }).join('');

  res.send(pageShell('Leaderboard', 'leaderboard', user, `
    <div class="page-header">
      <h1>🏆 Leaderboard</h1>
      <p class="subtitle">Top players ranked by experience points</p>
    </div>

    <div class="card">
      <table class="data-table">
        <thead>
          <tr><th>Rank</th><th>ID</th><th>Player</th><th>Tier</th><th>Level</th><th>XP</th><th>Wins</th><th>Win Rate</th><th>K/D</th></tr>
        </thead>
        <tbody>${rows}</tbody>
      </table>
    </div>
  `));
});

app.get('/inventory', requireAuth, (req, res) => {
  const user = req.user;
  const requestedId = req.query.player_id !== undefined ? parseInt(req.query.player_id) : null;
  const lookupId = requestedId !== null ? requestedId : user.id;
  const items = inventories[lookupId];
  const lookupUser = users.find(u => u.id === lookupId);

  let resultHtml = '';

  if (requestedId !== null) {
    if (!items || !lookupUser) {
      resultHtml = `
        <div class="error-msg" style="margin-top:20px;">
          No inventory found for Player ID #${esc(String(requestedId))}. This player may not exist.
        </div>`;
    } else {
      const ownerLabel = lookupId === user.id
        ? `<div class="owner-banner">🎒 Showing <strong>your</strong> inventory (${esc(user.displayName)}) — ${items.length} items</div>`
        : `<div class="owner-banner">👤 Showing inventory for <strong>${esc(lookupUser.displayName)}</strong> (Player #${lookupId}) — ${items.length} items</div>`;

      const itemCards = items.map(item => `
        <div class="inv-item rarity-${item.rarity.toLowerCase()}">
          <div class="inv-item-header">
            <div>
              <div class="inv-item-name">${esc(item.name)}</div>
              <div class="inv-item-id">${esc(item.id)}</div>
            </div>
            ${item.power > 0 ? `<span style="font-family:var(--font-mono);font-size:0.85rem;color:var(--accent-amber);">⚡ ${item.power.toLocaleString()}</span>` : ''}
          </div>
          <div class="inv-item-meta">
            ${rarityBadge(item.rarity)}
            <span class="badge badge-common">${esc(item.type)}</span>
          </div>
          <div class="inv-item-desc">${esc(item.description)}</div>
          <div style="margin-top:8px;font-size:0.72rem;color:var(--text-muted);">Acquired: ${esc(item.acquired)}</div>
        </div>
      `).join('');

