app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) {
    return res.redirect('/?error=Please+enter+both+username+and+password');
  }

  try {
    const query = `SELECT * FROM users WHERE username = '${username}' AND password = '${password}'`;
    const results = db.exec(query);

    if (!results.length || !results[0].values.length) {
      return res.redirect('/?error=Invalid+credentials.+Check+your+username+and+password.');
    }

    const cols = results[0].columns;
    const vals = results[0].values[0];
    const user = {};
    cols.forEach((c, i) => user[c] = vals[i]);

    const token = createSession(user.id);
    res.cookie('nexus_session', token, { httpOnly: false, sameSite: 'lax' });
    res.redirect('/dashboard');
  } catch (e) {
    return res.redirect('/?error=Authentication+error.+Please+try+again.');
  }
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nexus_session;
  if (token) delete sessions[token];
  res.clearCookie('nexus_session');
  res.redirect('/');
});

