// ── Helpers ───────────────────────────────────────────────────────────

function esc(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function avatarClass(role) {
  return role === 'director' ? 'avatar-director'
       : role === 'reviewer' ? 'avatar-reviewer'
       : 'avatar-citizen';
}

function initials(name) {
  return name.split(' ').map(n => n[0]).join('').toUpperCase();
}

function roleLabel(role) {
  return role === 'director' ? 'Director'
       : role === 'reviewer' ? 'Staff Reviewer'
       : 'Citizen';
}

function statusBadge(s) {
  const cls = {
    SUBMITTED: 'badge-submitted',
    REVIEWED:  'badge-reviewed',
    APPROVED:  'badge-approved',
    ISSUED:    'badge-issued',
  };
  return `<span class="badge ${cls[s] || 'badge-submitted'}">${s}</span>`;
}

function stepState(permitStatus, step) {
  const order = ['SUBMITTED', 'REVIEWED', 'APPROVED', 'ISSUED'];
  const cur = order.indexOf(permitStatus);
  const tgt = order.indexOf(step);
  if (tgt < cur) return 'step-done';
  if (tgt === cur) return 'step-active';
  return 'step-pending';
}

function renderSidebar(active, user) {
  const init = initials(user.name);
  return `
  <aside class="sidebar">
    <div class="sidebar-brand">
      <div class="brand-seal">🏛</div>
      <div class="brand-text">
        <div class="line1">City of Eldenvale</div>
        <div class="line2">Citizen Portal</div>
      </div>
    </div>
    <nav class="sidebar-nav">
      <div class="nav-section">Services</div>
      <a href="/dashboard" class="${active === 'dashboard' ? 'active' : ''}">
        <span class="icon">📊</span> Dashboard
      </a>
      <a href="/permits" class="${active === 'permits' ? 'active' : ''}">
        <span class="icon">📋</span> Permit Applications
      </a>
      <a href="/permits/new" class="${active === 'new' ? 'active' : ''}">
        <span class="icon">➕</span> New Application
      </a>
      <div class="nav-section">Account</div>
      <a href="/logout">
        <span class="icon">🚪</span> Sign Out
      </a>
    </nav>
    <div class="sidebar-user">
      <div class="user-avatar ${avatarClass(user.role)}">${init}</div>
      <div class="user-meta">
        <div class="user-name">${esc(user.name)}</div>
        <div class="user-role">${roleLabel(user.role)}</div>
      </div>
    </div>
  </aside>`;
}

function shell(title, active, user, body) {
  return `<!DOCTYPE html>
<html lang="en"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>${esc(title)} — Eldenvale Citizen Portal</title>
<style>${css}</style>
</head><body class="fade-in">
<div class="app">
  ${renderSidebar(active, user)}
  <main class="main">
    ${body}
  </main>
</div>
</body></html>`;
}

