app.post('/api/permits/:id/review', requireAuth, (req, res) => {
  const user = req.user;
  const permit = permits.find(p => p.id === req.params.id);

  if (!permit) return res.status(404).json({ error: 'Not found' });
  if (user.role !== 'reviewer' && user.role !== 'director') {
    return res.status(403).json({ error: 'Only staff reviewers can perform this action' });
  }
  if (permit.status !== 'SUBMITTED') {
    return res.status(400).json({ error: 'Application is not in SUBMITTED status' });
  }

  permit.status = 'REVIEWED';
  permit.reviewedAt = new Date().toISOString();
  permit.reviewNote = `Documentation reviewed by ${user.name}. Application meets initial requirements.`;

  res.redirect(`/permits/${permit.id}`);
});

app.post('/api/permits/:id/approve', requireAuth, (req, res) => {
  const user = req.user;
  const permit = permits.find(p => p.id === req.params.id);

  if (!permit) return res.status(404).json({ error: 'Not found' });
  if (user.role !== 'director') {
    return res.status(403).json({ error: 'Only a director can approve applications' });
  }
  if (permit.status !== 'REVIEWED') {
    return res.status(400).json({ error: 'Application must be in REVIEWED status before approval' });
  }

  permit.status = 'APPROVED';
  permit.approvedAt = new Date().toISOString();
  permit.approvalNote = `Formally approved by Director ${user.name}. Permit may now be issued.`;

  res.redirect(`/permits/${permit.id}`);
});

app.post('/api/permits/:id/execute', requireAuth, (req, res) => {
  const permit = permits.find(p => p.id === req.params.id);

  if (!permit) return res.status(404).json({ error: 'Permit application not found' });
  if (permit.status === 'ISSUED') return res.status(400).json({ error: 'Permit already issued' });

  permit.status = 'ISSUED';
  permit.issuedAt = new Date().toISOString();
  permit.documentId = 'DOC-' + crypto.randomBytes(4).toString('hex').toUpperCase();

  res.json({
    success: true,
    message: 'Permit successfully issued.',
    document: {
      documentId: permit.documentId,
      permitId: permit.id,
      type: permit.type,
      issuedTo: permit.applicantName,
      address: permit.address,
      issuedAt: permit.issuedAt,
      status: 'ISSUED',
      authorizationCode: flag,
    },
  });
});

