  const m = { Approved: 'badge-approved', Pending: 'badge-pending', Denied: 'badge-denied', 'Under Review': 'badge-review' };
  return '<span class="badge ' + (m[s] || 'badge-pending') + '">' + esc(s) + '</span>';
}

