app.post('/services/verify-document', requireAuth, async (req, res) => {
  const { url } = req.body;
  if (!url || typeof url !== 'string') {
    return res.json({ error: 'Please provide a valid URL.' });
  }
  try {
    const parsed = new URL(url);
    if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
      return res.json({ error: 'Only http and https protocols are allowed.' });
    }
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);
    const response = await fetch(url, {
      signal: controller.signal,
      headers: { 'User-Agent': 'CivicAccess-DocumentVerifier/1.0' },
      redirect: 'follow',
    });
    clearTimeout(timeout);
    const body = await response.text();
    res.json({ status: response.status, body: body, contentLength: body.length });
  } catch (e) {
    res.json({ error: 'Failed to fetch URL: ' + e.message });
  }
});

