function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function statusBadge(status) {
  if (status === 'Approved') return '<span class="badge badge-approved">' + esc(status) + '</span>';
  if (status === 'Pending Review' || status === 'Pending') return '<span class="badge badge-pending">' + esc(status) + '</span>';
  if (status === 'Denied') return '<span class="badge badge-denied">' + esc(status) + '</span>';
  return '<span class="badge badge-citizen">' + esc(status) + '</span>';
}

function roleBadge(role) {
  if (role === 'Director') return '<span class="badge badge-director">' + esc(role) + '</span>';
  if (role === 'Clerk') return '<span class="badge badge-clerk">' + esc(role) + '</span>';
  return '<span class="badge badge-citizen">' + esc(role) + '</span>';
}

