  res.send(loginPageTpl.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(loginPageTpl
      .replace('%%LOGIN_MSG%%', '<div class="error-msg">Invalid credentials.</div>')
      .replace('%%REG_MSG%%', ''));
  }
  const token = createSession(user.id);
  res.cookie('gsp_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(loginPageTpl
      .replace('%%LOGIN_MSG%%', '')
      .replace('%%REG_MSG%%', '<div class="error-msg">All fields are required.</div>'));
  }
  if (users.find(u => u.username === username)) {
    return res.send(loginPageTpl
      .replace('%%LOGIN_MSG%%', '')
      .replace('%%REG_MSG%%', '<div class="error-msg">Username already taken.</div>'));
  }
  const newUser = {
    id: nextUserId++, username, password, name,
    role: 'Citizen', department: 'N/A',
    email: username + '@govservices.gov',
    clearance: 'Public'
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('gsp_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.gsp_session;
  if (token) delete sessions[token];
  res.clearCookie('gsp_session');
  res.redirect('/');
});

