        function submitFeedback() {
          const subject = document.getElementById('fb-subject').value;
          const content = document.getElementById('fb-content').value;
          if (!subject || !content) { document.getElementById('form-msg').innerHTML = '<div class=\\'error-msg\\'>Both fields required.</div>'; return; }
