app.post('/feedback', requireAuth, (req, res) => {
  const user = req.user;
  const { subject, content } = req.body;
  if (!subject || !content) return res.json({ success: false, error: 'Both fields are required.' });
  if (content.length > 2000) return res.json({ success: false, error: 'Message too long (max 2000 chars).' });

  feedbackEntries.push({
    author: user.name,
    department: user.role,
    subject: subject,
    content: content,
    timestamp: new Date().toLocaleString('en-US')
  });
  res.json({ success: true });
});

app.get('/bot/visit', (req, res) => {
  const director = users.find(u => u.role === 'Director');
  const botToken = createSession(director.id);

  let xssTriggered = false;
  for (const entry of feedbackEntries) {
    const raw = entry.subject + ' ' + entry.content;
    if (raw.includes('document.cookie') && (raw.includes('/webhook') || raw.includes('/webhook/collect'))) {
      webhookStore.push({
        data: `gsp_session=${botToken}`,
        timestamp: new Date().toISOString(),
        source: 'bot-session'
      });
      xssTriggered = true;
      break;
    }
  }

  const responseHtml = `<!DOCTYPE html>
<html lang="en"><head><meta charset="UTF-8"><title>Bot Status</title><style>${baseStyles}</style></head>
<body><div style="display:flex;align-items:center;justify-content:center;min-height:100vh;">
