app.get('/webhook/collect', (req, res) => {
  const data = req.query.data;
  if (data) {
    webhookStore.push({
      data: data,
      timestamp: new Date().toISOString(),
      source: 'collect'
    });
  }
  res.json({ status: 'collected' });
});

app.get('/webhook', requireAuth, (req, res) => {
  const user = req.user;
  const items = webhookStore.length === 0
    ? '<p style="color:var(--text-muted);font-size:0.85rem;">No data collected yet. Webhook collector is listening at <code style="font-family:var(--font-mono);color:var(--accent);font-size:0.82rem;">/webhook/collect?data=...</code></p>'
    : webhookStore.map((w, i) => `
      <div class="webhook-item">
        <span style="color:var(--text-muted);font-size:0.7rem;">[${esc(w.timestamp)}]</span>
        <span style="color:var(--accent-green);"> ${esc(w.data)}</span>
      </div>`).join('');

  res.send(pageShell('Webhook Log', 'webhook', user, `
    <div class="page-header"><h1>Webhook Collector</h1>
    <p class="subtitle">Captured data from /webhook/collect endpoint</p></div>
