});

app.get('/admin/records', requireAuth, requireDirector, (req, res) => {
  const user = req.user;
  const q = req.query.q || '';
  let resultsHtml = '';
  let errorHtml = '';

  if (q) {
    try {
      const sql = `SELECT id, name, ssn, address, permit_status FROM citizens WHERE name LIKE '%${q}%'`;
      const results = db.exec(sql);
      if (results.length > 0 && results[0].values.length > 0) {
        const rows = results[0].values.map(row => `<tr>
          <td style="font-family:var(--font-mono);color:var(--accent);">${row[0]}</td>
          <td>${row[1]}</td>
          <td style="font-family:var(--font-mono);">${row[2]}</td>
          <td>${row[3]}</td>
          <td>${row[4]}</td>
        </tr>`).join('');

        resultsHtml = `
          <div style="margin-top:20px;">
            <h3 style="font-family:var(--font-mono);font-size:0.9rem;margin-bottom:12px;color:var(--accent);">
              Query Results (${results[0].values.length} records)
            </h3>
            <table class="data-table"><thead><tr>
              <th>ID</th><th>Name</th><th>SSN</th><th>Address</th><th>Status</th>
            </tr></thead><tbody>${rows}</tbody></table>
          </div>`;
      } else {
        resultsHtml = '<p style="color:var(--text-muted);margin-top:16px;font-size:0.85rem;">No records found matching your query.</p>';
      }
    } catch (err) {
      errorHtml = `<div class="sql-error">Database Error: ${esc(err.message)}</div>`;
    }
  }

  res.send(pageShell('Records Search', 'records', user, `
    <div class="page-header"><h1>Citizen Records Search</h1>
    <p class="subtitle">🔒 Director-level access — Query the citizen database</p></div>

    <div class="card">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:16px;">Search Citizens</h3>
      <form method="GET" action="/admin/records" style="display:flex;gap:12px;align-items:flex-end;">
        <div class="form-group" style="flex:1;margin-bottom:0;">
          <label>Search by Name</label>
          <input type="text" name="q" value="${esc(q)}" placeholder="Enter citizen name...">
        </div>
        <button type="submit" class="btn btn-primary" style="height:42px;">Search</button>
      </form>
      ${errorHtml}
      ${resultsHtml}
    </div>

    <div class="card" style="margin-top:20px;">
      <h3 style="font-family:var(--font-mono);font-size:0.9rem;margin-bottom:10px;color:var(--text-muted);">Database Info</h3>
      <p style="font-size:0.82rem;color:var(--text-muted);line-height:1.7;">
        This tool queries the <code style="font-family:var(--font-mono);color:var(--accent);font-size:0.8rem;">citizens</code> table in the SQLite database.
        Additional tables include <code style="font-family:var(--font-mono);color:var(--accent);font-size:0.8rem;">tax_records</code> and other internal tables.
        Use the <code style="font-family:var(--font-mono);color:var(--accent-blue);font-size:0.8rem;">sqlite_master</code> catalog for schema reference.
      </p>
    </div>
  `));
});

