function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function initials(name) {
  return name.split(' ').filter(n => n.length > 0).map(n => n[0]).join('').slice(0, 2);
}

function statusBadge(s) {
  const map = {
    'Approved': 'badge-approved', 'Pending Review': 'badge-pending',
    'Under Inspection': 'badge-review', 'Denied': 'badge-denied',
    'Processed': 'badge-processed', 'Finalized': 'badge-finalized',
    'Under Review': 'badge-review',
  };
  return `<span class="badge ${map[s] || 'badge-pending'}">${esc(s)}</span>`;
}

