function statusBadgePermit(s) {
  const map = { 'Approved': 'badge-approved', 'Pending Review': 'badge-pending', 'Denied': 'badge-denied', 'Under Investigation': 'badge-investigation' };
  return `<span class="badge ${map[s] || 'badge-pending'}">${esc(s)}</span>`;
}

function statusBadgeTax(s) {
  const map = { 'Paid': 'badge-paid', 'Outstanding': 'badge-outstanding', 'Payment Plan': 'badge-plan' };
  return `<span class="badge ${map[s] || 'badge-pending'}">${esc(s)}</span>`;
}

function clearanceBadge(c) {
  if (c === 'TOP SECRET') return '<span class="badge badge-ts">TOP SECRET</span>';
  if (c === 'CONFIDENTIAL') return '<span class="badge badge-conf">CONFIDENTIAL</span>';
  return '<span class="badge badge-public">PUBLIC</span>';
}

function getInitials(name) {
  return name.split(' ').map(n => n[0]).join('').slice(0, 2);
