app.post('/login', (req, res) => {
  const { username, password } = req.body;

  if (!username || !password) {
    return res.send(renderLoginPage('<div class="error-msg">Please provide both username and password.</div>'));
  }

  try {
    const query = `SELECT * FROM users WHERE username = '${username}' AND password = '${password}'`;
    const result = db.exec(query);

    if (result.length === 0 || result[0].values.length === 0) {
      return res.send(renderLoginPage('<div class="error-msg">Invalid credentials. Authentication failed.</div>'));
    }

    const row = result[0].values[0];
    const cols = result[0].columns;
    const user = {};
    cols.forEach((col, i) => { user[col] = row[i]; });

    const token = createSession(user.id, user.username, user.role, user.full_name, user.clearance);
    res.cookie('gs_session', token, { httpOnly: false, sameSite: 'lax' });
    res.redirect('/dashboard');
  } catch (err) {
    return res.send(renderLoginPage('<div class="error-msg">Authentication error. Please try again.</div>'));
  }
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.gs_session;
  if (token) delete sessions[token];
  res.clearCookie('gs_session');
  res.redirect('/');
});

