function statusBadge(s) {
  const map = { Approved: 'badge-approved', Pending: 'badge-pending', 'Under Review': 'badge-review', Paid: 'badge-paid', Due: 'badge-due', Filed: 'badge-approved' };
  return `<span class="badge ${map[s] || 'badge-pending'}">${esc(s)}</span>`;
