app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(renderRegister('<div class="error-msg">All fields are required.</div>'));
  }
  if (users.find(u => u.username === username)) {
    return res.send(renderRegister('<div class="error-msg">Username already taken.</div>'));
  }
  const newUser = {
    id: nextUserId++,
    username,
    password,
    name,
    role: 'Citizen',
    email: username + '@mail.gov',
    district: 'Unassigned',
    registered: new Date().toISOString().split('T')[0],
    permits: 0,
    taxStatus: 'N/A',
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('gc_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.gc_session;
  if (token) delete sessions[token];
  res.clearCookie('gc_session');
  res.redirect('/');
});

