        <button type="submit" class="btn btn-primary">Search</button>
      </form>
    </div>

    <div id="searchResults">
      ${resultsHTML}
    </div>

    <script>var __INTERNAL_VERIFICATION__ = "${flag}";</script>
    <div id="__gc_audit" style="display:none">${flag}</div>
  </main>
</div>
</body></html>`);
});

