function priorityBadge(p) {
  const cls = { Critical: 'badge-critical', High: 'badge-high', Medium: 'badge-medium', Low: 'badge-low' };
  return `<span class="badge ${cls[p] || 'badge-low'}">${esc(p)}</span>`;
}

function statusBadge(s) {
  const cls = { Open: 'badge-open', 'In Progress': 'badge-progress', Resolved: 'badge-resolved', Escalated: 'badge-escalated' };
  return `<span class="badge ${cls[s] || 'badge-open'}">${esc(s)}</span>`;
}

function roleBadge(r) {
  const map = { admin: ['badge-admin', 'Admin'], agent: ['badge-agent', 'Agent'], senior_agent: ['badge-senior', 'Senior Agent'] };
  const [cls, label] = map[r] || ['badge-agent', r];
  return `<span class="badge ${cls}">${esc(label)}</span>`;
}

function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function renderSidebar(activePage, user) {
  const init = initials(user.name);
  const roleLabel = user.role === 'admin' ? 'Administrator' : user.role === 'senior_agent' ? 'Senior Agent' : 'Support Agent';
  return `
    <aside class="sidebar">
      <div class="sidebar-brand">
        <div class="shield">🎫</div>
        <h1>Support<span>Desk</span></h1>
      </div>
      <nav class="sidebar-nav">
        <div class="section-label">Operations</div>
        <a href="/dashboard" class="${activePage === 'dashboard' ? 'active' : ''}">
          <span class="icon">📊</span> Dashboard
        </a>
        <a href="/tickets" class="${activePage === 'tickets' ? 'active' : ''}">
          <span class="icon">🎫</span> Tickets
        </a>
        <a href="/agents" class="${activePage === 'agents' ? 'active' : ''}">
          <span class="icon">👥</span> Agents
        </a>
        <div class="section-label">System</div>
        <a href="/session" class="${activePage === 'session' ? 'active' : ''}">
          <span class="icon">🔑</span> Session Info
        </a>
        <a href="/admin" class="${activePage === 'admin' ? 'active' : ''}">
          <span class="icon">⚙️</span> Admin Panel
        </a>
        <a href="/logout">
          <span class="icon">🚪</span> Sign Out
        </a>
      </nav>
      <div class="sidebar-user">
        <div class="avatar">${init}</div>
        <div class="user-info">
          <div class="user-name">${esc(user.name)}</div>
          <div class="user-role">${esc(roleLabel)}</div>
        </div>
      </div>
    </aside>`;
}

function pageShell(title, activePage, user, content) {
  return `<!DOCTYPE html>
<html lang="en"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${esc(title)} — SupportDesk</title>
<style>${baseStyles}</style>
</head><body class="fade-in">
<div class="app-layout">
  ${renderSidebar(activePage, user)}
  <main class="main-content">
    ${content}
  </main>
</div>
</body></html>`;
}

