app.get('/session', requireAuth, (req, res) => {
  const user = req.user;
  const token = req.rawToken;
  const parts = token.split('.');
  let headerDecoded = '';
  let payloadDecoded = '';
  try {
    headerDecoded = JSON.stringify(JSON.parse(Buffer.from(parts[0], 'base64url').toString()), null, 2);
    payloadDecoded = JSON.stringify(JSON.parse(Buffer.from(parts[1], 'base64url').toString()), null, 2);
  } catch(e) {
    headerDecoded = 'Error decoding';
    payloadDecoded = 'Error decoding';
  }

  res.send(pageShell('Session Info', 'session', user, `
    <div class="page-header">
      <h1>Session Information</h1>
      <p class="subtitle">Your current authentication token details</p>
    </div>

    <div class="card" style="margin-bottom:20px;">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:6px;color:var(--accent);">🔑 Active JWT Token</h3>
      <p style="font-size:0.78rem;color:var(--text-muted);margin-bottom:12px;">This token is stored in your <code style="font-family:var(--font-mono);color:var(--accent);">hd_token</code> cookie and sent with every request.</p>
      <div class="token-display">${esc(token)}</div>
    </div>

    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:20px;">
      <div class="card">
        <h3 style="font-family:var(--font-mono);font-size:0.9rem;margin-bottom:10px;">Header</h3>
        <div class="decoded-section">${esc(headerDecoded)}</div>
      </div>
      <div class="card">
        <h3 style="font-family:var(--font-mono);font-size:0.9rem;margin-bottom:10px;">Payload</h3>
        <div class="decoded-section">${esc(payloadDecoded)}</div>
      </div>
    </div>

    <div class="card">
      <h3 style="font-family:var(--font-mono);font-size:0.9rem;margin-bottom:10px;">Signature</h3>
      <p style="font-size:0.82rem;color:var(--text-secondary);line-height:1.7;">
        The token is signed using <span style="color:var(--accent);font-family:var(--font-mono);">HS256</span> (HMAC-SHA256).
        The server verifies the signature on each request to ensure the token has not been tampered with.
      </p>
      <div style="margin-top:12px;padding:10px;background:var(--bg-deep);border:1px solid var(--border);border-radius:var(--radius);font-family:var(--font-mono);font-size:0.75rem;color:var(--text-muted);">
        HMACSHA256(base64UrlEncode(header) + "." + base64UrlEncode(payload), <span style="color:var(--accent-red);">signing_secret</span>)
      </div>
    </div>
  `));
});

