const sessions = {};

function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSessionUser(req) {
  const token = req.cookies?.sd_session;
  if (!token || !sessions[token]) return null;
  return users.find(u => u.id === sessions[token]) || null;
}

function requireAuth(req, res, next) {
  const user = getSessionUser(req);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function getTier(points) {
  if (points >= 2500) return { name: 'Platinum', color: '#a855f7', icon: '💎', next: null, nextAt: null };
  if (points >= 1000) return { name: 'Gold', color: '#f59e0b', icon: '🥇', next: 'Platinum', nextAt: 2500 };
  if (points >= 500) return { name: 'Silver', color: '#94a3b8', icon: '🥈', next: 'Gold', nextAt: 1000 };
  return { name: 'Bronze', color: '#cd7c32', icon: '🥉', next: 'Silver', nextAt: 500 };
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

