function priorityBadge(p) {
  const cls = { Critical: 'badge-critical', High: 'badge-high', Medium: 'badge-medium', Low: 'badge-low' };
  return `<span class="badge ${cls[p] || 'badge-low'}">${esc(p)}</span>`;
}

function statusBadge(s) {
  const cls = { Open: 'badge-open', 'In Progress': 'badge-progress', Resolved: 'badge-resolved', Pending: 'badge-pending', Escalated: 'badge-escalated' };
  return `<span class="badge ${cls[s] || 'badge-open'}">${esc(s)}</span>`;
}

function tierBadge(tierName) {
  const cls = { Bronze: 'badge-bronze', Silver: 'badge-silver', Gold: 'badge-gold', Platinum: 'badge-platinum' };
  return `<span class="badge ${cls[tierName] || 'badge-bronze'}">${esc(tierName)}</span>`;
}

