app.post('/api/rewards/redeem', requireAuth, async (req, res) => {
  const { code } = req.body;
  const user = req.user;

  if (!code) return res.status(400).json({ error: 'Please enter a promo code.' });

  const promo = promoCodes.find(p => p.code === code.toUpperCase());
  if (!promo) return res.status(404).json({ error: 'Invalid promo code. Please check and try again.' });

  if (promo.redeemedBy.includes(user.id)) {
    return res.status(400).json({ error: 'You have already redeemed this code.' });
  }

  user.loyaltyPoints += promo.bonus;

  await new Promise(resolve => setTimeout(resolve, 600));

  promo.redeemedBy.push(user.id);

  const tier = getTier(user.loyaltyPoints);
  res.json({
    success: true,
    message: `+${promo.bonus} points credited from "${promo.code}"!`,
    points: user.loyaltyPoints,
    tier: tier.name,
    bonus: promo.bonus
  });
});

