  :root{
    --bg-deep:#04080f;--bg-main:#080e1a;--bg-card:#0c1424;--bg-card-hover:#101c32;
    --bg-sidebar:#060c18;--bg-input:#0a1220;--border:#152040;--border-glow:#0ea5e933;
    --accent:#0ea5e9;--accent-dim:rgba(14,165,233,0.08);--accent-mid:rgba(14,165,233,0.15);
    --accent-teal:#14b8a6;--accent-red:#ef4444;--accent-amber:#f59e0b;--accent-purple:#a855f7;
    --accent-green:#22c55e;
    --text-primary:#e2e8f0;--text-secondary:#94a3b8;--text-muted:#64748b;
    --font-mono:'JetBrains Mono','Fira Code',monospace;--font-sans:'Inter',-apple-system,sans-serif;
    --radius:8px;--radius-lg:12px;
  }
  html{font-size:15px}
  body{font-family:var(--font-sans);background:var(--bg-main);color:var(--text-primary);line-height:1.6;min-height:100vh;
    background-image:radial-gradient(circle at 15% 50%,rgba(14,165,233,0.03) 0%,transparent 50%),radial-gradient(circle at 85% 20%,rgba(20,184,166,0.03) 0%,transparent 50%)}
  a{color:var(--accent);text-decoration:none}a:hover{text-decoration:underline}
  .app-layout{display:flex;min-height:100vh}
  .sidebar{width:250px;background:var(--bg-sidebar);border-right:1px solid var(--border);display:flex;flex-direction:column;position:fixed;top:0;bottom:0;z-index:10}
  .sidebar-brand{padding:20px 16px;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:10px}
  .sidebar-brand .icon-box{width:36px;height:36px;background:linear-gradient(135deg,var(--accent),var(--accent-teal));border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0}
  .sidebar-brand h1{font-family:var(--font-mono);font-size:16px;font-weight:700;letter-spacing:-0.5px}
  .sidebar-brand h1 span{color:var(--accent)}
  .sidebar-nav{flex:1;padding:12px 8px;display:flex;flex-direction:column;gap:2px}
  .sidebar-nav .section-label{font-size:10px;font-weight:600;text-transform:uppercase;letter-spacing:1.2px;color:var(--text-muted);padding:16px 12px 6px}
  .sidebar-nav a{display:flex;align-items:center;gap:10px;padding:9px 12px;border-radius:var(--radius);color:var(--text-secondary);font-size:13px;font-weight:500;transition:all .2s;text-decoration:none}
  .sidebar-nav a:hover{background:var(--accent-dim);color:var(--text-primary)}
  .sidebar-nav a.active{background:var(--accent-mid);color:var(--accent);box-shadow:inset 3px 0 0 var(--accent)}
  .sidebar-nav a .ic{font-size:16px;width:20px;text-align:center}
  .sidebar-user{padding:14px 12px;border-top:1px solid var(--border);display:flex;align-items:center;gap:10px}
  .sidebar-user .avatar{width:32px;height:32px;background:linear-gradient(135deg,var(--accent),var(--accent-purple));border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:700;flex-shrink:0}
  .sidebar-user .uname{font-size:12px;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
  .sidebar-user .urole{font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:.5px}
  .main-content{margin-left:250px;flex:1;padding:32px;min-height:100vh}
  .page-header{margin-bottom:28px}
  .page-header h1{font-family:var(--font-mono);font-size:1.5rem;font-weight:700;margin-bottom:4px}
  .page-header .subtitle{font-size:.85rem;color:var(--text-muted)}
  .card{background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:20px;transition:all .25s}
  .card:hover{border-color:var(--border-glow);background:var(--bg-card-hover)}
  .stats-row{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-bottom:28px}
  .stat-card{background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:18px;text-align:center}
  .stat-card .sv{font-family:var(--font-mono);font-size:1.8rem;font-weight:700;color:var(--accent);margin-bottom:4px}
  .stat-card .sl{font-size:.75rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:.8px}
  .badge{display:inline-block;padding:3px 8px;border-radius:4px;font-size:.7rem;font-weight:600;text-transform:uppercase;letter-spacing:.5px}
  .badge-critical{background:rgba(239,68,68,.15);color:#ef4444;border:1px solid rgba(239,68,68,.3)}
  .badge-high{background:rgba(245,158,11,.15);color:#f59e0b;border:1px solid rgba(245,158,11,.3)}
  .badge-medium{background:rgba(59,130,246,.15);color:#3b82f6;border:1px solid rgba(59,130,246,.3)}
  .badge-low{background:rgba(34,197,94,.15);color:#22c55e;border:1px solid rgba(34,197,94,.3)}
  .badge-open{background:rgba(14,165,233,.1);color:var(--accent);border:1px solid rgba(14,165,233,.25)}
  .badge-progress{background:rgba(168,85,247,.1);color:var(--accent-purple);border:1px solid rgba(168,85,247,.25)}
  .badge-escalated{background:rgba(239,68,68,.15);color:#ef4444;border:1px solid rgba(239,68,68,.3)}
  .badge-closed{background:rgba(100,116,139,.15);color:var(--text-muted);border:1px solid rgba(100,116,139,.3)}
  .data-table{width:100%;border-collapse:separate;border-spacing:0}
  .data-table th{font-size:.7rem;text-transform:uppercase;letter-spacing:.8px;color:var(--text-muted);padding:10px 14px;text-align:left;border-bottom:1px solid var(--border);font-weight:600}
  .data-table td{padding:12px 14px;font-size:.85rem;border-bottom:1px solid rgba(21,32,64,.5)}
  .data-table tr:hover td{background:var(--accent-dim)}
  .btn{display:inline-block;padding:8px 16px;border-radius:var(--radius);font-size:.8rem;font-weight:600;cursor:pointer;border:none;transition:all .2s;text-decoration:none}
  .btn-primary{background:linear-gradient(135deg,var(--accent),var(--accent-teal));color:#000}
  .btn-primary:hover{filter:brightness(1.15);box-shadow:0 0 20px rgba(14,165,233,.2);text-decoration:none}
  .btn-ghost{background:transparent;border:1px solid var(--border);color:var(--text-muted)}
  .btn-ghost:hover{border-color:var(--accent);color:var(--text-secondary)}
  .login-page{display:flex;align-items:center;justify-content:center;min-height:100vh;padding:32px}
  .login-wrapper{width:100%;max-width:440px}
  .login-brand{text-align:center;margin-bottom:32px}
  .login-brand .icon-lg{width:56px;height:56px;background:linear-gradient(135deg,var(--accent),var(--accent-teal));border-radius:12px;display:inline-flex;align-items:center;justify-content:center;font-size:28px;margin-bottom:12px}
  .login-brand h1{font-family:var(--font-mono);font-size:1.6rem;font-weight:700}
  .login-brand h1 span{color:var(--accent)}
  .login-brand p{color:var(--text-muted);font-size:.85rem;margin-top:4px}
  .auth-card{background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:28px}
  .auth-card h2{font-family:var(--font-mono);font-size:1rem;margin-bottom:20px;color:var(--accent)}
  .form-group{margin-bottom:14px}
  .form-group label{display:block;font-size:.75rem;font-weight:600;text-transform:uppercase;letter-spacing:.5px;color:var(--text-muted);margin-bottom:6px}
  .form-group input[type="text"],.form-group input[type="password"],.form-group input[type="url"],.form-group textarea{width:100%;padding:10px 14px;background:var(--bg-input);border:1px solid var(--border);border-radius:var(--radius);color:var(--text-primary);font-size:.88rem;transition:border-color .2s;font-family:inherit}
  .form-group input:focus,.form-group textarea:focus{outline:none;border-color:var(--accent);box-shadow:0 0 0 3px rgba(14,165,233,.1)}
  .submit-btn{width:100%;padding:11px;border:none;border-radius:var(--radius);font-weight:600;font-size:.88rem;cursor:pointer;transition:all .2s;margin-top:6px}
  .demo-creds{margin-top:16px;padding:12px;background:var(--bg-deep);border-radius:var(--radius);border:1px solid var(--border)}
  .demo-creds p{font-size:.72rem;color:var(--text-muted);margin-bottom:6px;text-transform:uppercase;letter-spacing:.5px}
  .demo-creds code{display:block;font-family:var(--font-mono);font-size:.78rem;color:var(--text-secondary);padding:2px 0}
  .error-msg{padding:10px;background:rgba(239,68,68,.1);border:1px solid rgba(239,68,68,.3);border-radius:var(--radius);color:#ef4444;font-size:.82rem;margin-bottom:14px}
  .scanner-output{margin-top:20px;background:var(--bg-deep);border:1px solid var(--border);border-radius:var(--radius);padding:16px;max-height:400px;overflow:auto}
  .scanner-output pre{font-family:var(--font-mono);font-size:.8rem;color:var(--text-secondary);white-space:pre-wrap;word-break:break-all}
  .api-endpoint{background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:18px;margin-bottom:14px}
  .api-endpoint .method-badge{display:inline-block;padding:2px 8px;border-radius:4px;font-family:var(--font-mono);font-size:.72rem;font-weight:700;margin-right:8px}
  .api-endpoint .method-get{background:rgba(14,165,233,.15);color:var(--accent)}
  .api-endpoint .method-post{background:rgba(168,85,247,.15);color:var(--accent-purple)}
  .api-endpoint .path{font-family:var(--font-mono);font-size:.85rem;color:var(--text-primary)}
  .api-endpoint .desc{font-size:.8rem;color:var(--text-muted);margin-top:8px;padding-left:4px}
  .api-endpoint .auth-note{display:inline-block;margin-top:8px;font-size:.72rem;padding:3px 8px;background:rgba(239,68,68,.1);border:1px solid rgba(239,68,68,.25);border-radius:4px;color:var(--accent-red);font-family:var(--font-mono)}
  .agent-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:16px}
  .agent-card{background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:20px;text-align:center;transition:all .3s;position:relative;overflow:hidden}
  .agent-card::before{content:'';position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,var(--accent),var(--accent-teal));opacity:0;transition:opacity .3s}
  .agent-card:hover{border-color:var(--border-glow)}.agent-card:hover::before{opacity:1}
  .agent-card .ac-avatar{width:56px;height:56px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:20px;font-weight:700;margin:0 auto 12px;font-family:var(--font-mono)}
  .agent-card .ac-name{font-weight:600;margin-bottom:2px}
  .agent-card .ac-role{font-size:.8rem;color:var(--text-muted);margin-bottom:4px}
  .agent-card .ac-dept{font-size:.72rem;color:var(--text-muted);margin-bottom:12px}
  .fade-in{animation:fadeIn .3s ease-out}
  @keyframes fadeIn{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}
  .ticket-detail-card{background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:24px;margin-bottom:16px}
  .ticket-meta{display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin:16px 0}
  .ticket-meta .meta-item label{display:block;font-size:.7rem;text-transform:uppercase;letter-spacing:.8px;color:var(--text-muted);margin-bottom:4px}
  .ticket-meta .meta-item span{font-size:.88rem}
  .status-indicator{display:inline-flex;align-items:center;gap:6px}
  .status-indicator::before{content:'';width:8px;height:8px;border-radius:50%;background:currentColor}
`;

const avatarGradients = {
  Administrator: 'linear-gradient(135deg, #0ea5e9, #14b8a6)',
  'Senior Agent': 'linear-gradient(135deg, #a855f7, #6366f1)',
  Agent: 'linear-gradient(135deg, #f59e0b, #ef4444)',
};

function initials(name) { return name.split(' ').map(n => n[0]).join(''); }

function priorityBadge(p) {
  const c = { Critical: 'badge-critical', High: 'badge-high', Medium: 'badge-medium', Low: 'badge-low' };
  return `<span class="badge ${c[p] || 'badge-low'}">${esc(p)}</span>`;
}

function statusBadge(s) {
  const c = { Open: 'badge-open', 'In Progress': 'badge-progress', Escalated: 'badge-escalated', Closed: 'badge-closed' };
  return `<span class="badge ${c[s] || 'badge-closed'}">${esc(s)}</span>`;
}

function renderSidebar(page, user) {
  const i = initials(user.name);
  return `<aside class="sidebar">
    <div class="sidebar-brand"><div class="icon-box">🎫</div><h1>Nexus<span>Desk</span></h1></div>
    <nav class="sidebar-nav">
      <div class="section-label">Support</div>
      <a href="/dashboard" class="${page === 'dashboard' ? 'active' : ''}"><span class="ic">📊</span> Dashboard</a>
      <a href="/tickets" class="${page === 'tickets' ? 'active' : ''}"><span class="ic">🎫</span> Tickets</a>
      <a href="/agents" class="${page === 'agents' ? 'active' : ''}"><span class="ic">👥</span> Agents</a>
      <div class="section-label">Tools</div>
      <a href="/scanner" class="${page === 'scanner' ? 'active' : ''}"><span class="ic">🔗</span> Link Validator</a>
      <a href="/integrations" class="${page === 'integrations' ? 'active' : ''}"><span class="ic">📖</span> Integrations</a>
      <a href="/logout"><span class="ic">🚪</span> Sign Out</a>
    </nav>
    <div class="sidebar-user">
      <div class="avatar">${i}</div>
      <div style="flex:1;min-width:0"><div class="uname">${esc(user.name)}</div><div class="urole">${esc(user.role)}</div></div>
    </div>
  </aside>`;
}

function pageShell(title, page, user, content) {
  return `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0">
<title>${esc(title)} — NexusDesk</title><style>${baseStyles}</style></head><body class="fade-in">
<div class="app-layout">${renderSidebar(page, user)}<main class="main-content">${content}</main></div></body></html>`;
}

app.get('/', (req, res) => {
  const userId = getSession(req);
  if (userId && users.find(u => u.id === userId)) return res.redirect('/dashboard');
  res.send(renderLogin(''));
});

function renderLogin(errorHtml) {
  return `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0">
<title>NexusDesk — Helpdesk Portal</title><style>${baseStyles}</style></head><body>
<div class="login-page"><div class="login-wrapper">
  <div class="login-brand"><div class="icon-lg">🎫</div><h1>Nexus<span>Desk</span></h1><p>Internal Helpdesk &amp; Support Operations</p></div>
  <div class="auth-card">
    <h2>// Agent Sign In</h2>
    ${errorHtml}
    <form method="POST" action="/login">
      <div class="form-group"><label>Username</label><input type="text" name="username" placeholder="username" autocomplete="off" required></div>
      <div class="form-group"><label>Password</label><input type="password" name="password" placeholder="password" required></div>
      <button type="submit" class="submit-btn btn-primary">Authenticate</button>
    </form>
    <div class="demo-creds">
      <p>Agent Credentials</p>
      <code>marcus.webb / support42</code>
      <code>priya.sharma / agent2024</code>
    </div>
  </div>
</div></div></body></html>`;
}

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.send(renderLogin('<div class="error-msg">Invalid credentials.</div>'));
  const token = createSession(user.id);
  res.cookie('nxd_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nxd_session;
  if (token) delete sessions[token];
  res.clearCookie('nxd_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const allTickets = db.exec(`SELECT * FROM tickets`);
  const rows = allTickets[0] ? allTickets[0].values : [];
  const open = rows.filter(r => r[2] === 'Open').length;
  const esc_ = rows.filter(r => r[2] === 'Escalated').length;
  const prog = rows.filter(r => r[2] === 'In Progress').length;

  const recentRows = rows.slice(0, 5).map(r => `<tr>
    <td><a href="/tickets/${r[0]}" style="font-family:var(--font-mono);font-size:.8rem;">TKT-${String(r[0]).padStart(4, '0')}</a></td>
    <td>${esc(r[1])}</td>
    <td>${statusBadge(r[2])}</td>
    <td>${priorityBadge(r[3])}</td>
    <td>${esc(r[4])}</td>
    <td style="font-size:.8rem;color:var(--text-muted)">${esc(r[6])}</td>
  </tr>`).join('');

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header"><h1>Welcome back, ${esc(user.name.split(' ')[0])}</h1><p class="subtitle">NexusDesk Support Operations Dashboard</p></div>
    <div class="stats-row">
      <div class="stat-card"><div class="sv">${rows.length}</div><div class="sl">Total Tickets</div></div>
      <div class="stat-card"><div class="sv" style="color:var(--accent-teal)">${open}</div><div class="sl">Open</div></div>
      <div class="stat-card"><div class="sv" style="color:var(--accent-amber)">${prog}</div><div class="sl">In Progress</div></div>
      <div class="stat-card"><div class="sv" style="color:var(--accent-red)">${esc_}</div><div class="sl">Escalated</div></div>
    </div>
    <div class="card"><h3 style="font-family:var(--font-mono);font-size:.95rem;margin-bottom:14px;">Recent Tickets</h3>
      <table class="data-table"><thead><tr><th>ID</th><th>Subject</th><th>Status</th><th>Priority</th><th>Requester</th><th>Date</th></tr></thead>
      <tbody>${recentRows}</tbody></table>
    </div>`));
});

app.get('/tickets', requireAuth, (req, res) => {
  const user = req.user;
  const allTickets = db.exec(`SELECT * FROM tickets ORDER BY id DESC`);
  const rows = (allTickets[0] ? allTickets[0].values : []).map(r => `<tr>
    <td><a href="/tickets/${r[0]}" style="font-family:var(--font-mono);font-size:.8rem;">TKT-${String(r[0]).padStart(4, '0')}</a></td>
    <td>${esc(r[1])}</td>
    <td>${statusBadge(r[2])}</td>
    <td>${priorityBadge(r[3])}</td>
    <td>${esc(r[4])}</td>
    <td style="font-size:.82rem;color:var(--text-secondary)">${esc(r[5])}</td>
    <td style="font-size:.8rem;color:var(--text-muted)">${esc(r[6])}</td>
  </tr>`).join('');

  res.send(pageShell('Tickets', 'tickets', user, `
    <div class="page-header"><h1>Support Tickets</h1><p class="subtitle">All helpdesk tickets across departments</p></div>
    <div class="card"><table class="data-table"><thead><tr><th>ID</th><th>Subject</th><th>Status</th><th>Priority</th><th>Requester</th><th>Agent</th><th>Date</th></tr></thead>
    <tbody>${rows}</tbody></table></div>`));
});

app.get('/tickets/:id', requireAuth, (req, res) => {
  const user = req.user;
  const tid = parseInt(req.params.id);
  const result = db.exec(`SELECT * FROM tickets WHERE id = ?`, [tid]);
  if (!result[0] || !result[0].values[0]) {
    return res.send(pageShell('Not Found', 'tickets', user, '<div class="page-header"><h1>Ticket Not Found</h1></div>'));
  }
  const t = result[0].values[0];
  res.send(pageShell(`TKT-${String(t[0]).padStart(4,'0')}`, 'tickets', user, `
    <div class="page-header"><h1>TKT-${String(t[0]).padStart(4,'0')}</h1><p class="subtitle">${esc(t[1])}</p></div>
    <div class="ticket-detail-card">
      <div class="ticket-meta">
        <div class="meta-item"><label>Status</label>${statusBadge(t[2])}</div>
        <div class="meta-item"><label>Priority</label>${priorityBadge(t[3])}</div>
        <div class="meta-item"><label>Requester</label><span>${esc(t[4])}</span></div>
        <div class="meta-item"><label>Assigned Agent</label><span style="font-family:var(--font-mono)">${esc(t[5])}</span></div>
        <div class="meta-item"><label>Created</label><span>${esc(t[6])}</span></div>
      </div>
      <div style="margin-top:20px;padding-top:16px;border-top:1px solid var(--border)">
        <label style="display:block;font-size:.7rem;text-transform:uppercase;letter-spacing:.8px;color:var(--text-muted);margin-bottom:8px">Description</label>
        <p style="font-size:.88rem;color:var(--text-secondary);line-height:1.8">${esc(t[7])}</p>
      </div>
    </div>
    <a href="/tickets" class="btn btn-ghost" style="cursor:pointer;color:var(--text-secondary)">← Back to Tickets</a>`));
});

app.get('/agents', requireAuth, (req, res) => {
  const user = req.user;
  const cards = users.map(u => {
    const grad = avatarGradients[u.role] || 'linear-gradient(135deg,#64748b,#475569)';
    return `<div class="agent-card">
      <div class="ac-avatar" style="background:${grad}">${initials(u.name)}</div>
      <div class="ac-name">${esc(u.name)}</div>
      <div class="ac-role">${esc(u.role)}</div>
      <div class="ac-dept">${esc(u.department)}</div>
      <div style="font-size:.78rem;color:var(--text-muted);font-family:var(--font-mono)">${esc(u.email)}</div>
    </div>`;
  }).join('');
  res.send(pageShell('Agents', 'agents', user, `
    <div class="page-header"><h1>Agent Directory</h1><p class="subtitle">NexusDesk support operations team</p></div>
    <div class="agent-grid">${cards}</div>`));
});

app.get('/scanner', requireAuth, (req, res) => {
  const user = req.user;
  res.send(pageShell('Link Validator', 'scanner', user, `
