      <div class="form-group">
        <label>Target URL</label>
        <input type="url" id="scan-url" placeholder="https://example.com" style="font-family:var(--font-mono)">
      </div>
      <button class="btn btn-primary" id="scan-btn" onclick="scanUrl()">Scan URL</button>
      <div id="scan-result"></div>
    </div>
    <script>
    async function scanUrl() {
      const url = document.getElementById('scan-url').value;
      if (!url) return;
      const btn = document.getElementById('scan-btn');
      btn.textContent = 'Scanning...';
      btn.disabled = true;
      try {
        const resp = await fetch('/api/scan-url', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ url })
        });
        const data = await resp.json();
        let html = '<div class="scanner-output" style="margin-top:20px">';
        if (data.error) {
          html += '<pre style="color:#ef4444">Error: ' + data.error + '</pre>';
