          html += '<div style="margin-bottom:10px;font-size:.78rem;color:var(--text-muted)">HTTP ' + data.status + ' — ' + data.contentType + '</div>';
          html += '<pre>' + data.body.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</pre>';
        }
        html += '</div>';
        document.getElementById('scan-result').innerHTML = html;
      } catch(e) {
        document.getElementById('scan-result').innerHTML = '<div class="scanner-output"><pre style="color:#ef4444">Request failed: ' + e.message + '</pre></div>';
      }
      btn.textContent = 'Scan URL';
      btn.disabled = false;
    }
    </script>`));
});

app.post('/api/scan-url', requireAuth, async (req, res) => {
  const { url } = req.body;
  if (!url) return res.json({ error: 'No URL provided' });
  try {
    const parsed = new URL(url);
    if (!['http:', 'https:'].includes(parsed.protocol)) {
      return res.json({ error: 'Only HTTP and HTTPS protocols are supported' });
    }
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);
    const response = await fetch(url, {
      headers: {
        'User-Agent': 'NexusDesk-LinkValidator/2.1',
        'X-NXD-Internal': INTERNAL_TOKEN
      },
      redirect: 'follow',
      signal: controller.signal
    });
    clearTimeout(timeout);
    const body = await response.text();
    res.json({
      status: response.status,
      contentType: response.headers.get('content-type') || 'unknown',
      body: body.substring(0, 50000)
    });
  } catch (e) {
    res.json({ error: e.message || 'Failed to fetch URL' });
  }
});

app.get('/internal/api/search', (req, res) => {
  const internalAuth = req.headers['x-nxd-internal'];
  if (internalAuth !== INTERNAL_TOKEN) {
    return res.status(403).json({
      error: 'ACCESS DENIED',
      message: 'This endpoint is restricted to internal NexusDesk services. Direct access is not permitted.'
    });
  }

  const q = req.query.q;
  if (!q) {
    return res.json({ results: [], message: 'Provide a search query via the q parameter.' });
  }

  try {
    const query = `SELECT id, subject, status, priority FROM tickets WHERE subject LIKE '%${q}%'`;
    const result = db.exec(query);
    const rows = result[0] ? result[0].values.map(r => ({
      id: r[0], subject: r[1], status: r[2], priority: r[3]
    })) : [];
    res.json({ query: q, count: rows.length, results: rows });
  } catch (e) {
    res.status(500).json({ error: 'Query error', details: e.message });
  }
});

