const sessions = {};
let nextUserId = 4;
const webhookStore = [];

const adminToken = crypto.randomBytes(24).toString('hex');
sessions[adminToken] = 1;

function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getUser(req) {
  const token = req.cookies?.hd_session;
  if (!token || !sessions[token]) return null;
  const uid = sessions[token];
  const r = db.exec(`SELECT id, username, name, role, department, email FROM users WHERE id = ${uid}`);
  if (r.length === 0 || r[0].values.length === 0) return null;
  const row = r[0].values[0];
  return { id: row[0], username: row[1], name: row[2], role: row[3], department: row[4], email: row[5] };
}

function requireAuth(req, res, next) {
  const user = getUser(req);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function requireAdmin(req, res, next) {
  const user = getUser(req);
  if (!user) return res.redirect('/');
  if (user.role !== 'Admin') {
    return res.status(403).send(pageShell('Access Denied', 'audit', user, `
      <div class="page-header"><h1>Access Denied</h1><p class="subtitle">This section requires administrator privileges.</p></div>
      <div class="card"><p style="color:var(--text-muted);">Your current role <strong>${esc(user.role)}</strong> does not have access to this resource. Contact an administrator if you believe this is an error.</p></div>
    `));
  }
  req.user = user;
  next();
}

