  .search-box input:focus{outline:none;border-color:var(--accent);box-shadow:0 0 0 3px rgba(6,182,212,0.1)}
  .meta-row{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:14px;margin-bottom:20px}
  .meta-item{background:var(--bg-deep);border:1px solid var(--border);border-radius:var(--radius);padding:12px}
