  .webhook-entry .ts{color:var(--text-muted);font-size:0.7rem}
`;

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function priorityBadge(p) {
  const m = { Critical:'badge-critical', High:'badge-high', Medium:'badge-medium', Low:'badge-low' };
  return `<span class="badge ${m[p]||'badge-low'}">${esc(p)}</span>`;
}

function statusBadge(s) {
  const m = { Open:'badge-open', 'In Progress':'badge-progress', Escalated:'badge-escalated', Closed:'badge-closed' };
  return `<span class="badge ${m[s]||'badge-closed'}">${esc(s)}</span>`;
}

function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

