  const { username, password } = req.body;
  const r = db.exec(`SELECT id, username, password FROM users WHERE username = '${esc(username)}'`);
  if (r.length === 0 || r[0].values.length === 0 || r[0].values[0][2] !== password) {
    return res.send(loginPage.replace('ERRORPLACEHOLDER','<div class="error-msg">Invalid credentials.</div>').replace('REGISTERPLACEHOLDER',''));
