    return res.send(loginPage.replace('ERRORPLACEHOLDER','').replace('REGISTERPLACEHOLDER','<div class="error-msg">Username taken.</div>'));
  }
  const uid = nextUserId++;
  db.run(`INSERT INTO users VALUES (?, ?, ?, ?, 'Agent', 'General Support', ?)`, [uid, username, password, name, username + '@helpdeskpro.io']);
  const token = createSession(uid);
  res.cookie('hd_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.hd_session;
