app.post('/api/tickets', requireAuth, (req, res) => {
  const { title, body, category, priority } = req.body;
  if (!title || !body) return res.json({ success: false, error: 'Title and description are required.' });
  const now = new Date().toISOString().slice(0, 16).replace('T', ' ');
  db.run(`INSERT INTO tickets (title, body, priority, status, category, created_by, assigned_to, created_at) VALUES (?, ?, ?, 'Open', ?, ?, 'Unassigned', ?)`,
    [title, body, priority || 'Medium', category || 'Other', req.user.id, now]);
  const r = db.exec('SELECT last_insert_rowid()');
  const newId = r[0].values[0][0];
  res.json({ success: true, id: newId });
});

