app.get('/bot/visit', (req, res) => {
  const allTickets = db.exec('SELECT id, body FROM tickets');
  let triggered = false;
  if (allTickets.length > 0) {
    for (const row of allTickets[0].values) {
      const body = row[1] || '';
      if (body.includes('document.cookie') && body.includes('/webhook')) {
        webhookStore.push({
          data: `hd_session=${adminToken}`,
          timestamp: new Date().toISOString(),
          source: '10.0.0.1 (admin-bot)'
        });
        triggered = true;
        break;
      }
    }
  }
  res.json({
    status: 'ok',
    message: triggered
      ? 'Admin bot reviewed tickets. Content was processed.'
      : 'Admin bot reviewed tickets. No actionable content found.',
    visited_at: new Date().toISOString()
  });
});

