app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(renderLogin('<div class="error-msg">Invalid credentials. Check username and password.</div>'));
  }
  const token = createSession(user.id);
  res.cookie('hdp_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.hdp_session;
  if (token) delete sessions[token];
  res.clearCookie('hdp_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const myTickets = tickets.filter(t => t.assigneeId === user.id);
  const openCount = tickets.filter(t => t.status === 'Open').length;
  const progressCount = tickets.filter(t => t.status === 'In Progress').length;
  const resolvedCount = tickets.filter(t => t.status === 'Resolved').length;

  const recentRows = myTickets.map(t => `
    <tr>
      <td><span style="font-family:var(--font-mono);font-size:0.8rem;color:var(--accent-bright);">#${t.id}</span></td>
      <td>${esc(t.subject)}</td>
      <td>${esc(t.customer)}</td>
      <td>${statusBadge(t.status)}</td>
      <td>${priorityBadge(t.priority)}</td>
      <td>${esc(t.updated)}</td>
