function getTickets() {
  const results = db.exec('SELECT * FROM tickets ORDER BY created DESC');
  if (results.length === 0) return [];
  return results[0].values.map(r => ({
    id: r[0], subject: r[1], requester: r[2], status: r[3],
    priority: r[4], assignee: r[5], created: r[6], category: r[7], description: r[8]
  }));
}

function getNotes() {
  const results = db.exec('SELECT * FROM internal_notes ORDER BY created DESC');
  if (results.length === 0) return [];
  return results[0].values.map(r => ({
    id: r[0], ticket_id: r[1], author: r[2], note: r[3], created: r[4]
  }));
}

