app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) {
    return res.send(renderLoginPage('<div class="error-msg">Please enter both username and password.</div>'));
  }

  try {
    const query = `SELECT * FROM users WHERE username='${username}' AND password='${password}'`;
    const results = db.exec(query);

    if (results.length > 0 && results[0].values.length > 0) {
      const row = results[0].values[0];
      const userId = row[0];
      const token = createSession(userId);
      res.cookie('hd_session', token, { httpOnly: false, sameSite: 'lax' });
      return res.redirect('/dashboard');
    }

    res.send(renderLoginPage('<div class="error-msg">Invalid credentials. Please check your username and password.</div>'));
  } catch (e) {
    res.send(renderLoginPage('<div class="error-msg">Authentication error. Please try again.</div>'));
  }
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.hd_session;
  if (token) delete sessions[token];
  res.clearCookie('hd_session');
  res.redirect('/');
});

