app.get('/agents', requireAuth, (req, res) => {
  const user = req.user;
  const agentResults = db.exec('SELECT * FROM users ORDER BY id');
  const agents = agentResults.length > 0 ? agentResults[0].values.map(r => ({
    id: r[0], username: r[1], name: r[3], role: r[4], department: r[5], email: r[6], joined: r[7]
