  const cards = agents.map(a => {
    const init = initials(a.name);
    const color = agentColors[a.role] || 'linear-gradient(135deg, #64748b, #475569)';
    const roleBadge = a.role === 'Administrator' ? 'badge-critical' : a.role === 'Senior Agent' ? 'badge-high' : 'badge-low';
    return `
