        <div class="ac-avatar" style="background:${color};">${init}</div>
        <div class="ac-name">${esc(a.name)}</div>
        <div class="ac-role"><span class="badge ${roleBadge}">${esc(a.role)}</span></div>
        <div class="ac-dept">${esc(a.department)}</div>
        <div style="font-size:0.75rem;color:var(--text-muted);margin-top:8px;">
          <span style="font-family:var(--font-mono);">${esc(a.username)}</span>
        </div>
        <div style="font-size:0.72rem;color:var(--text-muted);margin-top:4px;">Joined ${esc(a.joined)}</div>
      </div>`;
  }).join('');

  res.send(pageShell('Agents', 'agents', user, `
    <div class="page-header">
      <h1>Agent Directory</h1>
      <p class="subtitle">SupportFlow helpdesk team members</p>
    </div>
