app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.send(renderLoginPage('<div class="error-msg">Invalid credentials.</div>', ''));
  const token = createSession(user.id);
  res.cookie('nc_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.send(renderLoginPage('', '<div class="error-msg">All fields required.</div>'));
  if (users.find(u => u.username === username)) return res.send(renderLoginPage('', '<div class="error-msg">Username taken.</div>'));
  const newUser = { id: nextUserId++, username, password, name, role: 'Patient', dob: 'N/A', bloodType: 'N/A', allergies: [], insurance: 'Pending', patientId: 'NC-' + Date.now().toString().slice(-8), phone: 'N/A' };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('nc_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nc_session;
  if (token) delete sessions[token];
  res.clearCookie('nc_session');
  res.redirect('/');
});

