app.post('/api/cart/add', requireAuth, (req, res) => {
  const { productId, quantity } = req.body;
  const product = products.find(p => p.id === productId);
  if (!product) return res.status(400).json({ error: 'Product not found' });
  const qty = Math.min(Math.max(parseInt(quantity) || 1, 1), 10);
  const cart = getUserCart(req.user.id);
  const existing = cart.find(i => i.productId === productId);
  if (existing) {
    existing.quantity = Math.min(existing.quantity + qty, 10);
  } else {
    cart.push({ productId, quantity: qty });
  }
  const cartCount = cart.reduce((s, i) => s + i.quantity, 0);
  res.json({ success: true, cartCount });
});

app.post('/api/cart/remove', requireAuth, (req, res) => {
  const { productId } = req.body;
  const cart = getUserCart(req.user.id);
  const idx = cart.findIndex(i => i.productId === productId);
  if (idx !== -1) cart.splice(idx, 1);
  res.json({ success: true });
});

app.get('/api/cart', requireAuth, (req, res) => {
  const cart = getUserCart(req.user.id);
  const items = cart.map(ci => {
    const p = products.find(pr => pr.id === ci.productId);
    return p ? { productId: p.id, name: p.name, icon: p.icon, price: p.price, quantity: ci.quantity, subtotal: +(p.price * ci.quantity).toFixed(2) } : null;
  }).filter(Boolean);
  const total = items.reduce((s, i) => s + i.subtotal, 0);
  res.json({ items, total: +total.toFixed(2) });
});

app.get('/api/coupons/validate', requireAuth, (req, res) => {
  const code = (req.query.code || '').toUpperCase().trim();
  const coupon = validCoupons[code];
  if (!coupon) return res.status(400).json({ valid: false, error: 'Invalid coupon code' });
  res.json({ valid: true, code, name: coupon.name, percent: coupon.percent, description: coupon.description });
});

app.post('/api/checkout', requireAuth, (req, res) => {
  const cart = getUserCart(req.user.id);
  if (cart.length === 0) return res.status(400).json({ error: 'Cart is empty' });

  const items = cart.map(ci => {
    const p = products.find(pr => pr.id === ci.productId);
    return p ? { name: p.name, price: p.price, quantity: ci.quantity, subtotal: +(p.price * ci.quantity).toFixed(2) } : null;
  }).filter(Boolean);

  const subtotal = items.reduce((s, i) => s + i.subtotal, 0);

  let couponCodes = req.body.coupons || [];
  if (typeof couponCodes === 'string') couponCodes = [couponCodes];
  if (!Array.isArray(couponCodes)) couponCodes = [];

  let totalDiscount = 0;
  const appliedCoupons = [];

  for (const raw of couponCodes) {
    const code = String(raw).toUpperCase().trim();
    const coupon = validCoupons[code];
    if (coupon && !appliedCoupons.find(c => c.code === code)) {
      appliedCoupons.push({ code, name: coupon.name, percent: coupon.percent });
      totalDiscount += coupon.percent;
    }
  }

  const discountAmount = +(subtotal * Math.min(totalDiscount, 100) / 100).toFixed(2);
  const finalTotal = +(subtotal - discountAmount).toFixed(2);

  const orderId = 'NC-ORD-' + (++orderCounter);

  carts[req.user.id] = [];

  if (finalTotal <= 0 && appliedCoupons.length > 1) {
    return res.json({
      success: true,
      orderId,
      items,
      subtotal: +subtotal.toFixed(2),
      appliedCoupons,
      totalDiscount,
      discountAmount,
      finalTotal: 0,
      message: 'Order confirmed! Total discounted to $0.00. As a special promotion reward, here is your exclusive access code.',
      specialReward: flag
    });
  }

  res.json({
    success: true,
    orderId,
    items,
    subtotal: +subtotal.toFixed(2),
    appliedCoupons,
    totalDiscount,
    discountAmount,
    finalTotal: Math.max(finalTotal, 0),
    message: 'Order placed successfully! Your items will be ready for pickup at the NovaCare pharmacy desk.'
  });
});

app.get('/cart', requireAuth, (req, res) => {
  const user = req.user;

  res.send(pageShell('Cart & Checkout', 'cart', user, `
    <div class="page-header">
      <h1>Cart & Checkout</h1>
      <p class="subtitle">Review your items and complete your order</p>
    </div>

    <div class="card" id="cart-container">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">🛒 Your Items</h3>
      <div id="cart-items"></div>

      <div class="checkout-section" id="checkout-section" style="display:none;">
        <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">💳 Checkout</h3>

        <div class="coupon-row">
          <input type="text" id="coupon-input" placeholder="Enter coupon code" style="text-transform:uppercase;">
          <button class="btn btn-primary btn-sm" id="apply-coupon-btn" onclick="applyCoupon()">Apply</button>
        </div>
        <div class="coupon-applied" id="coupon-status"></div>

        <div class="order-summary">
          <div>
            <div class="total-label">Subtotal</div>
            <div style="font-size:0.8rem;color:var(--text-muted);" id="discount-info"></div>
          </div>
          <div class="total-value" id="total-display">$0.00</div>
        </div>

        <button class="btn btn-green" style="width:100%;padding:12px;font-size:0.95rem;" onclick="placeOrder()">Place Order</button>
      </div>

      <div id="empty-cart" style="display:none;">
        <div class="empty-state">
          <div class="es-icon">🛒</div>
          <p>Your cart is empty</p>
          <a href="/pharmacy" class="btn btn-primary">Browse Pharmacy</a>
        </div>
      </div>
    </div>

    <div class="order-result" id="order-result"></div>

    <script>
      let cartData = { items: [], total: 0 };
      let appliedCoupon = null;

      function loadCart() {
        fetch('/api/cart').then(r => r.json()).then(data => {
          cartData = data;
          renderCart();
        });
      }

      function renderCart() {
        const container = document.getElementById('cart-items');
        const section = document.getElementById('checkout-section');
        const empty = document.getElementById('empty-cart');

        if (cartData.items.length === 0) {
          container.innerHTML = '';
          section.style.display = 'none';
          empty.style.display = 'block';
          return;
        }

        empty.style.display = 'none';
        section.style.display = 'block';

        container.innerHTML = cartData.items.map(item =>
          '<div class="cart-item">' +
            '<div class="ci-icon">' + item.icon + '</div>' +
            '<div class="ci-info">' +
              '<div class="ci-name">' + item.name + '</div>' +
              '<div class="ci-meta">Qty: ' + item.quantity + ' × $' + item.price.toFixed(2) + '</div>' +
            '</div>' +
            '<div class="ci-price">$' + item.subtotal.toFixed(2) + '</div>' +
            '<button class="btn btn-red btn-sm" onclick="removeItem(' + item.productId + ')">✕</button>' +
          '</div>'
        ).join('');

        updateTotals();
      }

      function removeItem(productId) {
        fetch('/api/cart/remove', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ productId })
        }).then(() => loadCart());
      }

      function applyCoupon() {
        if (appliedCoupon) return;
        const code = document.getElementById('coupon-input').value.trim().toUpperCase();
        if (!code) return;

        fetch('/api/coupons/validate?code=' + encodeURIComponent(code))
          .then(r => r.json())
          .then(data => {
            const status = document.getElementById('coupon-status');
            if (data.valid) {
              appliedCoupon = data;
              status.style.display = 'block';
              status.innerHTML = '✅ <strong>' + data.code + '</strong> applied — ' + data.percent + '% off (' + data.name + ')';
              status.style.background = 'rgba(16,185,129,0.1)';
              status.style.borderColor = 'rgba(16,185,129,0.25)';
              status.style.color = '#10b981';
              document.getElementById('coupon-input').disabled = true;
              document.getElementById('apply-coupon-btn').disabled = true;
              document.getElementById('apply-coupon-btn').textContent = 'Applied';
              updateTotals();
            } else {
              status.style.display = 'block';
              status.innerHTML = '❌ Invalid coupon code';
              status.style.background = 'rgba(239,68,68,0.1)';
              status.style.borderColor = 'rgba(239,68,68,0.25)';
              status.style.color = '#ef4444';
            }
          });
      }

      function updateTotals() {
        const subtotal = cartData.total;
        let discount = 0;
        let displayTotal = subtotal;

        if (appliedCoupon) {
          discount = subtotal * appliedCoupon.percent / 100;
          displayTotal = subtotal - discount;
        }

        document.getElementById('total-display').textContent = '$' + Math.max(displayTotal, 0).toFixed(2);
        document.getElementById('discount-info').textContent = appliedCoupon
          ? 'Discount: -$' + discount.toFixed(2) + ' (' + appliedCoupon.percent + '% off)'
          : '';
      }

      function placeOrder() {
        const coupons = appliedCoupon ? [appliedCoupon.code] : [];

        fetch('/api/checkout', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ coupons: coupons })
        })
        .then(r => r.json())
        .then(data => {
          const result = document.getElementById('order-result');
          result.style.display = 'block';

          if (data.specialReward) {
            result.className = 'order-result special';
            result.innerHTML =
              '<h3 style="font-family:var(--font-mono);color:var(--accent-purple);margin-bottom:12px;">🎉 Special Promotion Reward!</h3>' +
              '<p style="font-size:0.9rem;color:var(--text-secondary);margin-bottom:8px;">Order <strong style="color:var(--accent);font-family:var(--font-mono);">' + data.orderId + '</strong> confirmed at $0.00</p>' +
              '<p style="font-size:0.85rem;color:var(--text-secondary);margin-bottom:14px;">' + data.message + '</p>' +
              '<div style="padding:14px;background:var(--bg-deep);border:1px solid rgba(168,85,247,0.4);border-radius:var(--radius);font-family:var(--font-mono);font-size:0.95rem;color:var(--accent-purple);word-break:break-all;">' + data.specialReward + '</div>' +
              '<p style="margin-top:12px;font-size:0.78rem;color:var(--text-muted);">Coupons applied: ' + data.appliedCoupons.map(function(c){return c.code + ' (' + c.percent + '%)'}).join(', ') + ' — Total discount: ' + data.totalDiscount + '%</p>';
          } else {
            result.className = 'order-result success';
            result.innerHTML =
              '<h3 style="font-family:var(--font-mono);color:var(--accent-green);margin-bottom:12px;">✅ Order Confirmed</h3>' +
              '<p style="font-size:0.9rem;color:var(--text-secondary);margin-bottom:8px;">Order <strong style="color:var(--accent);font-family:var(--font-mono);">' + data.orderId + '</strong> — Total: <strong>$' + data.finalTotal.toFixed(2) + '</strong></p>' +
              '<p style="font-size:0.85rem;color:var(--text-muted);">' + data.message + '</p>';
          }

          document.getElementById('cart-container').style.display = 'none';
        });
      }

      loadCart();
    </script>
  `));
});

