let nextUserId = 4;
const sessions = {};

function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.mh_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const user = users.find(u => u.id === userId);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function requireInternal(req, res, next) {
  if (req.headers['x-medhub-internal'] !== INTERNAL_TOKEN) {
    return res.status(403).json({
      error: 'ACCESS DENIED',
      message: 'This endpoint is restricted to internal service-to-service requests only.',
      hint: 'Direct browser access is not permitted. This API is consumed by internal MedHub microservices.'
    });
  }
  next();
}

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

