function initials(name) {
  return name.split(' ').map(n => n[0]).join('').substring(0, 2);
}

function statusBadge(s) {
  const m = { Admitted: 'badge-admitted', Outpatient: 'badge-outpatient', Discharged: 'badge-discharged', ICU: 'badge-icu' };
  return `<span class="badge ${m[s] || 'badge-discharged'}">${esc(s)}</span>`;
}

function apptBadge(s) {
  const m = { Scheduled: 'badge-scheduled', Pending: 'badge-pending', Completed: 'badge-completed' };
  return `<span class="badge ${m[s] || 'badge-pending'}">${esc(s)}</span>`;
}

function noteBadge(s) {
  const m = { Critical: 'badge-critical', Priority: 'badge-priority', Routine: 'badge-routine' };
  return `<span class="badge ${m[s] || 'badge-routine'}">${esc(s)}</span>`;
}

