app.get('/', (req, res) => {
  res.send(loginPage.replace('LOGIN_ERROR', '').replace('REGISTER_MSG', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(loginPage
      .replace('LOGIN_ERROR', '<div class="error-msg">Invalid credentials.</div>')
      .replace('REGISTER_MSG', ''));
  }
  const token = createSession(user.id);
  res.cookie('mh_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(loginPage.replace('LOGIN_ERROR', '')
      .replace('REGISTER_MSG', '<div class="error-msg">All fields are required.</div>'));
  }
  if (users.find(u => u.username === username)) {
    return res.send(loginPage.replace('LOGIN_ERROR', '')
      .replace('REGISTER_MSG', '<div class="error-msg">Username already taken.</div>'));
  }
  const newUser = {
    id: nextUserId++, username, password, name,
    role: 'Staff', department: 'General', email: username + '@medhub.care',
    joined: new Date().toISOString().split('T')[0], clearance: 'Basic Access'
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('mh_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.mh_session;
  if (token) delete sessions[token];
  res.clearCookie('mh_session');
  res.redirect('/');
});

