        <button onclick="checkResource()" class="btn btn-primary" id="check-btn">Check Resource</button>
      </div>
      <div id="result-area"></div>
    </div>
    <div class="card" style="margin-top:20px;">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:10px;">ℹ️ About This Tool</h3>
      <p style="font-size:0.82rem;color:var(--text-secondary);line-height:1.7;">
