});

app.post('/api/fetch-resource', requireAuth, async (req, res) => {
  const { url } = req.body;
  if (!url) return res.status(400).json({ error: 'URL is required' });

  try {
    new URL(url);
  } catch (e) {
    return res.status(400).json({ error: 'Invalid URL format' });
  }

  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);
    const response = await fetch(url, {
      headers: {
        'User-Agent': 'MedHub-ResourceChecker/2.1',
        'X-MedHub-Internal': INTERNAL_TOKEN
      },
      redirect: 'follow',
      signal: controller.signal
    });
    clearTimeout(timeout);
    const contentType = response.headers.get('content-type') || '';
    const body = await response.text();
    res.json({ status: response.status, contentType, body });
  } catch (err) {
    res.status(500).json({ error: 'Failed to fetch resource: ' + err.message });
  }
});

app.get('/internal/api/patient-search', requireInternal, (req, res) => {
  const q = req.query.q || '';
  if (!q) {
    return res.json({ status: 'error', message: 'Query parameter q is required', found: false, count: 0 });
  }

  try {
    const results = db.exec(`SELECT id, mrn, name FROM patients WHERE mrn = '${q}' OR name LIKE '%${q}%'`);
    if (results.length > 0 && results[0].values.length > 0) {
      const count = results[0].values.length;
      res.json({ status: 'found', message: `Patient record(s) found`, count: count, found: true });
    } else {
      res.json({ status: 'not_found', message: 'No patient records matching query', count: 0, found: false });
    }
  } catch (err) {
    res.json({ status: 'error', message: 'Query processing error', count: 0, found: false });
  }
});

