function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSessionUser(req) {
  const token = req.cookies?.mv_session;
  if (!token || !sessions[token]) return null;
  return users.find(u => u.id === sessions[token]) || null;
}

function requireAuth(req, res, next) {
  const user = getSessionUser(req);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function requireAdmin(req, res, next) {
  const user = getSessionUser(req);
  if (!user) return res.redirect('/');
  if (user.role !== 'Administrator') {
    return res.status(403).send(pageShell('Access Denied', 'admin', user,
      `<div class="page-header"><h1>Access Denied</h1><p class="subtitle">This section requires Administrator privileges.</p></div>
       <div class="card"><p style="color:var(--text-muted);">You do not have sufficient permissions to access the records management system. Contact your system administrator if you believe this is an error.</p></div>`));
  }
  req.user = user;
  next();
}

function ensureAdminBotSession() {
  if (!adminBotToken || !sessions[adminBotToken]) {
    adminBotToken = crypto.randomBytes(24).toString('hex');
    sessions[adminBotToken] = 1;
  }
  return adminBotToken;
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function initials(name) {
  return name.split(' ').filter(n => !n.startsWith('Dr')).map(n => n[0]).join('').substring(0, 2);
}

