function renderSidebar(activePage, user) {
  const init = initials(user.name);
  const isAdmin = user.role === 'Administrator';
  return `
    <aside class="sidebar">
      <div class="sidebar-brand">
        <div class="shield">🏥</div>
        <h1>Meridian<span>Health</span></h1>
      </div>
      <nav class="sidebar-nav">
        <div class="section-label">Clinical</div>
        <a href="/dashboard" class="${activePage === 'dashboard' ? 'active' : ''}">
          <span class="icon">📊</span> Dashboard
        </a>
        <a href="/patients" class="${activePage === 'patients' ? 'active' : ''}">
          <span class="icon">🩺</span> Patients
        </a>
        <a href="/appointments" class="${activePage === 'appointments' ? 'active' : ''}">
          <span class="icon">📅</span> Appointments
        </a>
