app.get('/', (req, res) => {
  const user = getSessionUser(req);
  if (user) return res.redirect('/dashboard');
  res.send(loginPageTemplate.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(loginPageTemplate
      .replace('%%LOGIN_MSG%%', '<div class="error-msg">Invalid credentials. Please verify your username and password.</div>')
      .replace('%%REG_MSG%%', ''));
  }
  const token = createSession(user.id);
  res.cookie('mv_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(loginPageTemplate
      .replace('%%LOGIN_MSG%%', '')
      .replace('%%REG_MSG%%', '<div class="error-msg">All fields are required.</div>'));
  }
  if (users.find(u => u.username === username)) {
    return res.send(loginPageTemplate
      .replace('%%LOGIN_MSG%%', '')
      .replace('%%REG_MSG%%', '<div class="error-msg">Username already exists.</div>'));
  }
  const newUser = {
    id: nextUserId++, username, password, name,
    role: 'Nurse', department: 'General', email: username + '@meridianhealth.care',
    joined: new Date().toISOString().split('T')[0],
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('mv_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.mv_session;
  if (token) delete sessions[token];
  res.clearCookie('mv_session');
  res.redirect('/');
});

