app.get('/feedback', requireAuth, (req, res) => {
  const user = req.user;

  const entriesHtml = feedbackEntries.length === 0
    ? '<p style="color:var(--text-muted);font-size:0.88rem;padding:20px 0;">No feedback submitted yet. Be the first to share your thoughts.</p>'
    : feedbackEntries.slice().reverse().map(entry => `
      <div class="feedback-entry">
        <div class="feedback-meta">
          <span class="feedback-author">${esc(entry.authorName)}</span>
          <span class="feedback-date">${esc(entry.date)}</span>
        </div>
        <div class="feedback-body">${entry.message}</div>
      </div>`).join('');

  res.send(pageShell('Feedback Board', 'feedback', user, `
    <div class="page-header">
      <h1>Staff Feedback Board</h1>
      <p class="subtitle">Share suggestions, report issues, and collaborate with colleagues</p>
    </div>

    <div class="card" style="margin-bottom:24px;">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">Submit Feedback</h3>
      <div id="formMsg"></div>
      <form id="feedbackForm">
        <div style="margin-bottom:12px;">
          <label style="display:block;font-size:0.75rem;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;color:var(--text-muted);margin-bottom:6px;">Your Message</label>
          <textarea id="fbMessage" placeholder="Share your feedback, suggestions, or concerns..." rows="4"></textarea>
        </div>
        <button type="submit" class="btn btn-primary">Submit Feedback</button>
      </form>
      <script>
        document.getElementById('feedbackForm').addEventListener('submit', async function(e) {
          e.preventDefault();
          const msg = document.getElementById('fbMessage').value;
          if (!msg.trim()) return;
          try {
            const resp = await fetch('/feedback', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ message: msg })
            });
            const data = await resp.json();
            if (data.success) {
              document.getElementById('formMsg').innerHTML = '<div class="success-msg">Feedback submitted successfully.</div>';
              document.getElementById('fbMessage').value = '';
              setTimeout(function() { location.reload(); }, 800);
            } else {
              document.getElementById('formMsg').innerHTML = '<div class="error-msg">' + (data.error || 'Submission failed.') + '</div>';
            }
          } catch(err) {
            document.getElementById('formMsg').innerHTML = '<div class="error-msg">Network error. Please try again.</div>';
          }
        });
      </script>
    </div>

    <div>
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">Recent Feedback</h3>
      ${entriesHtml}
    </div>

    <div class="card" style="margin-top:24px;border-color:rgba(245,158,11,0.3);">
      <p style="font-size:0.8rem;color:var(--accent-amber);">
        <strong>⚠ Notice:</strong> This feedback board is reviewed daily by hospital administration (Dr. Harris).
        You can trigger a manual admin review by visiting <a href="/bot/visit" style="color:var(--accent);">/bot/visit</a>.
      </p>
    </div>
  `));
});

app.post('/feedback', requireAuth, (req, res) => {
  const user = req.user;
  const { message } = req.body;
  if (!message || !message.trim()) {
    return res.json({ success: false, error: 'Message cannot be empty.' });
  }
  if (message.length > 2000) {
    return res.json({ success: false, error: 'Message too long (max 2000 chars).' });
  }
  feedbackEntries.push({
    id: feedbackEntries.length + 1,
    authorName: user.name,
    authorId: user.id,
    message: message,
    date: new Date().toISOString().replace('T', ' ').substring(0, 19),
  });
  res.json({ success: true });
});

