function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function statusBadge(s) {
  const map = {
    'Admitted': 'badge-admitted', 'Discharged': 'badge-discharged',
    'ICU': 'badge-icu', 'Outpatient': 'badge-outpatient',
    'Observation': 'badge-observation', 'Scheduled': 'badge-scheduled',
    'Confirmed': 'badge-confirmed', 'Pending': 'badge-pending',
  };
  return `<span class="badge ${map[s] || 'badge-admitted'}">${esc(s)}</span>`;
}

function initials(name) {
  return name.replace(/^Dr\.\s*/, '').replace(/,.*/, '').split(' ').map(n => n[0]).join('');
}

