app.get('/', (req, res) => {
  const userId = getSession(req);
  if (userId) return res.redirect('/dashboard');
  res.send(buildLoginPage('', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(buildLoginPage('<div class="error-msg">Invalid credentials. Please verify your username and password.</div>', ''));
  }
  const token = createSession(user.id);
  res.cookie('mm_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(buildLoginPage('', '<div class="error-msg">All fields are required.</div>'));
  }
  if (users.find(u => u.username === username)) {
    return res.send(buildLoginPage('', '<div class="error-msg">Username already exists.</div>'));
  }
  const newUser = {
    id: nextUserId++, username, password, name, role: 'Resident',
    department: 'General Medicine', email: username + '@meridianmed.org',
    joined: new Date().toISOString().split('T')[0],
    specialization: 'Pending Assignment', badge: 'RES-' + Math.floor(1000 + Math.random() * 9000),
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('mm_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.mm_session;
  if (token) delete sessions[token];
  res.clearCookie('mm_session');
  res.redirect('/');
});

