app.get('/records', requireAuth, (req, res) => {
  const user = req.user;
  const patientId = req.query.id || '';
  let resultHtml = '';

  if (patientId) {
    try {
      const query = `SELECT patient_id, full_name, department, status FROM patients WHERE patient_id = '${patientId}'`;
      const results = db.exec(query);

      if (results.length > 0 && results[0].values.length > 0) {
        const count = results[0].values.length;
        resultHtml = `
          <div class="result-card result-found">
            <div class="result-icon">✓</div>
            <div class="result-title">${count} record(s) verified</div>
            <div class="result-sub">Patient record exists and is accessible. Contact medical records for full chart access.</div>
          </div>`;
      } else {
        resultHtml = `
          <div class="result-card result-empty">
            <div class="result-icon">✗</div>
            <div class="result-title">No records found</div>
            <div class="result-sub">No patient record matches identifier <strong style="font-family:var(--font-mono);color:var(--text-secondary);">${esc(patientId)}</strong></div>
          </div>`;
      }
    } catch (e) {
      resultHtml = `
        <div class="result-card result-empty">
          <div class="result-icon">✗</div>
          <div class="result-title">No records found</div>
          <div class="result-sub">No patient record matches the provided identifier.</div>
        </div>`;
    }
  }

  res.send(pageShell('Record Lookup', 'records', user, `
    <div class="page-header">
      <h1>Record Verification</h1>
      <p class="subtitle">Verify patient record existence before requesting full chart access</p>
