app.get('/notes', requireAuth, (req, res) => {
  const user = req.user;
  const results = db.exec('SELECT cn.patient_id, p.full_name, cn.author, cn.date, cn.note, cn.category FROM clinical_notes cn JOIN patients p ON cn.patient_id = p.patient_id ORDER BY cn.date DESC');
