app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) {
    return res.send(renderLogin('<div class="error-msg">Please enter both username and password.</div>'));
  }
  const rows = db.exec(`SELECT * FROM staff WHERE username = '${username.replace(/'/g, "''")}' AND password = '${password.replace(/'/g, "''")}'`);
  if (!rows.length || !rows[0].values.length) {
    return res.send(renderLogin('<div class="error-msg">Invalid credentials. Please check your username and password.</div>'));
  }
  const userId = rows[0].values[0][0];
  const token = createSession(userId);
  res.cookie('mc_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.mc_session;
  if (token) delete sessions[token];
  res.clearCookie('mc_session');
  res.redirect('/');
});

