function signToken(payload) {
  return jwt.sign(payload, JWT_SECRET, { algorithm: 'HS256', expiresIn: '24h' });
}

function verifyToken(token) {
  try {
    return jwt.verify(token, JWT_SECRET, { algorithms: ['HS256'] });
  } catch {
    return null;
  }
}

function requireAuth(req, res, next) {
  const token = req.cookies?.iot_session;
  if (!token) return res.redirect('/');
  const payload = verifyToken(token);
  if (!payload) { res.clearCookie('iot_session'); return res.redirect('/'); }
  req.user = payload;
  next();
}

function requireEngineer(req, res, next) {
  if (req.user.role !== 'engineer' && req.user.role !== 'admin') {
