const deviceIcons = { Climate:'🌡️', Security:'🔒', Lighting:'💡', Safety:'🔥' };

function initials(name) { return name.split(' ').map(n => n[0]).join(''); }

function statusBadge(s) {
  return `<span class="badge ${s === 'online' ? 'badge-online' : 'badge-offline'}">${esc(s)}</span>`;
}

function logBadge(level) {
  const m = { INFO:'badge-info', WARN:'badge-warn', ALERT:'badge-alert', ERROR:'badge-error' };
  return `<span class="badge ${m[level] || 'badge-info'}">${esc(level)}</span>`;
}

function roleBadge(role) {
  const m = { user:'badge-role-user', engineer:'badge-role-engineer', admin:'badge-role-admin' };
  return `<span class="badge ${m[role] || 'badge-role-user'}">${esc(role)}</span>`;
}

function renderSidebar(activePage, user) {
  const init = initials(user.name || user.username);
  const isEng = user.role === 'engineer' || user.role === 'admin';
  const isAdm = user.role === 'admin';
  return `
    <aside class="sidebar">
      <div class="sidebar-brand">
        <div class="icon-box">🏠</div>
        <h1>Nexus<span>Hub</span></h1>
      </div>
      <nav class="sidebar-nav">
        <div class="section-label">Monitoring</div>
        <a href="/dashboard" class="${activePage==='dashboard'?'active':''}"><span class="icon">📊</span> Dashboard</a>
        <a href="/devices" class="${activePage==='devices'?'active':''}"><span class="icon">📡</span> Devices</a>
        <div class="section-label">System</div>
        <a href="/diagnostics" class="${activePage==='diagnostics'?'active':''} ${isEng?'':'locked'}"><span class="icon">🔧</span> Diagnostics ${isEng?'':'🔒'}</a>
        <a href="/admin/panel" class="${activePage==='admin'?'active':''} ${isAdm?'':'locked'}"><span class="icon">⚙️</span> Admin ${isAdm?'':'🔒'}</a>
        <div class="section-label">Account</div>
        <a href="/session" class="${activePage==='session'?'active':''}"><span class="icon">🔑</span> Session</a>
        <a href="/logout"><span class="icon">🚪</span> Sign Out</a>
      </nav>
      <div class="sidebar-user">
        <div class="avatar">${esc(init)}</div>
        <div class="user-info">
          <div class="user-name">${esc(user.name || user.username)}</div>
          <div class="user-role">${esc(user.role)}</div>
        </div>
      </div>
    </aside>`;
}

function pageShell(title, activePage, user, content) {
  return `<!DOCTYPE html><html lang="en"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0">
<title>${esc(title)} — NexusHub</title><style>${baseStyles}</style>
</head><body class="fade-in">
<div class="app-layout">
  ${renderSidebar(activePage, user)}
  <main class="main-content">${content}</main>
</div></body></html>`;
}

