app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.redirect('/?error=Invalid+credentials');
  const token = signToken({ sub: user.id, username: user.username, name: user.name, role: user.role });
  res.cookie('iot_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.redirect('/?error=All+fields+required');
  if (users.find(u => u.username === username)) return res.redirect('/?error=Username+taken');
  const newUser = { id: nextUserId++, username, password, name, role: 'user' };
  users.push(newUser);
  const token = signToken({ sub: newUser.id, username: newUser.username, name: newUser.name, role: newUser.role });
  res.cookie('iot_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  res.clearCookie('iot_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const devResult = db.exec(`SELECT * FROM devices`);
  const devCount = devResult.length > 0 ? devResult[0].values.length : 0;
  const onlineCount = devResult.length > 0 ? devResult[0].values.filter(r => r[3] === 'online').length : 0;
  const offlineCount = devCount - onlineCount;
  const logResult = db.exec(`SELECT COUNT(*) FROM device_logs WHERE log_level='ALERT' OR log_level='ERROR'`);
  const alertCount = logResult.length > 0 ? logResult[0].values[0][0] : 0;

  const recentLogs = db.exec(`SELECT device_name, log_level, message, timestamp FROM device_logs ORDER BY id DESC LIMIT 6`);
  let logRows = '';
  if (recentLogs.length > 0) {
    logRows = recentLogs[0].values.map(r => `<tr>
      <td style="font-family:var(--font-mono);font-size:0.8rem;">${esc(r[0])}</td>
      <td>${logBadge(r[1])}</td>
      <td>${esc(r[2])}</td>
      <td style="font-family:var(--font-mono);font-size:0.78rem;color:var(--text-muted);">${esc(r[3])}</td>
    </tr>`).join('');
  }

  res.send(pageShell('Dashboard', 'dashboard', req.user, `
    <div class="page-header">
      <h1>Welcome, ${esc((req.user.name || req.user.username).split(' ')[0])}</h1>
      <p class="subtitle">NexusHub IoT Control Panel — System Overview</p>
    </div>
    <div class="stats-row">
      <div class="stat-card"><div class="stat-value">${devCount}</div><div class="stat-label">Total Devices</div></div>
      <div class="stat-card"><div class="stat-value" style="color:var(--accent-green);">${onlineCount}</div><div class="stat-label">Online</div></div>
      <div class="stat-card"><div class="stat-value" style="color:var(--accent-red);">${offlineCount}</div><div class="stat-label">Offline</div></div>
      <div class="stat-card"><div class="stat-value" style="color:var(--accent-amber);">${alertCount}</div><div class="stat-label">Alerts</div></div>
    </div>
    <div class="card">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">Recent Activity</h3>
      <table class="data-table">
        <thead><tr><th>Device</th><th>Level</th><th>Message</th><th>Timestamp</th></tr></thead>
        <tbody>${logRows}</tbody>
      </table>
    </div>
  `));
});

app.get('/devices', requireAuth, (req, res) => {
