app.get('/session', requireAuth, (req, res) => {
  const token = req.cookies?.iot_session;
  const parts = token.split('.');
  let decodedHeader = '{}';
  let decodedPayload = '{}';
  try {
    decodedHeader = JSON.stringify(JSON.parse(Buffer.from(parts[0], 'base64url').toString()), null, 2);
    decodedPayload = JSON.stringify(JSON.parse(Buffer.from(parts[1], 'base64url').toString()), null, 2);
  } catch(e) { /* ignore */ }

  res.send(pageShell('Session', 'session', req.user, `
    <div class="page-header">
      <h1>Session Information</h1>
      <p class="subtitle">Your current authentication token and session details</p>
    </div>
    <div class="card">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:6px;">Current Role</h3>
      <p style="margin-bottom:16px;">${roleBadge(req.user.role)}</p>
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:6px;">Raw JWT Token</h3>
      <div class="token-display">${esc(token)}</div>
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:6px;">Decoded Header</h3>
      <div class="payload-display" style="margin-bottom:16px;">${esc(decodedHeader)}</div>
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:6px;">Decoded Payload</h3>
      <div class="payload-display">${esc(decodedPayload)}</div>
    </div>
    <div class="card" style="border-color:rgba(245,158,11,0.3);">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:8px;color:var(--accent-amber);">⚠ Access Levels</h3>
      <p style="font-size:0.85rem;color:var(--text-secondary);line-height:1.7;">
