app.get('/diagnostics', requireAuth, requireEngineer, (req, res) => {
  const q = req.query.q || '';
  let resultHtml = '';
  let searched = false;

  if (q) {
    searched = true;
    const sql = `SELECT device_name, log_level, message, timestamp FROM device_logs WHERE device_name = '${q}'`;
    try {
      const result = db.exec(sql);
      if (result.length > 0 && result[0].values.length > 0) {
        const rows = result[0].values.map(r => `<tr>
          <td style="font-family:var(--font-mono);font-size:0.8rem;">${esc(String(r[0]))}</td>
          <td>${logBadge(String(r[1]))}</td>
          <td>${esc(String(r[2]))}</td>
          <td style="font-family:var(--font-mono);font-size:0.78rem;color:var(--text-muted);">${esc(String(r[3]))}</td>
        </tr>`).join('');
        resultHtml = `<div class="result-found">✓ Found ${result[0].values.length} log entries</div>
          <table class="data-table">
            <thead><tr><th>Device</th><th>Level</th><th>Message</th><th>Timestamp</th></tr></thead>
            <tbody>${rows}</tbody>
          </table>`;
      } else {
        resultHtml = `<div class="result-empty">No log entries found matching your query.</div>`;
      }
    } catch(e) {
      resultHtml = `<div class="result-error">Query error — check your input syntax.</div>`;
    }
  }

  const deviceNames = db.exec(`SELECT DISTINCT name FROM devices ORDER BY name`);
  let deviceList = '';
  if (deviceNames.length > 0) {
    deviceList = deviceNames[0].values.map(r =>
      `<span style="display:inline-block;padding:3px 10px;background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;font-family:var(--font-mono);font-size:0.75rem;color:var(--text-secondary);margin:3px;">${esc(String(r[0]))}</span>`
