app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.send(renderLogin('Invalid credentials.', ''));
  const token = createSession(user.id);
  res.cookie('nh_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.send(renderLogin('', 'All fields are required.'));
  if (users.find(u => u.username === username)) return res.send(renderLogin('', 'Username already taken.'));
  const initials = name.split(' ').map(w => w[0] || '').join('').toUpperCase().slice(0, 2);
  const newUser = { id: nextUserId++, username, password, name, role: 'Viewer', avatar: initials || 'U' };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('nh_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nh_session;
  if (token) delete sessions[token];
  res.clearCookie('nh_session');
  res.redirect('/');
});

