app.post('/api/firmware/check', requireAuth, async (req, res) => {
  const { url } = req.body;
  if (!url) return res.status(400).json({ error: 'URL is required' });

  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);

    const response = await fetch(url, {
      headers: {
        'User-Agent': 'NexaHome-Hub/4.2',
        'X-Hub-Auth': INTERNAL_TOKEN
      },
      signal: controller.signal,
      redirect: 'follow'
    });

    clearTimeout(timeout);
    const body = await response.text();
    res.json({ status: response.status, body });
  } catch (e) {
    res.json({ error: `Connection failed: ${e.message}` });
  }
});

app.get('/internal/api/query', (req, res) => {
  const hubAuth = req.headers['x-hub-auth'];
  if (!hubAuth || hubAuth !== INTERNAL_TOKEN) {
    return res.status(403).json({
      error: 'ACCESS DENIED',
      message: 'This endpoint is restricted to internal hub services. Direct access is not permitted.',
      required: 'X-Hub-Auth header with valid token'
    });
  }

  const category = req.query.category || 'all';

  let query;
  if (category === 'all') {
    query = `SELECT id, name, type, location, status, firmware_ver FROM devices`;
  } else {
    query = `SELECT id, name, type, location, status, firmware_ver FROM devices WHERE type = '${category}'`;
  }

  try {
    const result = db.exec(query);
    const rows = result.length ? result[0].values : [];
    const columns = result.length ? result[0].columns : [];
    res.json({
      endpoint: 'internal-device-query',
      category,
      columns,
      results: rows
    });
  } catch (e) {
    res.json({
      endpoint: 'internal-device-query',
      category,
      error: `Query error: ${e.message}`,
      columns: [],
      results: []
    });
  }
});

