function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function statusBadge(s) {
  const m = { Online: 'badge-online', Offline: 'badge-offline', Warning: 'badge-warning' };
  return `<span class="badge ${m[s] || 'badge-low'}">${esc(s)}</span>`;
}

function severityBadge(s) {
  const m = { Critical: 'badge-critical', High: 'badge-high', Medium: 'badge-medium', Low: 'badge-low' };
  return `<span class="badge ${m[s] || 'badge-low'}">${esc(s)}</span>`;
}

function roleBadge(r) {
  const m = { admin: 'badge-admin', system: 'badge-system', operator: 'badge-medium', technician: 'badge-low' };
  return `<span class="badge ${m[r] || 'badge-low'}">${esc(r)}</span>`;
}

function buildSidebar(active, user) {
  const init = initials(user.name);
  const adminLink = user.role === 'admin' ? `
    <div class="section-label">Administration</div>
    <a href="/admin/users" class="${active === 'admin' ? 'active' : ''}"><span class="ic">👤</span> User Management</a>` : '';
  return `
  <aside class="sidebar">
    <div class="sidebar-brand">
      <div class="icon-box">🏠</div>
      <h1>Nexa<span>Home</span></h1>
    </div>
    <nav class="sidebar-nav">
      <div class="section-label">Monitoring</div>
      <a href="/dashboard" class="${active === 'dashboard' ? 'active' : ''}"><span class="ic">📊</span> Dashboard</a>
      <a href="/devices" class="${active === 'devices' ? 'active' : ''}"><span class="ic">📡</span> Devices</a>
      <a href="/logs" class="${active === 'logs' ? 'active' : ''}"><span class="ic">📝</span> Device Logs</a>
      <div class="section-label">Resources</div>
      <a href="/api/docs" class="${active === 'docs' ? 'active' : ''}"><span class="ic">📖</span> API Docs</a>
      ${adminLink}
      <div style="flex:1;"></div>
      <a href="/logout"><span class="ic">🚪</span> Sign Out</a>
    </nav>
    <div class="sidebar-user">
      <div class="avatar">${init}</div>
      <div class="uinfo">
        <div class="uname">${esc(user.name)}</div>
        <div class="urole">${esc(user.role)}</div>
      </div>
    </div>
  </aside>`;
}

function pageShell(title, active, user, content) {
  return `<!DOCTYPE html><html lang="en"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0">
<title>${esc(title)} — NexaHome</title>
<style>${baseStyles}</style>
</head><body class="fade-in">
<div class="app-layout">
  ${buildSidebar(active, user)}
  <main class="main-content">${content}</main>
</div>
</body></html>`;
}

app.get('/', (req, res) => {
  const user = getSessionUser(req);
  if (user) return res.redirect('/dashboard');
  const err = req.query.error;
  const ok = req.query.registered;
  let errHtml = '';
  let okHtml = '';
  if (err === '1') errHtml = '<div class="error-msg">Invalid credentials.</div>';
  if (err === '2') errHtml = '<div class="error-msg">All fields are required.</div>';
  if (err === '3') errHtml = '<div class="error-msg">Username already exists.</div>';
  if (ok === '1') okHtml = '<div class="success-msg">Account created! Sign in below.</div>';

  res.send(`<!DOCTYPE html><html lang="en"><head>
