app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.redirect('/?error=1');
  const token = makeSession(user.id);
  res.cookie('iot_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.redirect('/?error=2');
  if (users.find(u => u.username === username)) return res.redirect('/?error=3');
  const newUser = {
    id: nextUserId++, username, password, name, role: 'operator',
    department: 'Field Ops', email: username + '@nexahome.io',
    joined: new Date().toISOString().split('T')[0],
    privateConfig: { recoveryKey: 'nxa_rec_new_' + crypto.randomBytes(4).toString('hex'), firmwareToken: null, notes: 'New operator account.' }
  };
  users.push(newUser);
  res.redirect('/?registered=1');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.iot_session;
  if (token) delete sessions[token];
  res.clearCookie('iot_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const online = devices.filter(d => d.status === 'Online').length;
