      <td>${severityBadge(l.severity)}</td>
      <td style="font-size:.82rem;">${esc(l.content.substring(0, 80))}${l.content.length > 80 ? '...' : ''}</td>
    </tr>`).join('');

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header">
      <h1>Welcome, ${esc(user.name.split(' ')[0])}</h1>
