      <div class="stat-card"><div class="sv" style="color:var(--accent-red);">${offline}</div><div class="sl">Offline</div></div>
      <div class="stat-card"><div class="sv" style="color:var(--accent-amber);">${warnings}</div><div class="sl">Warnings</div></div>
    </div>
