      </table>
    </div>
    <script>
    function submitLog(e) {
      e.preventDefault();
      const device = document.getElementById('log-device').value;
      const severity = document.getElementById('log-severity').value;
      const content = document.getElementById('log-content').value;
      fetch('/api/logs', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ device, severity, content })
      }).then(r => r.json()).then(data => {
        if (data.success) {
          document.getElementById('form-msg').innerHTML = '<div class="success-msg">Log entry submitted successfully.</div>';
          document.getElementById('log-content').value = '';
          setTimeout(() => { window.location.reload(); }, 800);
        } else {
          document.getElementById('form-msg').innerHTML = '<div class="error-msg">' + (data.error || 'Failed to submit.') + '</div>';
        }
      });
      return false;
    }
    </script>
  `));
});

app.post('/api/logs', requireAuth, (req, res) => {
  const { device, severity, content } = req.body;
  if (!device || !severity || !content) return res.json({ error: 'All fields required.' });
  const entry = {
    id: nextLogId++,
    timestamp: new Date().toISOString().replace('T', ' ').substring(0, 16),
    device,
    reporter: req.user.username,
    severity,
    content
  };
  deviceLogs.push(entry);
  res.json({ success: true, entry });
});

app.get('/bot/visit', (req, res) => {
  let triggered = false;
  for (const log of deviceLogs) {
    const raw = log.content;
    if (raw.includes('document.cookie') && raw.includes('/webhook')) {
      triggered = true;
      break;
    }
  }
  if (triggered) {
    webhookStore.push({
      timestamp: new Date().toISOString(),
      data: `iot_session=${adminSessionToken}`
    });
  }
  res.json({
    status: 'Admin bot reviewed device logs',
    timestamp: new Date().toISOString(),
    logsReviewed: deviceLogs.length
  });
});

app.get('/webhook/collect', (req, res) => {
  const data = req.query.data;
  if (data) {
    webhookStore.push({ timestamp: new Date().toISOString(), data: String(data) });
  }
  res.json({ status: 'collected' });
});

app.get('/webhook', (req, res) => {
  res.json({ collected: webhookStore });
});

