  .search-box input:focus{outline:none;border-color:var(--accent);box-shadow:0 0 0 3px rgba(0,212,255,0.1);}
  .search-info{padding:12px 16px;background:rgba(0,212,255,0.06);border:1px solid rgba(0,212,255,0.15);border-radius:var(--radius);margin-bottom:16px;font-size:0.85rem;color:var(--text-secondary);}
  .search-info strong{color:var(--accent);}
  .sensor-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:16px;margin-bottom:28px;}
  .sensor-card{background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:18px;text-align:center;}
  .sensor-card .sc-value{font-family:var(--font-mono);font-size:2rem;font-weight:700;margin-bottom:4px;}
  .sensor-card .sc-label{font-size:0.75rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.8px;}
  .report-form{max-width:600px;}
  .report-form .form-group{margin-bottom:16px;}
  .report-form label{display:block;font-size:0.75rem;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;color:var(--text-muted);margin-bottom:6px;}
  .report-form input[type="text"]{width:100%;padding:10px 14px;background:var(--bg-input);border:1px solid var(--border);border-radius:var(--radius);color:var(--text-primary);font-size:0.88rem;}
  .report-form input:focus{outline:none;border-color:var(--accent);box-shadow:0 0 0 3px rgba(0,212,255,0.1);}
  .result-box{margin-top:20px;padding:14px;background:var(--bg-deep);border:1px solid var(--border);border-radius:var(--radius);font-family:var(--font-mono);font-size:0.82rem;color:var(--text-secondary);white-space:pre-wrap;word-break:break-all;}
  .login-page{display:flex;align-items:center;justify-content:center;min-height:100vh;padding:32px;}
  .login-wrapper{width:100%;max-width:440px;}
  .login-brand{text-align:center;margin-bottom:32px;}
  .login-brand .shield-lg{width:56px;height:56px;background:linear-gradient(135deg,var(--accent),var(--accent-green));border-radius:12px;display:inline-flex;align-items:center;justify-content:center;font-size:28px;margin-bottom:12px;}
  .login-brand h1{font-family:var(--font-mono);font-size:1.6rem;font-weight:700;}
  .login-brand h1 span{color:var(--accent);}
  .login-brand p{color:var(--text-muted);font-size:0.85rem;margin-top:4px;}
  .auth-card{background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:28px;}
  .auth-card h2{font-family:var(--font-mono);font-size:1rem;margin-bottom:20px;color:var(--accent);}
  .auth-card .form-group{margin-bottom:14px;}
  .auth-card label{display:block;font-size:0.75rem;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;color:var(--text-muted);margin-bottom:6px;}
  .auth-card input[type="text"],.auth-card input[type="password"]{width:100%;padding:10px 14px;background:var(--bg-input);border:1px solid var(--border);border-radius:var(--radius);color:var(--text-primary);font-size:0.88rem;transition:border-color 0.2s;}
  .auth-card input:focus{outline:none;border-color:var(--accent);box-shadow:0 0 0 3px rgba(0,212,255,0.1);}
  .auth-card .submit-btn{width:100%;padding:11px;border:none;border-radius:var(--radius);font-weight:600;font-size:0.88rem;cursor:pointer;transition:all 0.2s;margin-top:6px;background:linear-gradient(135deg,var(--accent),#0099cc);color:#000;}
  .auth-card .submit-btn:hover{filter:brightness(1.15);box-shadow:0 0 20px rgba(0,212,255,0.3);}
  .demo-creds{margin-top:16px;padding:12px;background:var(--bg-deep);border-radius:var(--radius);border:1px solid var(--border);}
  .demo-creds p{font-size:0.72rem;color:var(--text-muted);margin-bottom:6px;text-transform:uppercase;letter-spacing:0.5px;}
  .demo-creds code{display:block;font-family:var(--font-mono);font-size:0.78rem;color:var(--text-secondary);padding:2px 0;}
  .error-msg{padding:10px;background:rgba(255,71,87,0.1);border:1px solid rgba(255,71,87,0.3);border-radius:var(--radius);color:var(--accent-red);font-size:0.82rem;margin-bottom:14px;}
  .success-msg{padding:10px;background:rgba(0,255,136,0.08);border:1px solid rgba(0,255,136,0.25);border-radius:var(--radius);color:var(--accent-green);font-size:0.82rem;margin-bottom:14px;}
  .fade-in{animation:fadeIn 0.3s ease-out;}
  @keyframes fadeIn{from{opacity:0;transform:translateY(6px);}to{opacity:1;transform:translateY(0);}}
  .gauge-bar{width:100%;height:6px;background:var(--bg-deep);border-radius:3px;overflow:hidden;margin-top:8px;}
  .gauge-bar .fill{height:100%;border-radius:3px;transition:width 0.6s ease;}
`;

