app.get('/devices', requireAuth, (req, res) => {
  const user = req.user;

  const deviceCardsHTML = devices.map(d => {
    const batteryHTML = d.battery
      ? `<span>🔋 ${esc(d.battery)}</span>`
      : `<span>⚡ Powered</span>`;
    return `<div class="device-card" data-name="${esc(d.name)}" data-type="${esc(d.type)}" data-location="${esc(d.location)}">
      <div class="dc-header">
        <span class="dc-icon">${d.icon}</span>
        <span class="badge badge-${d.status}">${d.status}</span>
      </div>
      <div class="dc-name">${esc(d.name)}</div>
      <div class="dc-location">${esc(d.location)} · ${esc(d.type)}</div>
      <div class="dc-value">${esc(d.value)}</div>
      <div class="dc-meta">
        ${batteryHTML}
        <span>${esc(d.firmware)}</span>
      </div>
    </div>`;
  }).join('');

  res.send(pageShell('Devices', 'devices', user, `
    <div class="page-header">
      <h1>Connected Devices</h1>
      <p class="subtitle">Manage and monitor all IoT devices in your network</p>
    </div>
    <div class="search-box">
      <input type="text" id="search-input" placeholder="Search devices by name, type, or location..." autocomplete="off">
      <button class="btn btn-primary" onclick="performSearch()">Search</button>
    </div>
    <div id="search-results"></div>
    <div id="device-grid" class="device-grid">
      ${deviceCardsHTML}
    </div>
    <script>
      const allDeviceCards = document.querySelectorAll('.device-card');
      const allDevicesHTML = document.getElementById('device-grid').innerHTML;

      function performSearch() {
        const q = document.getElementById('search-input').value.trim();
        if (q) {
          const newUrl = window.location.pathname + '?q=' + encodeURIComponent(q);
          window.history.pushState({}, '', newUrl);
          applyFilter(q);
        } else {
          window.history.pushState({}, '', window.location.pathname);
          document.getElementById('search-results').innerHTML = '';
          document.getElementById('device-grid').innerHTML = allDevicesHTML;
        }
      }

      function applyFilter(query) {
        var resultsDiv = document.getElementById('search-results');
        var gridDiv = document.getElementById('device-grid');
        resultsDiv.innerHTML = '<div class="search-info">Showing results for: <strong>' + query + '</strong></div>';
        var lower = query.toLowerCase();
        var filtered = [];
        allDeviceCards.forEach(function(card) {
          var name = card.getAttribute('data-name').toLowerCase();
          var type = card.getAttribute('data-type').toLowerCase();
          var loc = card.getAttribute('data-location').toLowerCase();
          if (name.includes(lower) || type.includes(lower) || loc.includes(lower)) {
            filtered.push(card.outerHTML);
          }
        });
        if (filtered.length > 0) {
          gridDiv.innerHTML = filtered.join('');
        } else {
          gridDiv.innerHTML = '<div style="text-align:center;padding:40px;color:var(--text-muted);">No devices found matching your search.</div>';
        }
      }

      (function() {
        var params = new URLSearchParams(window.location.search);
        var q = params.get('q');
        if (q) {
          document.getElementById('search-input').value = q;
          applyFilter(q);
        }
      })();

      document.getElementById('search-input').addEventListener('keypress', function(e) {
        if (e.key === 'Enter') performSearch();
      });
    </script>
  `));
});

