app.get('/report', requireAuth, (req, res) => {
  const user = req.user;
  res.send(pageShell('Report Link', 'report', user, `
    <div class="page-header">
      <h1>Report Suspicious Link</h1>
      <p class="subtitle">Submit a device configuration or dashboard link for the administrator to review</p>
    </div>
    <div class="card">
      <div class="report-form">
        <p style="font-size:0.85rem;color:var(--text-secondary);margin-bottom:18px;line-height:1.7;">
          If you encounter a suspicious device link or misconfigured dashboard URL, submit it here.
          The system administrator will review the link in their browser session.
        </p>
        <div class="form-group">
          <label>URL to Report</label>
          <input type="text" id="report-url" placeholder="e.g. /devices?q=thermostat" autocomplete="off">
        </div>
        <button class="btn btn-primary" id="submit-report" onclick="submitReport()">Submit to Admin</button>
        <div id="report-status" style="margin-top:16px;"></div>
      </div>
    </div>
    <div class="card" style="margin-top:20px;">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">📥 Data Collector</h3>
      <p style="font-size:0.82rem;color:var(--text-muted);margin-bottom:14px;">
        Any data sent to <code style="font-family:var(--font-mono);color:var(--accent);font-size:0.82rem;">/api/collect?data=...</code> will appear below.
        This endpoint is used for monitoring and diagnostics.
      </p>
      <button class="btn btn-ghost" style="cursor:pointer;margin-bottom:14px;" onclick="refreshCollections()">Refresh Collections</button>
      <div id="collections" class="result-box" style="min-height:60px;color:var(--text-muted);">No data collected yet.</div>
    </div>
    <script>
      function submitReport() {
        var url = document.getElementById('report-url').value.trim();
        if (!url) return;
        var statusDiv = document.getElementById('report-status');
        statusDiv.innerHTML = '<div style="color:var(--text-muted);font-size:0.85rem;">⏳ Submitting to admin...</div>';
        fetch('/api/admin/report-link', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ url: url })
        })
        .then(function(r) { return r.json(); })
        .then(function(data) {
          if (data.error) {
            statusDiv.innerHTML = '<div class="error-msg">' + data.error + '</div>';
          } else {
            statusDiv.innerHTML = '<div class="success-msg">' + data.message + '</div>';
          }
        })
        .catch(function() {
          statusDiv.innerHTML = '<div class="error-msg">Network error. Try again.</div>';
        });
      }

      function refreshCollections() {
        fetch('/api/collections')
          .then(function(r) { return r.json(); })
          .then(function(data) {
            var el = document.getElementById('collections');
            if (data.collections && data.collections.length > 0) {
              el.innerHTML = data.collections.map(function(c, i) {
                return '[' + i + '] ' + c.timestamp + '\\n    ' + c.data;
              }).join('\\n\\n');
              el.style.color = 'var(--accent-green)';
            } else {
              el.innerHTML = 'No data collected yet.';
              el.style.color = 'var(--text-muted)';
            }
          });
      }
    </script>
  `));
});

app.get('/api/collect', (req, res) => {
  const data = req.query.data;
  if (data) {
    collectedData.push({
      timestamp: new Date().toISOString(),
      data: data,
    });
  }
  res.status(200).json({ status: 'ok' });
});

app.get('/api/collections', requireAuth, (req, res) => {
  res.json({ collections: collectedData });
});

app.post('/api/admin/report-link', requireAuth, (req, res) => {
  const { url } = req.body;
  if (!url || typeof url !== 'string') {
    return res.status(400).json({ error: 'Please provide a valid URL.' });
  }

  let parsedUrl;
  try {
    if (url.startsWith('/')) {
      parsedUrl = new URL(url, 'http://localhost:3000');
    } else {
      parsedUrl = new URL(url);
    }
  } catch (e) {
    return res.status(400).json({ error: 'Invalid URL format. Example: /devices?q=thermostat' });
  }

  const pathname = parsedUrl.pathname;
  const qParam = parsedUrl.searchParams.get('q') || '';

  if (!pathname.startsWith('/devices') || !qParam) {
    return res.json({
      status: 'reviewed',
      message: 'The admin reviewed the link. No actionable content found.',
    });
  }

  const rawPayload = decodeURIComponent(qParam);

  const hasXSSTrigger = /<[^>]+\bon\w+\s*=/i.test(rawPayload) || /<script[\s>]/i.test(rawPayload);
  const accessesCookies = rawPayload.includes('document.cookie');
  const sendsToCollect = rawPayload.includes('/api/collect');

  if (hasXSSTrigger && accessesCookies && sendsToCollect) {
    const adminCookieString = `nhub_session=${adminSessionToken}; device_master_key=${flag}`;
    collectedData.push({
      timestamp: new Date().toISOString(),
      data: adminCookieString,
    });
    return res.json({
      status: 'reviewed',
      message: 'The admin opened the link in their browser. Review complete.',
    });
  }

  if (hasXSSTrigger) {
    return res.json({
      status: 'reviewed',
      message: 'The admin opened the link. The page rendered but no data was exfiltrated.',
    });
  }

  res.json({
    status: 'reviewed',
    message: 'The admin reviewed the link. Looks like a normal device search.',
  });
});

