function signToken(user) {
  return jwt.sign({ id: user.id, username: user.username, name: user.name, role: user.role }, JWT_KEY, { algorithm: 'HS256', expiresIn: '24h' });
}

function verifyToken(token) {
  try {
    return jwt.verify(token, JWT_KEY, { algorithms: ['HS256'] });
  } catch (e) {
    return null;
  }
}

function requireAuth(req, res, next) {
  const token = req.cookies?.tf_session;
  if (!token) return res.redirect('/');
  const payload = verifyToken(token);
  if (!payload) return res.redirect('/');
  req.user = payload;
  next();
}

function requireRecruiter(req, res, next) {
  const token = req.cookies?.tf_session;
  if (!token) return res.redirect('/');
  const payload = verifyToken(token);
  if (!payload) return res.redirect('/');
  req.user = payload;
  if (payload.role !== 'recruiter' && payload.role !== 'admin') {
    return res.status(403).send(pageShell('Access Denied', 'recruiter', payload, `
      <div class="page-header"><h1>Access Denied</h1><p class="subtitle">Recruiter clearance required</p></div>
      <div class="card" style="max-width:560px;">
        <div style="text-align:center;padding:32px 0;">
          <div style="font-size:48px;margin-bottom:16px;">🔒</div>
