          <p style="color:var(--text-muted);font-size:0.85rem;margin-bottom:20px;">
            This area is restricted to users with the <code style="font-family:var(--font-mono);color:var(--accent);background:var(--accent-dim);padding:2px 6px;border-radius:3px;">recruiter</code> role.<br>
            Your current role: <code style="font-family:var(--font-mono);color:var(--accent-amber);background:rgba(245,158,11,0.1);padding:2px 6px;border-radius:3px;">${esc(payload.role)}</code>
          </p>
          <a href="/dashboard" class="btn btn-primary">← Back to Dashboard</a>
        </div>
      </div>
    `));
  }
  next();
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

