app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) return res.redirect('/?error=fields');
  const results = db.exec("SELECT id, username, password, name, role FROM users WHERE username = ? AND password = ?", [username, password]);
  if (!results.length || !results[0].values.length) return res.redirect('/?error=invalid');
  const row = results[0].values[0];
  const user = { id: row[0], username: row[1], name: row[3], role: row[4] };
  const token = signToken(user);
  res.cookie('tf_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.redirect('/?error=fields');
  const existing = db.exec("SELECT id FROM users WHERE username = ?", [username]);
  if (existing.length && existing[0].values.length) return res.redirect('/?error=taken');
  db.run("INSERT INTO users (username, password, name, role) VALUES (?, ?, ?, 'candidate')", [username, password, name]);
  return res.redirect('/?success=registered');
});

app.get('/logout', (req, res) => {
  res.clearCookie('tf_session');
  res.redirect('/');
});

