app.get('/session', requireAuth, (req, res) => {
  const user = req.user;
  const rawToken = req.cookies?.tf_session || '';
  let decoded = {};
  try {
    const parts = rawToken.split('.');
    if (parts.length === 3) {
      decoded = JSON.parse(Buffer.from(parts[1], 'base64url').toString());
    }
  } catch (e) {
    decoded = { error: 'Could not decode' };
  }

  res.send(pageShell('My Session', 'session', user, `
