app.get('/api/recruiter/candidates', requireRecruiter, (req, res) => {
  const department = req.query.department || '';
  if (!department) return res.json({ found: false, count: 0, candidates: [], message: 'Provide a department parameter' });

  try {
    const sql = `SELECT id, name, email, department, skills, experience, status FROM candidates WHERE department = '${department}'`;
    const results = db.exec(sql);

    if (results.length && results[0].values.length) {
      const candidates = results[0].values.map(r => ({
        id: r[0], name: r[1], email: r[2], department: r[3], skills: r[4], experience: r[5], status: r[6]
      }));
      return res.json({ found: true, count: candidates.length, candidates });
    }
    return res.json({ found: false, count: 0, candidates: [] });
  } catch (e) {
    return res.json({ found: false, count: 0, candidates: [], error: 'Query error' });
  }
});

