function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSessionUser(req) {
  const token = req.cookies?.hv_session;
  if (!token || !sessions[token]) return null;
  return users.find(u => u.id === sessions[token]) || null;
}

function requireAuth(req, res, next) {
  const user = getSessionUser(req);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function requireAdmin(req, res, next) {
  const user = getSessionUser(req);
  if (!user) return res.redirect('/');
  if (user.role !== 'admin') return res.status(403).send(pageShell('Access Denied', 'dashboard', user, '<div class="page-header"><h1>Access Denied</h1><p class="subtitle">Administrator privileges required.</p></div>'));
  req.user = user;
  next();
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

