app.get('/', (req, res) => {
  const user = getSessionUser(req);
  if (user) return res.redirect('/dashboard');
  res.send(loginPageTemplate.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password && u.status === 'active');
  if (!user) return res.send(loginPageTemplate.replace('%%LOGIN_MSG%%', '<div class="error-msg">Invalid credentials.</div>').replace('%%REG_MSG%%', ''));
  const token = createSession(user.id);
  res.cookie('hv_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.send(loginPageTemplate.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', '<div class="error-msg">All fields required.</div>'));
  if (users.find(u => u.username === username)) return res.send(loginPageTemplate.replace('%%LOGIN_MSG%%', '').replace('%%REG_MSG%%', '<div class="error-msg">Username taken.</div>'));
  const newUser = { id: nextUserId++, username, password, name, role: 'candidate', status: 'active', email: username + '@hirevault.io', location: 'Not specified', skills: [], bio: 'New candidate.', confidentialNotes: 'Pending review.', appliedJobs: [] };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('hv_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.hv_session;
  if (token) delete sessions[token];
  res.clearCookie('hv_session');
  res.redirect('/');
});

