app.post('/api/apply', requireAuth, (req, res) => {
  const user = req.user;
  if (user.role !== 'candidate') return res.json({ error: 'Only candidates can apply.' });
  const { jobId, message } = req.body;
  const job = jobs.find(j => j.id === jobId);
  if (!job) return res.json({ error: 'Job not found.' });
  if (applications.some(a => a.candidateId === user.id && a.jobId === jobId)) return res.json({ error: 'Already applied.' });
  if (!message || !message.trim()) return res.json({ error: 'Message is required.' });

  const app_entry = { id: nextAppId++, jobId, candidateId: user.id, candidateName: user.name, message: message, date: new Date().toISOString().split('T')[0] };
  applications.push(app_entry);
  user.appliedJobs.push(jobId);
  res.json({ success: true, applicationId: app_entry.id });
});

