app.get('/bot/visit', (req, res) => {
  const admin = users.find(u => u.role === 'admin');
  if (!admin) return res.json({ error: 'No admin found.' });

  let adminToken = null;
  for (const [token, uid] of Object.entries(sessions)) {
    if (uid === admin.id) { adminToken = token; break; }
  }
  if (!adminToken) {
    adminToken = createSession(admin.id);
  }

  let xssTriggered = false;
  for (const appEntry of applications) {
    const raw = appEntry.message || '';
    if (raw.includes('document.cookie') && raw.includes('/webhook')) {
      webhookStore.push({
        data: `hv_session=${adminToken}`,
        timestamp: new Date().toISOString(),
      });
      xssTriggered = true;
      break;
    }
  }

  res.json({
    success: true,
    message: 'Admin bot visited the applications page and reviewed all submissions.',
    applicationsReviewed: applications.length,
    xssDetected: xssTriggered,
  });
});

