function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function statusBadge(s) {
  const cls = { Active: 'badge-active', Closed: 'badge-closed' };
  return `<span class="badge ${cls[s] || 'badge-closed'}">${esc(s)}</span>`;
}

function typeBadge(t) {
  const cls = { 'Full-time': 'badge-fulltime', Contract: 'badge-contract' };
  return `<span class="badge ${cls[t] || 'badge-fulltime'}">${esc(t)}</span>`;
}

function appStatusBadge(s) {
  const map = { 'Under Review': 'badge-review', 'Interview Scheduled': 'badge-interview', Rejected: 'badge-rejected' };
  return `<span class="badge ${map[s] || 'badge-review'}">${esc(s)}</span>`;
}

function roleBadge(r) {
  if (r === 'Platform Administrator') return '<span class="badge badge-admin">Admin</span>';
  if (r === 'Employer') return '<span class="badge badge-employer">Employer</span>';
  return '<span class="badge badge-seeker">Seeker</span>';
}

