app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) {
    return res.send(renderLogin('<div class="error-msg">Please enter both username and password.</div>'));
  }

  const query = `SELECT * FROM users WHERE username = '${username}' AND password = '${password}'`;

  try {
    const result = db.exec(query);

    if (result.length === 0 || result[0].values.length === 0) {
      return res.send(renderLogin('<div class="error-msg">Invalid credentials. Please try again.</div>'));
    }

    const cols = result[0].columns;
    const row = result[0].values[0];
    const user = {};
    cols.forEach((c, i) => user[c] = row[i]);

    const token = createSession(user.id, user.role);
    res.cookie('hh_session', token, { httpOnly: false, sameSite: 'lax' });
    res.redirect('/dashboard');
  } catch (e) {
    return res.send(renderLogin('<div class="error-msg">Authentication error. Please check your input.</div>'));
  }
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.hh_session;
  if (token) delete sessions[token];
  res.clearCookie('hh_session');
  res.redirect('/');
});

