  'Head Librarian': 'linear-gradient(135deg, #d4a574, #c9944a)',
  'Senior Librarian': 'linear-gradient(135deg, #5b8fd9, #6366f1)',
  'Research Member': 'linear-gradient(135deg, #a78bfa, #8b5cf6)',
};

function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function collectionBadge(c) {
  if (c === 'Vault Collection') return '<span class="badge badge-vault">🔒 Vault</span>';
  if (c === 'Rare Books') return '<span class="badge badge-rare">Rare</span>';
  if (c === 'Special Collections') return '<span class="badge badge-special">Special</span>';
  return '<span class="badge badge-general">General</span>';
}

function statusBadge(s) {
  const m = { submitted: 'badge-submitted', reviewed: 'badge-reviewed', approved: 'badge-approved', fulfilled: 'badge-fulfilled' };
  return `<span class="badge ${m[s] || 'badge-submitted'}">${esc(s)}</span>`;
}

