function pageShell(title, activePage, user, content) {
  return `<!DOCTYPE html>
<html lang="en"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${esc(title)} — Thornfield Library</title>
<style>${baseStyles}</style>
</head><body class="fade-in">
<div class="app-layout">
  ${renderSidebar(activePage, user)}
  <main class="main-content">${content}</main>
</div>
</body></html>`;
}

function renderWorkflowSteps(status) {
  const order = ['submitted', 'reviewed', 'approved', 'fulfilled'];
  const currentIdx = order.indexOf(status);
  let html = '<div class="workflow-steps">';
  const labels = ['Submit', 'Review', 'Approve', 'Execute'];
  for (let i = 0; i < 4; i++) {
    if (i > 0) html += `<div class="wf-connector${i <= currentIdx ? ' done' : ''}"></div>`;
    const cls = i < currentIdx ? 'done' : i === currentIdx ? 'active' : '';
    html += `<div class="wf-step ${cls}"><div class="step-num">${i + 1}</div><div class="step-label">${labels[i]}</div></div>`;
  }
  html += '</div>';
  return html;
}

