app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.send(renderLoginPage('Invalid credentials.', ''));
  const token = createSession(user.id);
  res.cookie('tfl_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.send(renderLoginPage('', 'All fields required.'));
  if (users.find(u => u.username === username)) return res.send(renderLoginPage('', 'Username taken.'));
  const newUser = {
    id: nextUserId++, username, password, name,
    role: 'Research Member', department: 'External',
    email: username + '@thornfield.lib', joined: new Date().toISOString().split('T')[0],
    permissions: ['submit'], bio: 'New library member.'
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('tfl_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.tfl_session;
  if (token) delete sessions[token];
  res.clearCookie('tfl_session');
  res.redirect('/');
});

