app.get('/requests/:id', requireAuth, (req, res) => {
  const user = req.user;
  const r = requests.find(x => x.id === req.params.id);
  if (!r) return res.send(pageShell('Not Found', 'requests', user, '<div class="page-header"><h1>Request Not Found</h1></div>'));

  const item = catalog.find(b => b.id === r.itemId);
  const canReview = user.permissions.includes('review') && r.status === 'submitted';
  const canApprove = user.permissions.includes('approve') && r.status === 'reviewed';
  const canExecute = user.permissions.includes('execute') && r.status === 'approved';

  res.send(pageShell(r.id, 'requests', user, `
    <div class="page-header">
      <h1>${esc(r.id)}</h1>
      <p class="subtitle">${esc(r.title)}</p>
    </div>
    ${renderWorkflowSteps(r.status)}
    <div class="card" style="margin-bottom:20px;">
      <div class="card-title">Request Details</div>
      <div class="detail-grid">
        <div class="detail-item"><label>Status</label><span>${statusBadge(r.status)}</span></div>
        <div class="detail-item"><label>Submitted By</label><span>${esc(r.submittedBy)}</span></div>
        <div class="detail-item"><label>Item</label><span>${item ? esc(item.title) : esc(r.itemId)}</span></div>
        <div class="detail-item"><label>Collection</label><span>${item ? collectionBadge(item.collection) : 'N/A'}</span></div>
        <div class="detail-item"><label>Submitted</label><span>${esc(r.submittedAt.split('T')[0])}</span></div>
        <div class="detail-item"><label>Reviewed By</label><span>${r.reviewedBy ? esc(r.reviewedBy) : '—'}</span></div>
        <div class="detail-item"><label>Approved By</label><span>${r.approvedBy ? esc(r.approvedBy) : '—'}</span></div>
        <div class="detail-item"><label>Executed By</label><span>${r.executedBy ? esc(r.executedBy) : '—'}</span></div>
      </div>
      <div style="margin-top:16px;">
        <label style="display:block;font-size:0.68rem;text-transform:uppercase;letter-spacing:0.8px;color:var(--text-muted);margin-bottom:4px;">Purpose</label>
        <p style="font-size:0.85rem;color:var(--text-secondary);line-height:1.7;">${esc(r.purpose)}</p>
      </div>
    </div>
    <div class="card">
      <div class="card-title">Workflow Actions</div>
      <div style="display:flex;gap:12px;flex-wrap:wrap;">
        ${canReview
          ? `<button class="btn btn-blue" onclick="doAction('review')">✓ Mark as Reviewed</button>`
          : `<span class="btn btn-disabled">Review ${r.status === 'submitted' ? '(requires Senior Librarian)' : '(done)'}</span>`}
        ${canApprove
          ? `<button class="btn btn-primary" onclick="doAction('approve')">✓ Approve Request</button>`
          : `<span class="btn btn-disabled">Approve ${r.status === 'reviewed' ? '(requires Head Librarian)' : r.status === 'submitted' ? '(needs review first)' : '(done)'}</span>`}
        ${canExecute
          ? `<button class="btn btn-green" onclick="doAction('execute')">⚡ Execute / Fulfill</button>`
          : `<span class="btn btn-disabled">Execute ${r.status === 'approved' ? '(requires Head Librarian)' : r.status === 'fulfilled' ? '(done)' : '(needs approval first)'}</span>`}
      </div>
      <div id="actionResult" style="margin-top:14px;"></div>
    </div>
    <div style="margin-top:16px;"><a href="/requests" class="btn btn-ghost-active">← Back to Requests</a></div>
    <script>
      async function doAction(action) {
        const res = await fetch('/api/requests/${esc(r.id)}/' + action, { method: 'POST' });
        const data = await res.json();
        if (data.success) {
          document.getElementById('actionResult').innerHTML = '<div class="success-msg">' + (data.message || 'Done!') + (data.materials ? '<br><br><strong>Materials:</strong><pre style="margin-top:8px;white-space:pre-wrap;font-family:var(--font-mono);font-size:0.82rem;color:var(--accent);">' + JSON.stringify(data.materials, null, 2) + '</pre>' : '') + '</div>';
          setTimeout(() => location.reload(), 1500);
        } else {
          document.getElementById('actionResult').innerHTML = '<div class="error-msg">' + (data.error || 'Error') + '</div>';
        }
      }
    </script>
  `));
});

