});

app.post('/api/requests', requireAuthAPI, (req, res) => {
  const { itemId, title, purpose } = req.body;
  if (!itemId || !title || !purpose) return res.status(400).json({ error: 'Missing required fields: itemId, title, purpose' });

  const item = catalog.find(b => b.id === itemId);
  if (!item) return res.status(404).json({ error: 'Catalog item not found' });

  const newReq = {
    id: 'REQ-' + (requestIdCounter++),
    submittedBy: req.user.username,
    itemId,
    title,
    purpose,
    status: 'submitted',
    submittedAt: new Date().toISOString(),
    reviewedBy: null, reviewedAt: null,
    approvedBy: null, approvedAt: null,
    executedBy: null, executedAt: null
  };
  requests.push(newReq);
  res.json({ success: true, request: { id: newReq.id, status: newReq.status } });
});

app.post('/api/requests/:id/review', requireAuthAPI, (req, res) => {
  const r = requests.find(x => x.id === req.params.id);
  if (!r) return res.status(404).json({ error: 'Request not found' });

  if (!req.user.permissions.includes('review')) {
    return res.status(403).json({ error: 'ACCESS DENIED: You do not have review permissions. Requires Senior Librarian role or above.' });
  }
  if (r.status !== 'submitted') {
    return res.status(400).json({ error: `Cannot review: request is currently "${r.status}". Only submitted requests can be reviewed.` });
  }

  r.status = 'reviewed';
  r.reviewedBy = req.user.username;
  r.reviewedAt = new Date().toISOString();
  res.json({ success: true, message: `Request ${r.id} marked as reviewed.`, status: r.status });
});

app.post('/api/requests/:id/approve', requireAuthAPI, (req, res) => {
  const r = requests.find(x => x.id === req.params.id);
  if (!r) return res.status(404).json({ error: 'Request not found' });

  if (!req.user.permissions.includes('approve')) {
    return res.status(403).json({ error: 'ACCESS DENIED: You do not have approval permissions. Requires Head Librarian role.' });
  }
  if (r.status !== 'reviewed') {
    return res.status(400).json({ error: `Cannot approve: request is currently "${r.status}". Only reviewed requests can be approved.` });
  }

  r.status = 'approved';
  r.approvedBy = req.user.username;
  r.approvedAt = new Date().toISOString();
  res.json({ success: true, message: `Request ${r.id} approved.`, status: r.status });
});

app.post('/api/requests/:id/execute', requireAuthAPI, (req, res) => {
  const r = requests.find(x => x.id === req.params.id);
  if (!r) return res.status(404).json({ error: 'Request not found' });

  r.status = 'fulfilled';
  r.executedBy = req.user.username;
  r.executedAt = new Date().toISOString();

  const item = catalog.find(b => b.id === r.itemId);
  if (item && item.collection === 'Vault Collection') {
    const vaultContents = {
      'BK-006': { title: 'Gutenberg Bible Fragment', content: 'Digital scan of the 42-line Bible fragment. Provenance records attached.', classification: 'RESTRICTED' },
      'BK-007': { title: 'The Meridian Codex', content: `Full digitized manuscript — 17th century cryptographic treatise. Decoded colophon reads: "${flag}"`, classification: 'TOP SECRET' },
      'BK-009': { title: 'Liber Primus', content: 'Roger Bacon\'s treatise on optics and natural philosophy. Conservation notes attached.', classification: 'RESTRICTED' },
    };
    const materials = vaultContents[r.itemId] || { title: item.title, content: 'Access granted.', classification: 'RESTRICTED' };
    return res.json({
      success: true,
      message: `Request ${r.id} fulfilled. Vault access granted.`,
      status: r.status,
      materials
    });
  }

  res.json({ success: true, message: `Request ${r.id} fulfilled.`, status: r.status });
});

