function signToken(member) {
  return jwt.sign({ id: member.id, username: member.username, role: member.role }, JWT_SECRET, { algorithm: 'HS256', expiresIn: '24h' });
}

function requireAuth(req, res, next) {
  const token = req.cookies?.alx_token;
  if (!token) return res.redirect('/');
  try {
    const decoded = jwt.verify(token, JWT_SECRET, { algorithms: ['HS256'] });
    const member = members.find(m => m.id === decoded.id);
    if (!member) {
      req.tokenUser = decoded;
    } else {
      req.tokenUser = { ...decoded, role: decoded.role };
    }
    req.member = member || null;
    next();
  } catch (e) {
    res.clearCookie('alx_token');
    return res.redirect('/');
  }
}

function requireStaff(req, res, next) {
  if (req.tokenUser.role !== 'librarian' && req.tokenUser.role !== 'director') {
    return res.status(403).send(pageShell('Access Denied', 'staff', req.tokenUser, `
      <div class="page-header"><h1>Access Denied</h1><p class="subtitle">Insufficient privileges</p></div>
