function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function roleBadge(role) {
  const cls = { member: 'badge-member', librarian: 'badge-librarian', director: 'badge-director' };
  return `<span class="badge ${cls[role] || 'badge-member'}">${esc(role)}</span>`;
}

function renderSidebar(activePage, tokenUser) {
  const displayName = tokenUser.username || 'Unknown';
  const displayRole = tokenUser.role || 'member';
  const init = displayName.substring(0, 2).toUpperCase();
  const isStaff = displayRole === 'librarian' || displayRole === 'director';

  return `
    <aside class="sidebar">
      <div class="sidebar-brand">
        <div class="shield">📚</div>
        <h1><span>Alexandria</span> Library</h1>
      </div>
      <nav class="sidebar-nav">
        <div class="section-label">Browse</div>
