function pageShell(title, activePage, tokenUser, content) {
  return `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>${esc(title)} — Alexandria Library</title><style>${baseStyles}</style></head><body class="fade-in"><div class="app-layout">${renderSidebar(activePage, tokenUser)}<main class="main-content">${content}</main></div></body></html>`;
}

