app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const member = members.find(m => m.username === username && m.password === password);
  if (!member) {
    return res.send(loginPage
      .replace('ERRORPLACEHOLDER', '<div class="error-msg">Invalid credentials.</div>')
      .replace('REGISTERPLACEHOLDER', ''));
  }
  const token = signToken(member);
  res.cookie('alx_token', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/catalog');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(loginPage.replace('ERRORPLACEHOLDER', '').replace('REGISTERPLACEHOLDER', '<div class="error-msg">All fields required.</div>'));
  }
  if (members.find(m => m.username === username)) {
    return res.send(loginPage.replace('ERRORPLACEHOLDER', '').replace('REGISTERPLACEHOLDER', '<div class="error-msg">Username taken.</div>'));
  }
  const newMember = {
    id: nextMemberId++, username, password, name, role: 'member',
    email: username + '@alexandria-lib.org', memberSince: new Date().toISOString().split('T')[0],
    department: null, bio: 'New library member.', privateNotes: '', favoriteGenre: 'Unset',
    booksRead: 0, activeLoans: 0
  };
  members.push(newMember);
  const token = signToken(newMember);
  res.cookie('alx_token', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/catalog');
});

app.get('/logout', (req, res) => {
  res.clearCookie('alx_token');
