app.get('/session', requireAuth, (req, res) => {
  const rawToken = req.cookies?.alx_token || '';
  const parts = rawToken.split('.');
  let headerJson = '{}', payloadJson = '{}';
  try {
    headerJson = JSON.stringify(JSON.parse(Buffer.from(parts[0], 'base64url').toString()), null, 2);
    payloadJson = JSON.stringify(JSON.parse(Buffer.from(parts[1], 'base64url').toString()), null, 2);
  } catch (e) {}

  res.send(pageShell('Session Info', 'session', req.tokenUser, `
    <div class="page-header">
