      <div class="mc-stat" style="margin-top:4px;">Member since ${esc(m.memberSince)}</div>
      <br>
      <a href="javascript:void(0)" onclick="fetchMember(${m.id})" class="btn btn-primary" style="font-size:0.75rem;">View Details</a>
    </div>`;
  }).join('');

  res.send(pageShell('Staff Panel', 'staff', req.tokenUser, `
    <div class="page-header">
      <h1>Staff Panel</h1>
      <p class="subtitle">Member management and lookup — Staff access only</p>
    </div>

    <div class="stats-row">
      <div class="stat-card"><div class="stat-value">${members.length}</div><div class="stat-label">Total Members</div></div>
      <div class="stat-card"><div class="stat-value">${members.filter(m => m.role === 'librarian').length}</div><div class="stat-label">Librarians</div></div>
      <div class="stat-card"><div class="stat-value">${loans.filter(l => l.status === 'Active').length}</div><div class="stat-label">Active Loans</div></div>
      <div class="stat-card"><div class="stat-value">${loans.filter(l => l.status === 'Overdue').length}</div><div class="stat-label">Overdue</div></div>
    </div>

    <div class="card" style="margin-bottom:20px;">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:10px;">🔍 Member Lookup API</h3>
      <p style="font-size:0.82rem;color:var(--text-muted);margin-bottom:12px;">Use the staff API to look up any member by ID. Endpoint: <code style="font-family:var(--font-mono);color:var(--accent);">GET /api/staff/members/:id</code></p>
      <div style="display:flex;gap:10px;align-items:center;">
        <input type="number" id="lookup-id" placeholder="Member ID" min="1" style="padding:8px 12px;background:var(--bg-input);border:1px solid var(--border);border-radius:var(--radius);color:var(--text-primary);font-family:var(--font-mono);width:140px;">
        <button onclick="fetchMember(document.getElementById('lookup-id').value)" class="btn btn-primary">Lookup</button>
      </div>
      <div id="lookup-result" style="margin-top:14px;"></div>
    </div>

    <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">📇 Registered Members</h3>
    <div class="member-grid">${cards}</div>

    <script>
      function fetchMember(id) {
        if (!id) return;
        fetch('/api/staff/members/' + id)
          .then(r => r.json())
          .then(data => {
            const box = document.getElementById('lookup-result');
            if (data.error) {
              box.innerHTML = '<div class="error-msg">' + data.error + '</div>';
              return;
            }
            let html = '<div class="card" style="margin-top:8px;"><table class="data-table">';
            for (const [key, val] of Object.entries(data)) {
              const escaped = String(val).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
              html += '<tr><td style="color:var(--text-muted);width:160px;font-weight:600;">' + key + '</td><td style="font-family:var(--font-mono);font-size:0.82rem;">' + escaped + '</td></tr>';
            }
            html += '</table></div>';
            box.innerHTML = html;
          })
          .catch(err => {
            document.getElementById('lookup-result').innerHTML = '<div class="error-msg">Request failed: ' + err.message + '</div>';
          });
      }
    </script>
  `));
});

app.get('/api/staff/members/:id', requireAuth, (req, res) => {
  if (req.tokenUser.role !== 'librarian' && req.tokenUser.role !== 'director') {
    return res.status(403).json({ error: 'Staff access required. Your role: ' + req.tokenUser.role });
  }

  const memberId = parseInt(req.params.id);
  const member = members.find(m => m.id === memberId);

  if (!member) {
    return res.status(404).json({ error: 'Member not found with ID: ' + memberId });
  }

  res.json({
    id: member.id,
    username: member.username,
    name: member.name,
    role: member.role,
    email: member.email,
    memberSince: member.memberSince,
    department: member.department,
    bio: member.bio,
    favoriteGenre: member.favoriteGenre,
    booksRead: member.booksRead,
    activeLoans: member.activeLoans,
    privateNotes: member.privateNotes,
  });
});

