app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.json({ success: false, message: 'Invalid credentials. Check username and password.' });
  const token = createSession(user.id);
  res.cookie('pv_session', token, { httpOnly: false, sameSite: 'lax' });
  res.json({ success: true });
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.pv_session;
  if (token) delete sessions[token];
  res.clearCookie('pv_session');
  res.redirect('/');
});

