            box.textContent = JSON.stringify(parsed, null, 2);
          } catch(e) {
            box.textContent = data.body;
          }
        }
      })
      .catch(function(err) {
        btn.textContent = 'Validate Resource';
        btn.disabled = false;
        box.textContent = 'ERROR: ' + err.message;
        box.style.color = '#ef4444';
      });
    }
    </script>
  `));
});

app.post('/api/fetch-resource', requireAuth, async (req, res) => {
  const { url } = req.body;
  if (!url) return res.json({ error: 'URL is required' });

  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);

    const response = await fetch(url, {
      headers: {
        'X-PV-Internal-Gateway': 'trusted-proxy',
        'User-Agent': 'PageVault-ResourceChecker/1.0'
      },
      signal: controller.signal,
      redirect: 'follow'
    });

    clearTimeout(timeout);
    const body = await response.text();
    res.json({ status: response.status, body: body });
  } catch (err) {
    res.json({ error: err.message || 'Failed to fetch resource' });
  }
});

app.get('/internal/catalog/search', (req, res) => {
  const gatewayHeader = req.headers['x-pv-internal-gateway'];
  if (gatewayHeader !== 'trusted-proxy') {
    return res.status(403).json({
      error: 'ACCESS DENIED',
      message: 'This endpoint is restricted to internal service requests only. Direct access is not permitted.'
    });
  }

  const q = req.query.q;
  if (!q) {
    return res.json({ endpoint: 'internal-catalog-search', usage: 'Provide ?q= parameter to search books', example: '/internal/catalog/search?q=crypto' });
  }

  try {
    const sql = `SELECT id, title, author, isbn, genre FROM books WHERE title LIKE '%${q}%' OR author LIKE '%${q}%'`;
    const results = db.exec(sql);

    let rows = [];
    if (results.length > 0) {
      const cols = results[0].columns;
      rows = results[0].values.map(vals => {
        const obj = {};
        cols.forEach((c, i) => { obj[c] = vals[i]; });
        return obj;
      });
    }
    res.json({ query: q, count: rows.length, results: rows });
  } catch (err) {
    res.status(500).json({ error: 'Query failed', detail: err.message });
  }
});

