function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSessionUser(req) {
  const token = req.cookies?.sw_session;
  if (!token || !sessions[token]) return null;
  const userId = sessions[token];
  const rows = db.exec(`SELECT * FROM users WHERE id = ${userId}`);
  if (!rows.length || !rows[0].values.length) return null;
  const r = rows[0].values[0];
  return { id: r[0], username: r[1], password: r[2], name: r[3], role: r[4], email: r[5], bio: r[6], joined: r[7] };
}

function requireAuth(req, res, next) {
  const user = getSessionUser(req);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function requireAdmin(req, res, next) {
  const user = getSessionUser(req);
  if (!user) return res.redirect('/');
  if (user.role !== 'Admin') {
    return res.status(403).send(pageShell('Access Denied', 'royalties', user, `
      <div class="page-header"><h1>🚫 Access Denied</h1>
      <p class="subtitle">This section requires administrator privileges.</p></div>
      <a href="/dashboard" class="btn btn-ghost" style="cursor:pointer;color:var(--text-secondary);">← Back to Dashboard</a>
    `));
  }
  req.user = user;
  next();
}

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

