function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function genreBadge(g) {
  const cls = { Electronic: 'badge-electronic', Techno: 'badge-techno', Ambient: 'badge-ambient', DnB: 'badge-dnb', Chillwave: 'badge-chillwave' };
  return `<span class="badge ${cls[g] || 'badge-electronic'}">${esc(g)}</span>`;
}

function renderSidebar(activePage, user) {
  const init = initials(user.name);
  const adminLink = user.role === 'Admin' ? `
    <div class="section-label">Administration</div>
    <a href="/admin/royalties" class="${activePage === 'royalties' ? 'active' : ''}">
      <span class="icon">💰</span> Royalty Reports
    </a>` : '';
  return `
    <aside class="sidebar">
      <div class="sidebar-brand">
        <div class="shield">🎵</div>
        <h1>Sound<span>Wave</span></h1>
      </div>
      <nav class="sidebar-nav">
        <div class="section-label">Music</div>
        <a href="/dashboard" class="${activePage === 'dashboard' ? 'active' : ''}">
          <span class="icon">📊</span> Dashboard
        </a>
        <a href="/library" class="${activePage === 'library' ? 'active' : ''}">
          <span class="icon">🎶</span> Library
        </a>
        <a href="/reviews" class="${activePage === 'reviews' ? 'active' : ''}">
          <span class="icon">💬</span> All Reviews
        </a>
        ${adminLink}
        <div class="section-label">Tools</div>
        <a href="/webhook" class="${activePage === 'webhook' ? 'active' : ''}">
          <span class="icon">📡</span> Webhook Log
        </a>
