app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const rows = db.exec(`SELECT * FROM users WHERE username = '${username.replace(/'/g, "''")}' AND password = '${password.replace(/'/g, "''")}'`);
  if (!rows.length || !rows[0].values.length) {
    return res.redirect('/?error=Invalid+credentials');
  }
  const user = rows[0].values[0];
  const token = createSession(user[0]);
  res.cookie('sw_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.redirect('/?error=All+fields+required');
  const existing = db.exec(`SELECT id FROM users WHERE username = '${username.replace(/'/g, "''")}'`);
  if (existing.length && existing[0].values.length) return res.redirect('/?error=Username+already+taken');
  const maxId = db.exec('SELECT MAX(id) FROM users');
  const newId = (maxId[0].values[0][0] || 0) + 1;
  db.run(`INSERT INTO users VALUES (${newId}, '${username.replace(/'/g, "''")}', '${password.replace(/'/g, "''")}', '${name.replace(/'/g, "''")}', 'Listener', '${username.replace(/'/g, "''")}@soundwave.io', 'New user.', '${new Date().toISOString().split('T')[0]}')`);
  res.redirect('/?registered=1');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.sw_session;
  if (token) delete sessions[token];
  res.clearCookie('sw_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const trackCount = db.exec('SELECT COUNT(*) FROM tracks')[0].values[0][0];
  const reviewCount = db.exec('SELECT COUNT(*) FROM reviews')[0].values[0][0];
  const totalPlays = db.exec('SELECT SUM(plays) FROM tracks')[0].values[0][0];
  const userCount = db.exec('SELECT COUNT(*) FROM users')[0].values[0][0];

  const recentTracks = db.exec('SELECT * FROM tracks ORDER BY plays DESC LIMIT 5');
  let trackRows = '';
  if (recentTracks.length) {
    trackRows = recentTracks[0].values.map(t => `
      <tr>
        <td><a href="/tracks/${t[0]}" style="font-family:var(--font-mono);font-size:0.82rem;">${esc(String(t[1]))}</a></td>
        <td style="color:var(--accent-pink)">${esc(String(t[2]))}</td>
        <td>${genreBadge(String(t[4]))}</td>
        <td style="font-family:var(--font-mono)">${Number(t[6]).toLocaleString()}</td>
      </tr>`).join('');
