app.get('/tracks/:id', requireAuth, (req, res) => {
  const user = req.user;
  const trackId = parseInt(req.params.id);
  const trackResult = db.exec(`SELECT * FROM tracks WHERE id = ${trackId}`);
  if (!trackResult.length || !trackResult[0].values.length) {
    return res.send(pageShell('Not Found', 'library', user, `<div class="page-header"><h1>Track Not Found</h1></div>`));
  }
  const t = trackResult[0].values[0];
  const reviewResult = db.exec(`SELECT * FROM reviews WHERE track_id = ${trackId} ORDER BY id DESC`);
  let reviewsHtml = '<p style="color:var(--text-muted);font-size:0.85rem;">No reviews yet. Be the first!</p>';
  if (reviewResult.length && reviewResult[0].values.length) {
    reviewsHtml = reviewResult[0].values.map(r => `
      <div class="review-card">
        <div class="review-author">@${esc(String(r[2]))}</div>
        <div class="review-content">${r[3]}</div>
        <div class="review-date">${esc(String(r[4]))}</div>
      </div>`).join('');
  }

  res.send(pageShell(String(t[1]), 'library', user, `
    <div class="page-header">
      <h1>${esc(String(t[1]))}</h1>
      <p class="subtitle">by ${esc(String(t[2]))} · ${esc(String(t[3]))} · ${esc(String(t[5]))}</p>
    </div>
    <div class="stats-row" style="grid-template-columns:repeat(3,1fr);">
      <div class="stat-card"><div class="stat-value">${Number(t[6]).toLocaleString()}</div><div class="stat-label">Plays</div></div>
      <div class="stat-card"><div class="stat-value">${esc(String(t[4]))}</div><div class="stat-label">Genre</div></div>
      <div class="stat-card"><div class="stat-value">${esc(String(t[5]))}</div><div class="stat-label">Duration</div></div>
    </div>
    <div class="card" style="margin-bottom:20px;">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">💬 Reviews</h3>
      <div id="reviews-container">${reviewsHtml}</div>
    </div>
    <div class="card" style="margin-bottom:20px;">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">✍️ Write a Review</h3>
      <div id="review-msg"></div>
      <textarea id="review-content" placeholder="Share your thoughts on this track..." rows="3"></textarea>
      <button class="btn btn-primary" style="margin-top:10px;" onclick="submitReview()">Post Review</button>
    </div>
    <a href="/library" class="btn btn-ghost" style="cursor:pointer;color:var(--text-secondary);">← Back to Library</a>
    <script>
    function submitReview() {
      const content = document.getElementById('review-content').value;
      if (!content.trim()) return;
      fetch('/api/reviews', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ trackId: ${trackId}, content: content })
      }).then(r => r.json()).then(data => {
        if (data.success) {
          document.getElementById('review-msg').innerHTML = '<div class="success-msg">Review posted!</div>';
          document.getElementById('review-content').value = '';
          setTimeout(() => location.reload(), 800);
        } else {
          document.getElementById('review-msg').innerHTML = '<div class="error-msg">' + (data.error || 'Failed') + '</div>';
        }
      }).catch(() => {
        document.getElementById('review-msg').innerHTML = '<div class="error-msg">Network error</div>';
      });
    }
    </script>
  `));
});

app.post('/api/reviews', requireAuth, (req, res) => {
  const { trackId, content } = req.body;
  if (!trackId || !content || !content.trim()) {
    return res.json({ error: 'Review content required' });
  }
  const stmt = db.prepare('INSERT INTO reviews (track_id, username, content, created_at) VALUES (?, ?, ?, ?)');
  stmt.run([parseInt(trackId), req.user.username, content, new Date().toISOString()]);
  stmt.free();
  res.json({ success: true });
});

