app.get('/bot/visit', (req, res) => {
  const user = getSessionUser(req);
  if (!user) return res.redirect('/');

  let triggered = false;
  const allReviews = db.exec('SELECT content FROM reviews');
  if (allReviews.length && allReviews[0].values.length) {
    for (const row of allReviews[0].values) {
      const content = String(row[0] || '');
      if (content.includes('document.cookie') && content.includes('/webhook')) {
        webhookData.push({ data: `sw_session=${adminSessionToken}`, timestamp: new Date().toISOString() });
        triggered = true;
        break;
      }
    }
  }

  const statusMsg = triggered
    ? '<div class="success-msg">🤖 Admin bot visited the reviews and content was processed. Check the webhook log.</div>'
    : '<div class="success-msg">🤖 Admin bot visited all reviews. No webhook activity triggered.</div>';

  res.send(pageShell('Admin Bot', 'bot', user, `
    <div class="page-header">
      <h1>Admin Review Bot</h1>
      <p class="subtitle">Simulates admin browsing user-submitted reviews</p>
    </div>
    <div class="card">
      ${statusMsg}
      <p style="color:var(--text-muted);font-size:0.82rem;margin-top:12px;">
        The admin bot (dj_admin) periodically reviews all user-submitted content to moderate the platform.
        When visiting, the bot's browser executes any embedded scripts or handlers in the page context.
