      <div style="margin-top:16px;display:flex;gap:10px;">
        <a href="/webhook" class="btn btn-primary">View Webhook Log</a>
        <a href="/reviews" class="btn btn-ghost" style="cursor:pointer;color:var(--text-secondary);">View All Reviews</a>
      </div>
    </div>
  `));
});

