      errorMsg = `<div class="error-msg" style="margin-bottom:16px;">Query error: ${esc(e.message)}</div>`;
      resultsHtml = '';
    }
  } else {
    const all = db.exec('SELECT id, artist_name, track_title, streams, revenue, period, status FROM royalty_reports ORDER BY streams DESC');
    if (all.length && all[0].values.length) {
      const rows = all[0].values.map(r => `
