        </tr>`).join('');
      resultsHtml = `<table class="data-table">
        <thead><tr><th>ID</th><th>Artist</th><th>Track</th><th>Streams</th><th>Revenue</th><th>Period</th><th>Status</th></tr></thead>
        <tbody>${rows}</tbody></table>`;
    }
  }

  const totalRevenue = db.exec("SELECT SUM(CAST(REPLACE(REPLACE(revenue,'$',''),',','') AS REAL)) FROM royalty_reports");
  const totalStreams = db.exec('SELECT SUM(streams) FROM royalty_reports');
  const paidCount = db.exec("SELECT COUNT(*) FROM royalty_reports WHERE status='Paid'");
  const pendingCount = db.exec("SELECT COUNT(*) FROM royalty_reports WHERE status='Pending'");

  res.send(pageShell('Royalty Reports', 'royalties', user, `
    <div class="page-header">
      <h1>💰 Royalty Reports</h1>
      <p class="subtitle">Artist payment tracking and revenue analytics — <span class="badge badge-admin">ADMIN ONLY</span></p>
    </div>
    <div class="stats-row">
      <div class="stat-card"><div class="stat-value">$${((totalRevenue[0]?.values[0][0] || 0) / 1000).toFixed(1)}K</div><div class="stat-label">Total Revenue</div></div>
      <div class="stat-card"><div class="stat-value">${((totalStreams[0]?.values[0][0] || 0) / 1000000).toFixed(1)}M</div><div class="stat-label">Total Streams</div></div>
      <div class="stat-card"><div class="stat-value">${paidCount[0]?.values[0][0] || 0}</div><div class="stat-label">Paid</div></div>
      <div class="stat-card"><div class="stat-value">${pendingCount[0]?.values[0][0] || 0}</div><div class="stat-label">Pending</div></div>
    </div>
    <div class="card">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">Search Royalty Records</h3>
      <form method="GET" action="/admin/royalties">
        <div class="search-bar">
          <input type="text" name="q" placeholder="Search by artist name or track title..." value="${esc(q)}">
          <button type="submit">Search</button>
        </div>
      </form>
      ${errorMsg}
      ${resultsHtml}
    </div>
  `));
});

