function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

const avatarColors = {
  'Artist': 'linear-gradient(135deg, #a855f7, #ec4899)',
  'Listener-Premium': 'linear-gradient(135deg, #ec4899, #f59e0b)',
  'Listener-Free': 'linear-gradient(135deg, #22d3ee, #3b82f6)',
};

function getAvatarColor(user) {
  if (user.role === 'Artist') return avatarColors['Artist'];
  if (user.plan === 'Premium') return avatarColors['Listener-Premium'];
  return avatarColors['Listener-Free'];
}

function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function planBadge(user) {
  if (user.role === 'Artist') return '<span class="badge badge-pro">Artist Pro</span>';
  if (user.plan === 'Premium') return '<span class="badge badge-premium">Premium</span>';
  return '<span class="badge badge-free">Free</span>';
}

