app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.send(renderLoginPage('Invalid username or password.', ''));
  const token = createSession(user.id);
  res.cookie('ss_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.send(renderLoginPage('', 'All fields are required.'));
  if (users.find(u => u.username === username)) return res.send(renderLoginPage('', 'Username already taken.'));
  const newUser = {
    id: nextUserId++,
    username, password, name,
    role: 'Listener', plan: 'Free',
    email: username + '@soundstage.io',
    joined: new Date().toISOString().split('T')[0],
    genre: 'Not set',
    monthlyListeners: null, totalStreams: null,
    bio: 'New to SoundStage!',
    royaltyToken: null,
  };
  users.push(newUser);
  userPlaylists[newUser.id] = [];
  const token = createSession(newUser.id);
  res.cookie('ss_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.ss_session;
  if (token) delete sessions[token];
  res.clearCookie('ss_session');
  res.redirect('/');
});

