app.post('/settings', requireAuth, (req, res) => {
  const loggedInUser = req.user;
  const targetId = parseInt(req.body.userId);
  const targetUser = users.find(u => u.id === targetId);

  if (!targetUser) {
    return res.send(renderSettingsPage(loggedInUser, loggedInUser, '', 'User not found.'));
  }

  if (req.body.name) targetUser.name = req.body.name;
  if (req.body.email) targetUser.email = req.body.email;
  if (req.body.genre) targetUser.genre = req.body.genre;
  if (req.body.bio !== undefined) targetUser.bio = req.body.bio;

  res.send(renderSettingsPage(loggedInUser, targetUser, 'Profile updated successfully!', ''));
});

