      async function doFetch() {
        const url = document.getElementById('urlInput').value.trim();
        const resultBox = document.getElementById('resultBox');
        const errorBox = document.getElementById('errorBox');
        const loading = document.getElementById('loading');
        const resultContent = document.getElementById('resultContent');

        resultBox.style.display = 'none';
        errorBox.style.display = 'none';

        if (!url) {
          errorBox.textContent = 'Please enter a URL.';
          errorBox.style.display = 'block';
          return;
        }

        loading.className = 'loading-spinner active';
        document.getElementById('fetchBtn').disabled = true;

        try {
          const resp = await fetch('/api/fetch-url', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ url })
          });
          const data = await resp.json();

          if (data.error) {
            errorBox.textContent = data.error;
            errorBox.style.display = 'block';
          } else {
            resultContent.textContent = data.body || '(empty response)';
            resultBox.style.display = 'block';
          }
        } catch (err) {
          errorBox.textContent = 'Request failed: ' + err.message;
          errorBox.style.display = 'block';
        } finally {
          loading.className = 'loading-spinner';
          document.getElementById('fetchBtn').disabled = false;
        }
      }

      document.getElementById('urlInput').addEventListener('keydown', function(e) {
        if (e.key === 'Enter') doFetch();
      });
    </script>
  `));
});

function serverFetch(url) {
  return new Promise((resolve, reject) => {
    const timeout = setTimeout(() => { reject(new Error('Request timed out')); }, 5000);
    const client = url.startsWith('https') ? https : http;
    const req = client.get(url, (res) => {
      let body = '';
      res.on('data', chunk => { body += chunk; });
      res.on('end', () => {
        clearTimeout(timeout);
        resolve({ status: res.statusCode, body, headers: res.headers });
      });
    });
    req.on('error', (err) => {
      clearTimeout(timeout);
      reject(err);
    });
  });
}

app.post('/api/fetch-url', requireAuth, async (req, res) => {
  const { url } = req.body;

  if (!url) {
    return res.json({ error: 'URL is required.' });
  }

  if (!url.startsWith('http://') && !url.startsWith('https://')) {
    return res.json({ error: 'URL must start with http:// or https://' });
  }

  try {
    const result = await serverFetch(url);
    res.json({ status: result.status, body: result.body });
  } catch (err) {
    res.json({ error: 'Failed to fetch URL: ' + err.message });
  }
});

