let adminSessionToken = null;

function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.ss_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const user = users.find(u => u.id === userId);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function requireAdmin(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.status(403).json({ error: 'Not authenticated' });
  const user = users.find(u => u.id === userId);
  if (!user || user.role !== 'admin') return res.status(403).json({ error: 'Admin access required' });
  req.user = user;
  next();
}

function ensureAdminSession() {
  if (!adminSessionToken || !sessions[adminSessionToken]) {
    const admin = users.find(u => u.role === 'admin');
    adminSessionToken = createSession(admin.id);
  }
  return adminSessionToken;
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function formatPlays(n) {
  if (n >= 1000000) return (n / 1000000).toFixed(1) + 'M';
  if (n >= 1000) return (n / 1000).toFixed(1) + 'K';
  return String(n);
}

