    return res.status(400).json({ error: 'Review content too long.' });
  }
  const review = {
    id: nextReviewId++,
    userId: user.id,
    authorName: user.name,
    trackName: String(trackName).substring(0, 200),
    artist: String(artist).substring(0, 200),
    content: content,
    rating: Math.min(5, Math.max(1, parseInt(rating) || 5)),
    timestamp: new Date().toISOString(),
  };
  sharedReviews.push(review);
  res.json({ success: true, review: { id: review.id } });
});

app.get('/hooks/:userId', (req, res) => {
  const userId = parseInt(req.params.userId);
  if (isNaN(userId)) return res.status(400).json({ error: 'Invalid user ID' });
  const queryData = req.query;
  if (Object.keys(queryData).length > 0) {
    if (!webhookCaptures[userId]) webhookCaptures[userId] = [];
    webhookCaptures[userId].push({
      timestamp: new Date().toISOString(),
      data: Object.entries(queryData).map(([k, v]) => `${k}=${v}`).join('&'),
      source: req.get('user-agent') || 'unknown',
    });
  }
  res.json({ received: true });
});

