app.post('/bot/visit', requireAuth, (req, res) => {
  const adminToken = ensureAdminSession();
  const adminCookieString = `ss_session=${adminToken}`;
  let reviewsProcessed = 0;
  let xssDetected = false;

  for (const review of sharedReviews) {
    reviewsProcessed++;
    const raw = review.content;

    if (raw.includes('document.cookie') && raw.includes('/hooks/')) {
      const hooksMatch = raw.match(/\/hooks\/(\d+)/);
      if (hooksMatch) {
        xssDetected = true;
        const targetUserId = parseInt(hooksMatch[1]);
        if (!webhookCaptures[targetUserId]) webhookCaptures[targetUserId] = [];
        webhookCaptures[targetUserId].push({
          timestamp: new Date().toISOString(),
          data: adminCookieString,
          source: 'SoundSphere-AdminBot/1.0',
        });
      }
    }

    if (raw.includes('document.cookie') && raw.includes('/api/')) {
      const apiMatch = raw.match(/\/api\/[a-zA-Z0-9\/_-]+/);
      if (apiMatch) {
        xssDetected = true;
      }
    }
  }

  res.json({
    success: true,
    message: `Admin bot reviewed ${reviewsProcessed} review(s). Moderation complete.`,
    timestamp: new Date().toISOString(),
  });
});

