function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function roleBadge(role) {
  const cls = { admin: 'badge-admin', artist: 'badge-artist', listener: 'badge-listener' };
  return `<span class="badge ${cls[role] || 'badge-listener'}">${esc(role)}</span>`;
}

