app.post('/api/reviews', requireAuth, (req, res) => {
  const user = req.user;
  const { trackId, content } = req.body;

  if (!content || !trackId) {
    return res.json({ success: false, error: 'Review content is required.' });
  }

  if (content.length > 2000) {
    return res.json({ success: false, error: 'Review too long (max 2000 chars).' });
  }

  const track = tracks.find(t => t.id === parseInt(trackId));
  if (!track) {
    return res.json({ success: false, error: 'Track not found.' });
  }

  const review = {
    id: crypto.randomBytes(8).toString('hex'),
    trackId: parseInt(trackId),
    userId: user.id,
    username: user.username,
    avatar: user.avatar,
    role: user.role,
    content: content,
    date: new Date().toISOString().split('T')[0],
  };

