function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function categoryBadge(cat) {
  const cls = { Politics: 'badge-politics', Technology: 'badge-technology', Business: 'badge-business', Investigation: 'badge-investigation' };
  return '<span class="badge ' + (cls[cat] || 'badge-draft') + '">' + esc(cat) + '</span>';
}

function statusBadge(s) {
  const cls = { Published: 'badge-published', Draft: 'badge-draft', 'Under Review': 'badge-review' };
  return '<span class="badge ' + (cls[s] || 'badge-draft') + '">' + esc(s) + '</span>';
}

