app.get('/articles/:id', requireAuth, (req, res) => {
  const payload = req.tokenPayload;
  const articleId = parseInt(req.params.id);
  const article = articles.find(a => a.id === articleId);

  if (!article) {
    return res.send(pageShell('Not Found', 'articles', payload,
      '<div class="page-header"><h1>Article Not Found</h1></div><p style="color:var(--text-muted);">No article with that ID.</p>'));
  }

  const articleComments = comments.filter(c => c.articleId === articleId);
  const commentsHtml = articleComments.length > 0
    ? articleComments.map(c => `
      <div class="comment-card">
        <div class="cc-user">@${esc(c.user)}</div>
        <div class="cc-text">${esc(c.text)}</div>
        <div class="cc-date">${esc(c.date)}</div>
      </div>`).join('')
    : '<p style="color:var(--text-muted);font-size:0.85rem;">No comments yet.</p>';

  res.send(pageShell(article.title, 'articles', payload, `
    <div class="page-header">
      <div style="margin-bottom:12px;">${categoryBadge(article.category)} ${statusBadge(article.status)}</div>
      <h1>${esc(article.title)}</h1>
      <p class="subtitle">By ${esc(article.author)} · ${esc(article.date)} · ${article.views.toLocaleString()} views</p>
    </div>

    <div class="card" style="margin-bottom:24px;">
      <p style="font-size:0.95rem;color:var(--text-secondary);line-height:1.8;">${esc(article.excerpt)}</p>
      <p style="font-size:0.85rem;color:var(--text-muted);margin-top:16px;font-style:italic;">[Full article content available in the editorial CMS]</p>
    </div>

    <div class="card">
      <h3 style="font-family:var(--font-mono);font-size:0.9rem;margin-bottom:16px;">💬 Comments (${articleComments.length})</h3>
      ${commentsHtml}
    </div>

    <div style="margin-top:20px;">
      <a href="/articles" class="btn btn-ghost">← Back to Articles</a>
    </div>
  `));
});

