  try {
    headerDecoded = JSON.stringify(base64urlDecode(parts[0]), null, 2);
    payloadDecoded = JSON.stringify(base64urlDecode(parts[1]), null, 2);
  } catch (e) {
    headerDecoded = 'Error decoding';
    payloadDecoded = 'Error decoding';
