          Contact the Editor-in-Chief if you believe this is an error.
        </p>
      </div>
    `));
  }
  next();
}

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

