function statusBadge(s) {
  const cls = { published: 'badge-published', draft: 'badge-draft', review: 'badge-review', embargoed: 'badge-embargoed' };
  return '<span class="badge ' + (cls[s] || 'badge-draft') + '">' + esc(s) + '</span>';
}

function roleBadge(r) {
  const cls = { admin: 'badge-role-admin', journalist: 'badge-role-journalist', user: 'badge-role-user' };
  return '<span class="badge ' + (cls[r] || 'badge-role-user') + '">' + esc(r) + '</span>';
}

function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

