app.post('/api/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.json({ success: false, error: 'Invalid credentials. Check username and password.' });
  }
  const token = createSession(user.id);
  res.cookie('dp_session', token, { httpOnly: false, sameSite: 'lax' });
  res.json({ success: true });
});

app.post('/api/register', (req, res) => {
  const body = req.body;
  if (!body.username || !body.password || !body.name) {
    return res.json({ success: false, error: 'All fields are required.' });
  }
  if (body.username.length < 3) {
    return res.json({ success: false, error: 'Username must be at least 3 characters.' });
  }
  if (body.password.length < 4) {
    return res.json({ success: false, error: 'Password must be at least 4 characters.' });
  }
  if (users.find(u => u.username === body.username)) {
    return res.json({ success: false, error: 'Username already taken.' });
  }

  const newUser = {
    id: nextUserId++,
    username: body.username,
    password: body.password,
    name: body.name,
    role: body.role || 'user',
    email: body.username + '@dailypulse.news',
    joined: new Date().toISOString().split('T')[0],
    bio: body.bio || 'New team member.',
    beat: body.beat || 'Unassigned',
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('dp_session', token, { httpOnly: false, sameSite: 'lax' });
  res.json({ success: true, user: { id: newUser.id, username: newUser.username, role: newUser.role } });
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.dp_session;
  if (token) delete sessions[token];
  res.clearCookie('dp_session');
  res.redirect('/');
});

