app.get('/comments', requireAuth, (req, res) => {
  const user = req.user;

  const commentItems = comments.map(c => {
    const article = articles.find(a => a.id === c.articleId);
    return `
    <div class="comment-item">
      <span class="ci-author">@${esc(c.author)}</span>
      <span class="ci-date">${esc(c.date)}</span>
      <span style="font-size:0.72rem;color:var(--text-muted);margin-left:8px;">on "${article ? esc(article.title) : 'Unknown'}"</span>
      <div class="ci-text">${esc(c.text)}</div>
    </div>`;
  }).join('');

  res.send(pageShell('Comments', 'comments', user, `
    <div class="page-header">
      <h1>Reader Comments</h1>
      <p class="subtitle">Recent comments across all published articles</p>
    </div>

    <div class="card">
      ${commentItems}
    </div>

    <div class="card" style="margin-top:20px;">
      <h3 style="font-family:var(--font-serif);font-size:1rem;margin-bottom:14px;">Post a Comment</h3>
      <div style="display:grid;grid-template-columns:1fr 2fr;gap:12px;">
        <div>
          <label style="display:block;font-size:0.72rem;text-transform:uppercase;letter-spacing:0.5px;color:var(--text-muted);margin-bottom:6px;">Article ID</label>
          <input type="number" id="comment-article" min="1" max="${articles.length}" value="1" style="width:100%;padding:10px 14px;background:var(--bg-input);border:1px solid var(--border);border-radius:var(--radius);color:var(--text-primary);font-size:0.88rem;">
