function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function signToken(user) {
  return jwt.sign({ id: user.id, username: user.username, role: user.role }, JWT_SECRET, { algorithm: 'HS256', expiresIn: '24h' });
}

function verifyToken(req) {
  const token = req.cookies?.pw_token;
  if (!token) return null;
  try {
    return jwt.verify(token, JWT_SECRET, { algorithms: ['HS256'] });
  } catch { return null; }
}

function requireAuth(req, res, next) {
  const payload = verifyToken(req);
  if (!payload) return res.redirect('/');
  req.userPayload = payload;
  req.currentUser = users.find(u => u.id === payload.id) || { id: payload.id, username: payload.username, name: payload.username, role: payload.role };
  next();
}

function requireRole(role) {
  return (req, res, next) => {
    if (!req.userPayload || req.userPayload.role !== role) {
      return res.status(403).send(pageShell('Access Denied', '', req.currentUser || { name: 'Unknown', role: 'unknown' }, `
        <div class="page-header"><h1>🔒 Access Denied</h1><p class="subtitle">You don't have the required <code style="color:var(--accent-cyan);font-family:var(--font-mono);">${esc(role)}</code> role to access this page.</p></div>
        <a href="/feed" class="btn btn-ghost" style="cursor:pointer;color:var(--text-secondary);margin-top:16px;">← Back to Feed</a>
      `));
    }
    next();
  };
}

