function initials(name) { return name.split(' ').map(n => n[0]).join(''); }

function categoryBadge(c) {
  const map = { Technology: 'badge-tech', Politics: 'badge-politics', Climate: 'badge-climate', Investigation: 'badge-investigation' };
  return `<span class="badge ${map[c] || 'badge-draft'}">${esc(c)}</span>`;
}

function statusBadge(s) {
  const map = { published: 'badge-published', draft: 'badge-draft', review: 'badge-review', embargoed: 'badge-embargoed' };
  return `<span class="badge ${map[s] || 'badge-draft'}">${esc(s)}</span>`;
}

function roleBadge(r) {
  const map = { editor: 'badge-editor', journalist: 'badge-journalist', admin: 'badge-investigation' };
  return `<span class="badge ${map[r] || 'badge-draft'}">${esc(r)}</span>`;
}

