app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.status(401).json({ error: 'Invalid credentials.' });
  const token = signToken(user);
  res.cookie('pw_token', token, { httpOnly: false, sameSite: 'lax' });
  res.json({ success: true });
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.status(400).json({ error: 'All fields required.' });
  if (users.find(u => u.username === username)) return res.status(409).json({ error: 'Username taken.' });
  const newUser = {
    id: nextUserId++, username, password, name, role: 'journalist',
    email: username + '@pulsewire.news', bio: 'New team member.', joined: new Date().toISOString().split('T')[0],
    beat: 'General', visible: true,
  };
  users.push(newUser);
  const token = signToken(newUser);
  res.cookie('pw_token', token, { httpOnly: false, sameSite: 'lax' });
  res.json({ success: true });
});

app.get('/logout', (req, res) => {
  res.clearCookie('pw_token');
  res.redirect('/');
});

