// ── HTML Helpers ──────────────────────────────────────────────────────

function esc(s) {
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function initials(name) {
  return name.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase();
}

function formatDate(iso) {
  return new Date(iso).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
}

function siteHeader(user) {
  const nav = user ? `
    <nav class="header-nav">
      <a href="/" class="">Home</a>
      <a href="/dashboard">Dashboard</a>
      ${user.role === 'admin' ? '<a href="/admin">Admin</a>' : ''}
    </nav>
    <div class="header-actions">
      <div class="header-user">
        <div class="avatar">${initials(user.name)}</div>
        <span>${esc(user.name)}</span>
      </div>
      <a href="/logout" class="btn btn-ghost btn-sm">Sign out</a>
    </div>
  ` : `
    <nav class="header-nav"></nav>
    <div class="header-actions">
      <a href="/login" class="btn btn-amber btn-sm">Sign In</a>
    </div>
  `;
  return `
    <header class="site-header">
      <div class="header-inner">
        <a href="/" class="site-logo">Press<span>Room</span></a>
        ${nav}
      </div>
    </header>`;
}

function shell(title, body, user = null, opts = {}) {
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${esc(title)} — PressRoom</title>
  <style>${baseStyles}</style>
</head>
<body class="fade-in">
  ${siteHeader(user)}
  ${body}
</body>
</html>`;
}

