app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user || user.role === 'system') return res.redirect('/login?msg=error');
  const token = createSession(user.id);
  res.cookie('np_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect(user.role === 'admin' ? '/admin' : '/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.redirect('/login?msg=error');
  if (users.find(u => u.username === username)) return res.redirect('/login?msg=taken');
  const newUser = {
    id: users.length + 1 + Math.floor(Math.random() * 1000),
    username,
    password,
    name,
    role: 'reader',
    email: username + '@pressroom.news',
    bio: 'Community reader.',
    joined: new Date().toISOString().split('T')[0],
    clearance: 'reader',
    privateNotes: '',
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('np_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.np_session;
  if (token) delete sessions[token];
  res.clearCookie('np_session');
  res.redirect('/login?msg=logout');
});

