app.get('/article/:id', (req, res) => {
  const userId = getSession(req);
  const user = userId ? users.find(u => u.id === userId) : null;
  const articleId = parseInt(req.params.id);
  const article = articles.find(a => a.id === articleId);
  if (!article) return res.redirect('/');

  const articleComments = comments.filter(c => c.articleId === articleId);

  const commentListHtml = articleComments.length > 0
    ? articleComments.map(c => `
        <div class="comment-item">
          <div class="comment-meta">
            <div class="comment-av">${c.author.slice(0, 2).toUpperCase()}</div>
            <span class="comment-author">${esc(c.author)}</span>
            <span class="comment-time">${formatDate(c.timestamp)}</span>
          </div>
          <div class="comment-body">${c.body}</div>
        </div>`).join('')
    : '<p style="color:var(--text-3);font-size:0.85rem;padding:20px 0;">No comments yet. Be the first to respond.</p>';

  const commentFormHtml = user ? `
    <div class="comment-form">
      <h3>Post a Response</h3>
      <div id="comment-status"></div>
      <div class="form-row">
        <label>Display Name</label>
        <input type="text" id="c-author" value="${esc(user.username)}" placeholder="Your name">
      </div>
      <div class="form-row">
        <label>Comment</label>
        <textarea id="c-body" placeholder="Share your thoughts on this article..."></textarea>
      </div>
      <button onclick="postComment(${articleId})" class="btn btn-amber">Post Comment</button>
    </div>
    <script>
      function postComment(artId) {
        const author = document.getElementById('c-author').value.trim();
        const body = document.getElementById('c-body').value.trim();
        const statusEl = document.getElementById('comment-status');
        if (!author || !body) {
          statusEl.innerHTML = '<div class="alert alert-error">Please fill in all fields.</div>';
          return;
        }
        fetch('/api/comments', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ articleId: artId, author, body })
        })
        .then(r => r.json())
        .then(data => {
          if (data.success) {
            statusEl.innerHTML = '<div class="alert alert-success">Comment posted! Refresh to see it.</div>';
            document.getElementById('c-body').value = '';
          } else {
            statusEl.innerHTML = '<div class="alert alert-error">' + (data.error || 'Failed to post.') + '</div>';
          }
        })
        .catch(() => {
          statusEl.innerHTML = '<div class="alert alert-error">Network error.</div>';
        });
      }
    </script>
  ` : `<div class="alert alert-info" style="margin-top:20px;"><a href="/login">Sign in</a> to leave a comment.</div>`;

  const commentsBlock = article.comments ? `
    <div class="comments-section">
      <h2>Comments (${articleComments.length})</h2>
      <div id="comments-list">${commentListHtml}</div>
      ${commentFormHtml}
    </div>` : '';

  res.send(shell(article.title, `
    <div class="page-wrap-sm">
      <div class="article-header">
        <div class="cat-tag">${esc(article.category)}</div>
        <h1>${esc(article.title)}</h1>
        <div class="article-byline">
          <div class="bav">${initials(article.authorName)}</div>
          <span>By <strong>${esc(article.authorName)}</strong></span>
          <span style="color:var(--text-3);">·</span>
          <span>${esc(article.date)}</span>
          ${article.tags.map(t => `<span class="badge badge-muted" style="font-size:0.65rem;">#${esc(t)}</span>`).join(' ')}
        </div>
      </div>
      <div class="article-body">${article.body}</div>
      <a href="/" class="btn btn-ghost btn-sm">← Back to Home</a>
      ${commentsBlock}
    </div>
  `, user));
});

