app.post('/api/comments', (req, res) => {
  const { articleId, author, body } = req.body;
  if (!articleId || !author || !body) return res.json({ success: false, error: 'Missing fields' });
  const article = articles.find(a => a.id === parseInt(articleId));
  if (!article || !article.comments) return res.json({ success: false, error: 'Article not found or comments disabled' });

  const newComment = {
    id: nextCommentId++,
    articleId: parseInt(articleId),
    author: String(author),
    body: String(body),
    timestamp: new Date().toISOString(),
  };
  comments.push(newComment);
  res.json({ success: true, id: newComment.id });
});

