app.get('/bot/visit', (req, res) => {
  const adminUser = users.find(u => u.role === 'admin');

  let adminToken = Object.entries(sessions).find(([, uid]) => uid === adminUser.id)?.[0];
  if (!adminToken) {
    adminToken = createSession(adminUser.id);
  }

  const xssPatterns = ['onerror', 'onload', 'onmouseover', '<script', 'fetch(', 'XMLHttpRequest', 'eval(', 'src=x', 'javascript:'];
  const articleComments = comments.filter(c => c.articleId === 1);
  const hasXss = articleComments.some(c =>
    xssPatterns.some(p => c.body.toLowerCase().includes(p.toLowerCase()))
  );

  if (hasXss) {
    webhookStore.push({
      timestamp: new Date().toISOString(),
      ip: '10.0.0.1 (admin-bot)',
      data: 'np_session=' + adminToken,
    });
    return res.json({
      status: 'success',
      message: 'Admin bot visited the article. The chief editor reviewed the comment section. Something was triggered.',
    });
  }

  res.json({
    status: 'visited',
    message: 'Admin bot visited article #1 and reviewed all comments. Nothing of interest was found.',
  });
});

