function categoryBadge(cat) {
  const cls = {
    World: 'badge-world', Technology: 'badge-tech', Science: 'badge-science',
    Investigation: 'badge-investigation', Politics: 'badge-politics', General: 'badge-general'
  };
  return `<span class="badge ${cls[cat] || 'badge-general'}">${esc(cat)}</span>`;
}

function statusBadge(s) {
  return `<span class="badge ${s === 'published' ? 'badge-published' : 'badge-draft'}">${esc(s)}</span>`;
}

function roleBadge(r) {
  const cls = { 'Editor-in-Chief': 'badge-eic', 'Senior Reporter': 'badge-senior', 'Staff Writer': 'badge-staff', Contributor: 'badge-contributor' };
  return `<span class="badge ${cls[r] || 'badge-contributor'}">${esc(r)}</span>`;
}

function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

