function renderLogin(loginMsg, registerMsg) {
  return loginPageTemplate
    .replace('%%LOGIN_MSG%%', loginMsg || '')
    .replace('%%REGISTER_MSG%%', registerMsg || '');
}

app.get('/', (req, res) => {
  const userId = getSession(req);
  if (userId) return res.redirect('/dashboard');
  res.send(renderLogin('', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = queryOne('SELECT * FROM users WHERE username = ? AND password = ?', [username, password]);
  if (!user) {
    return res.send(renderLogin('<div class="error-msg">Invalid credentials. Check your username and password.</div>', ''));
  }
  const token = createSession(user.id);
  res.cookie('wire_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, display_name } = req.body;
  if (!username || !password || !display_name) {
    return res.send(renderLogin('', '<div class="error-msg">All fields are required.</div>'));
  }
  const existing = queryOne('SELECT id FROM users WHERE username = ?', [username]);
  if (existing) {
    return res.send(renderLogin('', '<div class="error-msg">Username already taken.</div>'));
  }
  db.run('INSERT INTO users (username, password, display_name, role, bio, joined) VALUES (?, ?, ?, ?, ?, ?)', [
    username, password, display_name, 'Contributor', 'New team member.', new Date().toISOString().split('T')[0]
  ]);
  const newUser = queryOne('SELECT * FROM users WHERE username = ?', [username]);
  const token = createSession(newUser.id);
  res.cookie('wire_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.wire_session;
  if (token) delete sessions[token];
  res.clearCookie('wire_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const allPublished = queryAll("SELECT * FROM articles WHERE status = 'published' ORDER BY created_at DESC");
  const totalViews = allPublished.reduce((s, a) => s + (a.views || 0), 0);
  const totalComments = queryAll("SELECT COUNT(*) as cnt FROM comments")[0]?.cnt || 0;

  const myArticlesQuery = `SELECT * FROM articles WHERE author_username = '${user.username}' AND status = 'published' ORDER BY created_at DESC`;
  let myArticles = [];
  try {
    myArticles = queryAll(myArticlesQuery);
  } catch (e) {
    myArticles = [];
  }

  const myDraftsQuery = `SELECT id, title, category, created_at, status FROM articles WHERE author_username = '${user.username}' AND status = 'draft' ORDER BY created_at DESC`;
  let myDrafts = [];
  try {
    myDrafts = queryAll(myDraftsQuery);
  } catch (e) {
    myDrafts = [];
  }

  const articleCards = myArticles.map(a => `
    <div class="article-card">
      ${a.featured ? '<div class="featured-strip"></div>' : ''}
      <div class="article-meta">
        ${categoryBadge(a.category)}
        ${statusBadge(a.status)}
        ${a.featured ? '<span class="badge badge-featured">★ Featured</span>' : ''}
      </div>
      <h3><a href="/article/${a.id}">${esc(a.title)}</a></h3>
      <p class="article-summary">${esc(a.summary || truncate(a.content, 180))}</p>
      <div class="article-footer">
        <span>📅 ${esc(a.created_at)}</span>
        <span>👁 ${a.views?.toLocaleString() || 0} views</span>
      </div>
    </div>`).join('') || '<p style="color:var(--text-muted);font-size:0.88rem;">No published articles yet. <a href="/compose">Write your first article →</a></p>';

  const draftRows = myDrafts.map(d => `
    <tr>
      <td><span style="font-family:var(--font-mono);color:var(--accent);font-size:0.8rem;">#${d.id}</span></td>
      <td>${esc(d.title)}</td>
      <td>${categoryBadge(d.category)}</td>
      <td>${esc(d.created_at)}</td>
    </tr>`).join('') || '<tr><td colspan="4" style="color:var(--text-muted);text-align:center;padding:20px;">No drafts</td></tr>';

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header">
      <h1>Welcome back, ${esc(user.display_name)}</h1>
      <p class="subtitle">The Wire — Editorial Dashboard</p>
    </div>

    <div class="stats-row">
      <div class="stat-card">
        <div class="stat-value">${allPublished.length}</div>
        <div class="stat-label">Published Articles</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">${totalViews.toLocaleString()}</div>
        <div class="stat-label">Total Views</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">${totalComments}</div>
        <div class="stat-label">Comments</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">${myArticles.length}</div>
        <div class="stat-label">Your Published</div>
      </div>
    </div>

    <div style="margin-bottom:28px;">
      <h2 style="font-family:var(--font-serif);font-size:1.15rem;margin-bottom:16px;">Your Published Articles</h2>
      ${articleCards}
    </div>

    <div class="card">
      <h3 style="font-family:var(--font-serif);font-size:1rem;margin-bottom:14px;">Your Drafts</h3>
      <table class="data-table">
        <thead><tr><th>ID</th><th>Title</th><th>Category</th><th>Date</th></tr></thead>
        <tbody>${draftRows}</tbody>
      </table>
    </div>
  `));
});

