app.get('/article/:id', requireAuth, (req, res) => {
  const user = req.user;
  const articleId = parseInt(req.params.id);
  const article = queryOne('SELECT a.*, u.display_name FROM articles a JOIN users u ON a.author_username = u.username WHERE a.id = ? AND a.status = ?', [articleId, 'published']);

  if (!article) {
    return res.send(pageShell('Not Found', 'articles', user,
      '<div class="page-header"><h1>Article Not Found</h1></div><p style="color:var(--text-muted);">This article does not exist or is not published.</p><br><a href="/articles" class="btn btn-ghost" style="cursor:pointer;color:var(--text-secondary);">← Back to Articles</a>'));
