app.post('/article/:id/comment', requireAuth, (req, res) => {
  const articleId = parseInt(req.params.id);
  const { content } = req.body;
  const user = req.user;
  if (content && content.trim()) {
    db.run('INSERT INTO comments (article_id, author_name, content, created_at) VALUES (?, ?, ?, ?)', [
      articleId, user.display_name, content.trim(), new Date().toISOString().split('T')[0]
    ]);
  }
  res.redirect('/article/' + articleId);
});

app.get('/newsroom', requireAuth, (req, res) => {
  const user = req.user;
  const journalists = queryAll('SELECT * FROM users ORDER BY joined ASC');

  const avatarColors = {
    'Editor-in-Chief': 'linear-gradient(135deg, #d4a538, #8a6820)',
    'Senior Reporter': 'linear-gradient(135deg, #5b8af0, #6366f1)',
    'Staff Writer': 'linear-gradient(135deg, #a07ce8, #7c3aed)',
    Contributor: 'linear-gradient(135deg, #64748b, #475569)',
  };

  const cards = journalists.map(j => {
    const init = initials(j.display_name);
    const color = avatarColors[j.role] || avatarColors.Contributor;
    const articleCount = queryAll("SELECT COUNT(*) as cnt FROM articles WHERE author_username = ? AND status = 'published'", [j.username])[0]?.cnt || 0;

    return `
      <div class="team-card">
        <div class="tc-avatar" style="background:${color};">${esc(init)}</div>
        <div class="tc-name">${esc(j.display_name)}</div>
