function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function statusBadge(s) {
  const cls = { Confirmed: 'badge-confirmed', Pending: 'badge-pending', Waitlist: 'badge-waitlist' };
  return '<span class="badge ' + (cls[s] || 'badge-pending') + '">' + esc(s) + '</span>';
}

function orderStatusBadge(s) {
  const cls = { Preparing: 'badge-preparing', Fired: 'badge-fired', Queued: 'badge-queued', Ready: 'badge-ready' };
  return '<span class="badge ' + (cls[s] || 'badge-queued') + '">' + esc(s) + '</span>';
}

