app.get('/', (req, res) => {
  res.send(loginPage.replace('ERRORPLACEHOLDER', '').replace('REGISTERPLACEHOLDER', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(loginPage
      .replace('ERRORPLACEHOLDER', '<div class="error-msg">Invalid credentials. Please check your username and password.</div>')
      .replace('REGISTERPLACEHOLDER', ''));
  }
  const token = createSession(user.id);
  res.cookie('lb_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(loginPage
      .replace('ERRORPLACEHOLDER', '')
      .replace('REGISTERPLACEHOLDER', '<div class="error-msg">All fields are required.</div>'));
  }
  if (users.find(u => u.username === username)) {
    return res.send(loginPage
      .replace('ERRORPLACEHOLDER', '')
      .replace('REGISTERPLACEHOLDER', '<div class="error-msg">Username already taken.</div>'));
  }
  const newUser = {
    id: nextUserId++,
    username, password, name,
    role: 'Staff',
    department: 'Front of House',
    email: username + '@labraseria.com',
    joined: new Date().toISOString().split('T')[0],
    accessLevel: 'Basic',
    specialization: 'Pending Assignment',
    certifications: [],
    bio: 'New staff member.',
    apiKey: null,
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('lb_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.lb_session;
  if (token) delete sessions[token];
  res.clearCookie('lb_session');
  res.redirect('/');
});

