const JWT_SECRET = 'secret';
const ADMIN_PIN = 'x9Kf2mR7vL4bQw8sYdE1nP6cJtA3hG0z';

function b64urlEncode(obj) {
  return Buffer.from(JSON.stringify(obj)).toString('base64url');
}

function b64urlDecode(str) {
  return JSON.parse(Buffer.from(str, 'base64url').toString());
}

function signJWT(payload) {
  const h = b64urlEncode({ alg: 'HS256', typ: 'JWT' });
  const p = b64urlEncode(payload);
  const sig = crypto.createHmac('sha256', JWT_SECRET).update(`${h}.${p}`).digest('base64url');
  return `${h}.${p}.${sig}`;
}

function verifyJWT(token) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) return null;
    const expected = crypto.createHmac('sha256', JWT_SECRET).update(`${parts[0]}.${parts[1]}`).digest('base64url');
    if (parts[2] !== expected) return null;
    return b64urlDecode(parts[1]);
  } catch { return null; }
}

