function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function requireAuth(req, res, next) {
  const token = req.cookies?.bellini_session;
  if (!token) return res.redirect('/');
  const payload = verifyJWT(token);
  if (!payload) {
    res.clearCookie('bellini_session');
    return res.redirect('/');
  }
  req.user = payload;
  next();
}

function requireRole(roles) {
  const allowed = Array.isArray(roles) ? roles : [roles];
  return (req, res, next) => {
    if (!allowed.includes(req.user.role)) {
      return res.status(403).send(pageShell('Access Denied', 'none', req.user,
        `<div class="page-header"><h1>🚫 Accesso Negato</h1><p class="subtitle">Your role <code style="color:var(--accent);font-family:var(--font-mono);">${esc(req.user.role)}</code> does not have permission to access this area. Required: <code style="color:var(--accent-red);font-family:var(--font-mono);">${esc(allowed.join(' | '))}</code></p></div>`
      ));
    }
    next();
  };
}

