app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) return res.redirect('/?error=1');
  const result = db.exec(`SELECT * FROM users WHERE username = ? AND password = ?`, [username, password]);
  if (!result.length || !result[0].values.length) return res.redirect('/?error=1');
  const row = result[0].values[0];
  const cols = result[0].columns;
  const user = {};
  cols.forEach((c, i) => user[c] = row[i]);
  const token = signJWT({ id: user.id, username: user.username, name: user.name, role: user.role, iat: Math.floor(Date.now() / 1000) });
  res.cookie('bellini_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/menu');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.redirect('/?error=1');
  try {
    db.run(`INSERT INTO users (username, password, name, role) VALUES (?, ?, ?, 'customer')`, [username, password, name]);
    res.redirect('/?registered=1');
  } catch {
    res.redirect('/?error=1');
  }
});

app.get('/logout', (req, res) => {
  res.clearCookie('bellini_session');
  res.redirect('/');
});

