app.get('/kitchen', requireAuth, requireRole('chef'), (req, res) => {
  const q = req.query.q || '';
  let searchHTML = '';

  if (q) {
    try {
      const results = db.exec(`SELECT order_ref, customer_name, table_num, items, status, total FROM orders WHERE order_ref = '${q}'`);
      if (results.length && results[0].values.length) {
        const cols = results[0].columns;
        let tableRows = '';
        for (const row of results[0].values) {
          const o = {};
          cols.forEach((c, i) => o[c] = row[i]);
          tableRows += `<tr>
            <td style="font-family:var(--font-mono);color:var(--accent);">${esc(String(o.order_ref))}</td>
            <td>${esc(String(o.customer_name))}</td>
            <td style="text-align:center;">T${o.table_num}</td>
            <td>${esc(String(o.items))}</td>
            <td>${statusBadge(String(o.status))}</td>
            <td style="font-family:var(--font-mono);">€${Number(o.total).toFixed(2)}</td>
          </tr>`;
        }
        searchHTML = `<div class="search-found">
          <p style="color:var(--accent-green);font-weight:600;margin-bottom:10px;">✓ Order Found — ${results[0].values.length} result(s)</p>
          <table class="data-table"><thead><tr><th>Ref</th><th>Customer</th><th>Table</th><th>Items</th><th>Status</th><th>Total</th></tr></thead><tbody>${tableRows}</tbody></table>
        </div>`;
      } else {
        searchHTML = `<div class="search-empty">✗ No Orders Found matching "<span style="font-family:var(--font-mono);">${esc(q)}</span>"</div>`;
      }
    } catch (e) {
      searchHTML = `<div class="search-empty">✗ No Orders Found — query error</div>`;
    }
  }

  const pending = db.exec(`SELECT * FROM orders WHERE status != 'Completed' ORDER BY id`);
  let queueRows = '';
  if (pending.length) {
    const cols = pending[0].columns;
    for (const row of pending[0].values) {
      const o = {};
      cols.forEach((c, i) => o[c] = row[i]);
      queueRows += `<tr>
        <td style="font-family:var(--font-mono);color:var(--accent);">${esc(o.order_ref)}</td>
        <td>${esc(o.customer_name)}</td>
        <td style="text-align:center;">T${o.table_num}</td>
        <td>${esc(o.items)}</td>
        <td>${statusBadge(o.status)}</td>
        <td style="font-family:var(--font-mono);">€${Number(o.total).toFixed(2)}</td>
        <td style="font-size:0.8rem;color:var(--text-muted);">${esc(o.created_at)}</td>
      </tr>`;
    }
  }

  const statsResult = db.exec(`SELECT COUNT(*) as total, SUM(CASE WHEN status='Pending' THEN 1 ELSE 0 END) as pend, SUM(CASE WHEN status='Preparing' THEN 1 ELSE 0 END) as prep, SUM(CASE WHEN status='Completed' THEN 1 ELSE 0 END) as done FROM orders`);
  let stats = { total: 0, pend: 0, prep: 0, done: 0 };
  if (statsResult.length) {
    const row = statsResult[0].values[0];
    stats = { total: row[0], pend: row[1], prep: row[2], done: row[3] };
  }

  res.send(pageShell('Kitchen', 'kitchen', req.user, `
    <div class="page-header"><h1>👨‍🍳 La Cucina</h1><p class="subtitle">Kitchen management dashboard — Chef access only</p></div>

    <div class="stats-row">
      <div class="stat-card"><div class="stat-value">${stats.total}</div><div class="stat-label">Total Orders</div></div>
      <div class="stat-card"><div class="stat-value" style="color:var(--accent-blue);">${stats.pend}</div><div class="stat-label">Pending</div></div>
      <div class="stat-card"><div class="stat-value" style="color:#f59e0b;">${stats.prep}</div><div class="stat-label">Preparing</div></div>
      <div class="stat-card"><div class="stat-value" style="color:var(--accent-green);">${stats.done}</div><div class="stat-label">Completed</div></div>
    </div>

    <div class="card">
      <h3 style="font-family:var(--font-display);font-size:1rem;margin-bottom:14px;">Order Lookup</h3>
      <p style="font-size:0.8rem;color:var(--text-muted);margin-bottom:12px;">Search by order reference number (e.g., ORD-2401)</p>
      <form method="GET" action="/kitchen" class="search-box">
        <input type="text" name="q" placeholder="Enter order reference..." value="${esc(q)}" autocomplete="off">
        <button type="submit" class="btn btn-primary">Search</button>
      </form>
      ${searchHTML}
    </div>

    <div class="card">
      <h3 style="font-family:var(--font-display);font-size:1rem;margin-bottom:14px;">Active Order Queue</h3>
      <table class="data-table"><thead><tr><th>Ref</th><th>Customer</th><th>Table</th><th>Items</th><th>Status</th><th>Total</th><th>Time</th></tr></thead><tbody>${queueRows}</tbody></table>
    </div>
  `));
});

app.get('/api/kitchen/search', requireAuth, requireRole('chef'), (req, res) => {
  const q = req.query.q || '';
  if (!q) return res.json({ found: false, count: 0, message: 'No query provided' });
  try {
    const results = db.exec(`SELECT order_ref, customer_name, status FROM orders WHERE order_ref = '${q}'`);
    if (results.length && results[0].values.length) {
      const orders = results[0].values.map(row => ({
        order_ref: row[0], customer_name: row[1], status: row[2]
      }));
      res.json({ found: true, count: orders.length, orders });
    } else {
      res.json({ found: false, count: 0 });
    }
  } catch (e) {
    res.json({ found: false, count: 0 });
  }
});

