function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSessionUser(req) {
  const token = req.cookies?.ff_session;
  if (!token || !sessions[token]) return null;
  const uid = sessions[token];
  const result = db.exec(`SELECT id, username, name, role, email, joined FROM users WHERE id = ?`, [uid]);
  if (!result.length || !result[0].values.length) return null;
  const row = result[0].values[0];
  return { id: row[0], username: row[1], name: row[2], role: row[3], email: row[4], joined: row[5] };
}

function requireAuth(req, res, next) {
  const user = getSessionUser(req);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

