app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) return res.send(renderLogin('<div class="error-msg">All fields are required.</div>', ''));
  const result = db.exec(`SELECT id FROM users WHERE username = ? AND password = ?`, [username, password]);
  if (!result.length || !result[0].values.length) {
    return res.send(renderLogin('<div class="error-msg">Invalid username or password.</div>', ''));
  }
  const uid = result[0].values[0][0];
  const token = createSession(uid);
  res.cookie('ff_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.send(renderLogin('', '<div class="error-msg">All fields are required.</div>'));
  const existing = db.exec(`SELECT id FROM users WHERE username = ?`, [username]);
  if (existing.length && existing[0].values.length) {
    return res.send(renderLogin('', '<div class="error-msg">Username is already taken.</div>'));
  }
  db.run(`INSERT INTO users (username, password, name, role, email, joined) VALUES (?, ?, ?, 'Server', ?, ?)`, [username, password, name, username + '@ferroflame.com', new Date().toISOString().split('T')[0]]);
  const newUser = db.exec(`SELECT id FROM users WHERE username = ?`, [username]);
  const uid = newUser[0].values[0][0];
  const token = createSession(uid);
  res.cookie('ff_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.ff_session;
  if (token) delete sessions[token];
  res.clearCookie('ff_session');
  res.redirect('/');
});

