app.get('/menu', requireAuth, (req, res) => {
  const user = req.user;
  const category = req.query.category || '';

  let items = [];
  let queryUsed = '';
  let resultMessage = '';

  if (category) {
    try {
      const sql = `SELECT id, name, description, price, category, available FROM menu_items WHERE category = '${category}'`;
      queryUsed = category;
      const result = db.exec(sql);
      if (result.length && result[0].values.length) {
        items = result[0].values.map(r => ({ id: r[0], name: r[1], description: r[2], price: r[3], category: r[4], available: r[5] }));
        resultMessage = `<div class="result-count">Showing <strong>${items.length}</strong> item${items.length !== 1 ? 's' : ''} in <strong>${esc(category)}</strong></div>`;
      } else {
        resultMessage = `<div class="no-results"><div class="nr-icon">🍽️</div><div class="nr-text">No items found</div><div class="nr-hint">No menu items match this filter.</div></div>`;
      }
    } catch (e) {
      resultMessage = `<div class="no-results"><div class="nr-icon">🍽️</div><div class="nr-text">No items found</div><div class="nr-hint">No menu items match this filter.</div></div>`;
    }
  } else {
    const result = db.exec(`SELECT id, name, description, price, category, available FROM menu_items ORDER BY category, name`);
    if (result.length && result[0].values.length) {
      items = result[0].values.map(r => ({ id: r[0], name: r[1], description: r[2], price: r[3], category: r[4], available: r[5] }));
    }
    resultMessage = `<div class="result-count">Showing all <strong>${items.length}</strong> menu items</div>`;
  }

  const categories = ['Appetizers', 'Mains', 'Desserts', 'Drinks'];
  const catTabs = categories.map(c =>
    `<a href="/menu?category=${encodeURIComponent(c)}" class="category-tab ${category === c ? 'active' : ''}">${esc(c)}</a>`
  ).join('');

  const itemCards = items.map(item => `
    <div class="menu-card">
      <div class="mc-category">${esc(item.category)}</div>
      <div class="mc-name">${esc(item.name)}</div>
      <div class="mc-desc">${esc(item.description)}</div>
      <div class="mc-footer">
        <span class="mc-price">$${Number(item.price).toFixed(2)}</span>
        <span class="badge ${item.available ? 'badge-available' : 'badge-unavailable'}">${item.available ? 'Available' : 'Unavailable'}</span>
      </div>
    </div>
  `).join('');

  res.send(pageShell('Menu', 'menu', user, `
    <div class="page-header">
      <h1>Menu Management</h1>
      <p class="subtitle">Browse and filter the current Ferro & Flame menu</p>
    </div>

    <div class="search-bar">
      <input type="text" id="catSearch" placeholder="Type a category name to filter (e.g., Appetizers, Mains, Desserts, Drinks)..." value="${esc(queryUsed)}">
      <button class="btn btn-primary" onclick="filterMenu()">Filter</button>
      <a href="/menu" class="btn btn-ghost" style="display:flex;align-items:center;">All Items</a>
    </div>

    <div class="category-tabs">
      <a href="/menu" class="category-tab ${!category ? 'active' : ''}">All</a>
      ${catTabs}
    </div>

    ${resultMessage}

    <div class="menu-grid">
      ${itemCards}
    </div>

    <script>
      function filterMenu() {
        const val = document.getElementById('catSearch').value.trim();
        if (val) {
          window.location.href = '/menu?category=' + encodeURIComponent(val);
        } else {
          window.location.href = '/menu';
        }
      }
      document.getElementById('catSearch').addEventListener('keydown', function(e) {
        if (e.key === 'Enter') filterMenu();
      });
    </script>
  `));
});

app.get('/api/menu', requireAuth, (req, res) => {
  const category = req.query.category || '';
  if (!category) {
    const result = db.exec(`SELECT id, name, description, price, category, available FROM menu_items ORDER BY category, name`);
    const items = result.length ? result[0].values.map(r => ({ id: r[0], name: r[1], description: r[2], price: r[3], category: r[4], available: !!r[5] })) : [];
    return res.json({ found: true, count: items.length, items });
  }

  try {
    const sql = `SELECT id, name, description, price, category, available FROM menu_items WHERE category = '${category}'`;
    const result = db.exec(sql);
    if (result.length && result[0].values.length) {
      const items = result[0].values.map(r => ({ id: r[0], name: r[1], description: r[2], price: r[3], category: r[4], available: !!r[5] }));
      return res.json({ found: true, count: items.length, items });
    } else {
      return res.json({ found: false, count: 0, items: [] });
    }
  } catch (e) {
    return res.json({ found: false, count: 0, items: [] });
  }
});

