app.post('/login', (req, res) => {
  const { username, password } = req.body;
  try {
    const results = db.exec(`SELECT id, username, name, role FROM users WHERE username = '${username}' AND password = '${password}'`);
    if (results.length && results[0].values.length) {
      const row = results[0].values[0];
      const token = createSession(row[0]);
      res.cookie('eo_session', token, { httpOnly: false, sameSite: 'lax' });
      return res.redirect('/dashboard');
    }
    return res.redirect('/?error=Invalid+credentials');
  } catch (e) {
    return res.redirect('/?error=Invalid+credentials');
  }
});

app.post('/register', (req, res) => {
  const { name, username, password } = req.body;
  if (!name || !username || !password) return res.redirect('/?error=All+fields+required');
  try {
    const existing = db.exec(`SELECT id FROM users WHERE username = '${username.replace(/'/g, "''")}'`);
    if (existing.length && existing[0].values.length) {
      return res.redirect('/?error=Username+already+taken');
    }
    db.run(`INSERT INTO users VALUES (${nextUserId++}, '${username.replace(/'/g, "''")}', '${password.replace(/'/g, "''")}', '${name.replace(/'/g, "''")}', 'Staff')`);
    return res.redirect('/?registered=1');
  } catch (e) {
    return res.redirect('/?error=Registration+failed');
  }
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.eo_session;
  if (token) delete sessions[token];
  res.clearCookie('eo_session');
  res.redirect('/');
});

