// ── API: Server-side URL fetch ────────────────────────────────────────

app.post('/api/fetch-url', requireAuth, (req, res) => {
  const { url } = req.body;

  if (!url || typeof url !== 'string') {
    return res.status(400).json({ error: 'Missing or invalid URL parameter.' });
  }

  let parsedUrl;
  try {
    parsedUrl = new URL(url);
  } catch {
    return res.status(400).json({ error: 'Invalid URL format. Please include protocol (http:// or https://).' });
  }

  if (parsedUrl.protocol !== 'http:' && parsedUrl.protocol !== 'https:') {
    return res.status(400).json({ error: 'Only http and https protocols are supported.' });
  }

  const isHttps = parsedUrl.protocol === 'https:';
  const port = parsedUrl.port
    ? parseInt(parsedUrl.port)
    : isHttps ? 443 : 80;

  const options = {
    hostname: parsedUrl.hostname,
    port,
    path: parsedUrl.pathname + parsedUrl.search,
    method: 'GET',
    headers: {
      'User-Agent': 'TavolaCucina-WebhookTester/1.0',
      'Accept': 'application/json, text/plain, */*',
    },
    timeout: 8000,
  };

  if (isHttps) {
    import('https').then(({ default: httpsModule }) => {
      makeRequest(httpsModule, options, res, url);
    });
  } else {
    makeRequest(http, options, res, url);
  }
});

function makeRequest(transport, options, res, originalUrl) {
  const req = transport.request(options, (response) => {
    let body = '';
    response.on('data', chunk => { body += chunk; });
    response.on('end', () => {
      res.json({
        status: response.statusCode,
        headers: response.headers,
        body: body.slice(0, 4096),
        url: originalUrl,
      });
    });
  });

  req.on('error', (err) => {
    res.json({ error: 'Connection failed: ' + err.message, url: originalUrl });
  });

  req.on('timeout', () => {
    req.destroy();
    res.json({ error: 'Request timed out after 8 seconds.', url: originalUrl });
  });

  req.end();
}

