app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.redirect('/?error=Invalid+credentials.+Please+try+again.');
  }
  const token = createSession(user.id);
  res.cookie('sn_session', token, { httpOnly: false, sameSite: 'lax' });
  res.cookie('role', user.role, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/feed');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.redirect('/?error=All+fields+are+required.');
  }
  if (users.find(u => u.username === username)) {
    return res.redirect('/?error=Username+already+taken.');
  }
  const newUser = {
    id: nextUserId++,
    username,
    password,
    name,
    role: 'user',
    bio: 'New to SphereNet! 👋',
    location: 'Somewhere',
    joined: new Date().toISOString().split('T')[0],
    followers: 0,
    following: 0,
    posts: 0,
    avatar: '✨',
    color: 'linear-gradient(135deg, #8b5cf6, #6366f1)',
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('sn_session', token, { httpOnly: false, sameSite: 'lax' });
  res.cookie('role', 'user', { httpOnly: false, sameSite: 'lax' });
  res.redirect('/feed');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.sn_session;
  if (token) delete sessions[token];
  res.clearCookie('sn_session');
  res.clearCookie('role');
  res.redirect('/');
});

