app.get('/messages', requireAuth, (req, res) => {
  const user = req.user;
  const userMsgs = messages.filter(m => m.to === user.id || m.from === user.id);

  const msgRows = userMsgs.map(m => {
    const other = users.find(u => u.id === (m.from === user.id ? m.to : m.from));
    if (!other) return '';
    const isUnread = m.unread && m.to === user.id;
    return `
      <div class="msg-row ${isUnread ? 'msg-unread' : ''}">
        <div class="msg-avatar" style="background:${other.color};">${other.avatar}</div>
        <div class="msg-content">
          <div class="msg-subject">${esc(m.subject)}</div>
          <div class="msg-preview">${esc(m.preview)}</div>
        </div>
        <span class="msg-time">${esc(m.time)}</span>
      </div>`;
  }).join('');

  res.send(pageShell('Messages', 'messages', user, `
    <div class="page-header">
      <h1>Messages</h1>
      <p class="subtitle">Your private conversations</p>
    </div>
    <div class="card">
      ${userMsgs.length > 0 ? msgRows : '<p style="color:var(--text-muted);text-align:center;padding:30px;">No messages yet.</p>'}
    </div>
  `));
});

