function generateToken(user) {
  return jwt.sign({ id: user.id, username: user.username, role: user.role }, JWT_SECRET, { algorithm: 'HS256', expiresIn: '24h' });
}

function authenticateJWT(req, res, next) {
  const token = req.cookies?.pulse_token;
  if (!token) return res.redirect('/');
  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = decoded;
    const dbUser = users.find(u => u.id === decoded.id);
    if (dbUser) {
      req.user.name = dbUser.name;
      req.user.avatar = dbUser.avatar;
      req.user.bio = dbUser.bio;
      req.user.location = dbUser.location;
      req.user.followers = dbUser.followers;
      req.user.following = dbUser.following;
      req.user.postCount = dbUser.postCount;
      req.user.joined = dbUser.joined;
    } else {
      req.user.name = decoded.username;
      req.user.avatar = '👤';
    }
    next();
  } catch (err) {
    res.clearCookie('pulse_token');
    return res.redirect('/');
  }
}

function requireRole(minRole) {
  const hierarchy = { user: 1, moderator: 2, admin: 3 };
  return (req, res, next) => {
    const level = hierarchy[req.user.role] || 0;
    const required = hierarchy[minRole] || 99;
    if (level < required) {
      return res.status(403).send(buildPage('Access Denied', req.user, `
        <div class="access-denied">
          <div class="denied-icon">🔒</div>
          <h2>Access Denied</h2>
          <p>Your role <span class="role-badge role-${esc(req.user.role)}">${esc(req.user.role)}</span> does not have permission to access this area.</p>
          <p class="subtext">Required: <span class="role-badge role-${minRole}">${minRole}</span> or higher</p>
          <a href="/feed" class="btn btn-primary" style="margin-top:16px;">Return to Feed</a>
        </div>
      `));
    }
    next();
  };
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function timeAgo(dateStr) {
  const d = new Date(dateStr);
  const now = new Date();
  const diff = Math.floor((now - d) / 1000);
  if (diff < 3600) return Math.floor(diff / 60) + 'm ago';
  if (diff < 86400) return Math.floor(diff / 3600) + 'h ago';
  return Math.floor(diff / 86400) + 'd ago';
}

function userInitials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

