app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) return res.redirect('/?error=1');
  const token = generateToken(user);
  res.cookie('pulse_token', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/feed');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.redirect('/register?error=fields');
  if (users.find(u => u.username === username)) return res.redirect('/register?error=taken');
  const newUser = {
    id: nextUserId++, username, password, name, role: 'user',
    bio: 'New to PulseNet!', avatar: '✨', location: 'Unknown',
    joined: new Date().toISOString().split('T')[0],
    followers: 0, following: 0, postCount: 0,
    private_messages: [], visible: true
  };
  users.push(newUser);
  res.redirect('/?registered=1');
});

app.get('/logout', (req, res) => {
  res.clearCookie('pulse_token');
  res.redirect('/');
});

