function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSessionUser(req) {
  const token = req.cookies?.nx_session;
  if (!token || !sessions[token]) return null;
  const userId = sessions[token];
  const rows = db.exec(`SELECT id, username, display_name, role, bio, avatar_color, joined FROM users WHERE id = ${userId}`);
  if (!rows.length || !rows[0].values.length) return null;
  const r = rows[0].values[0];
  return { id: r[0], username: r[1], display_name: r[2], role: r[3], bio: r[4], avatar_color: r[5], joined: r[6] };
}

function requireAuth(req, res, next) {
  const user = getSessionUser(req);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function requireAdmin(req, res, next) {
  const user = getSessionUser(req);
  if (!user) return res.redirect('/');
  if (user.role !== 'admin') {
    return res.status(403).send(errorPage('Access Denied', 'This area is restricted to platform administrators.'));
  }
  req.user = user;
  next();
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function getInitials(name) {
  return String(name).split(' ').map(w => w[0]).join('').toUpperCase();
}

function timeAgo(dateStr) {
  const d = new Date(dateStr);
  const now = new Date();
  const diff = Math.floor((now - d) / 1000);
  if (diff < 60) return 'just now';
  if (diff < 3600) return Math.floor(diff / 60) + 'm ago';
  if (diff < 86400) return Math.floor(diff / 3600) + 'h ago';
  return Math.floor(diff / 86400) + 'd ago';
}

