app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const rows = db.exec(`SELECT id, password FROM users WHERE username = '${username.replace(/'/g, "''")}'`);
  if (!rows.length || !rows[0].values.length || rows[0].values[0][1] !== password) {
    return res.send(renderLogin('<div class="error-msg">Invalid username or password.</div>', ''));
  }
  const userId = rows[0].values[0][0];
  const token = createSession(userId);
  res.cookie('nx_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/feed');
});

app.post('/register', (req, res) => {
  const { username, password, display_name } = req.body;
  if (!username || !password || !display_name) {
    return res.send(renderLogin('', '<div class="error-msg">All fields are required.</div>'));
  }
  const existing = db.exec(`SELECT id FROM users WHERE username = '${username.replace(/'/g, "''")}'`);
  if (existing.length && existing[0].values.length) {
    return res.send(renderLogin('', '<div class="error-msg">Username already taken.</div>'));
  }
  const colors = ['#7c3aed', '#3b82f6', '#10b981', '#f59e0b', '#f43f5e', '#6366f1', '#ec4899'];
  const color = colors[Math.floor(Math.random() * colors.length)];
  const joined = new Date().toISOString().split('T')[0];
  const stmt = db.prepare(`INSERT INTO users (username, password, display_name, role, bio, avatar_color, joined) VALUES (?, ?, ?, 'user', '', ?, ?)`);
  stmt.run([username, password, display_name, color, joined]);
  stmt.free();
  const newRows = db.exec(`SELECT id FROM users WHERE username = '${username.replace(/'/g, "''")}'`);
  const newId = newRows[0].values[0][0];
  const token = createSession(newId);
  res.cookie('nx_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/feed');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.nx_session;
  if (token) delete sessions[token];
  res.clearCookie('nx_session');
  res.redirect('/');
});

app.get('/feed', requireAuth, (req, res) => {
  const user = req.user;
  const rows = db.exec(`SELECT id, user_id, username, display_name, content, likes, created_at FROM posts ORDER BY id DESC`);
  let postsHtml = '';
  if (rows.length && rows[0].values.length) {
    for (const r of rows[0].values) {
      const postContent = r[4];
      const authorColor = db.exec(`SELECT avatar_color FROM users WHERE username = '${String(r[2]).replace(/'/g, "''")}'`);
      const color = (authorColor.length && authorColor[0].values.length) ? authorColor[0].values[0][0] : '#6366f1';
      const init = getInitials(r[3]);
      postsHtml += `
        <div class="card post-card">
          <div class="post-header">
            <div class="post-avatar" style="background:${esc(color)}">${esc(init)}</div>
            <div>
              <div class="post-author">${esc(r[3])}</div>
              <div class="post-handle">@${esc(r[2])}</div>
            </div>
            <div class="post-time">${timeAgo(r[6])}</div>
          </div>
          <div class="post-content">${postContent}</div>
          <div class="post-footer">
            <div class="post-action">❤️ ${r[5]}</div>
            <div class="post-action">💬 Reply</div>
            <div class="post-action">🔗 Share</div>
          </div>
        </div>`;
    }
  } else {
    postsHtml = '<div class="card"><p style="color:var(--text-muted);text-align:center;padding:20px;">No posts yet. Be the first!</p></div>';
  }

  res.send(shell('Feed', 'feed', user, `
    <h1 class="page-title">Feed</h1>
    <p class="page-subtitle">See what everyone is sharing on Pulse</p>

    <div class="card compose-box">
      <form id="postForm">
        <textarea id="postContent" placeholder="What's on your mind, ${esc(user.display_name.split(' ')[0])}?" maxlength="2000"></textarea>
        <div class="compose-footer">
          <button type="submit" class="btn btn-primary">Post</button>
        </div>
      </form>
      <div id="postMsg"></div>
    </div>

    ${postsHtml}

    <script>
      document.getElementById('postForm').addEventListener('submit', function(e) {
        e.preventDefault();
        var content = document.getElementById('postContent').value;
        if (!content.trim()) return;
        fetch('/feed/post', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ content: content })
        }).then(function(r) { return r.json(); }).then(function(d) {
          if (d.success) { window.location.reload(); }
          else { document.getElementById('postMsg').innerHTML = '<div class="error-msg">' + (d.error || 'Failed') + '</div>'; }
        });
      });
    </script>
  `));
});

app.post('/feed/post', requireAuth, (req, res) => {
  const user = req.user;
  const content = req.body.content;
  if (!content || !content.trim()) {
    return res.json({ success: false, error: 'Post content cannot be empty.' });
  }
  if (content.length > 2000) {
    return res.json({ success: false, error: 'Post too long (max 2000 chars).' });
  }
  const now = new Date().toISOString().replace('T', ' ').split('.')[0];
  const stmt = db.prepare(`INSERT INTO posts (user_id, username, display_name, content, likes, created_at) VALUES (?, ?, ?, ?, 0, ?)`);
  stmt.run([user.id, user.username, user.display_name, content, now]);
  stmt.free();
  res.json({ success: true });
});

app.get('/profile/:username', requireAuth, (req, res) => {
  const user = req.user;
  const target = req.params.username;
  const rows = db.exec(`SELECT id, username, display_name, role, bio, avatar_color, joined FROM users WHERE username = '${target.replace(/'/g, "''")}'`);
  if (!rows.length || !rows[0].values.length) {
    return res.send(shell('Not Found', 'profile', user,
      '<h1 class="page-title">User Not Found</h1><p style="color:var(--text-muted)">No user with that username exists.</p>'));
  }
  const p = rows[0].values[0];
  const init = getInitials(p[2]);
  const roleBadge = p[3] === 'admin' ? '<span class="badge badge-admin">Admin</span>' : '<span class="badge badge-user">Member</span>';

  const postRows = db.exec(`SELECT id, content, likes, created_at FROM posts WHERE username = '${target.replace(/'/g, "''")}' ORDER BY id DESC`);
  let userPosts = '';
  if (postRows.length && postRows[0].values.length) {
    for (const pr of postRows[0].values) {
      userPosts += `
        <div class="card post-card">
          <div class="post-content">${pr[1]}</div>
          <div class="post-footer">
            <div class="post-action">❤️ ${pr[2]}</div>
            <div class="post-action" style="margin-left:auto;font-size:0.7rem;">${timeAgo(pr[3])}</div>
          </div>
        </div>`;
    }
  } else {
    userPosts = '<div class="card"><p style="color:var(--text-muted);text-align:center;padding:16px;">No posts yet.</p></div>';
  }

  res.send(shell(p[2], p[1] === user.username ? 'profile' : '', user, `
    <div class="profile-banner">
      <div class="p-avatar" style="background:${esc(p[5])}">${esc(init)}</div>
      <h2>${esc(p[2])} ${roleBadge}</h2>
      <div class="handle">@${esc(p[1])}</div>
      <div class="pbio">${esc(p[4] || 'No bio yet.')}</div>
      <div style="margin-top:10px;font-size:0.75rem;color:var(--text-muted);">Joined ${esc(p[6])}</div>
    </div>
    <h3 style="font-size:1rem;font-weight:700;margin-bottom:14px;">Posts</h3>
    ${userPosts}
  `));
});

