app.get('/bot/visit', (req, res) => {
  const adminRows = db.exec(`SELECT id FROM users WHERE role = 'admin' LIMIT 1`);
  if (!adminRows.length || !adminRows[0].values.length) {
    return res.json({ status: 'error', message: 'No admin user found.' });
  }
  const adminId = adminRows[0].values[0][0];
  const adminToken = createSession(adminId);

  const postRows = db.exec(`SELECT content FROM posts ORDER BY id DESC`);
  let triggered = false;
  if (postRows.length && postRows[0].values.length) {
    for (const row of postRows[0].values) {
      const raw = String(row[0]);
      if (raw.includes('document.cookie') && raw.includes('/webhook')) {
        webhookStore.push({
          data: `nx_session=${adminToken}`,
          timestamp: new Date().toISOString()
        });
        triggered = true;
        break;
      }
    }
  }

  if (triggered) {
    res.json({ status: 'visited', message: 'Admin bot browsed the feed. Something caught its eye...', timestamp: new Date().toISOString() });
  } else {
    delete sessions[adminToken];
    res.json({ status: 'visited', message: 'Admin bot browsed the feed. Nothing unusual found.', timestamp: new Date().toISOString() });
  }
});

app.get('/admin/moderation', requireAdmin, (req, res) => {
  const user = req.user;
  const searchTerm = req.query.q || '';
  let tableHtml = '';
  let resultCount = 0;

  if (searchTerm) {
    try {
      const query = `SELECT id, username, display_name, role, joined FROM users WHERE username LIKE '%${searchTerm}%' OR display_name LIKE '%${searchTerm}%'`;
      const results = db.exec(query);
      if (results.length && results[0].values.length) {
