          </div>`;
      } else {
        tableHtml = '<div class="card"><p style="color:var(--text-muted);text-align:center;padding:16px;">No results found.</p></div>';
      }
    } catch (e) {
      tableHtml = `<div class="error-msg">Query error: ${esc(String(e.message))}</div>`;
    }
  } else {
    const all = db.exec(`SELECT id, username, display_name, role, joined FROM users ORDER BY id`);
    if (all.length && all[0].values.length) {
      resultCount = all[0].values.length;
      const rows = all[0].values.map(r => `
        <tr>
          <td style="font-family:var(--font-mono);color:var(--accent-light);">${r[0]}</td>
          <td style="font-family:var(--font-mono);">${r[1]}</td>
          <td>${r[2]}</td>
          <td>${r[3] === 'admin' ? '<span class="badge badge-admin">Admin</span>' : '<span class="badge badge-user">User</span>'}</td>
          <td>${r[4]}</td>
        </tr>`).join('');
      tableHtml = `
        <div style="font-size:0.8rem;color:var(--text-muted);margin-bottom:10px;">Showing all ${resultCount} user(s)</div>
        <div class="card" style="overflow-x:auto;">
