function categoryBadge(cat) {
  const cls = { tech: 'cat-tech', art: 'cat-art', travel: 'cat-travel', food: 'cat-food', fitness: 'cat-fitness', system: 'cat-system' };
  return `<span class="post-category ${cls[cat] || 'cat-general'}">${esc(cat)}</span>`;
}

function renderPost(p) {
  const colors = { 1: '#e91e63', 2: '#2196f3', 3: '#9c27b0', 4: '#d63031' };
  const color = colors[p.user_id] || '#6b7394';
  return `
    <div class="card post-card">
      <div class="post-header">
        <div class="post-avatar" style="background:${color};">${getInitials(p.author_name)}</div>
        <div class="post-meta">
          <div class="post-author">${esc(p.author_name)} ${categoryBadge(p.category)}</div>
          <div class="post-time">${esc(timeAgo(p.created_at))}</div>
        </div>
      </div>
      <div class="post-content">${esc(p.content)}</div>
      <div class="post-footer">
        <span class="post-action">❤️ ${p.likes}</span>
        <span class="post-action">💬 Comment</span>
        <span class="post-action">🔄 Share</span>
      </div>
    </div>`;
}

function rowsToObjects(execResult) {
  if (!execResult || !execResult.length) return [];
  const cols = execResult[0].columns;
  return execResult[0].values.map(row => {
    const obj = {};
    cols.forEach((c, i) => { obj[c] = row[i]; });
    return obj;
  });
}

