  if (q) {
    try {
      const query = `SELECT * FROM posts WHERE content LIKE '%${q}%' AND visibility = 'public' ORDER BY created_at DESC`;
      const rows = db.exec(query);
      const posts = rowsToObjects(rows);

      countHtml = `<div class="result-count">Found <strong>${posts.length}</strong> result${posts.length !== 1 ? 's' : ''} for "<strong>${esc(q)}</strong>"</div>`;

