    --accent-blue:#38bdf8;--accent-blue-dim:rgba(56,189,248,0.1);
    --accent-red:#ef4444;--accent-green:#22c55e;--accent-purple:#a78bfa;
    --text-primary:#e2e8f0;--text-secondary:#94a3b8;--text-muted:#64748b;
    --font-mono:'JetBrains Mono','Fira Code',monospace;
    --font-sans:'Inter',-apple-system,BlinkMacSystemFont,sans-serif;
    --radius:8px;--radius-lg:12px;
  }
  html{font-size:15px;}
  body{font-family:var(--font-sans);background:var(--bg-main);color:var(--text-primary);line-height:1.6;min-height:100vh;
    background-image:radial-gradient(circle at 15% 50%,rgba(245,158,11,0.03) 0%,transparent 50%),radial-gradient(circle at 85% 20%,rgba(56,189,248,0.03) 0%,transparent 50%),linear-gradient(rgba(11,17,32,0.97),rgba(11,17,32,0.97)),repeating-linear-gradient(0deg,transparent,transparent 49px,rgba(27,39,68,0.25) 49px,rgba(27,39,68,0.25) 50px),repeating-linear-gradient(90deg,transparent,transparent 49px,rgba(27,39,68,0.25) 49px,rgba(27,39,68,0.25) 50px);}
  a{color:var(--accent);text-decoration:none;}a:hover{text-decoration:underline;}
  input,button,textarea{font-family:inherit;}
  .app-layout{display:flex;min-height:100vh;}
  .sidebar{width:260px;background:var(--bg-sidebar);border-right:1px solid var(--border);display:flex;flex-direction:column;position:fixed;top:0;bottom:0;z-index:10;}
  .sidebar-brand{padding:20px 16px;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:10px;}
  .sidebar-brand .logo{width:38px;height:38px;background:linear-gradient(135deg,var(--accent),#ea580c);border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0;}
  .sidebar-brand h1{font-family:var(--font-mono);font-size:17px;font-weight:700;letter-spacing:-0.5px;}
  .sidebar-brand h1 span{color:var(--accent);}
  .sidebar-nav{flex:1;padding:12px 8px;display:flex;flex-direction:column;gap:2px;}
  .sidebar-nav .section-label{font-size:10px;font-weight:600;text-transform:uppercase;letter-spacing:1.2px;color:var(--text-muted);padding:16px 12px 6px;}
  .sidebar-nav a{display:flex;align-items:center;gap:10px;padding:9px 12px;border-radius:var(--radius);color:var(--text-secondary);font-size:13px;font-weight:500;transition:all 0.2s;text-decoration:none;}
  .sidebar-nav a:hover{background:var(--accent-dim);color:var(--text-primary);}
  .sidebar-nav a.active{background:var(--accent-mid);color:var(--accent);box-shadow:inset 3px 0 0 var(--accent);}
  .sidebar-nav a .icon{font-size:16px;width:20px;text-align:center;}
  .sidebar-user{padding:14px 12px;border-top:1px solid var(--border);display:flex;align-items:center;gap:10px;}
  .sidebar-user .avatar{width:34px;height:34px;background:linear-gradient(135deg,var(--accent),#ea580c);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:700;flex-shrink:0;color:#000;}
  .sidebar-user .user-info{flex:1;min-width:0;}
  .sidebar-user .user-name{font-size:12px;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}
  .sidebar-user .user-role{font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;}
  .main-content{margin-left:260px;flex:1;padding:32px;min-height:100vh;}
  .page-header{margin-bottom:28px;}
  .page-header h1{font-family:var(--font-mono);font-size:1.5rem;font-weight:700;margin-bottom:4px;}
  .page-header .subtitle{font-size:0.85rem;color:var(--text-muted);}
  .card{background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:20px;transition:all 0.25s;}
  .card:hover{border-color:var(--border-glow);background:var(--bg-card-hover);}
  .stats-row{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-bottom:28px;}
  .stat-card{background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:18px;text-align:center;}
  .stat-card .stat-value{font-family:var(--font-mono);font-size:1.8rem;font-weight:700;color:var(--accent);margin-bottom:4px;}
  .stat-card .stat-label{font-size:0.75rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.8px;}
  .badge{display:inline-block;padding:3px 8px;border-radius:4px;font-size:0.7rem;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;}
  .badge-confirmed{background:rgba(34,197,94,0.12);color:#22c55e;border:1px solid rgba(34,197,94,0.3);}
  .badge-pending{background:rgba(245,158,11,0.12);color:#f59e0b;border:1px solid rgba(245,158,11,0.3);}
  .badge-platinum{background:rgba(168,139,250,0.15);color:#a78bfa;border:1px solid rgba(168,139,250,0.3);}
  .badge-gold{background:rgba(245,158,11,0.15);color:#f59e0b;border:1px solid rgba(245,158,11,0.3);}
  .badge-silver{background:rgba(148,163,184,0.15);color:#94a3b8;border:1px solid rgba(148,163,184,0.3);}
  .badge-flight{background:rgba(56,189,248,0.1);color:var(--accent-blue);border:1px solid rgba(56,189,248,0.25);}
  .badge-hotel{background:rgba(245,158,11,0.1);color:var(--accent);border:1px solid rgba(245,158,11,0.25);}
  .data-table{width:100%;border-collapse:separate;border-spacing:0;}
  .data-table th{font-size:0.7rem;text-transform:uppercase;letter-spacing:0.8px;color:var(--text-muted);padding:10px 14px;text-align:left;border-bottom:1px solid var(--border);font-weight:600;}
  .data-table td{padding:12px 14px;font-size:0.85rem;border-bottom:1px solid rgba(27,39,68,0.5);}
  .data-table tr:hover td{background:var(--accent-dim);}
  .btn{display:inline-block;padding:8px 16px;border-radius:var(--radius);font-size:0.8rem;font-weight:600;cursor:pointer;border:none;transition:all 0.2s;text-decoration:none;}
  .btn-primary{background:linear-gradient(135deg,var(--accent),#ea580c);color:#000;}
  .btn-primary:hover{filter:brightness(1.15);box-shadow:0 0 20px rgba(245,158,11,0.2);text-decoration:none;}
  .btn-blue{background:linear-gradient(135deg,var(--accent-blue),#6366f1);color:#fff;}
  .btn-blue:hover{filter:brightness(1.15);text-decoration:none;}
  .btn-ghost{background:transparent;border:1px solid var(--border);color:var(--text-muted);}
  .btn-ghost:hover{border-color:var(--accent);color:var(--accent);text-decoration:none;}
  .login-page{display:flex;align-items:center;justify-content:center;min-height:100vh;padding:32px;}
  .login-wrapper{width:100%;max-width:840px;}
  .login-brand{text-align:center;margin-bottom:32px;}
  .login-brand .logo-lg{width:60px;height:60px;background:linear-gradient(135deg,var(--accent),#ea580c);border-radius:14px;display:inline-flex;align-items:center;justify-content:center;font-size:30px;margin-bottom:14px;}
  .login-brand h1{font-family:var(--font-mono);font-size:1.7rem;font-weight:700;}
  .login-brand h1 span{color:var(--accent);}
  .login-brand p{color:var(--text-muted);font-size:0.85rem;margin-top:4px;}
  .login-grid{display:grid;grid-template-columns:1fr 1fr;gap:20px;}
  .auth-card{background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:28px;}
  .auth-card h2{font-family:var(--font-mono);font-size:1rem;margin-bottom:20px;color:var(--accent);}
  .auth-card .form-group{margin-bottom:14px;}
  .auth-card label{display:block;font-size:0.75rem;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;color:var(--text-muted);margin-bottom:6px;}
  .auth-card input[type="text"],.auth-card input[type="password"],.auth-card input[type="url"],input.form-input,textarea.form-input{width:100%;padding:10px 14px;background:var(--bg-input);border:1px solid var(--border);border-radius:var(--radius);color:var(--text-primary);font-size:0.88rem;transition:border-color 0.2s;}
  .auth-card input:focus,input.form-input:focus,textarea.form-input:focus{outline:none;border-color:var(--accent);box-shadow:0 0 0 3px rgba(245,158,11,0.1);}
  .auth-card .submit-btn{width:100%;padding:11px;border:none;border-radius:var(--radius);font-weight:600;font-size:0.88rem;cursor:pointer;transition:all 0.2s;margin-top:6px;}
  .demo-creds{margin-top:16px;padding:12px;background:var(--bg-deep);border-radius:var(--radius);border:1px solid var(--border);}
  .demo-creds p{font-size:0.72rem;color:var(--text-muted);margin-bottom:6px;text-transform:uppercase;letter-spacing:0.5px;}
  .demo-creds code{display:block;font-family:var(--font-mono);font-size:0.78rem;color:var(--text-secondary);padding:2px 0;}
  .error-msg{padding:10px;background:rgba(239,68,68,0.1);border:1px solid rgba(239,68,68,0.3);border-radius:var(--radius);color:#ef4444;font-size:0.82rem;margin-bottom:14px;}
  .success-msg{padding:10px;background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.25);border-radius:var(--radius);color:var(--accent-green);font-size:0.82rem;margin-bottom:14px;}
  .api-endpoint{background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:18px;margin-bottom:14px;}
  .api-endpoint .method-badge{display:inline-block;padding:2px 8px;border-radius:4px;font-family:var(--font-mono);font-size:0.72rem;font-weight:700;margin-right:8px;}
  .api-endpoint .method-get{background:rgba(34,197,94,0.15);color:#22c55e;}
  .api-endpoint .method-post{background:rgba(56,189,248,0.15);color:var(--accent-blue);}
  .api-endpoint .path{font-family:var(--font-mono);font-size:0.85rem;color:var(--text-primary);}
  .api-endpoint .desc{font-size:0.8rem;color:var(--text-muted);margin-top:8px;}
  .api-endpoint .auth-note{display:inline-block;margin-top:8px;font-size:0.72rem;padding:3px 8px;background:rgba(239,68,68,0.1);border:1px solid rgba(239,68,68,0.25);border-radius:4px;color:var(--accent-red);font-family:var(--font-mono);}
  .result-box{margin-top:16px;padding:16px;background:var(--bg-deep);border:1px solid var(--border);border-radius:var(--radius);max-height:400px;overflow:auto;}
  .result-box pre{font-family:var(--font-mono);font-size:0.8rem;color:var(--text-secondary);white-space:pre-wrap;word-break:break-all;}
  .stars{color:var(--accent);letter-spacing:2px;}
  .grid-2{display:grid;grid-template-columns:1fr 1fr;gap:16px;}
  .fade-in{animation:fadeIn 0.3s ease-out;}
  @keyframes fadeIn{from{opacity:0;transform:translateY(6px);}to{opacity:1;transform:translateY(0);}}
  textarea.form-input{resize:vertical;min-height:60px;}
`;

