function pageShell(title, active, user, content) {
  return `<!DOCTYPE html><html lang="en"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0">
<title>${esc(title)} — SkyWay</title>
<style>${baseStyles}</style>
</head><body class="fade-in">
<div class="app-layout">
  ${renderSidebar(active, user)}
  <main class="main-content">${content}</main>
</div>
</body></html>`;
}

function statusBadge(s) {
  const m = { confirmed:'badge-confirmed', pending:'badge-pending' };
  return `<span class="badge ${m[s]||'badge-pending'}">${esc(s)}</span>`;
}

function typeBadge(t) {
  return `<span class="badge ${t==='flight'?'badge-flight':'badge-hotel'}">${esc(t)}</span>`;
}

function tierBadge(t) {
  const m = { Platinum:'badge-platinum', Gold:'badge-gold', Silver:'badge-silver' };
  return `<span class="badge ${m[t]||'badge-silver'}">${esc(t)}</span>`;
}

function starsHtml(n) {
  return '<span class="stars">' + '★'.repeat(n) + '☆'.repeat(5-n) + '</span>';
}

