app.get('/', (req, res) => {
  res.send(loginPageTpl.replace('%%LOGIN_MSG%%','').replace('%%REG_MSG%%',''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(loginPageTpl
      .replace('%%LOGIN_MSG%%','<div class="error-msg">Invalid credentials.</div>')
      .replace('%%REG_MSG%%',''));
  }
  const token = createSession(user.id);
  res.cookie('sw_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(loginPageTpl.replace('%%LOGIN_MSG%%','').replace('%%REG_MSG%%','<div class="error-msg">All fields required.</div>'));
  }
  if (users.find(u => u.username === username)) {
    return res.send(loginPageTpl.replace('%%LOGIN_MSG%%','').replace('%%REG_MSG%%','<div class="error-msg">Username taken.</div>'));
  }
  const nu = { id: nextUserId++, username, password, name, role: 'Member', email: username + '@skyway.travel', joined: new Date().toISOString().split('T')[0] };
  users.push(nu);
  db.run(`INSERT INTO loyalty VALUES (?,?,?,?)`, [nu.id, nu.id, 0, 'Bronze']);
  const token = createSession(nu.id);
  res.cookie('sw_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const t = req.cookies?.sw_session;
  if (t) delete sessions[t];
  res.clearCookie('sw_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const myBookings = db.exec(`SELECT * FROM bookings WHERE user_id = ${user.id}`);
  const bookingCount = myBookings.length > 0 ? myBookings[0].values.length : 0;
  const loyaltyRes = db.exec(`SELECT points, tier FROM loyalty WHERE user_id = ${user.id}`);
  const points = loyaltyRes.length > 0 ? loyaltyRes[0].values[0][0] : 0;
  const tier = loyaltyRes.length > 0 ? loyaltyRes[0].values[0][1] : 'Bronze';

  const flightCount = db.exec(`SELECT COUNT(*) FROM flights`)[0].values[0][0];
  const hotelCount = db.exec(`SELECT COUNT(*) FROM hotels`)[0].values[0][0];

  const recentBookings = db.exec(`SELECT ref_code, type, description, travel_date, status FROM bookings WHERE user_id = ${user.id} ORDER BY id DESC LIMIT 4`);
  let recentRows = '<tr><td colspan="5" style="color:var(--text-muted);text-align:center;padding:24px;">No bookings yet</td></tr>';
  if (recentBookings.length > 0) {
    recentRows = recentBookings[0].values.map(r => `<tr>
      <td><span style="font-family:var(--font-mono);font-size:0.8rem;color:var(--accent);">${esc(r[0])}</span></td>
      <td>${typeBadge(r[1])}</td>
      <td>${esc(r[2])}</td>
      <td>${esc(r[3])}</td>
      <td>${statusBadge(r[4])}</td>
    </tr>`).join('');
  }

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header">
      <h1>Welcome, ${esc(user.name.split(' ')[0])} 👋</h1>
      <p class="subtitle">Your SkyWay travel dashboard</p>
    </div>
    <div class="stats-row">
      <div class="stat-card"><div class="stat-value">${bookingCount}</div><div class="stat-label">My Bookings</div></div>
      <div class="stat-card"><div class="stat-value">${points.toLocaleString()}</div><div class="stat-label">Loyalty Points</div></div>
      <div class="stat-card"><div class="stat-value">${flightCount}</div><div class="stat-label">Routes Available</div></div>
      <div class="stat-card"><div class="stat-value">${hotelCount}</div><div class="stat-label">Partner Hotels</div></div>
    </div>
    <div class="grid-2">
      <div class="card">
        <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">Recent Bookings</h3>
        <table class="data-table"><thead><tr><th>Ref</th><th>Type</th><th>Details</th><th>Date</th><th>Status</th></tr></thead>
        <tbody>${recentRows}</tbody></table>
      </div>
      <div class="card">
        <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">Loyalty Status</h3>
        <div style="text-align:center;padding:20px 0;">
          <div style="font-size:3rem;margin-bottom:8px;">⭐</div>
          <div style="margin-bottom:8px;">${tierBadge(tier)}</div>
          <div style="font-family:var(--font-mono);font-size:1.5rem;color:var(--accent);font-weight:700;">${points.toLocaleString()} pts</div>
          <p style="font-size:0.8rem;color:var(--text-muted);margin-top:8px;">Earn points on every booking</p>
        </div>
      </div>
    </div>
  `));
});

app.get('/flights', requireAuth, (req, res) => {
  const user = req.user;
  const dest = req.query.dest || '';
  let results;
  if (dest) {
    results = db.exec(`SELECT id, flight_no, origin, destination, departure, price FROM flights WHERE destination LIKE '%${esc(dest)}%'`);
  } else {
    results = db.exec(`SELECT id, flight_no, origin, destination, departure, price FROM flights`);
  }

  let rows = '<tr><td colspan="6" style="color:var(--text-muted);text-align:center;padding:24px;">No flights found</td></tr>';
  if (results.length > 0 && results[0].values.length > 0) {
    rows = results[0].values.map(r => `<tr>
      <td><span style="font-family:var(--font-mono);font-size:0.8rem;color:var(--accent-blue);">${esc(String(r[1]))}</span></td>
      <td>${esc(String(r[2]))}</td>
      <td>${esc(String(r[3]))}</td>
      <td>${esc(String(r[4]))}</td>
      <td style="font-family:var(--font-mono);color:var(--accent);">$${Number(r[5]).toFixed(2)}</td>
      <td><a href="#" class="btn btn-ghost" style="font-size:0.75rem;padding:5px 10px;">Book</a></td>
    </tr>`).join('');
  }

  res.send(pageShell('Flights', 'flights', user, `
    <div class="page-header">
      <h1>Flight Search ✈️</h1>
      <p class="subtitle">Search available routes and book your next adventure</p>
    </div>
    <div class="card" style="margin-bottom:20px;">
      <form method="GET" action="/flights" style="display:flex;gap:12px;align-items:end;">
        <div style="flex:1;">
          <label style="display:block;font-size:0.75rem;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;color:var(--text-muted);margin-bottom:6px;">Destination</label>
