app.post('/api/rate-check', requireAuth, async (req, res) => {
  const { url } = req.body;
  if (!url) return res.json({ error: 'URL is required' });

  try {
    new URL(url);
  } catch {
    return res.json({ error: 'Invalid URL format' });
  }

  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);
    const response = await fetch(url, {
      headers: {
        'User-Agent': 'SkyWay-RateAggregator/2.4',
        'Accept': 'application/json, text/plain, */*',
        'X-Skyway-Internal': INTERNAL_TOKEN,
      },
      signal: controller.signal,
      redirect: 'follow',
    });
    clearTimeout(timeout);
    const body = await response.text();
    res.json({ status: response.status, body });
  } catch (err) {
    res.json({ error: 'Failed to fetch: ' + err.message });
  }
});

app.get('/internal/api/search', (req, res) => {
  const token = req.headers['x-skyway-internal'];
  if (!token || token !== INTERNAL_TOKEN) {
    return res.status(403).json({
      error: 'ACCESS DENIED',
      message: 'This endpoint is restricted to internal SkyWay services. Direct access is not permitted.',
    });
  }

  const dest = req.query.dest || '';
  if (!dest) {
    return res.json({
      service: 'SkyWay Internal Flight Search API',
      version: '2.4.1',
      usage: 'Provide ?dest=<destination> to search flights',
      example: '/internal/api/search?dest=London',
    });
  }

  try {
    const results = db.exec(`SELECT id, flight_no, origin, destination, departure, price FROM flights WHERE destination LIKE '%${dest}%'`);
    const flights = [];
    if (results.length > 0) {
      results[0].values.forEach(row => {
        flights.push({
          id: row[0],
          flight_no: row[1],
          origin: row[2],
          destination: row[3],
          departure: row[4],
          price: row[5],
        });
      });
    }
    res.json({ results: flights.length, flights });
  } catch (err) {
    res.status(500).json({ error: 'Query error', detail: err.message });
  }
});

