function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function tierBadge(tier) {
  const cls = { 'Platinum Elite': 'badge-platinum', Gold: 'badge-gold', Silver: 'badge-silver' };
  return `<span class="badge ${cls[tier] || 'badge-silver'}">${esc(tier)}</span>`;
}

function statusBadge(s) {
  const cls = { Confirmed: 'badge-confirmed', Pending: 'badge-pending', Completed: 'badge-completed' };
  return `<span class="badge ${cls[s] || 'badge-completed'}">${esc(s)}</span>`;
}

function typeBadge(t) {
  const cls = { Flight: 'badge-flight', Hotel: 'badge-hotel' };
  return `<span class="badge ${cls[t] || 'badge-flight'}">${esc(t)}</span>`;
}

