app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(renderLoginPage('<div class="error-msg">Invalid username or password.</div>', ''));
  }
  const token = createSession(user.id);
  res.cookie('sw_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(renderLoginPage('', '<div class="error-msg">All fields are required.</div>'));
  }
  if (users.find(u => u.username === username)) {
    return res.send(renderLoginPage('', '<div class="error-msg">Username already taken.</div>'));
  }
  const newUser = {
    id: nextUserId++,
    username, password, name,
    email: username + '@skyward.travel',
    phone: '',
    tier: 'Silver',
    loyaltyPoints: 0,
    preferredAirport: '',
    seatPreference: 'No Preference',
    mealPreference: 'No Preference',
    joined: new Date().toISOString().split('T')[0],
    totalBookings: 0,
    rewardCode: null,
    bio: 'New SkyWard member.',
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('sw_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.sw_session;
  if (token) delete sessions[token];
  res.clearCookie('sw_session');
  res.redirect('/');
});

