  const tripCards = upcoming.length > 0 ? upcoming.map(b => `
    <div class="trip-card">
      <div class="tc-type">${typeBadge(b.type)} ${statusBadge(b.status)}</div>
      <div class="tc-route">${esc(b.route)}</div>
      <div class="tc-details">${esc(b.details)}</div>
      <div class="tc-date">📅 ${esc(b.date)} &nbsp; 💰 ${esc(b.price)}</div>
    </div>`).join('') : '<p style="color:var(--text-muted);font-size:0.9rem;">No upcoming trips. Start planning your next adventure!</p>';

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header">
