app.post('/profile', requireAuth, (req, res) => {
  const targetId = parseInt(req.body.userId);
  const target = users.find(u => u.id === targetId);

  if (!target) {
    return res.send(renderProfilePage(req.user, req.user, 'Error: User not found.'));
  }

  if (req.body.name && req.body.name.trim()) target.name = req.body.name.trim();
  if (req.body.email && req.body.email.trim()) target.email = req.body.email.trim();
  if (req.body.phone !== undefined) target.phone = req.body.phone.trim();
  if (req.body.preferredAirport !== undefined) target.preferredAirport = req.body.preferredAirport.trim();
  if (req.body.seatPreference) target.seatPreference = req.body.seatPreference;
  if (req.body.mealPreference) target.mealPreference = req.body.mealPreference;
  if (req.body.bio !== undefined) target.bio = req.body.bio.trim();

  res.send(renderProfilePage(req.user, target, 'Profile updated successfully!'));
});

