const sessions = {};

function createSession(userId, username, name, role) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = { userId, username, name, role };
  return token;
}

function getSession(req) {
  const token = req.cookies?.sv_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const session = getSession(req);
  if (!session) return res.redirect('/');
  req.session = session;
  next();
}

function isSuspicious(input) {
  const lower = input.toLowerCase();
  if (lower.includes('or 1=1')) return true;
  if (lower.includes('--')) return true;
  if (lower.includes('union')) return true;
  return false;
}

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

