app.get('/', (req, res) => {
  const session = getSession(req);
  if (session) return res.redirect('/dashboard');
  res.send(buildLoginPage('', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;

  if (!username || !password) {
    return res.send(buildLoginPage('Please enter both username and password.', ''));
  }

  if (isSuspicious(username) || isSuspicious(password)) {
    return res.send(buildLoginPage('', '⚠ Security Alert: Potentially malicious input detected. Your request has been blocked by our WAF.'));
  }

  try {
    const query = `SELECT * FROM users WHERE username = '${username}' AND password = '${password}'`;
    const result = db.exec(query);

    if (result.length === 0 || result[0].values.length === 0) {
      return res.send(buildLoginPage('Invalid username or password. Please try again.', ''));
    }

    const row = result[0].values[0];
    const columns = result[0].columns;
    const user = {};
    columns.forEach((col, i) => { user[col] = row[i]; });

    const token = createSession(user.id, user.username, user.name, user.role);
    res.cookie('sv_session', token, { httpOnly: false, sameSite: 'lax' });
    res.redirect('/dashboard');
  } catch (err) {
    return res.send(buildLoginPage('An error occurred during authentication. Please try again.', ''));
  }
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.sv_session;
  if (token) delete sessions[token];
  res.clearCookie('sv_session');
  res.redirect('/');
});

