  if (userResult.length > 0 && userResult[0].values.length > 0) {
    const cols = userResult[0].columns;
    const vals = userResult[0].values[0];
    const idx_points = cols.indexOf('loyalty_points');
    const idx_tier = cols.indexOf('tier');
    points = vals[idx_points] || 0;
    tier = vals[idx_tier] || 'Silver';
