app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const results = db.exec("SELECT * FROM courses");
  const courseCount = results.length > 0 ? results[0].values.length : 0;

  let gradeRows = [];
  let gpa = 'N/A';
  let enrollmentCount = 0;

  if (user.studentId) {
    const gResult = db.exec(`SELECT course_code, course_name, grade, semester FROM grades WHERE student_id = '${user.studentId}'`);
    if (gResult.length > 0) {
      gradeRows = gResult[0].values;
      enrollmentCount = gradeRows.length;
      const gradePoints = { 'A': 4.0, 'A-': 3.7, 'B+': 3.3, 'B': 3.0, 'B-': 2.7, 'C+': 2.3, 'C': 2.0 };
      let total = 0;
      let count = 0;
      gradeRows.forEach(r => {
        if (gradePoints[r[2]] !== undefined) { total += gradePoints[r[2]]; count++; }
      });
      gpa = count > 0 ? (total / count).toFixed(2) : 'N/A';
    }
  } else {
    enrollmentCount = db.exec("SELECT COUNT(DISTINCT student_id) FROM grades")[0]?.values[0][0] || 0;
  }

  const fbResult = user.studentId
    ? db.exec(`SELECT COUNT(*) FROM professor_feedback WHERE student_id = '${user.studentId}'`)
    : db.exec("SELECT COUNT(*) FROM professor_feedback");
  const feedbackCount = fbResult.length > 0 ? fbResult[0].values[0][0] : 0;

  const recentGrades = gradeRows.slice(0, 4).map(r => `
    <tr>
      <td><span style="font-family:var(--font-mono);font-size:0.8rem;color:var(--accent-gold);">${esc(r[0])}</span></td>
      <td>${esc(r[1])}</td>
      <td>${gradeBadge(r[2])}</td>
      <td>${esc(r[3])}</td>
    </tr>`).join('');

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header">
      <h1>Welcome, ${esc(user.name.split(' ')[0])}</h1>
      <p class="subtitle">Westbrook University ${esc(user.role)} Portal — Spring 2025</p>
    </div>
    <div class="stats-row">
      <div class="stat-card">
        <div class="stat-value">${courseCount}</div>
        <div class="stat-label">Courses Offered</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">${enrollmentCount}</div>
        <div class="stat-label">${user.role === 'Professor' ? 'Students' : 'Enrollments'}</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">${user.studentId ? gpa : '—'}</div>
        <div class="stat-label">${user.studentId ? 'Current GPA' : 'GPA'}</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">${feedbackCount}</div>
        <div class="stat-label">Feedback Items</div>
      </div>
    </div>
    ${user.studentId && recentGrades ? `
    <div class="card">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">Recent Grades</h3>
      <table class="data-table">
        <thead><tr><th>Course</th><th>Name</th><th>Grade</th><th>Semester</th></tr></thead>
        <tbody>${recentGrades}</tbody>
      </table>
    </div>` : `
    <div class="card">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:14px;">Faculty Dashboard</h3>
      <p style="color:var(--text-secondary);font-size:0.85rem;">Welcome back, Professor. Use the navigation to manage courses, view student grades, and check resource links.</p>
    </div>`}
