app.get('/grades', requireAuth, (req, res) => {
  const user = req.user;

  let rows = '';
  if (user.studentId) {
    const gResult = db.exec(`SELECT course_code, course_name, grade, semester FROM grades WHERE student_id = '${user.studentId}' ORDER BY semester DESC`);
    if (gResult.length > 0) {
      rows = gResult[0].values.map(r => `
        <tr>
          <td><span style="font-family:var(--font-mono);font-size:0.8rem;color:var(--accent-gold);">${esc(r[0])}</span></td>
          <td>${esc(r[1])}</td>
          <td>${gradeBadge(r[2])}</td>
          <td>${esc(r[3])}</td>
        </tr>`).join('');
    }
  } else {
    const gResult = db.exec("SELECT g.student_id, s.name, g.course_code, g.course_name, g.grade, g.semester FROM grades g JOIN students s ON g.student_id = s.student_id ORDER BY g.semester DESC, s.name");
    if (gResult.length > 0) {
      rows = gResult[0].values.map(r => `
