  }

  const tableHeader = user.studentId
    ? '<tr><th>Course Code</th><th>Course Name</th><th>Grade</th><th>Semester</th></tr>'
    : '<tr><th>Student ID</th><th>Student</th><th>Course Code</th><th>Course Name</th><th>Grade</th><th>Semester</th></tr>';

  res.send(pageShell('Grades', 'grades', user, `
    <div class="page-header">
      <h1>${user.studentId ? 'My Grades' : 'All Student Grades'}</h1>
      <p class="subtitle">${user.studentId ? 'Your academic performance records' : 'Grade records across all enrolled students'}</p>
