app.get('/resources', requireAuth, (req, res) => {
  const user = req.user;

  res.send(pageShell('Resource Link Checker', 'resources', user, `
    <div class="page-header">
      <h1>Resource Link Checker</h1>
      <p class="subtitle">Verify availability of course material links and external resources</p>
    </div>
    <div class="checker-info">
      📡 This tool fetches the target URL from the server and returns the response. Use it to verify that syllabus links, textbook URLs, and other course resources are accessible to students.
    </div>
    <div class="card">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:16px;">Check a URL</h3>
      <div class="auth-card" style="padding:0;border:none;background:transparent;">
        <div class="form-group">
          <label>Resource URL</label>
          <input type="url" id="check-url" placeholder="https://example.com/syllabus.pdf" style="width:100%;padding:10px 14px;background:var(--bg-input);border:1px solid var(--border);border-radius:var(--radius);color:var(--text-primary);font-size:0.88rem;">
        </div>
        <button onclick="checkResource()" class="btn btn-primary" style="width:100%;">🔍 Check Resource</button>
      </div>
      <div id="check-result"></div>
    </div>
    <div class="card" style="margin-top:16px;">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:12px;">Quick Links</h3>
      <p style="font-size:0.82rem;color:var(--text-muted);margin-bottom:12px;">Common resources to test:</p>
      <div style="display:flex;flex-wrap:wrap;gap:8px;">
        <button onclick="document.getElementById('check-url').value='https://httpbin.org/get'" class="btn btn-ghost" style="cursor:pointer;font-size:0.75rem;">httpbin.org/get</button>
        <button onclick="document.getElementById('check-url').value='https://jsonplaceholder.typicode.com/posts/1'" class="btn btn-ghost" style="cursor:pointer;font-size:0.75rem;">JSONPlaceholder</button>
        <button onclick="document.getElementById('check-url').value='http://localhost:3000/courses'" class="btn btn-ghost" style="cursor:pointer;font-size:0.75rem;">Local: /courses</button>
      </div>
    </div>
    <script>
      async function checkResource() {
        const url = document.getElementById('check-url').value;
        const resultDiv = document.getElementById('check-result');
        if (!url) {
          resultDiv.innerHTML = '<div class="error-msg" style="margin-top:16px;">Please enter a URL to check.</div>';
          return;
        }
        resultDiv.innerHTML = '<div style="margin-top:16px;color:var(--text-muted);font-size:0.85rem;">⏳ Fetching resource...</div>';
        try {
          const resp = await fetch('/api/check-resource', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ url })
          });
          const data = await resp.json();
          if (data.error) {
            resultDiv.innerHTML = '<div class="error-msg" style="margin-top:16px;">Error: ' + data.error + '</div>';
          } else {
            let bodyText = data.body || '';
            bodyText = bodyText.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
            resultDiv.innerHTML = '<div style="margin-top:16px;"><div class="success-msg">✅ Response received — Status: ' + data.status + '</div><div class="result-box">' + bodyText + '</div></div>';
          }
        } catch(e) {
          resultDiv.innerHTML = '<div class="error-msg" style="margin-top:16px;">Network error: ' + e.message + '</div>';
        }
      }
    </script>
  `));
});

app.post('/api/check-resource', requireAuth, async (req, res) => {
  const { url } = req.body;
  if (!url) {
    return res.json({ error: 'URL is required' });
  }
  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);
    const response = await fetch(url, {
      method: 'GET',
      headers: {
        'User-Agent': 'Westbrook-LinkChecker/2.1',
