app.get('/internal/api/student-grades', (req, res) => {
  const internalToken = req.headers['x-internal-token'];
  if (internalToken !== 'wb-checker-a7f3e9c1d4b8') {
    return res.status(403).json({
      error: 'ACCESS DENIED',
      message: 'This endpoint is restricted to internal services only. Direct browser access is not permitted.'
    });
  }

  const studentId = req.query.student_id;
  if (!studentId) {
    return res.status(400).json({
      error: 'Missing parameter',
      message: 'Required query parameter: student_id (e.g. S2024001)',
      available_tables: 'students, courses, grades, professor_feedback'
    });
  }

  const query = `SELECT id, student_id, course_code, course_name, grade, semester FROM grades WHERE student_id = '${studentId}'`;

  try {
    const results = db.exec(query);
    if (results.length === 0) {
      return res.json({ query_result: [], columns: ['id', 'student_id', 'course_code', 'course_name', 'grade', 'semester'], count: 0 });
    }
    const rows = results[0].values.map(r => ({
      id: r[0],
      student_id: r[1],
      course_code: r[2],
      course_name: r[3],
      grade: r[4],
      semester: r[5]
    }));
    res.json({ query_result: rows, columns: results[0].columns, count: rows.length });
  } catch (e) {
    res.status(500).json({ error: 'Query execution failed', details: e.message });
  }
});

