function gradeColor(g) {
  if (g.startsWith('A')) return '#22c55e';
  if (g === 'B+' || g === 'B') return '#3b82f6';
  if (g.startsWith('B')) return '#60a5fa';
  if (g.startsWith('C')) return '#f59e0b';
  return '#ef4444';
}

