function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function deptBadge(dept) {
  if (dept.includes('Computer')) return '<span class="badge badge-cs">' + esc(dept) + '</span>';
  if (dept.includes('Math')) return '<span class="badge badge-math">' + esc(dept) + '</span>';
  if (dept.includes('Phys')) return '<span class="badge badge-phys">' + esc(dept) + '</span>';
  return '<span class="badge badge-eng">' + esc(dept) + '</span>';
}

function gradeBadge(g) {
  const cls = g.startsWith('A') ? 'badge-a' : g.startsWith('B') ? 'badge-b' : g.startsWith('C') ? 'badge-c' : 'badge-d';
  return '<span class="badge ' + cls + '">' + esc(g) + '</span>';
}

