app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) {
    return res.send(renderLogin('<div class="error-msg">Please enter both username and password.</div>'));
  }
  const stmt = db.prepare('SELECT * FROM users WHERE username = ? AND password = ?');
  stmt.bind([username, password]);
  let user = null;
  if (stmt.step()) user = stmt.getAsObject();
  stmt.free();

  if (!user) {
    return res.send(renderLogin('<div class="error-msg">Invalid credentials. Please check your username and password.</div>'));
  }
  const token = createSession(user.id);
  res.cookie('wb_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.wb_session;
  if (token) delete sessions[token];
  res.clearCookie('wb_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const enrollResults = db.exec(`SELECT e.grade, e.score, c.credits FROM enrollments e JOIN courses c ON e.course_id = c.id WHERE e.user_id = ${user.id}`);

  let totalPoints = 0, totalCredits = 0, courseCount = 0, highestScore = 0;
  if (enrollResults.length > 0) {
    for (const row of enrollResults[0].values) {
      const grade = row[0];
      const score = row[1];
      const credits = row[2];
      const gp = gradePoints[grade] || 0;
      totalPoints += gp * credits;
      totalCredits += credits;
      courseCount++;
      if (score > highestScore) highestScore = score;
    }
  }
  const gpa = totalCredits > 0 ? (totalPoints / totalCredits).toFixed(2) : '0.00';

  const recentResults = db.exec(`SELECT c.code, c.name, e.grade, e.score, c.semester FROM enrollments e JOIN courses c ON e.course_id = c.id WHERE e.user_id = ${user.id} ORDER BY e.id DESC LIMIT 5`);
  let recentRows = '';
  if (recentResults.length > 0) {
    recentRows = recentResults[0].values.map(r => `
      <tr>
        <td><span style="font-family:var(--font-mono);font-size:0.8rem;color:var(--accent);">${esc(String(r[0]))}</span></td>
