        <td>${gradeBadge(String(r[2]))}</td>
        <td style="font-family:var(--font-mono);">${esc(String(r[3]))}</td>
        <td style="color:var(--text-muted);font-size:0.82rem;">${esc(String(r[4]))}</td>
      </tr>
    `).join('');
  }

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header">
      <h1>Welcome back, ${esc(user.full_name.split(' ')[0])}</h1>
      <p class="subtitle">Academic performance overview — ${esc(user.major)}, Year ${user.year}</p>
    </div>
