function gradeBadge(g) {
  if (g === 'In Progress') return '<span class="badge badge-progress">In Progress</span>';
  if (g.startsWith('A')) return '<span class="badge badge-a">' + esc(g) + '</span>';
  if (g.startsWith('B')) return '<span class="badge badge-b">' + esc(g) + '</span>';
  return '<span class="badge badge-c">' + esc(g) + '</span>';
}

function capacityBadge(enrolled, capacity) {
  const pct = enrolled / capacity;
  if (pct >= 1) return '<span class="badge badge-full">Full</span>';
  if (pct >= 0.85) return '<span class="badge badge-c">' + enrolled + '/' + capacity + '</span>';
  return '<span class="badge badge-open">' + enrolled + '/' + capacity + '</span>';
}

