app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(renderLoginPage('<div class="error-msg">Invalid username or password. Please try again.</div>'));
  }
  const token = createSession(user.id);
  res.cookie('gv_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.gv_session;
  if (token) delete sessions[token];
  res.clearCookie('gv_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const myGrades = grades.filter(g => g.studentId === user.id);
  const completedGrades = myGrades.filter(g => g.points !== null);
  const gpa = user.gpa || (completedGrades.length > 0 ? (completedGrades.reduce((s, g) => s + g.points, 0) / completedGrades.length).toFixed(2) : 'N/A');
  const enrolledCount = myGrades.length;

  const recentRows = myGrades.slice(0, 4).map(g => {
    const course = courses.find(c => c.code === g.courseCode);
    return `
    <tr>
      <td><span style="font-family:var(--font-mono);font-size:0.8rem;color:var(--accent);">${esc(g.courseCode)}</span></td>
      <td>${course ? esc(course.name) : 'Unknown'}</td>
      <td>${gradeBadge(g.grade)}</td>
      <td style="color:var(--text-muted);font-size:0.8rem;">${course ? esc(course.professor) : ''}</td>
    </tr>`;
  }).join('');

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header">
      <h1>Welcome, ${esc(user.name.split(' ').pop())}</h1>
      <p class="subtitle">Spring 2025 Academic Dashboard</p>
    </div>

    <div class="stats-row">
      <div class="stat-card">
        <div class="stat-value">${gpa}</div>
        <div class="stat-label">Current GPA</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">${enrolledCount}</div>
