app.get('/courses', requireAuth, (req, res) => {
  const user = req.user;
  const query = req.query.q || '';

  let filtered = courses;
  if (query) {
    const lower = query.toLowerCase();
    filtered = courses.filter(c =>
      c.code.toLowerCase().includes(lower) ||
      c.name.toLowerCase().includes(lower) ||
      c.professor.toLowerCase().includes(lower) ||
      c.description.toLowerCase().includes(lower)
    );
  }

  const searchResultsHtml = query
    ? `<div class="search-results-info">Showing results for: <strong>${query}</strong> — ${filtered.length} course${filtered.length !== 1 ? 's' : ''} found</div>`
    : '';

  const courseCards = filtered.map(c => {
    const myEnrollment = grades.find(g => g.studentId === user.id && g.courseCode === c.code);
    const enrollBadge = myEnrollment
      ? '<span class="badge badge-enrolled">Enrolled</span>'
      : capacityBadge(c.enrolled, c.capacity);

    return `
      <div class="course-card">
        <div class="cc-code">${esc(c.code)}</div>
        <div class="cc-name">${esc(c.name)}</div>
        <div class="cc-professor">${esc(c.professor)} · ${esc(c.schedule)}</div>
        <div class="cc-desc">${esc(c.description)}</div>
        <div class="cc-meta">
          <span class="credits">${c.credits} credits</span>
          <span>${esc(c.room)}</span>
          ${enrollBadge}
        </div>
      </div>`;
  }).join('');

  res.send(`<!DOCTYPE html>
<html lang="en"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Course Catalog — GrandView University</title>
<style>${baseStyles}</style>
</head><body class="fade-in">
<div class="app-layout">
  ${renderSidebar('courses', user)}
  <main class="main-content">
    <div class="page-header">
      <h1>Course Catalog</h1>
      <p class="subtitle">Spring 2025 — Browse and search available courses</p>
    </div>

    <form method="GET" action="/courses" class="search-container">
      <input type="text" name="q" placeholder="Search courses by name, code, or professor..." value="${esc(query)}">
      <button type="submit">🔍 Search</button>
    </form>

    ${searchResultsHtml}

    <div class="course-grid">
      ${courseCards.length > 0 ? courseCards : '<p style="color:var(--text-muted);grid-column:1/-1;text-align:center;padding:40px 0;">No courses match your search.</p>'}
    </div>
  </main>
</div>
<input type="hidden" id="__enrollment_verification_token" value="${flag}">
</body></html>`);
});

