app.get('/shop', requireAuth, (req, res) => {
  const user = req.user;

  const items = shopItems.map(item => `
    <div class="shop-item" id="item-${item.id}">
      <div class="item-icon">${item.icon}</div>
      <div class="item-name">${esc(item.name)}</div>
      <div class="item-cat">${esc(item.category)}</div>
      <div class="item-price">$${item.price.toFixed(2)}</div>
      <div class="qty-row">
        <input type="number" class="qty-input" id="qty-${item.id}" value="1" step="1">
        <button class="btn btn-teal btn-sm" onclick="addToCart(${item.id})">Add to Cart</button>
      </div>
    </div>
  `).join('');

  res.send(pageShell('Pet Supplies', 'shop', user, `
    <div class="page-header">
      <h1>🛒 Pet Supplies Shop</h1>
      <p class="subtitle">Quality products for your furry friends — Your balance: <strong style="color:var(--accent-teal);">$${user.balance.toFixed(2)}</strong></p>
    </div>

    <div id="cart-msg"></div>

    <div class="shop-grid">${items}</div>

    <div class="card" style="margin-top:24px;">
      <div class="card-title">🛍️ Your Cart</div>
      <div id="cart-contents" style="color:var(--text-muted);font-size:0.85rem;">Your cart is empty.</div>
      <div style="margin-top:16px;display:flex;align-items:center;gap:14px;">
        <button class="btn btn-primary" onclick="placeOrder()">Place Order</button>
        <button class="btn btn-ghost" onclick="clearCart()">Clear Cart</button>
        <span id="cart-total" style="font-family:var(--font-mono);font-size:1rem;color:var(--accent-teal);margin-left:auto;">Total: $0.00</span>
      </div>
    </div>

    <script>
      const cart = {};
      const items = ${JSON.stringify(shopItems)};

      function addToCart(id) {
        const qty = document.getElementById('qty-' + id).value;
        const qtyNum = Number(qty);
        if (isNaN(qtyNum) || qtyNum === 0) return;
        const item = items.find(i => i.id === id);
        if (!item) return;
        if (cart[id]) {
          cart[id].quantity += qtyNum;
        } else {
          cart[id] = { itemId: id, name: item.name, price: item.price, quantity: qtyNum };
        }
        if (cart[id].quantity === 0) delete cart[id];
        renderCart();
      }

      function clearCart() {
        Object.keys(cart).forEach(k => delete cart[k]);
        renderCart();
      }

      function renderCart() {
        const el = document.getElementById('cart-contents');
        const totalEl = document.getElementById('cart-total');
        const entries = Object.values(cart);
        if (entries.length === 0) {
          el.innerHTML = 'Your cart is empty.';
          totalEl.textContent = 'Total: $0.00';
          return;
        }
        let total = 0;
        let html = '<table class="data-table"><thead><tr><th>Item</th><th>Qty</th><th>Unit Price</th><th>Subtotal</th></tr></thead><tbody>';
        entries.forEach(e => {
          const sub = e.price * e.quantity;
          total += sub;
          html += '<tr><td>' + e.name + '</td><td style="font-family:var(--font-mono);">' + e.quantity + '</td><td style="font-family:var(--font-mono);">$' + e.price.toFixed(2) + '</td><td style="font-family:var(--font-mono);color:' + (sub < 0 ? 'var(--accent-green)' : 'var(--text-primary)') + ';">$' + sub.toFixed(2) + '</td></tr>';
        });
        html += '</tbody></table>';
        el.innerHTML = html;
        totalEl.textContent = 'Total: $' + total.toFixed(2);
        totalEl.style.color = total < 0 ? 'var(--accent-green)' : 'var(--accent-teal)';
      }

      function placeOrder() {
        const entries = Object.values(cart);
        if (entries.length === 0) return;
        const orderItems = entries.map(e => ({ itemId: e.itemId, quantity: e.quantity }));
        fetch('/api/order', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ items: orderItems })
        })
        .then(r => r.json())
        .then(data => {
          const msgEl = document.getElementById('cart-msg');
          if (data.error) {
            msgEl.innerHTML = '<div class="error-msg">' + data.error + '</div>';
          } else {
            msgEl.innerHTML = '<div class="success-msg">Order #' + data.orderId + ' placed! Total charged: $' + data.totalCharged.toFixed(2) + '. New balance: $' + data.newBalance.toFixed(2) + '</div>';
            clearCart();
          }
          setTimeout(() => { msgEl.innerHTML = ''; }, 6000);
        })
        .catch(() => {
