app.post('/api/order', requireAuth, (req, res) => {
  const user = req.user;
  const { items: orderItems } = req.body;

  if (!Array.isArray(orderItems) || orderItems.length === 0) {
    return res.status(400).json({ error: 'No items in order.' });
  }

  let total = 0;
  const resolvedItems = [];

  for (const oi of orderItems) {
    const product = shopItems.find(p => p.id === oi.itemId);
    if (!product) {
      return res.status(400).json({ error: `Item ID ${oi.itemId} not found.` });
    }

    const qty = Number(oi.quantity);
    if (isNaN(qty) || qty === 0) {
      return res.status(400).json({ error: `Invalid quantity for ${product.name}.` });
    }

    const subtotal = product.price * qty;
    total += subtotal;
    resolvedItems.push({
      itemId: product.id,
      name: product.name,
      unitPrice: product.price,
      quantity: qty,
      subtotal: subtotal,
    });
  }

  total = Math.round(total * 100) / 100;

  if (total > user.balance) {
    return res.status(400).json({ error: `Insufficient balance. Your balance: $${user.balance.toFixed(2)}, Order total: $${total.toFixed(2)}.` });
  }

  user.balance = Math.round((user.balance - total) * 100) / 100;

  const order = {
    id: nextOrderId++,
    userId: user.id,
    items: resolvedItems,
    total: total,
    date: new Date().toISOString().split('T')[0],
    status: total < 0 ? 'Refund Processed' : 'Confirmed',
  };
  orders.push(order);

  res.json({
    orderId: order.id,
    totalCharged: total,
    newBalance: user.balance,
    status: order.status,
  });
});

