function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.pc_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const user = users.find(u => u.id === userId);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function requireAdmin(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const user = users.find(u => u.id === userId);
  if (!user) return res.redirect('/');
  if (user.role !== 'Admin') {
    return res.status(403).send(pageShell('Access Denied', 'prescriptions', user, `
      <div class="page-header"><h1>🚫 Access Denied</h1><p class="subtitle">This section is restricted to clinic administrators.</p></div>
      <div class="card"><p style="color:var(--text-muted);">You do not have sufficient privileges to access the Pharmacy Database. Contact Dr. Harper for access.</p></div>
    `));
  }
  req.user = user;
  next();
}

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

