function initials(name) {
  return name.split(' ').map(n => n[0]).join('').substring(0, 2);
}

function starRating(n) {
  return '★'.repeat(n) + '☆'.repeat(5 - n);
}

function speciesIcon(s) {
  if (s === 'Dog') return '🐕';
  if (s === 'Cat') return '🐈';
  if (s === 'Rabbit') return '🐇';
  return '🐾';
}

function roleBadge(role) {
  const cls = { Admin: 'badge-admin', Veterinarian: 'badge-vet', Staff: 'badge-staff' };
  return `<span class="badge ${cls[role] || 'badge-staff'}">${esc(role)}</span>`;
}

function statusBadge(s) {
  return `<span class="badge ${s === 'Active' ? 'badge-active' : 'badge-completed'}">${esc(s)}</span>`;
}

function renderSidebar(activePage, user) {
  const init = initials(user.name);
  const isAdmin = user.role === 'Admin';
  return `
    <aside class="sidebar">
      <div class="sidebar-brand">
        <div class="icon-lg">🐾</div>
        <h1>Paws<span>Care</span></h1>
      </div>
      <nav class="sidebar-nav">
