app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(loginPage
      .replace('ERRORPLACEHOLDER', '<div class="error-msg">Invalid credentials.</div>')
      .replace('REGISTERPLACEHOLDER', ''));
  }
  const token = createSession(user.id);
  res.cookie('pc_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) {
    return res.send(loginPage.replace('ERRORPLACEHOLDER', '').replace('REGISTERPLACEHOLDER', '<div class="error-msg">All fields required.</div>'));
  }
  if (users.find(u => u.username === username)) {
    return res.send(loginPage.replace('ERRORPLACEHOLDER', '').replace('REGISTERPLACEHOLDER', '<div class="error-msg">Username taken.</div>'));
  }
  const newUser = { id: nextUserId++, username, password, name, role: 'Staff', title: 'Staff Member', email: username + '@pawscare.vet', joined: new Date().toISOString().split('T')[0], specialty: 'General' };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('pc_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.pc_session;
  if (token) delete sessions[token];
  res.clearCookie('pc_session');
  res.redirect('/');
});

