app.post('/api/reviews', requireAuth, (req, res) => {
  const { author, rating, message } = req.body;
  if (!author || !message || !rating) return res.json({ error: 'All fields required.', success: false });
  if (typeof rating !== 'number' || rating < 1 || rating > 5) return res.json({ error: 'Rating must be 1-5.', success: false });
  const review = { id: nextReviewId++, author: String(author).substring(0, 100), rating, message: String(message), date: new Date().toISOString().split('T')[0] };
  reviews.push(review);
  res.json({ success: true, id: review.id });
});

