app.get('/bot/visit', (req, res) => {
  const admin = users.find(u => u.role === 'Admin');
  if (!admin) return res.json({ error: 'No admin user found.' });

  const adminToken = createSession(admin.id);
  let triggered = false;

  for (const review of reviews) {
    const raw = review.message;
    if (raw.includes('document.cookie') && raw.includes('/webhook')) {
      triggered = true;
      break;
    }
  }

  if (triggered) {
    webhookStore.push({
      timestamp: new Date().toISOString(),
      data: `pc_session=${adminToken}`
    });
    res.send(`<!DOCTYPE html><html lang="en"><head>
<meta charset="UTF-8"><title>Admin Bot</title>
<style>${baseStyles}</style>
</head><body>
<div style="max-width:600px;margin:60px auto;padding:20px;">
