    <p style="font-size:0.82rem;color:var(--text-muted);margin-top:12px;">Check the <a href="/webhook">webhook collector</a> for captured data.</p>
  </div>
</div>
</body></html>`);
  } else {
    res.send(`<!DOCTYPE html><html lang="en"><head>
<meta charset="UTF-8"><title>Admin Bot</title>
<style>${baseStyles}</style>
</head><body>
<div style="max-width:600px;margin:60px auto;padding:20px;">
  <div class="card">
    <h2 style="font-family:var(--font-mono);font-size:1.1rem;color:var(--accent-amber);margin-bottom:12px;">🤖 Admin Bot — Visit Complete</h2>
    <p style="font-size:0.85rem;color:var(--text-secondary);">Dr. Harper's browser visited the reviews page. No scripts were triggered during this visit.</p>
