          <td>${statusBadge(String(row[6]))}</td>
        </tr>`).join('');
      }
    } catch (e) {
      errorMsg = `<div class="error-msg" style="margin-bottom:16px;"><strong>Database Error:</strong> ${esc(e.message)}</div>`;
    }
  } else {
    const allResults = db.exec('SELECT id, pet_name, medication, dosage, prescribed_by, date_issued, status FROM prescriptions');
    if (allResults.length > 0) {
      resultCount = allResults[0].values.length;
      resultRows = allResults[0].values.map(row => `<tr>
        <td style="font-family:var(--font-mono);color:var(--accent);">#${row[0]}</td>
        <td>${row[1]}</td><td style="font-weight:600;">${row[2]}</td>
        <td>${row[3]}</td><td>${row[4]}</td><td>${row[5]}</td>
        <td>${statusBadge(String(row[6]))}</td>
      </tr>`).join('');
    }
  }

  res.send(pageShell('Pharmacy Database', 'prescriptions', user, `
