    border: 1px solid var(--border);
    color: var(--text-muted);
  }
  .btn-ghost:hover { border-color: var(--border-glow); color: var(--text-primary); text-decoration: none; }

  /* ── Alert ───────────────────────────────────── */
  .alert {
    padding: 12px 16px;
    border-radius: var(--radius);
    font-size: 0.83rem;
    margin-bottom: 16px;
    display: flex;
    align-items: center;
    gap: 10px;
  }
