  .alert-success { background: rgba(20,184,166,0.08); border: 1px solid rgba(20,184,166,0.22); color: var(--accent-bright); }

  /* ── Divider ─────────────────────────────────── */
  .divider { border: none; border-top: 1px solid var(--border); margin: 20px 0; }

  /* ── Login Page ──────────────────────────────── */
  .login-page {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    padding: 32px 16px;
    background-image:
      radial-gradient(ellipse at 15% 50%, rgba(20,184,166,0.07) 0%, transparent 55%),
      radial-gradient(ellipse at 85% 10%, rgba(34,197,94,0.04) 0%, transparent 50%);
