  .login-wrap { width: 100%; max-width: 840px; }
  .login-brand {
    text-align: center;
    margin-bottom: 36px;
  }
  .login-brand .brand-icon {
    width: 64px; height: 64px;
    background: linear-gradient(135deg, var(--accent), #0d9488);
    border-radius: 18px;
    display: inline-flex; align-items: center; justify-content: center;
    font-size: 30px;
    margin-bottom: 14px;
    box-shadow: 0 0 30px rgba(20,184,166,0.3);
  }
  .login-brand h1 { font-size: 1.8rem; font-weight: 800; letter-spacing: -0.8px; }
  .login-brand h1 span { color: var(--accent); }
  .login-brand p { font-size: 0.85rem; color: var(--text-muted); margin-top: 6px; }
  .login-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 20px;
  }
  .auth-card {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: var(--radius-xl);
    padding: 30px;
  }
  .auth-card h2 {
    font-size: 1rem;
    font-weight: 800;
    margin-bottom: 22px;
    color: var(--accent-bright);
    display: flex;
    align-items: center;
    gap: 8px;
  }
  .form-group { margin-bottom: 14px; }
  .form-group label {
    display: block;
    font-size: 0.72rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.6px;
    color: var(--text-muted);
    margin-bottom: 6px;
  }
  .form-group input[type="text"],
  .form-group input[type="password"] {
    width: 100%;
    padding: 10px 14px;
    background: var(--bg-input);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    color: var(--text-primary);
    font-size: 0.88rem;
    transition: border-color 0.2s, box-shadow 0.2s;
  }
  .form-group input:focus {
    outline: none;
    border-color: var(--accent);
    box-shadow: 0 0 0 3px rgba(20,184,166,0.1);
  }
  .submit-btn {
    width: 100%;
    padding: 12px;
    border: none;
    border-radius: var(--radius);
    font-size: 0.9rem;
    font-weight: 700;
    cursor: pointer;
    transition: all 0.2s;
    margin-top: 4px;
  }
  .submit-btn-teal {
    background: linear-gradient(135deg, var(--accent), #0d9488);
    color: #041a1a;
  }
  .submit-btn-teal:hover { filter: brightness(1.1); box-shadow: 0 0 20px rgba(20,184,166,0.25); }
  .demo-creds {
    margin-top: 18px;
    padding: 14px;
    background: var(--bg-deep);
    border: 1px solid var(--border);
    border-radius: var(--radius);
  }
  .demo-creds-title { font-size: 0.68rem; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.8px; font-weight: 700; margin-bottom: 8px; }
  .demo-creds code {
    display: block;
    font-family: var(--font-mono);
    font-size: 0.78rem;
    color: var(--text-secondary);
    padding: 2px 0;
  }

  /* ── Microchip mono ──────────────────────────── */
  .mono { font-family: var(--font-mono); font-size: 0.82rem; color: var(--accent); }

  /* ── Appointment Card ────────────────────────── */
  .appt-row {
    display: flex;
    align-items: center;
    gap: 14px;
    padding: 12px 0;
    border-bottom: 1px solid rgba(22,48,48,0.5);
  }
  .appt-row:last-child { border-bottom: none; }
  .appt-date-box {
    width: 48px; height: 48px;
    background: var(--accent-dim);
    border: 1px solid rgba(20,184,166,0.15);
    border-radius: 10px;
    display: flex; flex-direction: column;
    align-items: center; justify-content: center;
    flex-shrink: 0;
    font-family: var(--font-mono);
  }
  .appt-date-box .aday { font-size: 1rem; font-weight: 700; line-height: 1; color: var(--accent-bright); }
  .appt-date-box .amon { font-size: 0.55rem; text-transform: uppercase; letter-spacing: 0.5px; color: var(--text-muted); }
  .appt-info { flex: 1; }
  .appt-type { font-size: 0.88rem; font-weight: 600; }
  .appt-sub { font-size: 0.76rem; color: var(--text-muted); margin-top: 1px; }

  .fade-in { animation: fadeIn 0.28s ease-out; }
  @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }

  .tag {
    display: inline-block;
    padding: 2px 8px;
    border-radius: 4px;
    font-size: 0.68rem;
    font-weight: 600;
    background: var(--accent-dim);
    color: var(--accent);
    border: 1px solid rgba(20,184,166,0.2);
  }
`;

