app.get('/', (req, res) => {
  res.send(buildLoginPage('', '', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username && u.password === password);
  if (!user) {
    return res.send(buildLoginPage('Invalid username or password.', '', ''));
  }
  const token = createSession(user.id);
  res.cookie('pawportal_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { name, username, password } = req.body;
  if (!name || !username || !password) {
    return res.send(buildLoginPage('', 'All fields are required.', ''));
  }
  if (users.find(u => u.username === username)) {
    return res.send(buildLoginPage('', 'Username is already taken.', ''));
  }
  const newUser = {
    id: users.length + 1,
    username,
    password,
    name,
    email: username + '@email.com',
    phone: 'Not provided',
    joined: new Date().toISOString().split('T')[0],
    petId: null,
  };
  users.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('pawportal_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.pawportal_session;
  if (token) delete sessions[token];
  res.clearCookie('pawportal_session');
  res.redirect('/');
});

app.get('/dashboard', requireAuth, (req, res) => {
  const user = req.user;
  const pet = pets.find(p => p.id === user.petId);
  const myAppts = appointments.filter(a => a.ownerId === user.id);
  const upcoming = myAppts.filter(a => a.status === 'Upcoming');
  const completed = myAppts.filter(a => a.status === 'Completed');

  const apptRows = upcoming.slice(0, 3).map(a => {
    const parts = a.date.split('-');
    const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    const day = parseInt(parts[2]);
    const mon = months[parseInt(parts[1]) - 1];
    return `
      <div class="appt-row">
        <div class="appt-date-box">
          <div class="aday">${day}</div>
          <div class="amon">${mon}</div>
        </div>
        <div class="appt-info">
          <div class="appt-type">${esc(a.type)}</div>
          <div class="appt-sub">${esc(a.time)} &nbsp;·&nbsp; ${esc(a.vet)}</div>
        </div>
        <span class="badge badge-upcoming">Upcoming</span>
      </div>`;
  }).join('');

  const petSection = pet ? `
    <div style="display:flex;align-items:center;gap:16px;margin-bottom:8px;">
      <div class="pet-avatar ${pet.species.toLowerCase()}">${pet.icon}</div>
      <div>
        <div style="font-size:1.2rem;font-weight:800;">${esc(pet.name)}</div>
        <div style="font-size:0.8rem;color:var(--text-muted);">${esc(pet.breed)} &nbsp;·&nbsp; ${esc(pet.age)} yrs</div>
        <div style="margin-top:6px;"><a href="/my-pet" class="btn btn-teal" style="font-size:0.76rem;padding:5px 14px;">View Full Profile →</a></div>
      </div>
    </div>` : `<p style="color:var(--text-muted);font-size:0.85rem;">No pet registered yet. Visit the clinic to register your pet.</p>`;

  res.send(pageShell('Dashboard', 'dashboard', user, `
    <div class="page-header">
      <h1>Welcome back, ${esc(user.name.split(' ')[0])} 👋</h1>
      <p class="subtitle">Here's a summary of your pet's care at PawPortal Veterinary Clinic</p>
    </div>

    <div class="stats-row">
      <div class="stat-card">
        <div class="stat-icon stat-icon-teal">📅</div>
        <div>
          <div class="stat-val" style="color:var(--accent-bright);">${upcoming.length}</div>
          <div class="stat-label">Upcoming Appointments</div>
        </div>
      </div>
      <div class="stat-card">
        <div class="stat-icon stat-icon-green">✅</div>
        <div>
          <div class="stat-val" style="color:var(--accent-green);">${completed.length}</div>
          <div class="stat-label">Past Visits</div>
        </div>
      </div>
      <div class="stat-card">
        <div class="stat-icon stat-icon-amber">💊</div>
        <div>
          <div class="stat-val" style="color:var(--accent-amber);">${pet ? 1 : 0}</div>
          <div class="stat-label">Active Prescriptions</div>
        </div>
      </div>
    </div>

    <div style="display:grid;grid-template-columns:1fr 1fr;gap:20px;">
      <div class="card">
        <div class="card-title">🐾 My Pet</div>
        ${petSection}
      </div>
      <div class="card">
        <div class="card-title">📅 Upcoming Appointments</div>
        ${apptRows || '<p style="color:var(--text-muted);font-size:0.84rem;">No upcoming appointments scheduled.</p>'}
      </div>
    </div>
  `));
});

