app.post('/prescriptions/view', requireAuth, (req, res) => {
  const user = req.user;
  const rxId = parseInt(req.body.prescription_id);

  if (!rxId || isNaN(rxId)) {
    return res.send(pageShell('Prescriptions', 'prescriptions', user, `
      <div class="page-header"><h1>Prescriptions</h1></div>
      <div class="alert alert-error">⚠️ Please enter a valid prescription record ID.</div>
      <a href="/prescriptions" class="btn btn-ghost">← Back</a>
    `));
  }

  const rx = prescriptions.find(r => r.id === rxId);

  if (!rx) {
    return res.send(pageShell('Prescriptions', 'prescriptions', user, `
      <div class="page-header"><h1>Prescriptions</h1></div>
      <div class="alert alert-error">⚠️ No prescription found with record ID <strong>${esc(String(rxId))}</strong>.</div>
      <a href="/prescriptions" class="btn btn-ghost">← Back</a>
    `));
  }

  const statusCls = rx.status === 'Active' ? 'badge-active' : 'badge-expired';

  res.send(pageShell('Prescription Details', 'prescriptions', user, `
    <div class="page-header">
      <h1>Prescription Details</h1>
      <p class="subtitle">Record #${esc(String(rx.id))} — retrieved from the medication registry</p>
    </div>

    <div class="rx-result">
      <div class="rx-result-header">
        <div>
          <h3>💊 ${esc(rx.medication)}</h3>
          <div style="font-size:0.78rem;color:var(--text-muted);margin-top:3px;">
            For <strong style="color:var(--text-primary);">${esc(rx.petName)}</strong>
            &nbsp;·&nbsp; Owner: ${esc(rx.ownerName)}
          </div>
        </div>
        <span class="badge ${statusCls}">${esc(rx.status)}</span>
      </div>

      <div class="rx-result-body">
        <div class="rx-meta-grid">
          <div class="rx-meta-item">
            <label>Dosage</label>
