function statusBadge(s) {
  const map = { Healthy: 'badge-healthy', 'Under Treatment': 'badge-treatment', Scheduled: 'badge-scheduled' };
  return `<span class="badge ${map[s] || 'badge-scheduled'}">${esc(s)}</span>`;
}

function apptStatusBadge(s) {
  const map = { Confirmed: 'badge-confirmed', Pending: 'badge-pending' };
  return `<span class="badge ${map[s] || 'badge-pending'}">${esc(s)}</span>`;
}

function apptTypeBadge(s) {
  const map = { Surgery: 'badge-surgery', 'Check-up': 'badge-checkup', 'Follow-up': 'badge-followup', Vaccination: 'badge-vaccination' };
  return `<span class="badge ${map[s] || 'badge-checkup'}">${esc(s)}</span>`;
}

function speciesIcon(s) {
  const map = { Dog: '🐕', Cat: '🐈', Rabbit: '🐇' };
  const cls = { Dog: 'species-dog', Cat: 'species-cat', Rabbit: 'species-rabbit' };
  return `<span class="species-icon ${cls[s] || ''}">${map[s] || '🐾'}</span>`;
}

