app.post('/api/notes', requireAuth, (req, res) => {
  const user = req.user;
  const { pet, content } = req.body;

  if (!content || !content.trim()) {
    return res.json({ error: 'Note content cannot be empty.' });
  }

  if (content.length > 2000) {
    return res.json({ error: 'Note too long (max 2000 chars).' });
  }

  const sanitized = stripScriptTags(content);

  clinicNotes.unshift({
    id: crypto.randomBytes(8).toString('hex'),
    author: user.name,
    authorId: user.id,
    pet: pet || 'General',
    content: sanitized,
    timestamp: new Date().toLocaleString('en-US', { dateStyle: 'medium', timeStyle: 'short' }),
  });

  res.json({ success: true });
});

app.post('/api/report-to-vet', requireAuth, (req, res) => {
  const adminCookieValue = `pc_session=vet_admin_internal; clinic_flag=${flag}`;

  let captured = false;

  for (const note of clinicNotes) {
    const rawContent = note.content;

    const eventHandlerRegex = /on(?:error|load|toggle|mouseover|focus|click|mouseenter)\s*=\s*["']?(.*?)["']?\s*(?:>|\/>)/gi;
    let match;

    while ((match = eventHandlerRegex.exec(rawContent)) !== null) {
      const handlerCode = match[1];

      if (handlerCode.includes('document.cookie') || handlerCode.includes('document[') || handlerCode.includes("document['cookie']")) {
        const captureUrlMatch = handlerCode.match(/\/api\/capture/);

        if (captureUrlMatch) {
          capturedData.unshift({
            id: crypto.randomBytes(6).toString('hex'),
            timestamp: new Date().toLocaleString('en-US', { dateStyle: 'medium', timeStyle: 'short' }),
            source: 'Dr. Martinez (bot review)',
            data: adminCookieValue,
          });
          captured = true;
        }
      }
    }
  }

  if (captured) {
    res.json({ message: 'Dr. Martinez reviewed the notes. Check the Audit Log for any captured activity.' });
  } else {
    res.json({ message: 'Dr. Martinez reviewed all notes. No issues found.' });
  }
});

app.get('/api/capture', requireAuth, (req, res) => {
  const data = req.query.c || req.query.data || '';
  if (data) {
    capturedData.unshift({
      id: crypto.randomBytes(6).toString('hex'),
      timestamp: new Date().toLocaleString('en-US', { dateStyle: 'medium', timeStyle: 'short' }),
      source: 'Client-side capture',
      data: data,
    });
    return res.json({ success: true });
  }
  res.json({ captures: capturedData });
});

