function invBadge(s) {
  const m = { 'In Stock':'badge-in','Low Stock':'badge-low','Out of Stock':'badge-out' };
  return `<span class="badge ${m[s]||''}">${esc(s)}</span>`;
}
function shipBadge(s) {
  const m = { 'In Transit':'badge-transit','Delivered':'badge-delivered','Pending':'badge-pending' };
  return `<span class="badge ${m[s]||''}">${esc(s)}</span>`;
}
function catBadge(c) {
  const m = { Equipment:'badge-equip',Packaging:'badge-pack',Safety:'badge-safety',Electronics:'badge-elec',Infrastructure:'badge-infra' };
  return `<span class="badge ${m[c]||'badge-user'}">${esc(c)}</span>`;
}
function supBadge(s) {
  return s === 'Active' ? '<span class="badge badge-active">Active</span>' : '<span class="badge badge-review">Review</span>';
}

