app.get('/', (req, res) => res.send(loginHTML()));

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const u = users.find(u => u.username === username && u.password === password);
  if (!u) return res.send(loginHTML('Invalid username or password.'));
  const tok = signJWT({ userId: u.id, username: u.username, name: u.name, role: u.role, initials: u.avatar, title: u.title, dept: u.dept, iat: Math.floor(Date.now()/1000) });
  res.cookie('wms_token', tok, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => { res.clearCookie('wms_token'); res.redirect('/'); });

