app.get('/session', requireAuth, (req, res) => {
  const u = req.user;
  const tok = req.rawToken;
  const parts = tok.split('.');

  let decodedPayload = {};
  try { decodedPayload = JSON.parse(b64urlDecode(parts[1])); } catch {}

  const payloadDisplay = JSON.stringify(decodedPayload, null, 2);
  const issuedAt = decodedPayload.iat ? new Date(decodedPayload.iat * 1000).toLocaleString('en-GB') : 'N/A';

  res.send(shell('Session Info', 'session', u, `
    <div class="page-header">
      <div class="breadcrumb"><span>WareTrack</span><span>›</span><span>Session Info</span></div>
      <div class="page-title">Session Information</div>
      <div class="page-sub">Your current authentication token and session details.</div>
    </div>

    <div class="alert alert-info gap-18">
      <span>ℹ️</span>
      <span>WareTrack uses <b>JSON Web Tokens (JWT)</b> with HS256 signing for session management. Your token is stored in the <code>wms_token</code> cookie and sent with every request.</span>
    </div>

    <div class="session-panel gap-18">
      <div class="session-panel-header">
        <span class="sp-icon">🔑</span>
        <h3>Active JWT Token</h3>
        <span class="sp-badge">HS256</span>
      </div>
      <div class="token-box" title="Click to select all">
        <span class="part-header">${esc(parts[0])}</span><span class="part-dot">.</span><span class="part-payload">${esc(parts[1])}</span><span class="part-dot">.</span><span class="part-sig">${esc(parts[2])}</span>
      </div>
      <div class="token-note">🎨 <span style="color:var(--blue);">Header</span> &nbsp;·&nbsp; <span style="color:var(--green);">Payload</span> &nbsp;·&nbsp; <span style="color:var(--accent);">Signature</span> — click to select</div>
      <div class="token-meta">
        <div class="token-meta-item"><label>Algorithm</label><span>HS256</span></div>
        <div class="token-meta-item"><label>Token Type</label><span>JWT</span></div>
        <div class="token-meta-item"><label>Role</label><span>${esc(u.role)}</span></div>
        <div class="token-meta-item"><label>Issued At</label><span>${esc(issuedAt)}</span></div>
      </div>
    </div>

    <div class="grid2">
      <div class="card">
        <div class="card-title"><span class="dot"></span>Decoded Header</div>
        <pre style="background:var(--bg);border:1px solid var(--border);border-radius:var(--r);padding:14px;font-family:var(--mono);font-size:0.75rem;color:var(--blue);overflow-x:auto;">${esc(JSON.stringify({ alg: 'HS256', typ: 'JWT' }, null, 2))}</pre>
      </div>
      <div class="card">
        <div class="card-title"><span class="dot" style="background:var(--green);"></span>Decoded Payload</div>
        <pre style="background:var(--bg);border:1px solid var(--border);border-radius:var(--r);padding:14px;font-family:var(--mono);font-size:0.75rem;color:var(--green);overflow-x:auto;">${esc(payloadDisplay)}</pre>
      </div>
    </div>

    <div class="card" style="margin-top:18px;">
      <div class="card-title"><span class="dot" style="background:var(--yellow);"></span>Token Usage</div>
      <p style="font-size:0.82rem;color:var(--text2);line-height:1.8;">
        This token is sent automatically via the <code>wms_token</code> cookie. To make authenticated API calls manually, include it as a cookie header or submit it via the <code>/api/auth-check</code> endpoint.
        The <b>role</b> field in the payload controls access to restricted areas — only <code>admin</code> role can access the Admin Panel.
      </p>
    </div>
  `));
});

