app.post('/api/loyalty/redeem', requireAuth, async (req, res) => {
  const { code } = req.body;
  const user = req.user;

  if (!code) {
    return res.status(400).json({ success: false, error: 'No code provided.' });
  }

  const referral = referralCodes.find(r => r.code === code);
  if (!referral) {
    return res.status(400).json({ success: false, error: 'Invalid referral code.' });
  }

  const alreadyUsed = usedReferrals.find(r => r.userId === user.id && r.code === code);
  if (alreadyUsed) {
    return res.status(400).json({ success: false, error: 'This code has already been redeemed on your account.' });
  }

  user.loyaltyPoints += referral.bonus;

  await new Promise(resolve => setTimeout(resolve, 200));

  usedReferrals.push({ userId: user.id, code: code, timestamp: Date.now() });

  if (user.loyaltyPoints >= PREMIUM_THRESHOLD) {
    user.tier = 'Premium';
  }

  res.json({
    success: true,
    pointsAdded: referral.bonus,
    totalPoints: user.loyaltyPoints,
    tier: user.tier
  });
});

