function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function statusBadge(s) {
  const cls = { 'In Transit': 'badge-transit', Delivered: 'badge-delivered', Processing: 'badge-processing', 'Customs Hold': 'badge-hold', Verified: 'badge-verified', 'Pending Review': 'badge-pending' };
  return '<span class="badge ' + (cls[s] || 'badge-pending') + '">' + esc(s) + '</span>';
}

function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function renderSidebar(activePage, user) {
  const init = initials(user.name);
  return `
