app.get('/internal/inventory-search', (req, res) => {
  const q = req.query.q || '';
  if (!q) {
    return res.json({ status: 'error', message: 'Query parameter q is required' });
  }
  if (!db) {
    return res.json({ status: 'error', message: 'Database not ready' });
  }

  try {
    const sql = `SELECT id, sku, name FROM inventory WHERE sku = '${q}'`;
    const result = db.exec(sql);
    if (result.length > 0 && result[0].values.length > 0) {
      res.json({
        status: 'found',
        message: 'Inventory match located',
        count: result[0].values.length,
      });
    } else {
      res.json({
        status: 'not_found',
        message: 'No inventory match for given query',
        count: 0,
      });
    }
  } catch (e) {
    res.json({ status: 'error', message: 'Query processing error' });
  }
});

