function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.sv_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const user = staff.find(u => u.id === userId);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function requireDirector(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.status(401).json({ error: 'Authentication required' });
  const user = staff.find(u => u.id === userId);
  if (!user) return res.status(401).json({ error: 'Authentication required' });
  if (user.role !== 'Director') return res.status(403).json({ error: 'Director-level access required' });
  req.user = user;
  next();
}

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function statusBadge(s) {
  const cls = { 'In Stock': 'badge-ok', 'Low Stock': 'badge-warn', 'Critical': 'badge-crit', 'In Transit': 'badge-transit', 'Delivered': 'badge-ok', 'Packing': 'badge-info', 'Scheduled': 'badge-sched' };
  return `<span class="badge ${cls[s] || 'badge-default'}">${esc(s)}</span>`;
}

function sevBadge(s) {
  const cls = { 'Critical': 'badge-crit', 'High': 'badge-warn', 'Medium': 'badge-info', 'Low': 'badge-ok' };
  return `<span class="badge ${cls[s] || 'badge-default'}">${esc(s)}</span>`;
}

function getInitials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

