  select{width:100%;padding:10px 14px;background:var(--bg-input);border:1px solid var(--border);border-radius:var(--radius);color:var(--text-primary);font-size:0.88rem;}
  select:focus{outline:none;border-color:var(--accent);}
  .report-entry{background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:18px;margin-bottom:12px;transition:all 0.25s;}
  .report-entry:hover{border-color:var(--border-glow);}
  .report-meta{display:flex;gap:12px;align-items:center;margin-bottom:10px;flex-wrap:wrap;}
  .report-meta .meta-item{font-size:0.75rem;color:var(--text-muted);}
  .report-meta .meta-item span{color:var(--text-secondary);font-family:var(--font-mono);}
  .report-desc{font-size:0.88rem;color:var(--text-secondary);line-height:1.7;padding:10px;background:var(--bg-deep);border-radius:var(--radius);border:1px solid rgba(21,32,64,0.5);}
  .fade-in{animation:fadeIn 0.3s ease-out;}
  @keyframes fadeIn{from{opacity:0;transform:translateY(6px);}to{opacity:1;transform:translateY(0);}}
  .webhook-entry{background:var(--bg-deep);border:1px solid var(--border);border-radius:var(--radius);padding:12px;margin-bottom:8px;font-family:var(--font-mono);font-size:0.82rem;color:var(--accent-warm);word-break:break-all;}
`;

