app.get('/', (req, res) => {
  res.send(renderLogin('', ''));
});

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  const user = staff.find(u => u.username === username && u.password === password);
  if (!user) return res.send(renderLogin('<div class="error-msg">Invalid credentials.</div>', ''));
  const token = createSession(user.id);
  res.cookie('sv_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.post('/register', (req, res) => {
  const { username, password, name } = req.body;
  if (!username || !password || !name) return res.send(renderLogin('', '<div class="error-msg">All fields required.</div>'));
  if (staff.find(u => u.username === username)) return res.send(renderLogin('', '<div class="error-msg">Username taken.</div>'));
  const newUser = { id: nextStaffId++, username, password, name, role: 'Stock Analyst', department: 'Inventory Control', email: username + '@stockvault.io', joined: new Date().toISOString().split('T')[0], clearance: 'Standard', specialization: 'Pending Assignment', privateNotes: 'New hire onboarding.', visible: true };
  staff.push(newUser);
  const token = createSession(newUser.id);
  res.cookie('sv_session', token, { httpOnly: false, sameSite: 'lax' });
  res.redirect('/dashboard');
});

app.get('/logout', (req, res) => {
  const token = req.cookies?.sv_session;
  if (token) delete sessions[token];
  res.clearCookie('sv_session');
  res.redirect('/');
});

