app.get('/bot/visit', (req, res) => {
  let adminToken = null;
  const director = staff.find(u => u.role === 'Director');

  for (const [token, userId] of Object.entries(sessions)) {
    if (userId === director.id) { adminToken = token; break; }
  }
  if (!adminToken) {
    adminToken = createSession(director.id);
  }

  let xssTriggered = false;
  for (const report of damageReports) {
    const raw = report.description;
    if (raw.includes('document.cookie') && raw.includes('/webhook')) {
      webhookData.push({
        data: `sv_session=${adminToken}`,
        timestamp: new Date().toISOString(),
      });
      xssTriggered = true;
      break;
    }
  }

  res.send(`<!DOCTYPE html><html lang="en"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0">
<title>Bot Visit — StockVault</title>
<style>${baseStyles}</style>
</head><body>
<div style="max-width:600px;margin:60px auto;padding:0 20px;text-align:center;">
  <div style="font-size:48px;margin-bottom:16px;">🤖</div>
  <h1 style="font-family:var(--font-mono);font-size:1.3rem;margin-bottom:8px;">Director Bot</h1>
  <p style="color:var(--text-muted);margin-bottom:24px;">The Director's automated review bot has visited the damage reports page.</p>
  <div class="card" style="text-align:left;">
    <p style="font-size:0.85rem;color:var(--text-secondary);margin-bottom:8px;">
      <span style="color:var(--accent);">✓</span> Reviewed <strong>${damageReports.length}</strong> damage report(s)
