let nextUserId = 4;
const sessions = {};

function createSession(userId) {
  const token = crypto.randomBytes(24).toString('hex');
  sessions[token] = userId;
  return token;
}

function getSession(req) {
  const token = req.cookies?.sp_session;
  return token ? sessions[token] : null;
}

function requireAuth(req, res, next) {
  const userId = getSession(req);
  if (!userId) return res.redirect('/');
  const user = users.find(u => u.id === userId);
  if (!user) return res.redirect('/');
  req.user = user;
  next();
}

function simulateExec(command) {
  let output = '';
  const parts = command.split(/;/);
  for (const segment of parts) {
    const trimmed = segment.trim();
    if (!trimmed) continue;

    const tokens = trimmed.split(/\s+/);
    const cmd = tokens[0].toLowerCase();

    if (cmd === 'ping') {
      const host = tokens[1] || 'unknown';
      const ip = host.match(/^\d+\.\d+\.\d+\.\d+$/) ? host : `${Math.floor(Math.random()*200)+10}.${Math.floor(Math.random()*255)}.${Math.floor(Math.random()*255)}.${Math.floor(Math.random()*255)+1}`;
      output += `PING ${host} (${ip}): 56 data bytes\n`;
      for (let i = 0; i < 4; i++) {
        const ms = (Math.random() * 40 + 5).toFixed(1);
        output += `64 bytes from ${ip}: icmp_seq=${i} ttl=64 time=${ms} ms\n`;
      }
      const avgMs = (Math.random() * 20 + 10).toFixed(1);
      output += `\n--- ${host} ping statistics ---\n4 packets transmitted, 4 received, 0% packet loss\nround-trip min/avg/max = ${(avgMs - 5).toFixed(1)}/${avgMs}/${(parseFloat(avgMs) + 8).toFixed(1)} ms\n`;
    } else if (cmd === 'nslookup' || cmd === 'dig') {
      const host = tokens[1] || 'unknown';
      const ip = `${Math.floor(Math.random()*200)+10}.${Math.floor(Math.random()*255)}.${Math.floor(Math.random()*255)}.${Math.floor(Math.random()*255)+1}`;
      output += `Server:\t\t8.8.8.8\nAddress:\t8.8.8.8#53\n\nNon-authoritative answer:\nName:\t${host}\nAddress: ${ip}\n`;
    } else if (cmd === 'traceroute' || cmd === 'tracert') {
      const host = tokens[1] || 'unknown';
      output += `traceroute to ${host}, 30 hops max, 60 byte packets\n`;
      const hops = Math.floor(Math.random() * 6) + 4;
      for (let i = 1; i <= hops; i++) {
        const hopIp = `${10 + i * 2}.${Math.floor(Math.random()*255)}.${Math.floor(Math.random()*255)}.${Math.floor(Math.random()*255)+1}`;
        const ms1 = (Math.random() * 20 + i * 3).toFixed(1);
        const ms2 = (Math.random() * 20 + i * 3).toFixed(1);
        const ms3 = (Math.random() * 20 + i * 3).toFixed(1);
        output += ` ${i}  ${hopIp}  ${ms1} ms  ${ms2} ms  ${ms3} ms\n`;
      }
    } else if (cmd === 'cat') {
      const filePath = tokens.slice(1).join(' ');
      if (!filePath) {
        output += `cat: missing operand\n`;
      } else {
        try {
          const content = fs.readFileSync(filePath, 'utf-8');
          output += content + '\n';
        } catch (e) {
          output += `cat: ${filePath}: No such file or directory\n`;
        }
      }
    } else if (cmd === 'ls') {
      try {
        const dir = tokens[1] || '.';
        const items = fs.readdirSync(dir);
        output += items.join('\n') + '\n';
      } catch (e) {
        output += `ls: cannot access: No such file or directory\n`;
      }
    } else if (cmd === 'whoami') {
      output += `stockpulse-app\n`;
    } else if (cmd === 'id') {
      output += `uid=1000(stockpulse) gid=1000(stockpulse) groups=1000(stockpulse)\n`;
    } else if (cmd === 'echo') {
      output += tokens.slice(1).join(' ') + '\n';
    } else if (cmd === 'hostname') {
      output += `sp-warehouse-prod-01\n`;
    } else {
      output += `sh: ${cmd}: command not found\n`;
    }
  }
  return output;
}

