  .supplier-card .sc-row { display: flex; justify-content: space-between; font-size: 0.8rem; padding: 4px 0; }
  .supplier-card .sc-label { color: var(--text-muted); }
  .supplier-card .sc-val { color: var(--text-primary); font-family: var(--font-mono); }
  .reliability-bar {
    width: 100%;
    height: 4px;
    background: var(--border);
    border-radius: 2px;
    margin-top: 12px;
    overflow: hidden;
  }
  .reliability-bar .fill {
    height: 100%;
    border-radius: 2px;
    transition: width 0.6s ease;
  }

  .fade-in { animation: fadeIn 0.3s ease-out; }
  @keyframes fadeIn { from { opacity: 0; transform: translateY(6px); } to { opacity: 1; transform: translateY(0); } }
`;

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function initials(name) {
  return name.split(' ').map(n => n[0]).join('');
}

function inventoryBadge(status) {
  if (status === 'In Stock') return '<span class="badge badge-instock">In Stock</span>';
  if (status === 'Low Stock') return '<span class="badge badge-lowstock">Low Stock</span>';
  return '<span class="badge badge-outofstock">Out of Stock</span>';
}

function shipmentBadge(status) {
  if (status === 'In Transit') return '<span class="badge badge-intransit">In Transit</span>';
  if (status === 'Delivered') return '<span class="badge badge-delivered">Delivered</span>';
  return '<span class="badge badge-pending">Pending</span>';
}

