app.get('/diagnostics', requireAuth, (req, res) => {
  const user = req.user;

  res.send(pageShell('Network Diagnostics', 'diagnostics', user, `
    <div class="page-header">
      <h1>Network Diagnostics</h1>
      <p class="subtitle">Check connectivity to warehouse nodes, supplier endpoints, and carrier APIs</p>
    </div>

    <div class="card" style="margin-bottom:20px;">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:6px;">Ping Utility</h3>
      <p style="font-size:0.82rem;color:var(--text-muted);margin-bottom:16px;">
        Enter a hostname or IP address to check network reachability from the warehouse server.
      </p>
      <div class="diag-input-group">
        <input type="text" id="pingTarget" placeholder="e.g. 192.168.1.1 or supplier.example.com" autocomplete="off">
        <button class="btn btn-primary" id="pingBtn" onclick="runPing()">Run Ping</button>
      </div>
      <div class="terminal-output" id="pingOutput"><span style="color:var(--text-muted);">$ Awaiting command...</span></div>
    </div>

    <div class="card">
      <h3 style="font-family:var(--font-mono);font-size:0.95rem;margin-bottom:6px;">Quick Actions</h3>
      <p style="font-size:0.82rem;color:var(--text-muted);margin-bottom:16px;">Common diagnostic targets for warehouse infrastructure.</p>
      <div style="display:flex;gap:10px;flex-wrap:wrap;">
        <button class="btn btn-teal" onclick="quickPing('192.168.10.1')">Gateway (192.168.10.1)</button>
        <button class="btn btn-teal" onclick="quickPing('10.0.50.5')">Inventory DB (10.0.50.5)</button>
        <button class="btn btn-teal" onclick="quickPing('carrier-api.fastfreight.io')">FastFreight API</button>
        <button class="btn btn-teal" onclick="quickPing('8.8.8.8')">Google DNS (8.8.8.8)</button>
      </div>
    </div>

    <script>
      function runPing() {
        const target = document.getElementById('pingTarget').value.trim();
        if (!target) return;
        const output = document.getElementById('pingOutput');
        const btn = document.getElementById('pingBtn');
        btn.disabled = true;
        btn.textContent = 'Running...';
        output.innerHTML = '<span style="color:var(--text-muted);">$ Executing ping ' + target.replace(/</g,'&lt;').replace(/>/g,'&gt;') + '...</span>\\n';

        fetch('/api/diagnostics/ping', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ target: target })
        })
        .then(r => r.json())
        .then(data => {
          const escaped = data.output.replace(/</g,'&lt;').replace(/>/g,'&gt;');
          output.innerHTML = '<span class="cmd-line">$ ping ' + target.replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</span>\\n<span class="cmd-output">' + escaped + '</span>';
          btn.disabled = false;
          btn.textContent = 'Run Ping';
        })
        .catch(() => {
          output.innerHTML += '<span style="color:#ef4444;">Error: Request failed.</span>';
          btn.disabled = false;
          btn.textContent = 'Run Ping';
        });
      }

      function quickPing(host) {
        document.getElementById('pingTarget').value = host;
        runPing();
      }
    </script>
  `));
});

app.post('/api/diagnostics/ping', requireAuth, (req, res) => {
  const { target } = req.body;
  if (!target || typeof target !== 'string') {
    return res.json({ output: 'Error: No target specified.\n' });
  }
  if (target.length > 300) {
    return res.json({ output: 'Error: Input too long.\n' });
  }

  const command = `ping -c 4 ${target}`;
  const output = simulateExec(command);
  res.json({ output });
});

